	@Override
	protected CubeVector prepareFilterConditionsForLOV(String strSearchText, String columnName, IDataObject cubeInfo,
			UserInfo userInfo, Map filterConditionMap, boolean showAllData, boolean isCustomSort, boolean isSkipcubedatasetcolumndataaccesspermission, String filterCondition)
			throws CubeException, ALSException {

		CubeVector combinedCon = null;
		CubeVector condList = new CubeVector();

		if (strSearchText != null && !strSearchText.equals("")) {
			CubeConditionInfo cubeCondition = new CubeConditionInfo(CubeConditionInfo.AND, columnName,
					CubeConditionInfo.STARTS_WITH, strSearchText);
			cubeCondition.setCaseSensitive(false);
			cubeCondition.setDisplayFormat(strSearchText);
			condList.add(cubeCondition);
			cubeCondition = null;
		}
		
		if (filterCondition != null && !filterCondition.equals("")) {
			String[] multipleCondition = filterCondition.split("#\\|\\|#");
			
			for(int i = 0; i < multipleCondition.length ; i++) {
				String singleCondition = multipleCondition[i];
				
				if (singleCondition != null && !singleCondition.equals("")) {
					CubeConditionInfo cubeCondition = new CubeConditionInfo(CubeConditionInfo.AND, singleCondition.split("=")[0],
							CubeConditionInfo.EQ, singleCondition.split("=")[1]);
					cubeCondition.setCaseSensitive(false);
					cubeCondition.setDisplayFormat(singleCondition.split("=")[1]);
					condList.add(cubeCondition);
					cubeCondition = null;
				}
			}
		}

		if (!showAllData && false) {
			CubeVector preloadedParList = getPreloadingParameterListFromOrgCube();
			if (preloadedParList.size() != 0)
				combinedCon = (CubeVector) CubeUtil.addConditions(preloadedParList, condList, false);
			else
				combinedCon = condList;
		} else {
			combinedCon = condList;
		}
		combinedCon = (CubeVector) CubeUtil.addConditions(combinedCon,
				dataAccessRightsServiceUtil.getDataAccessRightsConditions(cubeInfo, userInfo), false);

	
		Vector vDimension = null;
		CubeVector cvCondition2 = new CubeVector();
		Object[] keys = filterConditionMap.keySet().toArray();
		if (keys.length > 0)
			vDimension = cubeMetadataServiceUtil.getDimensionColumns(cubeInfo, userInfo,isSkipcubedatasetcolumndataaccesspermission);

		for (int k = 0; k < keys.length; k++) {
			if (vDimension!=null && vDimension.contains(keys[k].toString())) {
				if (!isCustomSort) {
					if (keys[k].toString().equals(columnName)) {
						continue;
					}
				}
				CubeVector cvCond = (CubeVector)filterConditionMap.get(keys[k].toString());
    			CubeVector cvCondition = new CubeVector();
    			
    			if(cvCond != null && !cvCond.isEmpty()) {
    				for(int i = 0; i<cvCond.size(); i++){
    					CubeConditionInfo cond1 = new CubeConditionInfo();
    					cond1 = (CubeConditionInfo) cvCond.get(i);
    					CubeConditionInfo cond = new CubeConditionInfo(cond1.getLogicalOperator(),cond1.getColumnName(),cond1.getConditionalOperator(),cond1.getConditionalValue(),cond1.getGroupId(),cond1.getRangeType(),cond1.getCriteriaType(), cond1.getCriteriaTypeTo(), cond1.getTimeSeriesYearType(), cond1.getTimeSeriesTimeType(), cond1.getxValue(), cond1.getxValueTo(), cond1.isSkipEmptyPeriod(), cond1.isIncludeCurrentDay(), cond1.getStrTimeSeriesValue(), cond1.getGroupIdNew(), cond1.getSequence());
    					Object contionObject = cond.getConditionalValue();
    					if(contionObject instanceof DateObject) {
    						DateObject dt1 = new DateObject();
    						dt1 = (DateObject) cond.getConditionalValue();
    						DateObject dt = new DateObject(dt1.isFinancialYear(),dt1.getFirstMonthOfYear(),dt1.getValueType(),dt1.getValue(),dt1.getToRange(),false,dt1.getRangeType(),dt1.isAggregatePeriod(),dt1.getTimeseriesondate(),dt1.getRealtimetoday());
    						if(!(dt.getValueType().equals("ytd") || dt.getValueType().equals("htd") || dt.getValueType().equals("qtd") || dt.getValueType().equals("mtd") || dt.getValueType().equals("wtd"))){
    							cvCondition.add(cond);
    						} 
    						cond.setConditionalValue(dt);
    					} else {
    						cvCondition.add(cond);
    					}
    				}
    			}
				if (cvCondition != null && cvCondition.size() > 0)
					cvCondition2 = (CubeVector) CubeUtil.addConditions(cvCondition2, (CubeVector) cvCondition.clone(),
							false);
			}
		}

		for (int i = 0; cvCondition2 != null && i < cvCondition2.size(); i++) {
			combinedCon.add(cvCondition2.elementAt(i));
		}

		return combinedCon;
	}

	@Override
	public List<SelectItem> getDataDisplayValueMappingOnLOV(HashtableEx ddvmMap, List<Object> cubeDataValueList,
			String userId, int itemType, String strColumnName) {
		
		List<SelectItem> lovDataList = new ArrayList<SelectItem>();
		String displayFormat = userManagementServiceUtil.getUserDateDisplayFormat(userId, itemType);

		
		ALSCalendarFormat alsCalendarFmt = null;
		boolean bFormatting = (displayFormat != null && !"".equals(displayFormat));
		if (bFormatting)
			alsCalendarFmt = new ALSCalendarFormat(displayFormat);

		Object dataObj = null;

		if (cubeDataValueList instanceof CubeVector<?>
				|| (cubeDataValueList instanceof List<?> && !cubeDataValueList.isEmpty() && !(cubeDataValueList.get(0) instanceof SelectItem))) {
			for (int i = 0; i < cubeDataValueList.size(); i++) {
				SelectItem item = new SelectItem();
				dataObj = cubeDataValueList.get(i);
				if (dataObj instanceof SelectItem) {
					item = (SelectItem) cubeDataValueList.get(i);
				} else {
					if (bFormatting && dataObj != null) {
						
						item.setValue(dataObj.toString()); 
						if (dataObj instanceof Date) {
							item.setLabel(alsCalendarFmt.format((java.util.Date) dataObj));
						}
					} else if (dataObj == null) { 
													
						item.setValue(AppConstants.NULL_DISPLAY_VALUE);
						dataObj = AppConstants.NULL_DISPLAY_VALUE;
					} else {
						item.setValue(dataObj.toString());
						item.setLabel(dataObj.toString());
					}
					
					if (ddvmMap != null && ddvmMap.size() > 0) {

						if (ddvmMap.containsKey(strColumnName)) {
							Vector packDisplayList = (Vector) ddvmMap.get(strColumnName);

							if (packDisplayList != null && packDisplayList.size() > 0) {
								for (Iterator iterator = packDisplayList.iterator(); iterator.hasNext();) {
									String[] values = (String[]) iterator.next();
									if (values[0].equalsIgnoreCase(dataObj + "")) {
										item.setLabel(dataObj + " [ " + values[1] + " ]");
										item.setValue(dataObj.toString());
										//break;
									} 
									/*else {
										item.setValue(dataObj.toString());
										item.setLabel(dataObj.toString());
									}*/
								}
							}
						} else {
							if (ddvmMap.containsKey(dataObj + "")) {
								item.setLabel(dataObj + " [ " + ddvmMap.get(dataObj + "") + " ]");
								item.setValue(dataObj.toString());
							}
							if (item.getLabel() == null) {
								item.setLabel(dataObj.toString());
							}
						}
					} else {
						if ("NULL".equals(item.getValue())) {
							item.setLabel(AppConstants.NULL_DISPLAY_VALUE);
						} else if (!bFormatting) {
							item.setLabel(item.getValue());
						} else {
							if (item.getValue().equals(AppConstants.NULL_DISPLAY_VALUE)) {
								item.setLabel(AppConstants.NULL_DISPLAY_VALUE);
							}

							if (item.getLabel() == null) {
								item.setLabel(dataObj.toString());
							}
						}
					}
				}
				lovDataList.add(item);
			}
		} else {

			for (int i = 0; i < cubeDataValueList.size(); i++) {
				SelectItem item = (SelectItem) cubeDataValueList.get(i);
				dataObj = item.getLabel();

				if (ddvmMap != null && ddvmMap.size() > 0) {

					if (ddvmMap.containsKey(strColumnName)) {
						Vector packDisplayList = (Vector) ddvmMap.get(strColumnName);

						if (packDisplayList != null && packDisplayList.size() > 0) {
							for (Iterator iterator = packDisplayList.iterator(); iterator.hasNext();) {
								String[] values = (String[]) iterator.next();
								if (values[0].equalsIgnoreCase((String) dataObj)) {
									item.setLabel(dataObj + " [ " + values[1] + " ]");
									//break;
								} 
								/*else {
									item.setLabel(dataObj.toString());
								}*/
							}
						}
					} else {
						if (ddvmMap.containsKey(dataObj + "")) {
							item.setLabel(dataObj + " [ " + ddvmMap.get(dataObj + "") + " ]");
						}
					}
				}

				lovDataList.add(item);
			}

		}

		return lovDataList;
	}

	@Override
	protected List<SelectItem> getUDHCItemsForLOV(String columnName, String strSearchText,
			List<Object> cubeDataValueList, Vector<CubeDataLabel> vUDHCList, HashtableEx ddvmMap) {

		Vector<CubeDataLabel> vUDLabel = new Vector<CubeDataLabel>();
		List<SelectItem> lovDataList = new ArrayList<SelectItem>();

		for (int i = 0; i < vUDHCList.size(); i++) {
			CubeDataLabel labelUDHC = (CubeDataLabel) (vUDHCList.elementAt(i));
			if (labelUDHC.getColumnName().equalsIgnoreCase(columnName)
					&& labelUDHC.getLabelText().toUpperCase().contains(strSearchText.toUpperCase())) {
				vUDLabel.addElement(labelUDHC);
			}
		}

		if (vUDLabel.size() != 0) {
			Object dataObj = null;

			for (int j = 0; j < vUDLabel.size(); j++) {
				dataObj = vUDLabel.elementAt(j);

				if (!cubeDataValueList.contains(dataObj)) {
					SelectItem item = new SelectItem();

					if (ddvmMap != null && ddvmMap.containsKey(columnName)) {
						Vector packDisplayList = (Vector) ddvmMap.get(columnName);
						if (packDisplayList != null && packDisplayList.size() > 0) {
							for (Iterator iterator = packDisplayList.iterator(); iterator.hasNext();) {
								String[] values = (String[]) iterator.next();
								if (values[0].equalsIgnoreCase(dataObj.toString())) {
									item.setLabel(dataObj + " [ " + values[1] + " ]");
									item.setValue(dataObj.toString());
									break;
								} else {
									item.setValue(dataObj.toString());
									item.setLabel(dataObj.toString());
								}
							}
						}
					} else {
						if (ddvmMap != null && ddvmMap.size() > 0) {
							if (ddvmMap.containsKey(dataObj.toString())) {
								item.setLabel(dataObj + " [ " + ddvmMap.get(dataObj.toString()) + " ]");
								item.setValue(dataObj.toString());
							} else {
								item.setValue(dataObj.toString());
								item.setLabel(dataObj.toString());
							}
						} else {
							item.setValue(dataObj.toString());
							item.setLabel(dataObj.toString());
						}
					}

					lovDataList.add(item);
				}
			}
		}

		return lovDataList;
	}

	@Override
	protected List<SelectItem> getGlobalVariableForLOV(String columnName, String strSearchText,
			List<Object> cubeDataValueList, List<ActiveGlobalVariableInfo> activeGlobalVariableInfoList,
			boolean isMeasure) {

		List<SelectItem> lovDataList = new ArrayList<SelectItem>();

		if (activeGlobalVariableInfoList != null && activeGlobalVariableInfoList.size() > 0) {
			try {
				int columnType = CubeUtil.getColumnType(columnName, this.getOriginalResultSetMetaData());
				for (int i = 0; i < activeGlobalVariableInfoList.size(); i++) {
					ActiveGlobalVariableInfo activeGlobalVariableInfo = activeGlobalVariableInfoList.get(i);
					GlobalVariableInfo globalVariableInfo = activeGlobalVariableInfo.getGlobalVariableInfo();
					String variableName = globalVariableInfo.getAssociatedColumnName();
					String type = globalVariableInfo.getType();
					String globalVariableName = globalVariableInfo.getGlobalVariableName().substring(1,
							globalVariableInfo.getGlobalVariableName().lastIndexOf("$"));
					if (!strSearchText.equals("")
							&& !globalVariableName.toLowerCase().contains(strSearchText.toLowerCase()))
						continue;
					if (!isMeasure) {
						if (type.equals(String.valueOf(columnType))) {
							SelectItem item = new SelectItem();
							item.setLabel(globalVariableName);
							item.setValue(globalVariableInfo.getGlobalVariableName());
							lovDataList.add(item);
						} else {
							if (type.equals(String.valueOf(Types.DOUBLE))) {
								if (columnType == Types.DECIMAL || columnType == Types.NUMERIC
										|| columnType == Types.FLOAT || columnType == Types.REAL) {
									SelectItem item = new SelectItem();
									item.setLabel(globalVariableName);
									item.setValue(globalVariableInfo.getGlobalVariableName());
									lovDataList.add(item);
								}
							} else if (type.equals(String.valueOf(Types.BOOLEAN))) {
								if (columnType == Types.BIT) {
									SelectItem item = new SelectItem();
									item.setLabel(globalVariableName);
									item.setValue(globalVariableInfo.getGlobalVariableName());
									lovDataList.add(item);
								}
							}
							
							if (type.equals(String.valueOf(Types.DATE)) || type.equals(String.valueOf(Types.TIME))
									|| type.equals(String.valueOf(Types.TIMESTAMP))) {
								if (columnType == Types.DATE || columnType == Types.TIME
										|| columnType == Types.TIMESTAMP) {
									SelectItem item = new SelectItem();
									item.setLabel(globalVariableName);
									item.setValue(globalVariableInfo.getGlobalVariableName());
									lovDataList.add(item);
								}

							}
						}
					} else {

						if (type.equals(String.valueOf(columnType))) {
							SelectItem item = new SelectItem();
							item.setLabel(globalVariableName);
							item.setValue(globalVariableInfo.getGlobalVariableName());
							lovDataList.add(item);
						} else {
							if ((type.equals(String.valueOf(Types.DOUBLE))
									|| type.equals(String.valueOf(Types.INTEGER)))
									&& (columnType == Types.DECIMAL || columnType == Types.NUMERIC
											|| columnType == Types.FLOAT || columnType == Types.REAL
											|| columnType == Types.INTEGER || columnType == Types.DOUBLE)) {
								SelectItem item = new SelectItem();
								item.setLabel(globalVariableName);
								item.setValue(globalVariableInfo.getGlobalVariableName());
								lovDataList.add(item);
							} else if (type.equals(String.valueOf(Types.BOOLEAN))) {
								if (columnType == Types.BIT) {
									SelectItem item = new SelectItem();
									item.setLabel(globalVariableName);
									item.setValue(globalVariableInfo.getGlobalVariableName());
									lovDataList.add(item);
								}
							}
							
							if (type.equals(String.valueOf(Types.DATE)) || type.equals(String.valueOf(Types.TIME))
									|| type.equals(String.valueOf(Types.TIMESTAMP))) {
								if (columnType == Types.DATE || columnType == Types.TIME
										|| columnType == Types.TIMESTAMP) {
									SelectItem item = new SelectItem();
									item.setLabel(globalVariableName);
									item.setValue(globalVariableInfo.getGlobalVariableName());
									lovDataList.add(item);
								}

							}
						}

					}
				}
			} catch (CubeException e) {
				ApplicationLog.error(e);
			}
		}
		return lovDataList;
	}

	/**
	 * To create cube.
	 * 
	 * @param strCubeName
	 *            cube name
	 * @param sUserName
	 *            user name
	 * @throws CubeException
	 * @throws NotBoundException
	 * @throws IOException
	 */
	public void createCube(String strCubeName, UserInfo userInfo, SmartenInfo graphInfo)
			throws CubeException, IOException, NotBoundException {

		FileEx cubeFileEx = null;
		if (strCubeName.endsWith(MashUpConstants.DATASETS_FILE_EXT)) {
			cubeFileEx = new FileEx(MashupsConstants.MASHUPS_MODULE_DATASETS, strCubeName);
		} else {
			cubeFileEx = new FileEx(com.elegantjbi.util.AppConstants.CUBES_DIR, strCubeName);
		}
		String strProjectDirectory = cubeFileEx.getCanonicalPath();

		graphCube = (Cube) applicationContext.getBean("cubeImpl");
		
		graphCube.setInfoOnResultSet(graphInfo.getCubeInfo(), graphInfo.getGraphName(), AppConstants.SMARTEN,
				graphInfo.getGraphId(), graphInfo.isEnableManagedMemory());
		
		graphCube.setUser(userInfo.getUserId());
		graphCube.setUserInfo(userInfo);
		graphCube.setSkipcubedatasetcolumndataaccesspermission(graphInfo.isSkipcubedatasetcolumndataaccesspermission());
		graphCube.setAllowanonymouspublicaccess(graphInfo.isAllowanonymouspublicaccess());
		graphCube.setEnablesubcube(graphInfo.isEnablesubcube());
		graphCube.setDirectory(strProjectDirectory, graphInfo.getCubeInfo());
		graphCube.setAutoRefresh(false);
		this.cubeDisplayName = graphInfo.getCubeInfo().getDataObjecName();
		this.graphDisplayName = graphInfo.getGraphName();
	}

	@SuppressWarnings("unchecked")
	private boolean setCubeData(SmartenInfo graphInfo, String loggedInUserId, boolean createdFromAnalysis)
			throws CubeException, DatabaseOperationException {

		boolean dataSet = false;

		graphInfo.setColColumns(new Vector());
		graphInfo.setRowColumns(new Vector());
		graphInfo.setDataColumns(new Vector());
		graphInfo.setLineGraphRowLabelsForCombinedGraph(new Vector());
		graphInfo.setLineGraphDataLabelsForCombinedGraph(new Vector());
		graphInfo.setDataColLabels3(new Vector());
		graphInfo.setTheDataColLabels4(new Vector());

		CubeViewInfo viewInfo = graphCube.getViewStruct(true);
		int theDataColumnCount = viewInfo.getDataColumnInfoList().size();
		int theRowLabelCount = viewInfo.getRowLabelInfoList().size();
		int theColLabelCount = viewInfo.getColLabelInfoList().size();

		Vector<CubeColumnInfo> dataColumnInfoList = new Vector<CubeColumnInfo>();

		CubeColumnInfo theYCubeColumnInfo = null;

		boolean isMapNull = false;
		boolean isFormatNull = false;

		if (getActiveDDVMs(graphInfo, loggedInUserId) == null) {
			isMapNull = true;
		}

		Hashtable<String, Vector<Object>> m_dataFormat = null;

		if (graphInfo.getColumnFormat() == null) {
			isFormatNull = true;
			m_dataFormat = new Hashtable<String, Vector<Object>>();
		}

		
		for (int theI = 1; theI <= theDataColumnCount; theI++) {
			theYCubeColumnInfo = (CubeColumnInfo) viewInfo.getDataColumnInfoList().elementAt(theI - 1);

			if (theYCubeColumnInfo instanceof CubeDataColumnInfo) {
				continue;
			}

			String theColumnName = theYCubeColumnInfo.toString();

			switch (theYCubeColumnInfo.getType()) {
			case Types.BINARY:
			case Types.VARBINARY:
			case Types.LONGVARBINARY:
				continue;
			}

			graphInfo.getDataColumns().addElement(theColumnName);
			graphInfo.getLineGraphDataLabelsForCombinedGraph().addElement(theColumnName);

			dataColumnInfoList.addElement(theYCubeColumnInfo);
		}

		
		for (int theI = 1; theI <= theRowLabelCount; theI++) {
			String rowName = viewInfo.getRowLabelInfoList().elementAt(theI - 1).toString();

			graphInfo.getRowColumns().addElement(rowName);
			graphInfo.getLineGraphRowLabelsForCombinedGraph().addElement(rowName);
		}

		
		for (int theI = 1; theI <= theColLabelCount; theI++) {
			String colName = viewInfo.getColLabelInfoList().elementAt(theI - 1).toString();

			graphInfo.getColColumns().addElement(colName);
		}

		Hashtable<String, Integer> m_colType = new Hashtable<String, Integer>();

		if (isMapNull || isFormatNull) {
			ICubeResultSetMetaData icubeMetaData = getOriginalResultSetMetaData();
			CubeColumnInfo cubeColumnInfo = null;
			for (int iIndex = 1; iIndex <= icubeMetaData.getColumnCount(); iIndex++) {
				cubeColumnInfo = icubeMetaData.getColumn(iIndex);
				m_colType.put(cubeColumnInfo.getName(), new Integer(cubeColumnInfo.getType()));

				if (isFormatNull) {
					
					switch (cubeColumnInfo.getType()) {
					case Types.DATE:
					case Types.TIME:
					case Types.TIMESTAMP:
						Vector<Object> dateData = new Vector<Object>();
						dateData.add(new Integer(DATE_FORMAT));
						dateData.add(new String("")); 
						dateData.add(new String("")); 

						m_dataFormat.put(cubeColumnInfo.getName(), dateData);
						break;
					case Types.DOUBLE:
					case Types.FLOAT:
					case Types.SMALLINT:
					case Types.TINYINT:
					case Types.INTEGER:
					case Types.BIGINT:
					case Types.DECIMAL:
					case Types.NUMERIC:
					case Types.REAL:
						Vector<Object> data = new Vector<Object>();
						data.add(new Integer(NUMBER_FORMAT));
						data.add(new Integer(0)); 
						data.add(new Integer(0)); 
						data.add(new Boolean(false));
						data.add(new String("")); 
						data.add(new Boolean(false));
						data.add(new Boolean(false));

						m_dataFormat.put(cubeColumnInfo.getName(), data);

						break;
					}
				}
			}
			cubeColumnInfo = null;
			icubeMetaData = null;

			CubeVector userDataColumnInfo = graphCube.getUserColumnInfoList();

			for (int i = 0; i < userDataColumnInfo.size(); i++) {
				UddcTemplateInfo dataLable = (UddcTemplateInfo) userDataColumnInfo.get(i);
				if (dataLable.isVirtual())
					graphInfo.getUserVirtualColumnInfoList().add(dataLable);
			}
			
			userDataColumnInfo = graphCube.prepareUserColumnInfoList(userDataColumnInfo,
					graphCube.getDataColumnInfoList(), new HashMap(), new HashMap(), new CubeVector(), new HashMap(), new HashMap(),
					new CubeVector());

			userDataColumnInfo = graphCube.prepareDataColumnInfoList(userDataColumnInfo);

			CubeVector dataInfoVec = new CubeVector();
			dataInfoVec.addAll(dataColumnInfoList);
			dataInfoVec.addAll(userDataColumnInfo);

			graphCube.setDataColumnInfoList(dataInfoVec);
			CubeDataColumnInfo cubeDataColumnInfo = null;

			for (int cnt = 0; cnt < userDataColumnInfo.size(); cnt++) {
				cubeDataColumnInfo = (CubeDataColumnInfo) userDataColumnInfo.get(cnt);

				m_colType.put(cubeDataColumnInfo.getName(), new Integer(cubeDataColumnInfo.getType()));

				if (isFormatNull) {
					
					switch (cubeDataColumnInfo.getType()) {
					case Types.DATE:
					case Types.TIME:
					case Types.TIMESTAMP:
						Vector<Object> dateData = new Vector<Object>();
						dateData.add(new Integer(DATE_FORMAT));
						dateData.add(new String("")); 
						dateData.add(new String(""));

						m_dataFormat.put(cubeDataColumnInfo.getName(), dateData);
						break;
					case Types.DOUBLE:
					case Types.FLOAT:
					case Types.SMALLINT:
					case Types.TINYINT:
					case Types.INTEGER:
					case Types.BIGINT:
					case Types.DECIMAL:
					case Types.NUMERIC:
					case Types.REAL:
						Vector<Object> data = new Vector<Object>();
						data.add(new Integer(NUMBER_FORMAT)); 
						data.add(new Integer(0)); 
						data.add(new Integer(0)); 
						data.add(new Boolean(false)); 
						data.add(new String("")); 
						data.add(new Boolean(false));
						data.add(new Boolean(false));

						m_dataFormat.put(cubeDataColumnInfo.getName(), data);

						break;
					}
				}
			}

			
			for (int iCnt = 0; iCnt < dataColumnInfoList.size(); iCnt++) {
				cubeColumnInfo = dataColumnInfoList.elementAt(iCnt);

				if (!cubeColumnInfo.getSourceName().equals(cubeColumnInfo.getName())) {
					Vector<Object> data = new Vector<Object>();
					data.add(new Integer(NUMBER_FORMAT));
					data.add(new Integer(0)); 
					data.add(new Integer(0)); 
					data.add(new Boolean(false));
					data.add(new String("")); 
					data.add(new Boolean(false)); 
					data.add(new Boolean(false)); 
					m_dataFormat.put(cubeColumnInfo.getName(), data);
				}
			}
			cubeColumnInfo = null;

			graphInfo.setColumnFormat(m_dataFormat);
		}

		graphInfo.setDataColumnInfoList(dataColumnInfoList);

		graphInfo.setColumnType(m_colType);

		if (graphInfo.getObjectCubeDefinition() == null) {
			graphInfo.setObjectCubeDefinition(new ObjectCubeDefinitionInfo());
		}

		graphOrgCube = (Cube) graphCube.Clone();
		graphInfo.setUserLabelInfoList(graphOrgCube.getUserLabelInfoList());

	
		graphInfo.setGraphVisible(true);

		dataSet = true;

		return dataSet;
	}

	private boolean setCubeData(SmartenInfo graphInfo, String loggedInUserId)
			throws DatabaseOperationException, CubeException {
		return setCubeData(graphInfo, loggedInUserId, false);
	}

	public SmartenInfo initializeGraph(int graphMode, Hashtable<String, Object> params, UserInfo loggedInUser,
			boolean putLock) throws MDXException, RealTimeCubeException, CubeException, IOException, NotBoundException,
			DatabaseOperationException, ObjectAccessException, ObjectNotFoundException, CubeNotFoundException,
			CubeAccessException, ALSException {

		return initializeGraph(graphMode, params, loggedInUser, null, putLock,null);
	}

	@SuppressWarnings("rawtypes")
	public SmartenInfo initializeGraph(int graphMode, Hashtable<String, Object> params, UserInfo loggedInUser,
			Cube cube, boolean putLock,SmartenInfo graphInfo) throws MDXException, RealTimeCubeException, CubeException, IOException,
			NotBoundException, DatabaseOperationException, ObjectAccessException, ObjectNotFoundException,
			CubeNotFoundException, CubeAccessException , ALSException{

		
		boolean requireSetGraph = false;
		IDataObject cubeInfo = null;

		Vector theDataColLabels = null;
		Vector theDataColLabels2 = null;
		Vector theRowColLabels = null;
		Vector theRowColLabels2 = null;
		Vector theColColLabels = null;
		if (graphMode == AppConstants.NEW_MODE) {
			
			if (params.get("cubeId").toString().endsWith(MashUpConstants.DATASETS_FILE_EXT)) {
				cubeInfo = dataSetsService.getById(params.get("cubeId").toString());
			} else if (!params.get("cubeId").toString().endsWith(AppConstants.NLP_FILE_EXT)){
				cubeInfo = cubeDataServiceUtil.getCubeByCubeId(params.get("cubeId").toString());
			}
			graphInfo = new SmartenInfo();
			graphInfo.setGraphMode(AppConstants.NEW_MODE);
			graphInfo.setGraphName(ResourceManager.getString("New SmartenView"));
			graphInfo.setCreatedBy(loggedInUser);
			graphInfo.setCubeInfo(cubeInfo);
			
			String graphId = String.valueOf(System.currentTimeMillis());
			graphInfo.setNewGraphId(graphId);
			
			try {
				graphInfo.setPdfPageSetup(pageSetupServiceUtil.getPDFPageSetupInfo());
			} catch (DatabaseOperationException e) {
				ApplicationLog.error(ResourceManager.getString("LOG_ERROR_MSG_FAILED_TO_SET_PDFPAGESETUP",
						new Object[] { loggedInUser.getUsername() }), e);
			}
		} else if (graphMode == AppConstants.OPEN_MODE) {
			String graphId = StringUtil.null2String(params.get("objectId"));
			if(graphInfo == null) {
				graphInfo = getGraphById(graphId);	
			}
			if(params.get("checkPermission") == null) {
				checkPermissions(graphInfo, AppConstants.SMARTEN, loggedInUser);
			}
			
			if (putLock) {
				lockObject(graphId, AppConstants.SMARTEN_TITLE, loggedInUser.getUserId());
			}
			cubeInfo = graphInfo.getCubeInfo();

			requireSetGraph = true;

			graphInfo.setReadFromCache(true);
		}

		if (cube != null) {
			
			graphCube = cube;
			IDataObject dataObject = graphInfo.getCubeInfo();
			if(cube != null && (cube.getCubeInfo() instanceof NlpDataInfo)) {
				dataObject = cube.getCubeInfo();
				graphInfo.setCubeInfo(dataObject);
			}
			graphCube.setInfoOnResultSet(dataObject, graphInfo.getGraphName(), AppConstants.GRAPH,
					graphInfo.getGraphId(), graphInfo.isEnableManagedMemory());
			graphCube.setEnablesubcube(graphInfo.isEnablesubcube());
			
			graphCube.setAutoRefresh(false);
			graphCube.setDataoperationison(graphInfo.getGraphProperties().getApplyDataoperationwhen());

		} else {
			createCube(cubeInfo.getDataObjectId(), loggedInUser, graphInfo);
			if (graphMode == AppConstants.NEW_MODE) {
				graphCube.setObjectId(graphInfo.getNewGraphId());// 2018 merge
				if (cubeInfo.getDatabaseCubeType() == ICubeConstants.R_CUBE
						|| cubeInfo.getDatabaseCubeType() == ICubeConstants.REALTIME_R_CUBE) {
					if (graphCube != null) {
						graphCube.setrProfileId(cubeInfo.getDatabaseId());
						graphCube.setrInputCubeId(cubeInfo.getrInputCubeId());
						graphCube.setrScriptInputVOs(cubeInfo.getrScriptInputVOs());
						graphCube.setrScriptOutputVOs(cubeInfo.getrScriptOutputVOs());
					}
				}
			}
		}
		

		if (graphInfo.getDataColumns() != null) {
			theDataColLabels = (Vector) graphInfo.getDataColumns().clone();
		}

		if (graphInfo.getRowColumns() != null) {
			theRowColLabels = (Vector) graphInfo.getRowColumns().clone();
		}
		if (graphInfo.getColColumns() != null) {
			theColColLabels = (Vector) graphInfo.getColColumns().clone();
		}
		if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
			theDataColLabels2 = (Vector) graphInfo.getLineGraphDataLabelsForCombinedGraph().clone();
			theRowColLabels2 = (Vector) graphInfo.getLineGraphRowLabelsForCombinedGraph().clone();
		}
		CubeVector vUserDefinedDataColumns = getAllUserDefinedColumns(loggedInUser);
		if(graphMode == AppConstants.OPEN_MODE && !loggedInUser.isFromAPI()) {
			metadatacolumnvalidation( graphInfo, loggedInUser,  vUserDefinedDataColumns);
		}
		if (requireSetGraph) {
			try {
				readObjectCubeDefinition(graphInfo, loggedInUser, cubeInfo);
			} catch (RScriptException e) {
				
				ApplicationLog.error(e);
			}
			Boolean fromPublishProcess = null;
			if (params.containsKey("fromPublishProcess")) {
				fromPublishProcess = (Boolean) params.get("fromPublishProcess");
			}

			if (!cubeColumnPermission && null != fromPublishProcess && !fromPublishProcess) {
				throw new ObjectAccessException("MSG_CHECK_OBJECT_PERMISSION");
			} else if (!cubeColumnPermission && null == fromPublishProcess) {
				throw new ObjectAccessException("MSG_CHECK_OBJECT_PERMISSION");
			}
			graphCube.setShowRankOthers(
					graphInfo.getGraphProperties().getxAxisProperties().getLabelProperties().isOthers());

			try {
				initializeActiveFilter(graphInfo, loggedInUser);
			} catch (RScriptException e) {
				
				ApplicationLog.error(e);
			}
		}

		setCubeData(graphInfo, loggedInUser.getUserId());

		if (params.containsKey("windowScreenHeight") && params.containsKey("windowScreenWidth")) {
			graphInfo.setWindowScreenWidth((Integer) (params.get("windowScreenWidth")));
			graphInfo.setWindowScreenHeight((Integer) (params.get("windowScreenHeight")));
		}
		if (params.containsKey("graphAreaFitToSection")) {
			graphInfo.setGraphAreaFitToSection((Boolean) params.get("graphAreaFitToSection"));
		}

		if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
			if (theRowColLabels.size() > 0 && theRowColLabels2.size() > 0 && theColColLabels.size() == 0) {
				if (theRowColLabels.get(0).equals(theRowColLabels2.get(0)))
					theRowColLabels2.remove(0);
			}
			graphInfo.setColColumns(theColColLabels);
			graphInfo.setRowColumns(theRowColLabels);
			graphInfo.setDataColumns(theDataColLabels);
			graphInfo.setLineGraphRowLabelsForCombinedGraph(theRowColLabels2);
			graphInfo.setLineGraphDataLabelsForCombinedGraph(theDataColLabels2);
		} else {
			if (theColColLabels != null) {
				graphInfo.setColColumns(theColColLabels);
			}
			if (theRowColLabels != null) {
				graphInfo.setRowColumns(theRowColLabels);
			}
			if (theDataColLabels != null) {
				graphInfo.setDataColumns(theDataColLabels);
			}
		}

		
		List<CubeLabelInfo> sortList = graphInfo.getActiveTemplateProperties().getSortList();
		if (sortList != null && sortList.size() > 0) {
			for (int i = 0; i < sortList.size(); i++) {
				CubeLabelInfo cubeLabelInfo = sortList.get(i);
				String columnName = cubeLabelInfo.getName();
				if (graphCube.getOriginalResultSetMetaData().findColumn(columnName) == 0) {
					sortList.remove(i);
				}
			}
		}

		GraphProperties gp = graphInfo.getGraphProperties();
		if (gp != null)
			this.setAdaptiveBehaviour("" + gp.getAdaptiveBehaviour());
		verifyUsedDimensionAndMeasures(graphInfo, loggedInUser);
		verifyFilterCondition(graphInfo);
		setDataFormatAndMapFromCube(graphInfo, loggedInUser);

		if (graphInfo.getSubCubeMetaDataInfo() != null) {
			
			graphOrgCube.setSubCubeMetadataList(graphInfo.getSubCubeMetaDataInfo().getSubCubeMetadataList());

			if (graphInfo.getSubCubeMetaDataInfo().getSubCubeMetadataDashBoardList() != null
					&& graphInfo.getSubCubeMetaDataInfo().getSubCubeMetadataDashBoardList().size() > 0) {
				graphOrgCube.setSubCubeMetadataListForDashBoard(
						graphInfo.getSubCubeMetaDataInfo().getSubCubeMetadataDashBoardList());
			}
		}

		initializeGraphImage(graphInfo, graphMode);

		boolean requireSetGraphData = false; 
		if (params.containsKey("fromPublishNow")) {
			requireSetGraphData = (boolean) params.get("fromPublishNow");
		}
		if (params.containsKey("autoRefresh_dashboard")) {
			boolean bRefresh = ((Boolean) params.get("autoRefresh_dashboard"));
			requireSetGraphData = bRefresh;
			graphInfo.setReadFromCache(bRefresh);
		}
		if(params.containsKey("isFromAPI")) {
			boolean bRefresh = ((Boolean)params.get("isFromAPI"));
			requireSetGraphData = bRefresh;
			graphInfo.setReadFromCache(false);
		}

		doGraphChanged(graphInfo.getGraphType(), requireSetGraphData, graphInfo, loggedInUser);
		if (requireSetGraphData) {
			setDefaultProperties(graphInfo);
		}
			Vector<String> tmpDataItemVector = (Vector<String>) graphInfo.getDataColumns().clone();
			if(tmpDataItemVector==null) {
				tmpDataItemVector=new Vector<>();
			}
			List<String> activeUddcList=new ArrayList<>();
			List<String> dataList=new ArrayList<>();
			List<ActiveUDDCInfo> tActiveUDDCList = graphInfo.getActiveUDDCInfo(loggedInUser.getUserId());
			if(tActiveUDDCList==null) {
				tActiveUDDCList=new ArrayList<>();
			}
			if(!tActiveUDDCList.isEmpty()) {
				for(String mesName:tmpDataItemVector) {
						dataList.add(mesName);
				}
				for(ActiveUDDCInfo uddc:tActiveUDDCList) {
					String mesName=uddc.getUddcTemplateInfo().getColumnName();
					if(!uddc.getUddcTemplateInfo().getBaseuddc().isEmpty())
						mesName=uddc.getUddcTemplateInfo().getBaseuddc();
					activeUddcList.add(mesName);
				}
			}
				
			if(!activeUddcList.isEmpty()) {
				List<String> rowColDimList=new ArrayList<>(dataList);
				Vector rowDim=graphInfo.getRowColumns();
				rowColDimList.addAll(rowDim);
				Vector colDim=graphInfo.getColColumns();
				rowColDimList.addAll(colDim);
				String[] activeUddcs=activeUddcList.toArray(new String[0]);
				String[] mesRowColDimItems=rowColDimList.toArray(new String[0]);
				checkOutlinerUddcdublicateColumn(new String[] {},activeUddcs,mesRowColDimItems,cubeInfo.getDataObjectId(),cubeInfo,false,loggedInUser,null,graphInfo.isSkipcubedatasetcolumndataaccesspermission(loggedInUser));
			}
		return graphInfo;
	}

	/**
	 * Verify condition if column has added in page filter condition and has been
	 * remove while cube rebuilding process from the cube method will remove deleted
	 * column condition and update the filter condition.
	 * 
	 * @param graphInfo
	 */

	private void verifyFilterCondition(SmartenInfo graphInfo) {

		if (graphInfo != null) {
			String[][] filterConditionArray = graphInfo.getMultiPageFilterInfo();

			if (filterConditionArray != null && filterConditionArray.length > 0) {
				List<String[]> tmpList = new ArrayList<String[]>();
				for (String[] strFilterInfoArray : filterConditionArray) {
					if (strFilterInfoArray != null && strFilterInfoArray.length > 0) {
						String columnName = strFilterInfoArray[0];
						try {
							if (graphCube.getOriginalResultSetMetaData().findColumn(columnName) > 0) {
								tmpList.add(strFilterInfoArray);
							} else {
								if (graphCube.getFilterConditions().containsKey(columnName)) {
									graphCube.getFilterConditionsMap().remove(columnName);
									CubeVector conditionsVector = graphInfo.getRayOuterConditions();
									CubeVector tmpCubeVector = new CubeVector();
									if (conditionsVector != null && conditionsVector.size() > 0) {
										for (Object object : conditionsVector) {
											if (object instanceof CubeConditionInfo) {
												CubeConditionInfo cubeConditionInfo = (CubeConditionInfo) object;
												if (!columnName.equals(cubeConditionInfo.getColumnName())) {
													tmpCubeVector.add(cubeConditionInfo);
												}
											}
										}
										graphInfo.setRayOuterConditions(tmpCubeVector);
									}

								}
							}
						} catch (CubeException e) {
							ApplicationLog.error(e);
						}
					}
				}
				int size = tmpList.size();
				if (size > 0) {
					String[][] updatedFilterConditionArray = new String[size][];
					for (int i = 0; i < tmpList.size(); i++) {
						updatedFilterConditionArray[i] = tmpList.get(i);
					}
					graphInfo.setMultiPageFilterInfo(updatedFilterConditionArray);
				} else {
					graphInfo.setMultiPageFilterInfo(null);
				}
				List<String> strColumnList = new ArrayList<String>();
				if (filterConditionArray != null && filterConditionArray.length > 0) {
					for (int i = 0; i < filterConditionArray.length; i++) {
						strColumnList.add(filterConditionArray[i][0]);
					}
				}
				graphOrgCube.setObjectpagefiltercolumnList(strColumnList);

			}
		}
		
		if (graphInfo != null && graphInfo.getActiveTemplateProperties() != null
				&& graphInfo.getActiveTemplateProperties().getPreloadingParameters() != null) {
			ArrayList<ParamItem> preLodedCondition = graphInfo.getActiveTemplateProperties().getPreloadingParameters();
			ArrayList<ParamItem> preLodedCondition1 = new ArrayList<ParamItem>();
			for (ParamItem item:preLodedCondition) {
				try {
					com.elegantjbi.core.olap.CubeColumnInfo cubeColumnInfo = null;
					if(graphCube.getOriginalResultSetMetaData()!=null) {
						for (int iIndex = 1; iIndex <= graphCube.getOriginalResultSetMetaData().getColumnCount(); iIndex++) {
							cubeColumnInfo = graphCube.getOriginalResultSetMetaData().getColumn(iIndex);
							if (cubeColumnInfo.getName().equals(item.getColumnName())) {
								break;
							} 
							cubeColumnInfo = null;
						}
					}
					if(cubeColumnInfo!=null){
						item.setColumnType(cubeColumnInfo.getType());
						preLodedCondition1.add(item);
					}
				} catch (CubeException e) {
					ApplicationLog.error(e);
				}
			}
			graphInfo.getActiveTemplateProperties().setPreloadingParameters(preLodedCondition1);
			setObjectprelodingparametercolumnList(preLodedCondition1);
		}
	}

