	/**
	 * Sets default flag for toolbar group visibility of specified Hashtable object.
	 * Is sets default flag when object's status not exists or null.
	 * 
	 * @param bgTable
	 *            Contains Toolbar Button Group Status
	 */
	@SuppressWarnings("unchecked")
	private void setDefaultToolbarGroup(Hashtable bgTable) {

		Boolean tbgStatus = null;

		tbgStatus = (Boolean) bgTable.get(GraphCommandNameList.CMD_NAME_FILE);
		if (tbgStatus == null) {
			bgTable.put(GraphCommandNameList.CMD_NAME_FILE, Boolean.TRUE);
		}

		tbgStatus = (Boolean) bgTable.get(GraphCommandNameList.CMD_NAME_FILE_EXPORT);
		if (tbgStatus == null) {
			bgTable.put(GraphCommandNameList.CMD_NAME_FILE_EXPORT, Boolean.TRUE);
		}

		tbgStatus = (Boolean) bgTable.get(ALSCommandNameList.CMD_NAME_VIEW_TOOLS);
		if (tbgStatus == null) {
			bgTable.put(ALSCommandNameList.CMD_NAME_VIEW_TOOLS, Boolean.TRUE);
		}

		tbgStatus = (Boolean) bgTable.get(GraphCommandNameList.CMD_NAME_VIEW);
		if (tbgStatus == null) {
			bgTable.put(GraphCommandNameList.CMD_NAME_VIEW, Boolean.TRUE);
		}

		tbgStatus = (Boolean) bgTable.get(GraphCommandNameList.CMD_NAME_FORMAT);
		if (tbgStatus == null) {
			bgTable.put(GraphCommandNameList.CMD_NAME_FORMAT, Boolean.TRUE);
		}
		tbgStatus = (Boolean) bgTable.get(GraphCommandNameList.CMD_NAME_ZOOM);
		if (tbgStatus == null) {
			bgTable.put(GraphCommandNameList.CMD_NAME_ZOOM, Boolean.TRUE);
		}
	}

	/**
	 * To get graph dimension map.
	 * 
	 * @param cubeInfo
	 *            Cube identifier
	 * @return graph dimension map
	 * @throws CubeException
	 */
	public Hashtable getGraphDimensionMap(IDataObject cubeInfo, UserInfo userInfo,SmartenInfo smarteninfo) throws CubeException {
		ALSColumnMap map;

		try {
			map = new ALSColumnMap(cubeInfo.getDataObjectId(), cubeInfo.getDataObjectDimensionMapInfoList());
			map.setSkipcubedatasetcolumndataaccesspermission(smarteninfo.isSkipcubedatasetcolumndataaccesspermission(userInfo));
			return map.getMap(userInfo, cubeInfo);
		} catch (CubeException e) {
			ApplicationLog.error(ResourceManager.getString("LOG_ERROR_FAILED_TO_GET_DIMENSION_MAP",
					new Object[] { cubeInfo, userInfo }), e);

			throw e;
		}
	}

	/**
	 * This method is use to get Graph OutLiner Detail
	 * 
	 * @param outlinerBean
	 *            out liner data object
	 * @param graphInfo
	 *            graph info
	 * @param loggedInUser
	 *            current logged in user detail
	 * @param dimensionList
	 *            cube dimension list
	 * @param strCubeId
	 *            cube id
	 * @param bFromFilter
	 *            flag for filter
	 * @return outliner bean obect
	 * @throws CubeException
	 *             exception
	 * @throws DatabaseOperationException
	 *             exception
	 */
	@SuppressWarnings("unchecked")
	public OutlinerBean getOutlinerData(OutlinerBean outlinerBean, SmartenInfo graphInfo, UserInfo loggedInUser,
			List<String> dimensionList, IDataObject cubeInfo, boolean bFromFilter)
			throws CubeException, DatabaseOperationException {

		boolean isPtreeEnable = outlinerBean.isPtreeEnable();
		Hashtable h_dimension_map = outlinerBean.getDimensionMap();
		Vector vcheck_dimension_column = outlinerBean.getCheckDimensionColumn();
		String userId = loggedInUser.getUserId();
		CubeVector vOrderedDataColumns = outlinerBean.getvOrderedDataColumns();
		h_dimension_map = new Hashtable();
		String sCubeName = graphCube.getName();
		
		CubeVector srcLabels = outlinerBean.getSrcLabels();
		Vector vKeyLabels = outlinerBean.getvKeyLabels();
		Vector vDataLabels = outlinerBean.getvDataLabels();
		Vector vTimeDimeDataLabel = outlinerBean.getvTimeDimeDataLabel();
		Vector vTimeDimeDataLavel = outlinerBean.getvTimeDimeDataLavel();
		CubeVector vUserDefinedDataColumns = outlinerBean.getvUserDefinedDataColumns();
		CubeVector pageLabels = outlinerBean.getPageLabels();
		CubeVector rowLabels = outlinerBean.getRowLabels();
		CubeVector colLabels = outlinerBean.getColLabels();
		CubeVector dataLabels = outlinerBean.getDataLabels();
		CubeVector vActiveUserDefinedDataColumns = outlinerBean.getvActiveUserDefinedDataColumns();
		Vector<String> itemDisplayName = outlinerBean.getItemDimsplayName();
		List<String> activeGlobalVarNames = new ArrayList<String>();
		CubeColumnExpExecutor expressionExecutor = getColumnExpressionExecutor();
		List<String> virtualUDDC = outlinerBean.getVirtualUDDC();
		try {
			com.elegantjbi.service.analysis.ALSColumnMap map = new com.elegantjbi.service.analysis.ALSColumnMap(
					sCubeName, cubeInfo.getDataObjectDimensionMapInfoList());
			h_dimension_map = map.getMap(loggedInUser, cubeInfo);
			outlinerBean.setDimensionMap(h_dimension_map);
			
			outlinerBean.setDimensionDescriptionMap(getColumnDescAndDisplayName(cubeInfo, graphInfo,false));

		} catch (Exception e) {
			ApplicationLog.error(ResourceManager.getString("LOG_ERROR_FAILED_GET_DIMENSION_MAP"), e);
		}
		if (!h_dimension_map.isEmpty()) {
			for (Enumeration enumer = h_dimension_map.keys(); enumer.hasMoreElements();) {
				String skey = enumer.nextElement().toString();
				Vector vtemp = (Vector) cubeMetadataServiceUtil.getAllowedColumns(loggedInUser,
						(Vector) h_dimension_map.get(skey), cubeInfo,graphInfo.isSkipcubedatasetcolumndataaccesspermission(loggedInUser));// (Vector) h_dimension_map.get(skey);

				for (int i = 0; i < vtemp.size(); i++) {
					vcheck_dimension_column.add(vtemp.elementAt(i).toString());
				}
			}

			List<String> tmp = new ArrayList();
			tmp.addAll(h_dimension_map.keySet());
			for (String key : tmp) {
				Vector tmpVector = (Vector) h_dimension_map.get(key);
				if (tmpVector.isEmpty()) {
					h_dimension_map.remove(key);
				}
			}
		}

		if (isPtreeEnable) {
			Vector vecData = cubeMetadataServiceUtil.getDimensionColumnVector(cubeInfo, loggedInUser, graphInfo.isSkipcubedatasetcolumndataaccesspermission(loggedInUser));
			if(vecData != null && !vecData.isEmpty()) {
				vKeyLabels = (Vector) vecData.elementAt(1);
				vDataLabels = (Vector) vecData.elementAt(2);
				vTimeDimeDataLabel = (Vector) vecData.elementAt(3);
				vTimeDimeDataLavel = (Vector) vecData.elementAt(4);
				outlinerBean.setvKeyLabels(vKeyLabels);
				outlinerBean.setvDataLabels(vDataLabels);
				outlinerBean.setvTimeDimeDataLabel(vTimeDimeDataLabel);
				outlinerBean.setvTimeDimeDataLavel(vTimeDimeDataLavel);
	
				Vector vAllDataList = new Vector();
				vAllDataList.addAll(vDataLabels);
				vAllDataList.addAll(uddcTemplateDAO.getUDDCNameList(sCubeName, userId));
				vAllDataList.addAll(globalVariableDAO.getGloblevariableNameListByCubeId(sCubeName));
				expressionExecutor.setColumnNames(vAllDataList);
			}
		}
		try {
			virtualUDDC = getVirtualUDDCs(loggedInUser.getUserId(), graphInfo);
			vUserDefinedDataColumns = getAllUserDefinedColumns(loggedInUser);

			List<UddcTemplateInfo> uddcTemplateInfoList = new ArrayList<UddcTemplateInfo>();
			for (int i = 0; i < vUserDefinedDataColumns.size(); i++) {
				uddcTemplateInfoList.add((UddcTemplateInfo) vUserDefinedDataColumns.get(i));
			}

			List<ActiveGlobalVariableInfo> activeGolbalVariableList = graphInfo.getActiveTemplateProperties()
					.getActiveGlobalVariableInfo(loggedInUser.getUserId());
			if (activeGolbalVariableList != null && activeGolbalVariableList.size() > 0) {
				for (ActiveGlobalVariableInfo activeGlobalVariableInfo : activeGolbalVariableList) {
					activeGlobalVarNames.add(activeGlobalVariableInfo.getGlobalVariableInfo().getGlobalVariableName());
				}
			}
			
			Vector<String> uddcMeasureList = new Vector<String>(vDataLabels);
			for (UddcTemplateInfo uinfo : uddcTemplateInfoList) {
				uddcMeasureList.add(uinfo.getTemplateName());
			}
			uddcMeasureList.addAll(vKeyLabels);
			uddcMeasureList.addAll(vTimeDimeDataLavel);
			CubeVector validUddcVect = new CubeVector();
			if (vDataLabels.size() > 0) {
				Vector<String> validUddcList = cubeMetadataServiceUtil.getValidUDDCNameList(uddcTemplateInfoList,
						loggedInUser.getUserId(), uddcMeasureList, activeGlobalVarNames, uddcTemplateInfoList);
				validUddcVect.addAll(validUddcList);
			}
			outlinerBean.setvUserDefinedDataColumns(validUddcVect);

			vActiveUserDefinedDataColumns = getUserColumnInfoList();

			List<UddcTemplateInfo> activeUddcInfoList = new ArrayList<UddcTemplateInfo>();
			for (int i = 0; i < vActiveUserDefinedDataColumns.size(); i++) {
				activeUddcInfoList.add((UddcTemplateInfo) vActiveUserDefinedDataColumns.get(i));
			}
			Vector<String> validActiveUddcList = cubeMetadataServiceUtil.getValidUDDCNameList(activeUddcInfoList,
					loggedInUser.getUserId(), uddcMeasureList, activeGlobalVarNames, uddcTemplateInfoList);
			CubeVector validActiveUddcVect = new CubeVector();
			for (int i = 0; i < vActiveUserDefinedDataColumns.size(); i++) {
				UddcTemplateInfo uddcTemplateInfo = (UddcTemplateInfo) vActiveUserDefinedDataColumns.get(i);
				if (validActiveUddcList.contains(uddcTemplateInfo.getTemplateName())) {
					validActiveUddcVect.add(uddcTemplateInfo);
				}
			}

			outlinerBean.setvActiveUserDefinedDataColumns(validActiveUddcVect);
			outlinerBean.setVirtualUDDC(virtualUDDC);
		} catch (Exception e) {
			throw new CubeException(ResourceManager.getString("LOG_ERROR_MSG_FAILED_GETTING_USER_DEFILED_COLUMN_LIST"),
					e);
		}


		Vector allowSrcColumn = cubeMetadataServiceUtil.getAllowedColumns(loggedInUser, getOrgItemNameList(graphInfo),
				cubeInfo,graphInfo.isSkipcubedatasetcolumndataaccesspermission(loggedInUser));
		if (allowSrcColumn != null) {
			srcLabels.addAll(allowSrcColumn);
		}

		outlinerBean.setSrcLabels(srcLabels);

		for (int i = 0; i < vTimeDimeDataLavel.size(); i++) {
			vKeyLabels.addElement(vTimeDimeDataLavel.elementAt(i));
		}
		outlinerBean.setvKeyLabels(vKeyLabels);
		if (cubeInfo.getDataObjectId() != null) {
			itemDisplayName.addAll(dimensionList);
			Vector activeValidUDDCs = outlinerBean.getActiveValidUDDCs();
			CubeVector displayOrderedDataColumnsName = outlinerBean.getDisplayOrderedDataColumnsName();
			CubeVector rowDisplayLabels = outlinerBean.getRowDisplayLabels();
			CubeVector colDisplayLabels = outlinerBean.getColDisplayLabels();
			CubeVector dataDisplayLabels = outlinerBean.getDataDisplayLabels();
			CubeVector pageDisplayLabels = outlinerBean.getPageDisplayLabels();
			CubeVector colLabelsPrestnt = outlinerBean.getColLabelsPrestnt();
			CubeVector dataLabelsPrestnt = outlinerBean.getDataLabelsPrestnt();
			CubeVector pageLabelsPrestnt = outlinerBean.getPageLabelsPrestnt();
			CubeVector rowLabelsPrestnt = outlinerBean.getRowLabelsPrestnt();

			Vector rowItemsForLineGraph = (Vector) getOutLinerDataWithoutSysGeneratedFields(false, graphInfo)
					.elementAt(3);

			String[] pageItems = outlinerBean.getPageItems();
			String[] rowItems = outlinerBean.getRowItems();
			String[] colItems = outlinerBean.getColItems();
			String[] dataItems = outlinerBean.getDataItems();

			try {

				if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
					int orderedColCnt = graphCube.getColumnCount();
					for (int cntr = 1; cntr <= orderedColCnt; cntr++)
						vOrderedDataColumns.add(graphCube.getColumnName(cntr));
				} else {
					CubeVector orderedDataColList = graphCube.getOrderedDataColumnInfoList();
					for (int i = 0; i < orderedDataColList.size(); i++) {
						String dataColName = orderedDataColList.get(i).toString();
						if (graphInfo.getGraphType() != SmartenConstants.BUBBLE_GRAPH) {
							Vector colNames = graphInfo.getColColumns();
							if (!colNames.contains(dataColName)) {
								vOrderedDataColumns.add(dataColName);
							}
						} else {
							vOrderedDataColumns.add(dataColName);
						}
					}
					if (graphInfo.getGraphType() != SmartenConstants.BUBBLE_GRAPH) {
					} else {
						Vector colNames = graphInfo.getColColumns();
						if (!colNames.isEmpty() && !vOrderedDataColumns.isEmpty()) {
							String firstColName = colNames.get(0).toString();
							String dataOrderCol = vOrderedDataColumns.get(0).toString();
							boolean isDimInMeasureInUDDC = isMeasureOrUDDC(firstColName, graphInfo,
									loggedInUser);
							if (isDimInMeasureInUDDC && dataOrderCol.equals(firstColName)) {
								vOrderedDataColumns.remove(0);
							}
							if (isDimInMeasureInUDDC && vOrderedDataColumns.contains(firstColName)) {
								vOrderedDataColumns.remove(firstColName);
							}
						}
					}
					
				}

			} catch (Exception e) {
				throw new CubeException(
						ResourceManager.getString("LOG_ERROR_MSG_FAILED_GETTING_ORDERED_DATA_COLUMN_LIST"), e);
			}

			if (pageItems == null) {
				pageLabels = getFilterColumnList(graphInfo, loggedInUser);
				outlinerBean.setPageLabels(pageLabels);
			} else {
				for (int i = 0; i < pageItems.length; i++) {
					if (srcLabels.contains(pageItems[i]))
						pageLabels.addElement(pageItems[i]);
				}
				outlinerBean.setPageLabels(pageLabels);
			}

			if (rowItems == null) {
				if (graphInfo.getSysGeneratedRowLabels().size() > 0) {
					Vector modifiedRowLabels = removeSysGenDimCols(graphInfo.getRowColumns(),
							graphInfo.getSysGeneratedRowLabels());
					rowLabels.addAll(modifiedRowLabels);
				} else {
					rowLabels.addAll(graphInfo.getRowColumns());
				}
				outlinerBean.setRowLabels(rowLabels);
			} else {
				for (int i = 0; i < rowItems.length; i++) {
					if (srcLabels.contains(rowItems[i]))
						rowLabels.addElement(rowItems[i]);
				}
				outlinerBean.setRowLabels(rowLabels);
			}

			if (colItems == null) {

				if (graphInfo.getSysGeneratedColumnLabels().size() > 0) {
					Vector modifiedRowLabels = removeSysGenDimCols(graphInfo.getColColumns(),
							graphInfo.getSysGeneratedColumnLabels());
					colLabels.addAll(modifiedRowLabels);
				} else {
					colLabels.addAll(graphInfo.getColColumns());
				}
				outlinerBean.setColLabels(colLabels);
			} else {
				for (int i = 0; i < colItems.length; i++) {
					if (srcLabels.contains(colItems[i]))
						colLabels.addElement(colItems[i]);
				}
				outlinerBean.setColLabels(colLabels);
			}

			if (!bFromFilter) {
				if (dataItems == null) {
					dataLabels = getOrgDataNameList(graphInfo);
					outlinerBean.setDataLabels(dataLabels);
				} else {
					for (int i = 0; i < dataItems.length; i++) {
						if (srcLabels.contains(dataItems[i]))
							dataLabels.addElement(dataItems[i]);
					}
					outlinerBean.setDataLabels(dataLabels);
				}
			}

			if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
				if (rowItemsForLineGraph == null) {
					rowItemsForLineGraph = new Vector();
				}

				outlinerBean.setRowItemsForLineGraph(rowItemsForLineGraph);

				List<String> rowDisplayLabelsForLine = new ArrayList<String>();

				for (int i = 0; rowItemsForLineGraph != null && i < rowItemsForLineGraph.size(); i++) {
					if (srcLabels.contains(rowItemsForLineGraph.elementAt(i))) {
						rowDisplayLabelsForLine = getAxisDisplayNameCombined(rowItemsForLineGraph, "line", graphInfo);
					}
				}

				outlinerBean.setRowDisplayLabelsForLine(rowDisplayLabelsForLine);

				outlinerBean.setDataItemsForBarGraph(getDataLabelsInSequence(graphInfo));
				outlinerBean.setDataItemsForLineGraph(getCombinedLineDataLabelsInSequence(graphInfo));

				List<String> dataDisplayLabelsInSequenceBar = new ArrayList<String>();
				List<String> dataDisplayLabelsInSequenceLine = new ArrayList<String>();
				dataDisplayLabelsInSequenceBar = getAxisDisplayNameCombined(getDataLabelsInSequence(graphInfo), "bar",
						graphInfo);
				dataDisplayLabelsInSequenceLine = getAxisDisplayNameCombined(
						getCombinedLineDataLabelsInSequence(graphInfo), "line", graphInfo);

				outlinerBean.setDateItemsDispItemsForBarGrf(
						(List<String>) StringUtil.jsEscapeVector(new Vector<String>(dataDisplayLabelsInSequenceBar)));
				outlinerBean.setDateItemsDispItemsForLineGrf(
						(List<String>) StringUtil.jsEscapeVector(new Vector<String>(dataDisplayLabelsInSequenceLine)));
			}

			activeValidUDDCs = outlinerBean.getvActiveUserDefinedDataColumns();
			outlinerBean.setActiveValidUDDCs(activeValidUDDCs);

			
			if (graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH
					&& (graphInfo.getColMeasureName() != null && graphInfo.getColMeasureName().size() > 0)) {
				if (graphInfo.getColMeasureName().get(0) != null && !graphInfo.getColMeasureName().get(0).equals("")) {
					dataLabels.remove(graphInfo.getColMeasureName().get(0).toString());
					outlinerBean.setDataLabels(dataLabels);
					vOrderedDataColumns.remove(graphInfo.getColMeasureName().get(0).toString());
				}
			}
			

			if (graphInfo.getGraphType() == SmartenConstants.CANDLE_STICK_GRAPH
					|| graphInfo.getGraphType() == SmartenConstants.HIGH_LOW_OPEN_CLOSE_GRAPH
					|| graphInfo.getGraphType() == SmartenConstants.HISTOGRAM_GRAPH) {
				displayOrderedDataColumnsName.add(getAxisDisplayName(vOrderedDataColumns.get(0).toString(), graphInfo));
			} else if ((graphInfo.getGraphType() == SmartenConstants.SCATTER_LINE_GRAPH
					&& graphInfo.getGraphData().isColoumMeasure())
					|| (graphInfo.getGraphType() == SmartenConstants.BUBBLE_GRAPH
							&& graphInfo.getGraphData().isMeasureInColForBubbLe())) {
				Vector colNames = graphInfo.getColColumns();
				for (int cntr = 0; cntr < vOrderedDataColumns.size(); cntr++) {
					displayOrderedDataColumnsName
							.add(getAxisDisplayName(vOrderedDataColumns.get(cntr).toString(), graphInfo));
				}
			} else if ((!graphInfo.getColColumns().isEmpty() && isColMeasureForOutliner
					&& graphInfo.getGraphType() != SmartenConstants.SCATTER_LINE_GRAPH)
					|| !graphInfo.getColColumns().isEmpty() && measureInColForBubbLe
							&& graphInfo.getGraphType() != SmartenConstants.BUBBLE_GRAPH)
																							
																							
			{
				Vector colNames = new Vector(graphInfo.getColColumns());
				vOrderedDataColumns.add(0, colNames.get(0));
				for (int cntr = 0; cntr < vOrderedDataColumns.size(); cntr++) {
					displayOrderedDataColumnsName
							.add(getAxisDisplayName(vOrderedDataColumns.get(cntr).toString(), graphInfo));
				}
				if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
					CubeVector orderedDataColList = graphCube.getOrderedDataColumnInfoList();
					if (orderedDataColList.indexOf(colNames.get(0)) != -1)
						colLabels = null;
				} else
					colLabels = null;
			} else {
				for (int cntr = 0; cntr < vOrderedDataColumns.size(); cntr++) {
					displayOrderedDataColumnsName
							.add(getAxisDisplayName(vOrderedDataColumns.get(cntr).toString(), graphInfo));
				}
			}
			for (int i = 0; rowLabels != null && i < rowLabels.size(); i++) {
				if (srcLabels.contains(rowLabels.elementAt(i))) {
					rowLabelsPrestnt.add(rowLabels.elementAt(i));
					rowDisplayLabels.add(getAxisDisplayName(rowLabels.elementAt(i).toString(), graphInfo));
				}
			}
			for (int i = 0; pageLabels != null && i < pageLabels.size(); i++) {
				if (srcLabels.contains(pageLabels.elementAt(i))) {
					pageLabelsPrestnt.add(pageLabels.elementAt(i));
					pageDisplayLabels.add(getAxisDisplayName(pageLabels.elementAt(i).toString(), graphInfo));
				}
			}
			for (int i = 0; colLabels != null && i < colLabels.size(); i++) {
				String col = colLabels.elementAt(i).toString();
				if ((graphInfo.getGraphType() == GraphConstants.SCATTER_LINE_GRAPH
						|| graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH) && colLabels.size() > 0) {
					for (int ii = 0; ii < vActiveUserDefinedDataColumns.size(); ii++) {
						UddcTemplateInfo uddcInfo = (UddcTemplateInfo) vActiveUserDefinedDataColumns.get(ii);
						if (uddcInfo != null && uddcInfo.getColumnName() != null) {
							String uddName = uddcInfo.getColumnName().toString();
							if (uddName.equals(col))
								srcLabels.add(colLabels.elementAt(i));
						}
					}
				}
				if (srcLabels.contains(colLabels.elementAt(i))) {
					colLabelsPrestnt.add(colLabels.elementAt(i));

					colDisplayLabels.add(getAxisDisplayName(colLabels.elementAt(i).toString(), graphInfo));
				}
				if (isColMeasureForOutliner && graphInfo.getGraphType() != GraphConstants.SCATTER_LINE_GRAPH)
					colDisplayLabels = new CubeVector();

				/** inactive uddc which is in data, when col has one measure so only one measure
				 remains in col and not in data**/
				if (colDisplayLabels != null && colDisplayLabels.size() > 0 && dataLabels != null
						&& dataLabels.size() > 0) {
					boolean colUddc = false;
					String colName = colDisplayLabels.get(0).toString();
					String dataName = dataLabels.get(0).toString();
					for (int ii = 0; ii < vActiveUserDefinedDataColumns.size(); ii++) {
						UddcTemplateInfo uddcInfo = (UddcTemplateInfo) vActiveUserDefinedDataColumns.get(ii);
						String uddcName = "";
						if (uddcInfo != null && uddcInfo.getColumnName() != null) {
							uddcName = uddcInfo.getColumnName();
							if (uddcName.equals(colName))
								colUddc = true;
						}
					}
					if (colUddc && colName.equals(dataName)) {
						dataLabels = new CubeVector();
						outlinerBean.setDataLabels(dataLabels);
						vOrderedDataColumns.clear();
					}
				}
			}

			
			if (graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH
					&& (graphInfo.getColMeasureName() != null && graphInfo.getColMeasureName().size() > 0)) {
				if (graphInfo.getColMeasureName().get(0) != null
						&& !graphInfo.getColMeasureName().get(0).toString().equals("")) {
					colLabels.clear();
					colLabels.add(graphInfo.getColMeasureName().get(0).toString());
					outlinerBean.setColLabels(colLabels);
					String name = graphInfo.getColMeasureName().get(0).toString();// COG_1
					String[] originalName = name.split("_");// COG
					colLabelsPrestnt.add(originalName[0]);
					colDisplayLabels
							.add(getAxisDisplayName(graphInfo.getColMeasureName().get(0).toString(), graphInfo));// colDisplayLabels.add(graphInfo.getColMeasureName());
				}
			}
			

			for (int i = 0; dataLabels != null && i < dataLabels.size(); i++) {
				dataLabelsPrestnt.add(dataLabels.elementAt(i));
				dataDisplayLabels.add(getAxisDisplayName(dataLabels.elementAt(i).toString(), graphInfo));
			}
			for (int i = 0; i < dimensionList.size(); i++) {
				itemDisplayName.add(getAxisDisplayName(dimensionList.get(i), graphInfo));
			}
			HashMap userAddedDataMap = getUserAddedDataNameList(graphInfo);
			HashMap vertualUDDCMap = getVirtualUDDCMap();
			HashMap hsmp = new HashMap();
			hsmp.putAll(userAddedDataMap);
			hsmp.putAll(vertualUDDCMap);

			Iterator iter = hsmp.keySet().iterator();
			String sColName = null;
			Vector<String> duplicateDataColumns = new Vector<String>(vDataLabels.size());
			Vector userAddedMeasures = new Vector<String>(vDataLabels.size());
			while (iter.hasNext()) {
				sColName = iter.next().toString();
				boolean bFound = false;
				int i = 0;
				for (; i < vDataLabels.size(); i++) {
					if (vDataLabels.get(i).equals(sColName)) {
						bFound = true;
						break;
					}
				}

				for (int j = 0; j < graphInfo.getActiveTemplateProperties().getActiveUDDCInfo().size(); j++) {
					if (graphInfo.getActiveTemplateProperties().getActiveUDDCInfo().get(j).getUddcTemplateInfo()
							.getColumnName().equals(sColName)) {
						bFound = true;
						break;
					}
				}

				if (bFound) {
					duplicateDataColumns.add(sColName);
					userAddedMeasures.add((CubeVector) hsmp.get(sColName));
				}
			}
			outlinerBean.setDuplicateDataColumns(duplicateDataColumns);
			outlinerBean.setUserAddedMeasures(userAddedMeasures);
		}
		return outlinerBean;
	}

	/**
	 * This method is use to get VirtualUDDC map key as uddc name and value vector
	 * contain vertual name of uddc.
	 * 
	 * @return HashMap
	 * @throws CubeException
	 */
	@SuppressWarnings("unchecked")
	private HashMap<String, Vector<String>> getVirtualUDDCMap() throws CubeException {
		CubeVector userColumns = getUserColumnInfoList();
		HashMap<String, Vector<String>> hsmp = new HashMap<String, Vector<String>>();
		for (int i = 0; i < userColumns.size(); i++) {
			UddcTemplateInfo uddcTemplateInfo = (UddcTemplateInfo) userColumns.get(i);
			if (uddcTemplateInfo.getBaseuddc().equals(uddcTemplateInfo.getColumnName()) && uddcTemplateInfo.isVirtual())
				continue;
			else if (!uddcTemplateInfo.getBaseuddc().equals(uddcTemplateInfo.getColumnName())
					&& uddcTemplateInfo.isVirtual()) {
				if (hsmp.containsKey(uddcTemplateInfo.getBaseuddc())) {
					((Vector) hsmp.get(uddcTemplateInfo.getBaseuddc())).addElement(uddcTemplateInfo.getColumnName());
				} else {
					Vector vecItemNameList = new CubeVector();
					vecItemNameList.addElement(uddcTemplateInfo.getColumnName());
					hsmp.put(uddcTemplateInfo.getBaseuddc(), vecItemNameList);
				}
			}

		}
		return hsmp;
	}

