	/**
	 * Gets valid user defined data columns.
	 * 
	 * @param user
	 *            Specifyed user
	 * @param includeVirtual
	 *            if its value true then return all the uddc with dummy or virtual
	 * @return CubeVector
	 * @throws CubeException
	 * @throws DatabaseOperationException
	 */
	@SuppressWarnings("unchecked")
	private CubeVector getAllUserDefinedColumns(UserInfo user) throws CubeException, DatabaseOperationException {
		CubeVector vUserDefinedDataColumns = new CubeVector();
		List<UddcTemplateInfo> uddcTemplateInfoList = null;
		try {
			uddcTemplateInfoList = uddcTemplateDAO.getUddcTemplateListByUserId(graphCube.getName(), user.getUserId());
		} catch (DatabaseOperationException ex) {
			ApplicationLog.error(ex);
		}
		if (uddcTemplateInfoList != null) {
			for (int i = 0; i < uddcTemplateInfoList.size(); i++) {
				UddcTemplateInfo uddcTemplateInfo = uddcTemplateInfoList.get(i);
				if (!uddcTemplateInfo.isVirtual()) {
					vUserDefinedDataColumns.add(uddcTemplateInfo);
				}
			}
		}

		return vUserDefinedDataColumns;
	}

	private List<String> getVirtualUDDCs(String strUSerId, SmartenInfo graphInfo)
			throws DatabaseOperationException, CubeException {
		List<String> virtualUDDCList = new ArrayList<String>();
		List<UddcTemplateInfo> uddcTemplateInfoList = null;
		try {
			uddcTemplateInfoList = uddcTemplateDAO.getUddcTemplateListByUserId(graphCube.getName(), strUSerId);
		} catch (DatabaseOperationException ex) {
			ApplicationLog.error(ex);
		}
		if (uddcTemplateInfoList != null) {
			for (int i = 0; i < uddcTemplateInfoList.size(); i++) {
				UddcTemplateInfo uddcTemplateInfo = uddcTemplateInfoList.get(i);
				if (uddcTemplateInfo.isVirtual()) {
					virtualUDDCList.add(uddcTemplateInfo.getColumnName());
				}
			}
		}
		List<ActiveUDDCInfo> activeUDDCList = graphInfo.getActiveUDDCInfo(strUSerId);
		if (activeUDDCList != null && activeUDDCList.size() > 0) {
			for (int cnt = 0; cnt < activeUDDCList.size(); cnt++) {
				ActiveUDDCInfo uddcInfo = activeUDDCList.get(cnt);
				if (!virtualUDDCList.contains(uddcInfo.getUddcTemplateInfo().getColumnName())
						&& uddcInfo.getUddcTemplateInfo().isVirtual()) {
					virtualUDDCList.add(uddcInfo.getUddcTemplateInfo().getColumnName());
				}
			}
		}
		return virtualUDDCList;
	}

