	/**
	 * Gets Original item name list
	 * 
	 * @return Cube Vector
	 */
	@SuppressWarnings("unchecked")
	public CubeVector getOrgItemNameList(SmartenInfo graphInfo) throws CubeException {

		if (graphCube == null) {
			throw new CubeException(ResourceManager.getString("MSG_TEXT_CUBE_NOT_FORMED",
					new Object[] { this.graphDisplayName, this.cubeDisplayName }));
		}
		String strItemName = "";
		CubeVector vecItemNameList = new CubeVector();
		try {
			ICubeResultSetMetaData icubeMetaData = getOriginalResultSetMetaData();
			for (int iIndex = 1; iIndex <= icubeMetaData.getColumnCount(); iIndex++) {
				strItemName = icubeMetaData.getColumnName(iIndex);
				vecItemNameList.addElement(strItemName);
			}
		} catch (Exception e) {
			throw new CubeException(ResourceManager.getString("MSG_TEXT_ITEM_INFO_RETRIEVAL_FAILED",
					new Object[] { AppConstants.GRAPH, AppConstants.GRAPH, graphInfo.getCubeInfo().getDataObjecName(),
							AppConstants.GRAPH, graphInfo.getGraphName(), AppConstants.GRAPH, strItemName,
							"Retrive dimenaion from cube", e.getMessage(), "GraphServies" }));
		}

		return vecItemNameList;
	}

