	/**
	 * Gets original data column names.
	 * 
	 * @return original data column names
	 */
	@SuppressWarnings("unchecked")
	private CubeVector getOrgDataNameList(SmartenInfo graphInfo) {
		CubeVector vecItemNameList = new CubeVector();

		for (int iCnt = 0; iCnt < graphInfo.getDataColumns().size(); iCnt++) {

			if (graphInfo.getDataColumns().elementAt(iCnt) instanceof CubeDataLabelItem) {
				continue;
			}

			vecItemNameList.addElement(graphInfo.getDataColumns().elementAt(iCnt));
		}

		return vecItemNameList;
	}

	/**
	 * Sets row,column,data labels.
	 * 
	 * @param requestParamMap
	 *            HashMap of parameter
	 * @throws ALSException
	 * @throws CubeException
	 * @throws RScriptException
	 * @throws DatabaseOperationException
	 */
	public void setPageRowColDataItems(HashMap<String, String> requestParamMap, SmartenInfo graphInfo, UserInfo uInfo,
			List dimensionList, List measureListTab) throws ALSException, MDXException, RealTimeCubeException,
			CubeException, DatabaseOperationException, RScriptException {

		String bRayOuter = (String) requestParamMap.get("rayouter");
		String bRaystatus = (String) requestParamMap.get("raystatus");
		removeDataLabels(requestParamMap,graphInfo.getIgnoreDimAndMeasureList());
		if ((bRayOuter != null && bRayOuter.trim().length() > 0)
				|| (bRaystatus != null && bRaystatus.trim().length() > 0)) {
			String[] pageItems = StringUtil.toArray((String) requestParamMap.get("pagelabels"));
			String[] rowItems = StringUtil.toArray((String) requestParamMap.get("rowlabels"));
			String[] colItems = StringUtil.toArray((String) requestParamMap.get("collabels"));
			String[] dataItems = StringUtil.toArray((String) requestParamMap.get("datalabels"));
			String[] userAddedDataItems = StringUtil.toArray((String) requestParamMap.get("useraddeddatalabels"));
			String[] userAddedDataItemsPosition = StringUtil
					.toArray((String) requestParamMap.get("useraddeddatalabelsposition"));
			String[] activeUddcs = StringUtil.toArray((String) requestParamMap.get("userDataLabels"));
			String[] userAddedUddcs = StringUtil.toArray((String) requestParamMap.get("useraddeduddcs"));
			String[] oldActiveUddcs = StringUtil.toArray((String) requestParamMap.get("oldactiveuddc"));
			String isFromFilter = StringUtil.null2String(requestParamMap.get("isFromOutLinerFilter"));
			List<String> mesColRowDimList=new ArrayList<>(Arrays.asList(dataItems));
			mesColRowDimList.addAll(Arrays.asList(rowItems));
			mesColRowDimList.addAll(Arrays.asList(colItems));
			String[] mesRowColDim=mesColRowDimList.toArray(new String[0]);
			List<String> uddcList1 = uddcTemplateDAO.getUDDCNameList(graphCube.getName(),AppConstants.ADMIN_USERNAME);
			checkOutlinerUddcdublicateColumn(userAddedUddcs,activeUddcs,mesRowColDim,graphCube.getName(),graphInfo.getCubeInfo(),true,uInfo,uddcList1,graphInfo.isSkipcubedatasetcolumndataaccesspermission(uInfo));
			String[] colMeasureName = StringUtil.toArray((String) requestParamMap.get("duplicateColMeasure"));
			if (colMeasureName.length > 0) {
				Vector colMeasure = new Vector();
				colMeasure.add(colMeasureName[0]);
				graphInfo.setColMeasureName(colMeasure);
			} else
				graphInfo.setColMeasureName(new Vector());

			String[] rowItemsForLine = StringUtil.toArray((String) requestParamMap.get("rowlabels2"));
			String[] dataItemsForLine = StringUtil.toArray((String) requestParamMap.get("datalabels2"));
			String[] userAddedDataItemsForLine = StringUtil
					.toArray((String) requestParamMap.get("useraddeddatalabels2"));

			String[] sDataAndUserDataBar = StringUtil.toArray((String) requestParamMap.get("dataandUserLabelsBar"));
			String[] sDataAndUserDataLine = StringUtil.toArray((String) requestParamMap.get("dataandUserLabelsLine"));

			String orderedDataLabels = requestParamMap.get("orderedDataLabels");
			String[] tempData = StringUtil.toArray((String) requestParamMap.get("orderedDataLabels"));
			
				List measureListTabular = new ArrayList();
				measureListTabular.addAll(Arrays.asList(tempData));
			

			if (graphInfo.isSmartenMap() && graphInfo.getGraphType() == SmartenConstants.SMARTENVIEW_MAP) {
				rowItems = colItems.clone();
				for (int i = 0; i < colItems.length; i++) {
					colItems[i] = "";
				}
			}

			if (graphInfo.getGraphType() == SmartenConstants.SMARTENVIEW_MAP) {
				if (rowItems.length == 0) {
					rowItems = new String[1];
					rowItems[0] = graphInfo.getGeoColumnName();
				}
				if (colItems.length > 0)
				{
					colItems[0] = "";
				}
				requestParamMap.put("rows", "");
				requestParamMap.put("coloumns", "");
			}
			
			String rowsDimensionName = requestParamMap.get("rows");
			String coloumnsDimensionValue = requestParamMap.get("coloumns");
			
			if (rowsDimensionName.endsWith(",")) {
				rowsDimensionName = rowsDimensionName.substring(0, rowsDimensionName.length() - 1);
			}
			if (coloumnsDimensionValue.endsWith(",")) {
				coloumnsDimensionValue = coloumnsDimensionValue.substring(0, coloumnsDimensionValue.length() - 1);
			}
			
			boolean removeRowsCols = graphInfo.getGraphType() == GraphConstants.D3_BUBBLE
					|| graphInfo.getGraphType() == GraphConstants.D3_CHORD
					|| graphInfo.getGraphType() == GraphConstants.D3_SUNBURST
					|| graphInfo.getGraphType() == GraphConstants.D3_TREELAYOUT
					|| graphInfo.getGraphType() == GraphConstants.D3_TREEMAP
					|| graphInfo.getGraphType() == GraphConstants.SMARTENVIEW_MAP
					|| graphInfo.getGraphType() == GraphConstants.SMARTENVIEW_TABULAR;
			
			if(removeRowsCols)
			{
				rowsDimensionName = "";
				coloumnsDimensionValue = "";
			}
			
			
			String[] rows = StringUtil.toArray(rowsDimensionName);
			String[] coloumns = StringUtil.toArray(coloumnsDimensionValue);
			
			if (rows.length > 0) {
				List smartenRowList = new ArrayList();
				graphInfo.getGraphData().setSmartenRowsEnable(true);
				for (int i = 0; i < rows.length; i++) {
					smartenRowList.add(rows[i].toString());
				}
				graphInfo.getGraphData().setSmartenRowList(smartenRowList);
				Vector rowsVectorTemp = new Vector(smartenRowList);
				graphInfo.setRowsColumns(rowsVectorTemp);
			} else {
				graphInfo.setRowsColumns(new Vector());
			}

			
			if (coloumns.length > 0) {
				List smartenColList = new ArrayList();
				graphInfo.getGraphData().setSmartenColoumnsEnable(true);
				for (int i = 0; i < coloumns.length; i++) {
					smartenColList.add(coloumns[i].toString());
				}
				graphInfo.getGraphData().setSmartenColList(smartenColList);
				Vector colsVectorTemp = new Vector(smartenColList);
				graphInfo.setColsColumns(colsVectorTemp);
			} else {
				graphInfo.setColsColumns(new Vector());
			}
			
			boolean isD3Graph = false;
			if (graphInfo.getGraphType() == GraphConstants.D3_CHORD
					|| graphInfo.getGraphType() == GraphConstants.D3_TREEMAP
					|| graphInfo.getGraphType() == GraphConstants.D3_SUNBURST
					|| graphInfo.getGraphType() == GraphConstants.D3_BUBBLE) {
				isD3Graph = true;
			}

			
			if (dimensionList != null && dimensionList.size() > 0) {
			
				if ((graphInfo.isSmartenTabular() || graphInfo.isSmartenMap() || isD3Graph)
						&& !graphInfo.isSmartenMode() && graphInfo.getIgnoreDimAndMeasureList() != null
						&& graphInfo.getIgnoreDimAndMeasureList().size() > 0)
					dimensionList.removeAll(graphInfo.getIgnoreDimAndMeasureList());
				graphInfo.getGraphData().setDimensionListForSmartenview(dimensionList);
				graphInfo.setDimensionTitleList(dimensionList);
			} else {
				
				graphInfo.setDimensionTitleList(new ArrayList());
			}

			if (measureListTabular != null && measureListTabular.size() > 0) {
				
				if ((graphInfo.isSmartenTabular() || isD3Graph) && !graphInfo.isSmartenMode()
						&& graphInfo.getIgnoreDimAndMeasureList() != null
						&& graphInfo.getIgnoreDimAndMeasureList().size() > 0)
					measureListTabular.removeAll(graphInfo.getIgnoreDimAndMeasureList());
				
				graphInfo.getGraphData().setMeasureListForSmartenview(measureListTabular);
				graphInfo.setMeasureTitleList(measureListTabular);
			} else {
				
				graphInfo.setMeasureTitleList(new ArrayList());
			}

			boolean isSmartenModeOn = false;
			String smartenMode = requestParamMap.get("smartenModeEnable");
			if (smartenMode != null && smartenMode.equalsIgnoreCase("true"))
				isSmartenModeOn = true;
			String gType = requestParamMap.get("sngraphtype");
			String[] useraddeddatalabels = StringUtil.toArray((String) requestParamMap.get("useraddeddatalabels"));
			List allMeasureList = graphInfo.getGraphData().getMeasureListForSmartenview();
			if (allMeasureList.size() == 2 && gType != null && !gType.equalsIgnoreCase("")
					&& gType.equalsIgnoreCase("70") && !isSmartenModeOn) {
				
				if (useraddeddatalabels.length == 0)
					requestParamMap.put("datalabels", requestParamMap.get("orderedDataLabels"));
				setMultipleYAxisLabelsEnable(true, graphInfo);
			}

			if (graphInfo.getGraphData().getMeasureListForSmartenview().size() == 0
					&& graphInfo.getGraphData().isSmartenRowsEnable()
					&& graphInfo.getSmartenType() == SmartenConstants.AUTO_GRAPH) {
				graphInfo.getGraphData().setSmartenRowsEnable(false);
				graphInfo.setRowsColumns(new Vector());
			}
			if (graphInfo.getGraphData().getMeasureListForSmartenview().size() == 0
					&& graphInfo.getGraphData().isSmartenColoumnsEnable()
					&& graphInfo.getSmartenType() == SmartenConstants.AUTO_GRAPH) {
				graphInfo.getGraphData().setSmartenColoumnsEnable(false);
				graphInfo.setColsColumns(new Vector());
			}

			/**
			 * colItems first element is not in orderedDataLabel(mesureList) add it at first
			 * place if colItems first element is measure or UDDC
			 */
			if (graphInfo.getGraphType() == SmartenConstants.SCATTER_LINE_GRAPH
					|| graphInfo.getGraphType() == SmartenConstants.BUBBLE_GRAPH) {
				if (null != colItems && colItems.length > 0 && null != graphInfo.getCubeInfo()) {
					List<String> measureList = metadataServiceUtil.getMeasureList(graphInfo.getCubeInfo(), uInfo,
							false,graphInfo.isSkipcubedatasetcolumndataaccesspermission(uInfo));
					List<String> uddcList = uddcTemplateDAO.getUDDCNameList(graphCube.getName(), uInfo.getUserId());
					if ((null != measureList && measureList.contains(colItems[0]))
							|| (null != uddcList && uddcList.contains(colItems[0]))) {
						CubeVector ordDataColItms = StringUtil
								.fromStringArrayToCubeVector(StringUtil.toArray((String) orderedDataLabels));
						if (null != ordDataColItms && !ordDataColItms.contains(colItems[0])) {
							orderedDataLabels = colItems[0] + "," + orderedDataLabels;
							colItems = new String[] { colItems[0] };
						}
					}
				}
			}
			CubeVector orderedDataItems = StringUtil
					.fromStringArrayToCubeVector(StringUtil.toArray((String) orderedDataLabels));
			CubeVector totalDataItem = (CubeVector) orderedDataItems.clone();

			String sRowItems = "", sColItems = "", sDataItems = "", sRowItemsForLineGraph = "",
					sDataItemsForLineGraph = "", sPageItems = "";

			CubeVector rowLabels = new CubeVector();
			CubeVector colLabels = new CubeVector();
			CubeVector dataLabels = new CubeVector();
			CubeVector allLabels = new CubeVector();
			CubeVector rowLabelsForLineGraph = new CubeVector();
			CubeVector dataLabelsForLineGraph = new CubeVector();
			CubeVector pageLabels = new CubeVector();

			if (rowItems != null) {
				for (int i = 0; i < rowItems.length; i++) {
					if (getColumnMetaData(graphInfo, rowItems[i]) != null) {
						rowLabels.addElement(rowItems[i]);
						allLabels.addElement(rowItems[i]);

						sRowItems = sRowItems + rowItems[i].toString() + ",";
					}
				}
				if (sRowItems.endsWith(","))
					sRowItems = sRowItems.substring(0, sRowItems.length() - 1);
			}

			if (pageItems != null) {
				for (int i = 0; i < pageItems.length; i++) {
					if (getColumnMetaData(graphInfo, pageItems[i]) != null) {
						pageLabels.addElement(pageItems[i]);
					}
				}
			}

			if (colItems != null) {
				for (int i = 0; i < colItems.length; i++) {
					if (graphInfo.getGraphType() == SmartenConstants.SCATTER_LINE_GRAPH
							|| graphInfo.getGraphType() == SmartenConstants.BUBBLE_GRAPH) {
						List tempActiveUddcs = new ArrayList();
						List tempUserAddedUddcs = new ArrayList();
						List list = uddcTemplateDAO.getUDDCNameList(graphCube.getName(), uInfo.getUserId());
						if (list != null && list.contains(colItems[i])) {

							tempActiveUddcs.add(colItems[i]);
							
							for (int k = 0; k < activeUddcs.length; k++) {
								tempActiveUddcs.add(activeUddcs[k]);
							}
							colLabels.addElement(colItems[i]);
							allLabels.addElement(colItems[i]);

							sColItems = sColItems + colItems[i].toString() + ",";
							if (tempActiveUddcs.size() > 0) {
								String[] temp = new String[tempActiveUddcs.size()];
								for (int j = 0; j < tempActiveUddcs.size(); j++) {
									temp[j] = tempActiveUddcs.get(j).toString();
								}
								activeUddcs = temp;
							}
						} else {
							if (getColumnMetaData(graphInfo, colItems[i]) != null) {
								colLabels.addElement(colItems[i]);
								allLabels.addElement(colItems[i]);
								sColItems = sColItems + colItems[i].toString() + ",";
							}
							
							if (userAddedDataItems.length > 0) {
								for (int t = 0; t < userAddedDataItems.length; t++) {
									if (userAddedDataItems[t].toString().equals(colItems[i])) {
										colLabels.addElement(colItems[i]);
										allLabels.addElement(colItems[i]);

										sColItems = sColItems + colItems[i].toString() + ",";
									}
								}
							}
						}

					} else {
						if (getColumnMetaData(graphInfo, colItems[i]) != null) {
							colLabels.addElement(colItems[i]);
							allLabels.addElement(colItems[i]);

							sColItems = sColItems + colItems[i].toString() + ",";
						}
					}

				}

				if (sColItems.endsWith(","))
					sColItems = sColItems.substring(0, sColItems.length() - 1);
			}
			
			if (dataItems != null) {
				for (int i = 0; i < dataItems.length; i++) {
					ALSName alsDataName = new ALSName(dataItems[i], dataItems[i]);
					if (getColumnMetaData(graphInfo, dataItems[i]) != null) {
						dataLabels.addElement(alsDataName);

						allLabels.addElement(dataItems[i]);
						if (sDataItems != null && sDataItems.equalsIgnoreCase(""))
							sDataItems = dataItems[i].toString() + ",";
						else
							sDataItems = sDataItems + dataItems[i].toString() + ",";

				}
			}
			}


			List<CubeRankDataLabel> rankList = graphInfo.getActiveTemplateProperties().getRankList();
			if(rankList !=null && !rankList.isEmpty()) {
				for (int i = 0; i < rankList.size(); i++) {
					if (orderedDataItems.size() > 0) {
						CubeRankDataLabel label = rankList.get(i);
						if (!(orderedDataItems.contains(label.getDataColumn()))) {
							label.setDataColumn(orderedDataItems.firstElement().toString());
						}
					} else {
						rankList.clear();
					}
				}
			}

			if (userAddedDataItems != null) {
				for (int i = 0; i < userAddedDataItems.length; i = i + 2) {
					CubeColumnInfo userAddedColumn = getColumnMetaData(graphInfo, userAddedDataItems[i]);

					if (userAddedDataItemsPosition != null && userAddedDataItemsPosition.length > 0) {
						int index = Integer.parseInt(userAddedDataItemsPosition[i / 2]);

						if (userAddedColumn != null) {
							ALSName alsUserAddedDataName = new ALSName(userAddedDataItems[i],
									userAddedDataItems[i + 1]);

							if (dataLabels.size() > index) {
								dataLabels.insertElementAt(alsUserAddedDataName, index);
							} else {
								dataLabels.addElement(alsUserAddedDataName);
							}
							sDataItems = sDataItems + userAddedDataItems[i + 1].toString() + ",";
						} else {
							if (orderedDataItems.contains(userAddedDataItems[i + 1]))
								orderedDataItems.remove(userAddedDataItems[i + 1]);
						}
					} else {
						if (userAddedColumn != null) {
							ALSName alsUserAddedDataName = new ALSName(userAddedDataItems[i],
									userAddedDataItems[i + 1]);

							dataLabels.addElement(alsUserAddedDataName);
							sDataItems = sDataItems + userAddedDataItems[i + 1].toString() + ",";
						} else {
							if (orderedDataItems.contains(userAddedDataItems[i + 1]))
								orderedDataItems.remove(userAddedDataItems[i + 1]);
						}
					}
				}
			}

			if (sDataItems.endsWith(","))
				sDataItems = sDataItems.substring(0, sDataItems.length() - 1);

			if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
				
				if (rowItemsForLine != null) {
					for (int i = 0; i < rowItemsForLine.length; i++) {
						if (getColumnMetaData(graphInfo, rowItemsForLine[i]) != null) {
							rowLabelsForLineGraph.addElement(rowItemsForLine[i]);
							allLabels.addElement(rowItemsForLine[i]);

							sRowItemsForLineGraph = sRowItemsForLineGraph + rowItemsForLine[i].toString() + ",";
						}
					}
					if (sRowItemsForLineGraph.endsWith(","))
						sRowItemsForLineGraph = sRowItemsForLineGraph.substring(0, sRowItemsForLineGraph.length() - 1);
				}

				
				if (dataItemsForLine != null) {
					for (int i = 0; i < dataItemsForLine.length; i++) {
						ALSName alsDataName = new ALSName(dataItemsForLine[i], dataItemsForLine[i]);
						if (getColumnMetaData(graphInfo, dataItemsForLine[i]) != null) {
							dataLabelsForLineGraph.addElement(alsDataName);

							allLabels.addElement(dataItemsForLine[i]);

							sDataItemsForLineGraph = sDataItemsForLineGraph + dataItemsForLine[i].toString() + ",";
						} else {
							if (orderedDataItems.contains(dataItemsForLine[i]))
								orderedDataItems.remove(dataItemsForLine[i]);
						}
					}
				}

				
				if (userAddedDataItemsForLine != null) {
					for (int i = 0; i < userAddedDataItemsForLine.length; i = i + 2) {
						ALSName alsUserAddedDataName = new ALSName(userAddedDataItemsForLine[i],
								userAddedDataItemsForLine[i + 1]);

						if (getColumnMetaData(graphInfo, userAddedDataItemsForLine[i]) != null) {
							dataLabelsForLineGraph.addElement(alsUserAddedDataName);
							sDataItemsForLineGraph = sDataItemsForLineGraph
									+ userAddedDataItemsForLine[i + 1].toString() + ",";
						} else {
							if (orderedDataItems.contains(userAddedDataItemsForLine[i + 1]))
								orderedDataItems.remove(userAddedDataItemsForLine[i + 1]);
						}
					}
				}

				if (sDataItemsForLineGraph.endsWith(","))
					sDataItemsForLineGraph = sDataItemsForLineGraph.substring(0, sDataItemsForLineGraph.length() - 1);
			}

			boolean bRefresh = false;

			for (int i = 0; !bRefresh && i < rowLabels.size(); i++) {
				if (getColumnMetaData(graphInfo, rowLabels.elementAt(i).toString()) == null) {
					bRefresh = true;
					break;
				}
			}
			for (int i = 0; !bRefresh && i < colLabels.size(); i++) {
				if (getColumnMetaData(graphInfo, colLabels.elementAt(i).toString()) == null) {
					bRefresh = true;
					break;
				}
			}
			for (int i = 0; !bRefresh && i < dataLabels.size(); i++) {
				String dataItemName = ((ALSName) dataLabels.elementAt(i)).GetName();
				if (getColumnMetaData(graphInfo, dataItemName) == null) {
					bRefresh = true;
					break;
				}
			}
			for (int i = 0; !bRefresh && i < rowLabelsForLineGraph.size(); i++) {
				if (getColumnMetaData(graphInfo, rowLabelsForLineGraph.elementAt(i).toString()) == null) {
					bRefresh = true;
					break;
				}
			}
			for (int i = 0; !bRefresh && i < dataLabelsForLineGraph.size(); i++) {
				String dataItemName = ((ALSName) dataLabelsForLineGraph.elementAt(i)).GetName();
				if (getColumnMetaData(graphInfo, dataItemName) == null) {
					bRefresh = true;
					break;
				}
			}

			CubeVector vUddcCols = getAllUserDefinedColumns(uInfo);
			List<ActiveUDDCInfo> activeUDDCList = graphInfo.getActiveUDDCInfo(uInfo.getUserId());

			boolean bChangeUddc = false;
			boolean bTemp = false;
			/** To active-deactive uddcs from rayouter**/
			if ((oldActiveUddcs == null || oldActiveUddcs.length == 0)
					&& (activeUddcs == null || activeUddcs.length == 0)) {
				bChangeUddc = false;
			} else if (activeUddcs.length == oldActiveUddcs.length) {
				for (int i = 0; i < oldActiveUddcs.length; i++) {
					for (int j = 0; j < activeUddcs.length; j++) {
						if (oldActiveUddcs[i].equals(activeUddcs[j]))
							break;
						else
							bTemp = true;
					}
					if (bTemp)
						break;
				}
				if (bTemp)
					bChangeUddc = true;
			} else
				bChangeUddc = true;

			String[] allActiveUddcs = null;
			CubeVector userColInfo = new CubeVector();
			try {
				userColInfo = getUserColumnInfoList();
			} catch (Exception e) {
				ApplicationLog.error(e);
			}
			if (userAddedUddcs != null) {
				ArrayList<String> alTemp = new ArrayList<String>();
				String srcUddc = "";
				String newUddc = "";
				UddcTemplateInfo newDataColumn = null;
				int colIndex = -1;

				for (int i = 0; i < userAddedUddcs.length; i = i + 2) {
					srcUddc = userAddedUddcs[i].toString();
					newUddc = userAddedUddcs[i + 1].toString();
					colIndex = TemplateUtil.indexOfDataColumn(vUddcCols, srcUddc);
					if (colIndex != -1) {
						newDataColumn = (UddcTemplateInfo) ((UddcTemplateInfo) vUddcCols.elementAt(colIndex)).clone();
						newDataColumn.setColumnName(newUddc);
						alTemp.add(newUddc);
						newDataColumn.setStatus(true);
						/**
						 * here Virtual is true; newUddc is the Virtual uddc like test_1;test_2
						 */
						if (!newUddc.equals(srcUddc)) {
							newDataColumn.setVirtual(true);
						}
						newDataColumn.setBaseuddc(srcUddc);
						userColInfo.add(newDataColumn);
						bChangeUddc = true;
					}
				}
				allActiveUddcs = new String[activeUddcs.length + alTemp.size()];

				for (int i = 0; i < allActiveUddcs.length; i++) {
					if (i < activeUddcs.length)
						allActiveUddcs[i] = activeUddcs[i];
					else
						allActiveUddcs[i] = alTemp.get(i - activeUddcs.length);
				}

				activeUddcs = allActiveUddcs;
			}

			List<ActiveUDDCInfo> delInfoList = new ArrayList<ActiveUDDCInfo>();
			for (int i = 0; i < userColInfo.size(); i++) {
				String uddcName = ((UddcTemplateInfo) userColInfo.get(i)).getColumnName();

				if (!totalDataItem.contains(uddcName)) {
					userColInfo.remove(i);
					UddcTemplateInfo uddcTemplateInfo = uddcTemplateDAO
							.getUddcTemplateByCubeIdAndTemplateName(graphCube.getName(), uddcName);
					if (uddcTemplateInfo != null) {
						if (activeUDDCList != null && activeUDDCList.size() > 0) {
							for (int cnt = 0; cnt < activeUDDCList.size(); cnt++) {
								ActiveUDDCInfo uddcInfo = activeUDDCList.get(cnt);
								long lsavedTmpId = uddcInfo.getUddcTemplateInfo().getId();
								if (lsavedTmpId == uddcTemplateInfo.getId()) {
									delInfoList.add(uddcInfo);
								}
							}
						}
					} else {
						if (activeUDDCList != null && activeUDDCList.size() > 0) {
							for (int cnt = 0; cnt < activeUDDCList.size(); cnt++) {
								ActiveUDDCInfo uddcInfo = activeUDDCList.get(cnt);
								String strColummnName = uddcInfo.getUddcTemplateInfo().getColumnName();
								if (strColummnName.equals(uddcName)) {
									delInfoList.add(uddcInfo);
								}
							}
						}
					}
					i--;
				}
			}

			for (ActiveUDDCInfo activeInfo : delInfoList) {
				activeUDDCList.remove(activeInfo);
			}

			if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
				if (sDataAndUserDataBar != null) {
					CubeVector temp = null;

					for (String uddcName : sDataAndUserDataBar) {
						UddcTemplateInfo obj = uddcTemplateDAO
								.getUddcTemplateByCubeIdAndTemplateName(graphCube.getName(), uddcName);

						if (temp == null)
							temp = new CubeVector();

						if (obj == null) {
							for (int j = 0; j < userColInfo.size(); j++) {
								if (uddcName.equals(((UddcTemplateInfo) userColInfo.get(j)).getColumnName())) {
									temp.add(uddcName);
									break;
								}
							}
						} else {
							temp.add(uddcName);
						}

						if (obj == null)
							continue;
					}

					graphInfo.setUddcInfoListForBarCombinedGraph(temp);
				}

				if (sDataAndUserDataLine != null) {
					CubeVector temp = null;

					for (String uddcName : sDataAndUserDataLine) {
						UddcTemplateInfo obj = uddcTemplateDAO
								.getUddcTemplateByCubeIdAndTemplateName(graphCube.getName(), uddcName);

						if (temp == null)
							temp = new CubeVector();

						if (obj == null) {
							for (int j = 0; j < userColInfo.size(); j++) {
								if (uddcName.equals(((UddcTemplateInfo) userColInfo.get(j)).getColumnName())) {
									temp.add(uddcName);
								}
							}
						} else {
							temp.add(uddcName);
						}
						if (obj == null)
							continue;
					}

					graphInfo.setUddcInfoListForLineCombinedGraph(temp);
				}
			}
			else
			{
				
				graphInfo.setUddcInfoListForLineCombinedGraph(new CubeVector()); 
			}

			
			List<String> totalDimensioOld = new ArrayList<String>();
			totalDimensioOld.addAll(graphInfo.getRowColumns());
			totalDimensioOld.addAll(graphInfo.getColColumns());
			totalDimensioOld.addAll(graphInfo.getLineGraphRowLabelsForCombinedGraph());

			if (sRowItems.equals(""))
				graphInfo.setRowColumns(new Vector<String>());
			else
				graphInfo.setRowColumns(new Vector<String>(Arrays.asList(sRowItems.split(","))));

			if (sColItems.equals(""))
				graphInfo.setColColumns(new Vector<String>());
			else
				graphInfo.setColColumns(new Vector<String>(Arrays.asList(sColItems.split(","))));

			if (isFromFilter.equals("true")) {
				graphInfo.setDataColumns(new Vector<String>(
						Arrays.asList(requestParamMap.get("orderedDataLabels").toString().split(","))));
			} else {
				graphInfo.setDataColumns(new Vector<String>(Arrays.asList(sDataItems.split(","))));
			}
			CubeVector pageFilterConditionOLD = getFilterColumnList(graphInfo, uInfo);
			if (pageFilterConditionOLD != null) {
				for (int i = 0; i < pageFilterConditionOLD.size(); i++) {
					totalDimensioOld.add(pageFilterConditionOLD.get(i).toString());
				}
			}
			if(graphInfo.getNlpInfo() == null && !graphInfo.isFromNlp())
				setFilterInfoList(pageItems, graphInfo, allLabels);

			if (!isFromFilter.equals("true") && bRaystatus != null && bRaystatus.length() > 0) {

				HashMap mapLMRecentInfo = getLMRecentInfo();

				if ((mapLMRecentInfo != null) && (mapLMRecentInfo.size() > 0)) {

					if ((dataLabels == null) || (dataLabels.size() == 0)) {
						mapLMRecentInfo.clear();
					} else {

						Iterator mapKeyIterator = ((HashMap) mapLMRecentInfo.clone()).keySet().iterator();
						while (mapKeyIterator.hasNext()) {

							String mapKey = mapKeyIterator.next().toString();
							ALSName alsname = null;
							boolean bRemove = true;
							for (int i = 0; i < dataLabels.size(); i++) {
								alsname = (ALSName) dataLabels.get(i);
								if (alsname.GetAileas().equals(mapKey)) {
									bRemove = false;
									break;
								}
							}
							if (bRemove)
								mapLMRecentInfo.remove(mapKey);
						}
					}
					setLMRecentInfo(mapLMRecentInfo);
				}

				setOrderedDataColumnInfoList(orderedDataItems);

				if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
					changeListNotifyCombined(ALSOutlineListener.OUTLINE_CHANGED_ALL, rowLabels, colLabels, dataLabels,
							rowLabelsForLineGraph, colLabels, dataLabelsForLineGraph, graphInfo);
				} else {
					changeListNotify(ALSOutlineListener.OUTLINE_CHANGED_ALL, rowLabels, colLabels, dataLabels,
							graphInfo, uInfo);
				}
			}
			
			
			CubeViewInfo tempViewInfo = getViewStruct();
			CubeVector rowCubeVecter=new CubeVector();
			CubeVector colCubeVecter=new CubeVector();
			
			if(tempViewInfo.getRowLabelInfoList()!=null && tempViewInfo.getRowLabelInfoList().size()>0){
				for(int v=0;v<tempViewInfo.getRowLabelInfoList().size();v++) {
						CubeLabelInfo rowlabelInfo = (CubeLabelInfo) ((CubeLabelInfo) tempViewInfo.getRowLabelInfoList().get(v)).clone();
						if(!orderedDataItems.contains(rowlabelInfo.getTargetName())) {
							rowlabelInfo.setSortType(ICubeConstants.sortTypeByName);
						}
						rowCubeVecter.add(rowlabelInfo);
				}
			}
			
			if(tempViewInfo.getColLabelInfoList()!=null && tempViewInfo.getColLabelInfoList().size()>0){
				for(int v=0;v<tempViewInfo.getColLabelInfoList().size();v++) {
						CubeLabelInfo collabelInfo = (CubeLabelInfo) ((CubeLabelInfo) tempViewInfo.getColLabelInfoList().get(v)).clone();
						if(!orderedDataItems.contains(collabelInfo.getTargetName())) {
							collabelInfo.setSortType(ICubeConstants.sortTypeByName);
						}
						colCubeVecter.add(collabelInfo);
				}
			}
			
			if(rowCubeVecter!=null && rowCubeVecter.size()>0) {
				tempViewInfo.setRowLabelInfoList(rowCubeVecter);
			}
			
			if(colCubeVecter!=null && colCubeVecter.size()>0) {
				tempViewInfo.setColLabelInfoList(colCubeVecter);
			}
			setDataItemonViewInfo(tempViewInfo);
			
			
			List<CubeLabelInfo> sortList = graphInfo.getActiveTemplateProperties().getSortList();
			boolean flag1=true;
			if(sortList != null && sortList.size() > 0) {
				for(int i=0; i<sortList.size(); i++) {
					CubeLabelInfo cubeLabelInfo = sortList.get(i);
					if(cubeLabelInfo.getSortType()==ICubeConstants.sortTypeByValue){
						for(int j=0;j<tempViewInfo.getDataColumnInfoList().size();j++){
							if(orderedDataItems.contains(cubeLabelInfo.getTargetName())){
								flag1=false;
							break;
						}
					}
					if(flag1){
						sortList.get(i).setSortType(ICubeConstants.sortTypeByName);
						sortList.get(i).setTargetName("");
					}
					flag1=true;
					}
					
				}
			}
			
			IDataObject cubeInfo = null; 
			if(!graphInfo.isFromNlp()) {
				cubeInfo = cubeDataServiceUtil.getCubeForCubeColumnInfoByCubeId(getCubeName());
			} else {
				cubeInfo = graphInfo.getCubeInfo();
			}
			if(cubeInfo == null) {
				cubeInfo = graphOrgCube.getCubeInfo();
			}
			Vector vCubeMeasures = cubeMetadataServiceUtil.getMeasureColumns(cubeInfo);
			Vector userAddedData = new Vector();
			userAddedData = getAllUserAddedDataNameList(graphInfo);
			Vector measureList = getDataNameList(graphInfo);
			CubeColumnExpExecutor m_Expexec = getColumnExpressionExecutor();

			String uddcName = "";
			String[] newActiveUddc = null;
			HashMap uddcExpList = new HashMap();

			if (bChangeUddc) {
				UddcTemplateInfo uddcColumn = null;
				boolean flag = false;
				Vector vExpCols = new Vector();

				if (m_Expexec.getColumnNames() != null)
					vExpCols = m_Expexec.getColumnNames();

				for (Iterator iterator = vExpCols.iterator(); iterator.hasNext();) {
					String value = (String) iterator.next();
					if (!measureList.contains(value)) {
						if (vCubeMeasures.contains(value)) {
							measureList.add(value);
						}
					}
				}

				for (int i = 0; i < vUddcCols.size(); i++) {
					flag = false;
					uddcColumn = (UddcTemplateInfo) ((UddcTemplateInfo) vUddcCols.elementAt(i)).clone();
					uddcExpList.put(uddcColumn.getColumnName(), uddcColumn.getExpression());
				}

				for (int j = 0; j < activeUddcs.length; j++) {
					flag = false;
					if (uddcExpList.keySet().size() > 0 && uddcExpList.containsKey(activeUddcs[j])) {
						m_Expexec.setAllowUnknownVariables(true);
						m_Expexec.setColumnNames(measureList);
						m_Expexec.setExpression((String) uddcExpList.get(activeUddcs[j]));
						if (m_Expexec.verifyExp())
							flag = true;
					} else if (activeUddcs[j].indexOf('_') != -1) {
						String SourceColNameifDummy = activeUddcs[j].substring(0, activeUddcs[j].lastIndexOf('_'));
						if (uddcExpList.keySet().size() > 0 && uddcExpList.containsKey(SourceColNameifDummy)) {
							m_Expexec.setAllowUnknownVariables(true);
							m_Expexec.setColumnNames(measureList);
							m_Expexec.setExpression((String) uddcExpList.get(SourceColNameifDummy));
							if (m_Expexec.verifyExp())
								flag = true;
						}
					}
					if (flag) {
						uddcName += activeUddcs[j] + "~#~";
					} else {
						orderedDataItems.remove(activeUddcs[j]);
					}
				}
				if (!uddcName.equalsIgnoreCase(""))
					newActiveUddc = uddcName.split("~#~");
				else
					newActiveUddc = new String[0];

				setOrderedDataColumnInfoList(orderedDataItems);
				if (!isFromFilter.equals("true")) {
					boolean isAlreadyActive = false;
					ActiveUDDCInfo aUDDCInfo = null;
					Object[] activeUDDCVec = new Object[newActiveUddc.length];
					for (int i = 0; i < newActiveUddc.length; i++) {
						UddcTemplateInfo uddcTemplateInfo = uddcTemplateDAO
								.getUddcTemplateByCubeIdAndTemplateName(graphCube.getName(), newActiveUddc[i]);
						isAlreadyActive = false;
						if (uddcTemplateInfo == null) {
							for (int j = 0; j < userColInfo.size(); j++) {
								UddcTemplateInfo dataCol = (UddcTemplateInfo) userColInfo.get(j);
								if (dataCol.isVirtual() && dataCol.getColumnName().equals(newActiveUddc[i])) {
									if (dataCol.getBaseuddc().equals("")) {
										dataCol.setBaseuddc(dataCol.getColumnName().substring(0,
												dataCol.getColumnName().indexOf("_")));
									}
									activeUDDCVec[i] = userColInfo.get(j);
									if (activeUDDCList != null && activeUDDCList.size() > 0) {
										for (int cnt = 0; cnt < activeUDDCList.size(); cnt++) {
											ActiveUDDCInfo uddcInfo = activeUDDCList.get(cnt);
											String strColumnName = uddcInfo.getUddcTemplateInfo().getColumnName();
											if (strColumnName.equals(dataCol.getColumnName()) && dataCol.isVirtual()) {
												isAlreadyActive = true;
											}
										}
									}

									if (!isAlreadyActive) {
										dataCol.setStatus(true);
										aUDDCInfo = new ActiveUDDCInfo();
										aUDDCInfo.setCubeId(dataCol.getCubeId());
										aUDDCInfo.setObjectId(graphInfo.getGraphId());
										aUDDCInfo.setUddcTemplateInfoId(dataCol.getId());
										aUDDCInfo.setUddcTemplateInfo(dataCol);
										aUDDCInfo.setVirtualUddcName(dataCol.getColumnName());
										activeUDDCList.add(aUDDCInfo);
									}
								}
							}
						} else {
							activeUDDCVec[i] = uddcTemplateInfo;
							if (activeUDDCList != null && activeUDDCList.size() > 0) {
								for (int cnt = 0; cnt < activeUDDCList.size(); cnt++) {
									ActiveUDDCInfo uddcInfo = activeUDDCList.get(cnt);
									long lsavedTmpId = uddcInfo.getUddcTemplateInfo().getId();
									String strColumnName = uddcInfo.getUddcTemplateInfo().getColumnName();
									if (lsavedTmpId == uddcTemplateInfo.getId()
											&& strColumnName.equals(uddcTemplateInfo.getColumnName())) {
										isAlreadyActive = true;
									}
								}
							}
							if (!isAlreadyActive) {
								uddcTemplateInfo.setStatus(true);
								aUDDCInfo = new ActiveUDDCInfo();
								aUDDCInfo.setCubeId(uddcTemplateInfo.getCubeId());
								aUDDCInfo.setObjectId(graphInfo.getGraphId());
								aUDDCInfo.setUddcTemplateInfoId(uddcTemplateInfo.getId());
								aUDDCInfo.setUddcTemplateInfo(uddcTemplateInfo);
								activeUDDCList.add(aUDDCInfo);
							}
						}
					}

					setCubeActiveTemplates(TemplateUtil.ANA_USER_UDDC, activeUDDCVec, false);
				}

			} else {
				if (graphCube != null) {
					setOrderedDataColumnInfoList(orderedDataItems);
				}
			}
			graphInfo.getActiveTemplateProperties().setActiveUDDCInfo(activeUDDCList);

			setDataFormatAndMapFromCube(graphInfo, uInfo);
			CubeVector totalDimensionNew = new CubeVector();
			totalDimensionNew.addAll(graphInfo.getRowColumns());
			totalDimensionNew.addAll(graphInfo.getColColumns());
			totalDimensionNew.addAll(graphInfo.getLineGraphRowLabelsForCombinedGraph());

			if (graphInfo.getGraphData().isSmartenRowsEnable())
				totalDimensionNew.addAll(graphInfo.getGraphData().getSmartenRowList());
			if (graphInfo.getGraphData().isSmartenColoumnsEnable())
				totalDimensionNew.addAll(graphInfo.getGraphData().getSmartenColList());

			totalDimensionNew.addAll(pageLabels);
			if(graphInfo.isFromNlp()) {
				totalDimensioOld.clear();
			}
			List<DDVMTemplateInfo> ddvmTemplateInfoList = new ArrayList<DDVMTemplateInfo>();
			for (int i = 0; i < totalDimensionNew.size(); i++) {
				if (!totalDimensioOld.contains(totalDimensionNew.get(i).toString())) {
					ddvmTemplateInfoList.addAll(ddvmTemplateDAO.getDDVMTempInfoByCubeAndColumnName(
							graphInfo.getCubeInfo().getDataObjectId(), totalDimensionNew.get(i).toString()));
				}
			}
			activeddvmForNewAddedColumn(graphInfo, ddvmTemplateInfoList);
			if (!isFromFilter.equals("true") && (bRaystatus == null || "".equals(bRaystatus))) {
				refresh(graphInfo);
			}
		}
	}

	/**
	 * Gets Column meta data.
	 * 
	 * @param inName
	 * @return CubeColumnInfo
	 * @throws CubeException
	 */
	public CubeColumnInfo getColumnMetaData(SmartenInfo graphInfo, String inName) throws CubeException {
		return getColumnMetaData(graphInfo, inName, null);
	}

	/**
	 * Gets Column meta data.
	 * 
	 * @param inName
	 *            Column name
	 * @return Column meta data
	 * @throws CubeException
	 */
	public CubeColumnInfo getColumnMetaData(SmartenInfo graphInfo, String inName, String user) throws CubeException {
		if (graphOrgCube == null) {
			return null;
		}

		CubeColumnInfo cubeColumnInfo = null;

		if (graphInfo.getDataColumns() != null && graphInfo.getDataColumns().size() > 0) {
			for (int i = 0; i < graphInfo.getDataColumnInfoList().size(); i++) {
				cubeColumnInfo = (CubeColumnInfo) graphInfo.getDataColumnInfoList().elementAt(i);
				if (cubeColumnInfo.toString().compareTo(inName) == 0) {
					return cubeColumnInfo;
				} else
					cubeColumnInfo = null;
			}
		}
		if (getUserDataColumn(inName) != null)
			return new CubeColumnInfo(inName);

		if (user != null) {
			try {
				Vector vUDDC = graphOrgCube.getAllUserDefinedColumnsFromCube(user);

				for (int cntr = 0; cntr < vUDDC.size(); cntr++) {
					if (vUDDC.get(cntr).toString().equals(inName)) {
						return new CubeColumnInfo(inName);
					}
				}
			} catch (Exception exec) {
			}
		}

		try {
			ICubeResultSetMetaData icubeMetaData = graphOrgCube.getOriginalResultSetMetaData();
			for (int iIndex = 1; iIndex <= icubeMetaData.getColumnCount(); iIndex++) {
				cubeColumnInfo = icubeMetaData.getColumn(iIndex);
				if (cubeColumnInfo.getName().equals(inName)) {
					break;
				} else
					cubeColumnInfo = null;
			}
		} catch (Exception e) {
			int cubeType=0;
			String cubename="";
			if(cubeColumnInfo!=null) {
				cubeType= cubeColumnInfo.getType(); 
				cubename=cubeColumnInfo.getName();
			}
			
			ApplicationLog.error(ResourceManager.getString("MSG_TEXT_GRAPH_SETDATA_FAILED",
					new Object[] { graphInfo.getCubeInfo().getDataObjecName(), AppConstants.GRAPH,
							graphInfo.getGraphName(),cubeType, cubename,
							"CubeColumn Form Result set metadeta", e.getMessage(), "GraphService.java" }),
					e);
		}

		return cubeColumnInfo;
	}

	/**
	 * Returns CubeDataColumn objects of given column name.
	 * 
	 * @param name
	 * @return CubeDataColumn
	 * @throws CubeException
	 */
	private UddcTemplateInfo getUserDataColumn(String name) throws CubeException {
		UddcTemplateInfo userDataColumn = null;
		CubeVector userColumnInfoList = getUserColumnInfoList();

		for (int m = 0; m < userColumnInfoList.size(); m++) {
			userDataColumn = (UddcTemplateInfo) userColumnInfoList.elementAt(m);
			if (userDataColumn.getColumnName().equals(name))
				return userDataColumn;
		}

		return null;
	}

