	/**
	 * To set active templates.
	 * 
	 * @param type
	 *            Template type
	 * @param templates
	 *            List of template
	 * @throws RScriptException
	 * @throws ALSException
	 */
	public void setActiveTemplates(int type, Object[] templates, SmartenInfo graphInfo, String userId, boolean refresh)
			throws MDXException, RealTimeCubeException, CubeException, RScriptException {

		if (graphCube == null) {
			throw new CubeException(ResourceManager.getString("MSG_TEXT_CUBE_NOT_FORMED",
					new Object[] { this.graphDisplayName, this.cubeDisplayName }));
		}

		if (type == TemplateUtil.ANA_USER_UDDC) {
			if (graphInfo != null && graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
				if (graphInfo.getUddcInfoListForBarCombinedGraph() != null) {
					if (graphInfo.getUddcInfoListForBarCombinedGraph().isEmpty()) {
						for (int i = 0; i < templates.length; i++) {
							UddcTemplateInfo uddcTemplateInfo = (UddcTemplateInfo) templates[i];
							if (!graphInfo.getUddcInfoListForLineCombinedGraph()
									.contains(uddcTemplateInfo.getTemplateName())) {
								graphInfo.getUddcInfoListForBarCombinedGraph().add(uddcTemplateInfo.getTemplateName());
							}
						}
					} else {
						for (int i = 0; i < templates.length; i++) {
							UddcTemplateInfo uddcTemplateInfo = (UddcTemplateInfo) templates[i];
							if (!graphInfo.getUddcInfoListForBarCombinedGraph()
									.contains(uddcTemplateInfo.getTemplateName())) {
								if (!graphInfo.getUddcInfoListForLineCombinedGraph()
										.contains(uddcTemplateInfo.getTemplateName())) {
									graphInfo.getUddcInfoListForBarCombinedGraph()
											.add(uddcTemplateInfo.getTemplateName());
								}
							}
						}
					}
				}
			}
		}
		if (TemplateUtil.isCubeTemplate(type)) {
			setCubeActiveTemplates(type, templates, refresh);
		}
	}

	/**
	 * This method is used to sets grouped(packed) column name.
	 */
	public void setPackDDVMInfo(SmartenInfo graphInfo, HashtableEx ddvmValues) {
		Map packDDVMValues = graphInfo.getPackDDVMValues();
		if (packDDVMValues != null) {
			Set colNames = packDDVMValues.keySet();

			for (Iterator iterator = colNames.iterator(); iterator.hasNext();) {
				String colName = (String) iterator.next();

				if (ddvmValues.containsKey(colName)) {

					Vector valuesVect = (Vector) ddvmValues.get(colName);
					Vector packValuesVect = (Vector) packDDVMValues.get(colName);

					for (int j = 0; j < packValuesVect.size(); j++) {
						String[] packValues = (String[]) packValuesVect.get(j);
						boolean actualValuesMatched = false;

						for (int i = 0; i < valuesVect.size(); i++) {
							String[] values = (String[]) valuesVect.get(i);

							if (values[0].equals(packValues[0])) {
								valuesVect.set(i, packValues);
								actualValuesMatched = true;
								break;
							}
						}

						if (!actualValuesMatched) {
							valuesVect.add(packValues);
						}
						ddvmValues.put(colName, valuesVect);
					}
				} else {
					ddvmValues.put(colName, packDDVMValues.get(colName));
				}
			}
		}
	}

	/**
	 * To get axis display name.
	 * 
	 * @param columnVect
	 *            the column names
	 * @return Axis display name
	 */
	
	private Vector getAxisDisplayName(Vector columnVect, SmartenInfo graphInfo) {
		Vector newDisplayVect = new Vector();

		if (columnVect != null && columnVect.size() > 0) {
			for (int i = 0; i < columnVect.size(); i++) {
				newDisplayVect.add(getAxisDisplayName(String.valueOf(columnVect.get(i)), graphInfo));
			}
		}
		return newDisplayVect;
	}

	/**
	 * To get display name of axis.
	 * 
	 * @param columnName
	 *            the column names
	 * @return new display name
	 */
	public String getAxisDisplayName(String columnName, SmartenInfo graphInfo) {
		if (columnName == null || columnName.isEmpty()) {
	        return "";
	    }
	    if (graphInfo == null 
	            || graphInfo.getGraphProperties() == null) {
	        return columnName;
	    }
		String newDisplayName = columnName;
		Map<String, String> axisValueMap = graphInfo.getGraphProperties().getColLabelsMap();//graphInfo.getAxisDisplayValues();
		 if (axisValueMap == null || axisValueMap.isEmpty()) {
			 axisValueMap = graphInfo.getAxisDisplayValues();
		 }
		if (axisValueMap != null) {
			if (axisValueMap.containsKey(columnName) && !(columnName.equals(axisValueMap.get(columnName)))) {
				newDisplayName = axisValueMap.get(columnName);//.concat(" [ " + columnName + " ]");
			} else {
				newDisplayName = columnName;
			}
		}

		return newDisplayName;
	}

	/**
	 * This function returns the Display name of the specified Measure Column Name.
	 * 
	 * @param columnName
	 *            the column name
	 * @return Multiple measure display name
	 */
	private String getMMDisplayName(String columnName, SmartenInfo graphInfo) {
		Vector multiMeasureVect = graphInfo.getMultiMeasureDisplayValues();

		if (multiMeasureVect != null && multiMeasureVect.size() > 0) {
			int displayVectLength = multiMeasureVect.size();
			for (int i = 0; i < displayVectLength; i++) {
				String[] values = (String[]) multiMeasureVect.get(i);

				if (columnName.equals(values[0]) && !values[0].equals(values[1])) {
					String newDisplayName = null;
					newDisplayName = values[1].concat(" [ " + columnName + " ]");

					return newDisplayName;
				}
			}
		}

		return columnName;
	}

