	private Map createCategoryMeasure(SmartenInfo graphInfo, Map keyValueTempMap, List<String> measureList,
			GraphData graphData, List measurePositionCategory) {
		
		int noOfRanges = 4;
		int divValue = 1;
		NumberFormat formatter2 = new DecimalFormat("#.00");
		int rangeType = 0;

		String precisionLabel = "";
		int rowsMeasureIndex = 0;
		int precision = 2;

		Map categoryMeasureMap = new HashMap();
		NumberFormat formatter = new DecimalFormat("#.00");
		String[] customRangesString = null;

		int categoryMeasureIndex = 0;
		if (measurePositionCategory.size() > 0)
			categoryMeasureIndex = Integer.parseInt(measurePositionCategory.get(0).toString());
		List newCategoryList = new ArrayList();
		List rowsTitle = new ArrayList();
		divValue = rangeList(graphInfo, measureList, categoryMeasureMap, newCategoryList,
				graphInfo.getRowsDimMeasureList().get(1).toString(), rowsTitle, divValue);
		rowsTitle = null;
		
		Map finalMap = new HashMap();

		String rowsRange = "";
		String colsRange = "";
		String originalKey = "";
		String finalKey = "";
		Iterator it = keyValueTempMap.entrySet().iterator();

		while (it.hasNext()) {
			Map.Entry pair = (Map.Entry) it.next();
			originalKey = pair.getKey().toString();
			String[] arr = originalKey.split("categoryMeasure");

			double val = Double.valueOf(arr[1]) / divValue;
			val = Double.valueOf(formatter.format(val));
			arr[1] = "" + val;
			if (categoryMeasureMap.get(arr[1]) != null)
				finalKey = arr[0] + categoryMeasureMap.get(arr[1]).toString() + arr[2];

			finalMap.put(finalKey, pair.getValue());
		}
		

		graphData.setColList(newCategoryList);
		graphInfo.getGraphData().setColList(newCategoryList);
		if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
			graphData.setCmbBarcolList(newCategoryList);
			graphData.setCmbLinecolList(newCategoryList);
		}
		return finalMap;
	}

