	/**
	 * This method is responsible to generate clubbed keys of both rows and cols
	 * when both are enabled.
	 * 
	 * @param graphData
	 * @param colsKeyList
	 * @param rowsKeyList
	 */
	private void generateBothRowsAndColsKeys(SmartenInfo graphInfo, GraphData graphData, List<String> colsKeyList,
			List<String> rowsKeyList, boolean isPieWithRow) {
		String key = "";
		String combinedTitle = "";
		String seprator = "|cr|";
		int tempCount = 1;
		int pieCount = 0;
		List combinedKeys = new ArrayList();
		List combinedTitleList = new ArrayList();
		List rowTitleList = graphInfo.getGraphData().getSmartenRowsTitleList();
		List colTitleList = graphInfo.getGraphData().getSmartenColsTitleList();

		int rowsKeysSize = rowsKeyList.size();
		int colsKeysSize = colsKeyList.size();
		int colListSize = graphInfo.getGraphData().getColList().size();
		boolean pieWithRow = graphInfo.getGraphType() == GraphConstants.PIE_GRAPH
				&& (graphInfo.getGraphData().getRowList() != null && graphInfo.getGraphData().getRowList().size() > 0);

		if (pieWithRow) {
			for (int i = 0; i < rowsKeysSize; i++) {
				for (int j = 0; j < colsKeysSize; j++) {
					for (int j2 = 0; j2 < colListSize; j2++) {
						key = rowsKeyList.get(i) + colsKeyList.get(j);
						combinedKeys.add(key);
						combinedTitle = rowTitleList.get(i) + seprator + colTitleList.get(j);
						combinedTitleList.add(combinedTitle);
						tempCount++;
						pieCount++;
					}
				}
			}
		} else {
			for (int i = 0; i < rowsKeysSize; i++) {
				for (int j = 0; j < colsKeysSize; j++) {
					key = rowsKeyList.get(i) + colsKeyList.get(j);
					combinedTitle = rowTitleList.get(i) + seprator + colTitleList.get(j);
					combinedKeys.add(key);
					combinedTitleList.add(combinedTitle);

					tempCount++;
				}
			}
		}
		if (!isPieWithRow)
			graphData.setSmartenRowsColsTitleList(combinedTitleList);
		graphData.setRowsColsKeyList(combinedKeys);
	}

