	/**
	 * Sets default properties of Graph.
	 */
	private void setDefaultProperties(SmartenInfo graphInfo) {
		int graphType = graphInfo.getGraphType();

		if (graphInfo.getGraphMode() == AppConstants.NEW_MODE) {
			graphInfo.getGraphProperties().getTitleProperties().getTitleFont().setFontSize(16);
			graphInfo.getGraphProperties().getTitleProperties().getTitleFont().setFontWeight("bold");
			graphInfo.getGraphProperties().getxAxisProperties().getxAxisTitleTrendProperties().getFontProperties()
					.setFontSize(12);
			graphInfo.getGraphProperties().getxAxisProperties().getxAxisTitleTrendProperties().getFontProperties()
					.setFontWeight("normal");
			graphInfo.getGraphProperties().getyAxisProperties().getyAxisTitleTrendProperties().getFontProperties()
					.setFontSize(12);
			graphInfo.getGraphProperties().getyAxisProperties().getyAxisTitleTrendProperties().getFontProperties()
					.setFontWeight("normal");

			graphInfo.getGraphProperties().getCombinedYaxisProperties().getBarYaxisProperties()
					.getyAxisTitleTrendProperties().getFontProperties().setFontSize(12);
			graphInfo.getGraphProperties().getCombinedYaxisProperties().getBarYaxisProperties()
					.getyAxisTitleTrendProperties().getFontProperties().setFontWeight("normal");
			graphInfo.getGraphProperties().getCombinedYaxisProperties().getLineYaxisProperties()
					.getyAxisTitleTrendProperties().getFontProperties().setFontSize(12);
			graphInfo.getGraphProperties().getCombinedYaxisProperties().getLineYaxisProperties()
					.getyAxisTitleTrendProperties().getFontProperties().setFontWeight("normal");

			graphInfo.getGraphProperties().getSmartenProperties().getSmartenTitleProperties().getFontProperties()
					.setFontWeight("normal");
			graphInfo.getGraphProperties().getSmartenProperties().getSmartenLabelProperties().getFontProperties()
					.setFontWeight("normal");
			graphInfo.getGraphProperties().getSmartenProperties().getSmartenTitleProperties().getFontProperties()
					.setFontWeight("normal");
			graphInfo.getGraphProperties().getSmartenProperties().getSmartenTitleProperties().getFontProperties()
					.setFontSize(12);
			
			graphInfo.getGraphProperties().getCombinedYaxisProperties().getBarYaxisProperties().getLabelProperties()
					.setNumberOfDigits(0);
			graphInfo.getGraphProperties().getCombinedYaxisProperties().getLineYaxisProperties().getLabelProperties()
					.setNumberOfDigits(0);
			graphInfo.getGraphProperties().getxAxisProperties().getLabelProperties().setNumberOfDigits(0);
		}

		if (graphType == SmartenConstants.PIE_GRAPH && graphInfo.getGraphMode() == AppConstants.NEW_MODE) {
			graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setWidth(50);
			graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setHeight(50);
			graphInfo.getGraphProperties().getLegendProperties().getLegendPanelProperties().setLegendPanelHeight(50);
			graphInfo.getGraphProperties().getLegendProperties().getTitleProperties()
			.getTitleFont().setFontSize(10);
		} else if (graphType == SmartenConstants.DOUGHNUT_GRAPH && graphInfo.getGraphMode() == AppConstants.NEW_MODE) {
			graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setWidth(45);
			graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setHeight(45);
			graphInfo.getGraphProperties().getLegendProperties().getLegendPanelProperties().setLegendPanelHeight(45);
		} else {
			if (isFromAnalysis()) {
				graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setWidth(120);
				graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setHeight(60);
				graphInfo.getGraphProperties().getLegendProperties().getLegendPanelProperties()
						.setLegendPanelHeight(60);
				graphInfo.getGraphProperties().getLegendProperties().getLegendPanelProperties()
						.setLegendPanelFloatable(true);
			} else {
				if (graphInfo.getGraphMode() == AppConstants.NEW_MODE) {
					graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setWidth(90);
					graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setHeight(45);
					graphInfo.getGraphProperties().getLegendProperties().getLegendPanelProperties()
							.setLegendPanelHeight(45);
				}
			}
		}

		if ((graphType == SmartenConstants.DRILLED_RADAR_GRAPH
				|| graphType == SmartenConstants.DRILLED_STACKED_RADAR_GRAPH)
				&& (graphInfo.getGraphMode() == AppConstants.NEW_MODE)) {
			graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setWidth(70);
			graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setHeight(45);
			graphInfo.getGraphProperties().getLegendProperties().getLegendPanelProperties().setLegendPanelHeight(45);
		}

		boolean showRankOthers = graphInfo.getGraphProperties().getxAxisProperties().getLabelProperties().isOthers();
		graphOrgCube.setShowRankOthers(showRankOthers);

		if (graphType == SmartenConstants.COMBINED_GRAPH && graphInfo.getGraphMode() == AppConstants.NEW_MODE) {
			if (!isForDashboard()) {
				if (graphInfo.getGraphProperties().getCombinedYaxisProperties().getLineYaxisProperties()
						.getyAxisTitleTrendProperties().getRotateCharacter() == 0) {
					graphInfo.getGraphProperties().getCombinedYaxisProperties().getLineYaxisProperties()
							.getyAxisTitleTrendProperties().setRotateCharacter(90);
				} else {
					graphInfo.getGraphProperties().getCombinedYaxisProperties().getLineYaxisProperties()
							.getyAxisTitleTrendProperties().setRotateCharacter(0);
				}
			}
		}

		else if (graphType == SmartenConstants.NUMERIC_DIAL_GAUGE) {
			if (graphInfo.getGraphMode() == AppConstants.NEW_MODE) {
				graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setWidth(210);
				graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setHeight(100);
				graphInfo.getGraphProperties().getLegendProperties().getLegendPanelProperties()
						.setLegendPanelHeight(-1);
			}
		}

		else if (graphType == SmartenConstants.LEVEL_GAUGE) {
			if (graphInfo.getGraphMode() == AppConstants.NEW_MODE) {
				graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setWidth(210);
				graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setHeight(350);
				graphInfo.getGraphProperties().getLegendProperties().getLegendPanelProperties()
						.setLegendPanelHeight(-1);
			}
		}

		else if (graphType == SmartenConstants.THERMOMETER_GAUGE) {
			if (graphInfo.getGraphMode() == AppConstants.NEW_MODE) {
				graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setWidth(210);
				graphInfo.getGraphProperties().getGraphAreaProperties().getGeneralGraphArea().setHeight(245);
				graphInfo.getGraphProperties().getLegendProperties().getLegendPanelProperties()
						.setLegendPanelHeight(-1);
			}
		}
		if (graphInfo.getGraphType() == GraphConstants.D3_CHORD || graphInfo.getGraphType() == GraphConstants.D3_TREEMAP
				|| graphInfo.getGraphType() == GraphConstants.D3_SUNBURST
				|| graphInfo.getGraphType() == GraphConstants.D3_BUBBLE
				|| graphInfo.getGraphType() == GraphConstants.D3_TREELAYOUT) {
			if (graphInfo.isSmartenColorAutoCustom())
				graphInfo.getGraphProperties().setColorType(0);
			graphInfo.getGraphProperties().setRecommendedColorType(0);
		}
		if (graphInfo.getGraphMode() == AppConstants.NEW_MODE && graphInfo.getGraphType() == GraphConstants.SMARTENVIEW_MAP
				&& graphInfo.isSmartenColorAutoCustom())
		{
			graphInfo.getGraphProperties().setColorType(0);
			graphInfo.getGraphProperties().setRecommendedColorType(0);
		}
		if (!graphInfo.isBubbleSizeChanged())
			graphInfo.getGraphProperties().getBarProperties().setBubbleSize(10);
		if (graphInfo.isXyChart() && graphInfo.getGraphDataVector() != null
				&& graphInfo.getGraphDataVector().size() > 0) {
			int adjustedDigits = GraphsUtil.getSmartviewAutoAdjustDigit(graphInfo.getGraphDataVector());
			graphInfo.getGraphProperties().getxAxisProperties().getLabelProperties().setAdjustedDigit(adjustedDigits);
		}
	}

	/**
	 * To set filter condition information on cube.
	 * 
	 * @param colConditions
	 *            the column condition
	 * @throws Exception
	 */
	public void setFilterConditionsOnCube(CubeVector colConditions) throws Exception {
		if (graphOrgCube != null) {
			HashMap conditionsMap = new HashMap();

			CubeConditionInfo cubeCondInfo = null;
			String colName = null;
			if (colConditions != null) {
				for (int cntr = 0; cntr < colConditions.size(); cntr++) {
					cubeCondInfo = (CubeConditionInfo) colConditions.get(cntr);
					colName = cubeCondInfo.getColumnName();

					CubeVector cubeVector = (CubeVector) conditionsMap.get(colName);
					if (cubeVector == null) {
						cubeVector = new CubeVector();
						conditionsMap.put(colName, cubeVector);
					}
					cubeVector.add(cubeCondInfo);
				}
			}
			graphOrgCube.setFilterConditions(conditionsMap, false);
		}
	}

