	/**
	 * This method will returns information of selected Page dimensions for the
	 * object. This String array has below format.
	 * 
	 * <pre>
	 * String[][0] : Column Name
	 *         [1] : Column Type
	 *         [2] : Tooltip Value
	 *         [4] : Cube Id
	 *         [7] : Cube display name
	 * </pre>
	 * 
	 * @param graphInfo
	 *            Reference of graph with processed information
	 * @return Information of Page dimensions for the object
	 * @throws CubeException
	 */
	public String[][] getPageFilters(SmartenInfo graphInfo) throws CubeException {

		String[][] pageFilters = null;
		if (graphInfo != null && graphInfo.getMultiPageFilterInfo() != null) {
			String[][] filterColumnsInfo = graphInfo.getMultiPageFilterInfo();
			if (filterColumnsInfo.length > 0 && filterColumnsInfo[0].length < 4) {
				String[][] newfilterColumnsInfo = new String[filterColumnsInfo.length][4];
				for (int i = 0; i < filterColumnsInfo.length; i++) {
					for (int j = 0; j < filterColumnsInfo[i].length; j++) {
						newfilterColumnsInfo[i][j] = filterColumnsInfo[i][j];
					}
					newfilterColumnsInfo[i][3] = "false";
				}
				graphInfo.setMultiPageFilterInfo(newfilterColumnsInfo);
			}
			filterColumnsInfo = graphInfo.getMultiPageFilterInfo();
			pageFilters = new String[filterColumnsInfo.length][];

			String columnName = null;
			String columnType = null;
			String cubeName = null;
			String toolTipValue = null;
			String toolTipId = null;
			String pageIndex = null;
			String none = ResourceManager.getString("LBL_NONE");
			String clearDisplayStyle = null;
			String clearVisibilityStyle = null;
			int filterCount = 0; 
			String pFID = "";
			boolean isTimeSeries = false;

			for (int i = 0; i < filterColumnsInfo.length; i++) {
				String isFromDsbTimeSeries = filterColumnsInfo[i].length > 5 ? filterColumnsInfo[i][5] : "false";
				if (isFromDsbTimeSeries != null && isFromDsbTimeSeries.equals("true"))
					continue;

				cubeName = filterColumnsInfo[i].length > 4 ? filterColumnsInfo[i][4] : "";
				pageIndex = "" + i;
				columnName = filterColumnsInfo[i][0];
				columnType = filterColumnsInfo[i][1];

				if (columnType.equalsIgnoreCase("3")
						&& !filterColumnsInfo[i][2].equalsIgnoreCase(ResourceManager.getString("LBL_NONE"))) {
					toolTipValue = CalendarUtil.getSelectedFinancialYear(getFilterConditions(columnName)) + " "
							+ filterColumnsInfo[i][2];
				} else
					toolTipValue = filterColumnsInfo[i][2];

				
				if (columnType.equalsIgnoreCase("3")) {
					pFID = "txt_" + columnName + "_" + cubeName;
					isTimeSeries = true;
				}

				toolTipId = columnName + "_" + cubeName;

				if (toolTipValue.length() == 0 || toolTipValue.equals(none)) {
					clearVisibilityStyle = "visibility:hidden";
				} else {
					clearVisibilityStyle = "visibility:";
				}

				String displayName = "";
				displayName = columnName;
				pageFilters[filterCount] = new String[9];

				pageFilters[filterCount][0] = columnName;
				pageFilters[filterCount][1] = columnType;
				pageFilters[filterCount][2] = toolTipValue;
				pageFilters[filterCount][4] = cubeName;
				pageFilters[filterCount][7] = graphInfo.getCubeInfo().getDataObjecName() + ","
						+ graphInfo.getCubeInfo().getDataObjectId();
				if (filterColumnsInfo[filterCount].length >= 4) {
					pageFilters[filterCount][8] = filterColumnsInfo[filterCount][3];
					if (filterColumnsInfo[filterCount][3] == null) {
						pageFilters[filterCount][8] = "false";
					}
				} else {
					pageFilters[filterCount][8] = "false";
				}

				filterCount++;
			}
		}

		return pageFilters;
	}
	
	public ArrayList<PageFilterNew> getPageFilterNew(SmartenInfo smartenInfo) throws CubeException {
		ArrayList<PageFilterNew> pageFilterInfoList = new ArrayList<PageFilterNew>();
		pageFilterInfoList = smartenInfo.getPageFilterColumnInfo();
		if(pageFilterInfoList == null) {
			pageFilterInfoList = new ArrayList<PageFilterNew>();
		}
		return pageFilterInfoList;
	}

	public String[][] getRetrivalParameter(SmartenInfo graphInfo) throws CubeException {
		String[][] pageFilters = null;
		if (graphInfo != null && !graphInfo.getActiveTemplateProperties().getPreloadingParameters().isEmpty()) {
			int columnTypes[] = new int[graphInfo.getActiveTemplateProperties().getPreloadingParameters().size()];
			String[][] filterColumnsInfo = new String[graphInfo.getActiveTemplateProperties().getPreloadingParameters()
					.size()][];
			String[] columnNames = new String[graphInfo.getActiveTemplateProperties().getPreloadingParameters().size()];
			int count = 0;
			ArrayList<ParamItem> retVal=graphInfo.getActiveTemplateProperties().getPreloadingParameters();
			for (ParamItem item:retVal) {
				columnNames[count] = item.getColumnName().replace("[", "").replace("]", "");
				columnTypes[count] = GeneralFiltersUtil.getCubeColumnType(graphInfo.getCubeInfo(), columnNames[count]);
				count++;
			}

			pageFilters = new String[graphInfo.getActiveTemplateProperties().getPreloadingParameters().size()][];

			String columnName = "";
			String columnType = null;
			String condOperator = "0";
			StringBuilder condValue = new StringBuilder();
			String criteriaType = "1";
			String criteriaTypeTo = "1";
			String timeSeriesType = "0";
			String timeSeriesTypeTo = "0";
			String timeSeriesYearType = "0";
			String timeSeriesTimeType = "0";
			String numberValue = "";
			String xValue = "";
			String skipEmptyPeriod = "false";
			String includeCurrentDay = "false";
			String timeSeriesStr = "";
			String numberValueTo = "";
			String xValueTo = "";
			String logicalOperator = "1";
			String status = "true";
			String groupId = "0";
			String filterApplied = "true";
			String cubeName = null;
			String toolTipValue = null;
			String toolTipId = null;
			String pageIndex = null;
			String none = ResourceManager.getString("LBL_NONE");
			String clearDisplayStyle = null;
			String clearVisibilityStyle = null;
			int filterCount = 0;

			for (int i = 0; i < retVal.size(); i++) {
				columnName = columnNames[i];
				columnType = "" + columnTypes[i];
				condOperator = ""+retVal.get(i).getCondOperator();
				criteriaType = ""+retVal.get(i).getCriteriaType();
				criteriaTypeTo = ""+retVal.get(i).getCriteriaTypeTo();
				timeSeriesType = ""+retVal.get(i).getTimeSeriesType();
				timeSeriesTypeTo = ""+retVal.get(i).getTimeSeriesTypeTo();
				timeSeriesYearType = ""+retVal.get(i).getTimeSeriesYear();
				timeSeriesTimeType = ""+retVal.get(i).getTimeSeriesTime();
				numberValue = ""+retVal.get(i).getNumberValue();
				xValue = ""+retVal.get(i).getxValue();
				skipEmptyPeriod = ""+retVal.get(i).isSkipEmptyPeriod();
				includeCurrentDay = ""+retVal.get(i).isIncludeCurrentDay();
				timeSeriesStr = ""+retVal.get(i).getStrTimeseriesValue();
				numberValueTo = ""+retVal.get(i).getNumberValueTo();
				xValueTo = ""+retVal.get(i).getxValueTo();
				logicalOperator = ""+retVal.get(i).getLogicalOperator();
				status = ""+retVal.get(i).isStatus();
				groupId = ""+retVal.get(i).getGroupId();
				filterApplied = ""+retVal.get(i).isFilterApplied();
				condValue = new StringBuilder();
				StringBuilder sb = new StringBuilder();
				if (retVal.get(i).getCondValue()!=null && !retVal.get(i).getCondValue().isEmpty()) {
					List<String> retrivalParameter = retVal.get(i).getCondValue();

					for (int j = 0; j < retrivalParameter.size(); j++) {
						condValue.append(String.valueOf(retrivalParameter.get(j)));
						if(j != retrivalParameter.size()-1) {
							condValue.append(AppConstants.CUBE_CONDITION_FILTER_VALUE_SEPERATOR);
						}
						sb.append(columnName).append("=").append(String.valueOf(retrivalParameter.get(j)));
						if (j == retrivalParameter.size() - 1)
							break;
						sb.append(AppConstants.CUBE_CONDITION_FILTER_VALUE_SEPERATOR);
					}
					toolTipValue = sb.toString();
				} else
					toolTipValue = none;

				pageFilters[filterCount] = new String[28];
				pageFilters[filterCount][0] = columnName;
				pageFilters[filterCount][1] = columnType;
				pageFilters[filterCount][2] = toolTipValue;
				pageFilters[filterCount][4] = graphInfo.getCubeInfo().getDataObjectId();
				pageFilters[filterCount][7] = graphInfo.getCubeInfo().getDataObjecName();
				pageFilters[filterCount][8] = "false";
				pageFilters[filterCount][9] = condOperator;
				pageFilters[filterCount][10] = criteriaType;
				pageFilters[filterCount][11] = criteriaTypeTo;
				pageFilters[filterCount][12] = condValue.toString();
				pageFilters[filterCount][13] = timeSeriesType;
				pageFilters[filterCount][14] = timeSeriesTypeTo;
				pageFilters[filterCount][15] = timeSeriesYearType;
				pageFilters[filterCount][16] = timeSeriesTimeType;
				pageFilters[filterCount][17] = numberValue;
				pageFilters[filterCount][18] = xValue;
				pageFilters[filterCount][19] = skipEmptyPeriod;
				pageFilters[filterCount][20] = includeCurrentDay;
				pageFilters[filterCount][21] = timeSeriesStr;
				pageFilters[filterCount][22] = numberValueTo;
				pageFilters[filterCount][23] = xValueTo;
				pageFilters[filterCount][24] = logicalOperator;
				pageFilters[filterCount][25] = status;
				pageFilters[filterCount][26] = groupId;
				pageFilters[filterCount][27] = filterApplied;
				filterCount++;
			}
		}

		return pageFilters;
	}

	/**
	 * Sets filter information list.
	 * 
	 * @param filterInfoList
	 *            filter information list
	 * @param columnNames
	 *            column name list
	 * @param refresh
	 *            true to refresh otherwise false
	 * @throws ALSException
	 * @throws CubeException
	 */
	private void setFilterInfoList(String[] filterInfoList, SmartenInfo graphInfo, CubeVector columnNames)
			throws ALSException, CubeException {

		graphInfo.setMultiPageFilterInfo(getFilterInfoList(filterInfoList, graphInfo));
	}

	/**
	 * Gets filter information list.
	 * 
	 * @param filterInfoList
	 *            filter information list
	 * @return filter information list
	 * @throws ALSException
	 * @throws CubeException
	 */
	private String[][] getFilterInfoList(String[] filterInfoList, SmartenInfo graphInfo)
			throws MDXException, RealTimeCubeException, ALSException, CubeException {

		String[][] s2DArrfilterInfoList = null;
		if (filterInfoList.length > 0) {
			s2DArrfilterInfoList = new String[filterInfoList.length][4];

			int iType = -1;
			String colType = "0";

			String columnName = null;
			CubeColumnInfo columnInfo = null;

			for (int i = 0; i < filterInfoList.length; i++) {
				columnName = filterInfoList[i];

				columnInfo = getColumnMetaData(graphInfo, columnName);
				if (columnInfo == null)
					continue;

				iType = columnInfo.getTypeIF();

				colType = "" + CubeUtil.getColType(iType);

				s2DArrfilterInfoList[i][0] = filterInfoList[i];
				s2DArrfilterInfoList[i][1] = colType;
				s2DArrfilterInfoList[i][2] = ResourceManager.getString("LBL_NONE");
			}
		} else {
			s2DArrfilterInfoList = new String[][] {};
		}

		Map<String, CubeVector> pageFilterConditionMap = null;
		CubeVector vector = new CubeVector();
		if (s2DArrfilterInfoList != null && s2DArrfilterInfoList.length > 0) {
			if (pageFilterConditionMap == null) {
				pageFilterConditionMap = new HashMap<String, CubeVector>();
			}

			for (String[] filterInfo : s2DArrfilterInfoList) {
				pageFilterConditionMap.put(filterInfo[0], getFilterConditions(filterInfo[0]));
			}

			if (pageFilterConditionMap != null && pageFilterConditionMap.size() > 0) {

				for (String colNameKey : pageFilterConditionMap.keySet()) {
					if (pageFilterConditionMap.get(colNameKey) != null) {
						CubeVector v1 = pageFilterConditionMap.get(colNameKey);
						if (v1 != null && v1.size() > 0) {
							vector.addAll(v1);
						}
					}
				}
			}
		}

		if (!graphInfo.isGraphFromDashBoard() && !graphInfo.isFromNlp())// For bug no 11769
			graphInfo.setRayOuterConditions(vector);
		try {
			setFilterConditions(vector);
		} catch (Exception e) {
			ApplicationLog.error(e);
		}
		HashMap toolTipDataMap = GeneralFiltersUtil.generateToolTipDataForPageValue(pageFilterConditionMap,
				s2DArrfilterInfoList, graphCube.getOriginalResultSetMetaData(), graphInfo.getCubeInfo());
		if (filterInfoList != null && filterInfoList.length > 0) {
			for (int i = 0; i < filterInfoList.length; i++) {
				s2DArrfilterInfoList[i][2] = StringUtil.null2String(toolTipDataMap.get(s2DArrfilterInfoList[i][0]));
			}
		}

		return s2DArrfilterInfoList;
	}

	/**
	 * Get LOV data from cube for specified column
	 * 
	 * @param strColumnName
	 *            column name
	 * @param strStartWith
	 *            start with character
	 * @param strCubeId
	 *            cube id
	 * @param userInfo
	 *            user id
	 * @param graphInfo
	 *            graph info
	 * @param filterCondition 
	 * @return list of lov data
	 * @throws ALSException
	 * @throws CubeException
	 * @throws DAIFException
	 */
	public List<SelectItem> getLovData(String strColumnName, String strStartWith, String strCubeId, UserInfo userInfo,
			SmartenInfo graphInfo, boolean isCustomSort, boolean hideUdhc, boolean showGV, boolean showAllData,
			int lastIndexValue, boolean isFromPageFilter, boolean isRealData, boolean isBackEnd, String filterCondition)
			throws ALSException, CubeException, DAIFException {

		List<Object> valueList = null;
		CubeVector combinedCon = null;
		List lovDataList = new ArrayList();
		setLoggedInUserId(userInfo.getUserId());
		int iType = -1;
		ALSItem alsItem = null;
		CubeColumnInfo cubeColumnInfo = null;
		try {
			cubeColumnInfo = getColumnMetaData(graphInfo, strColumnName);
		} catch (CubeException e) {
			ApplicationLog.error(
					ResourceManager.getString("LOG_ERROR_MSG_ERROR_FETCHING_PAGE_FILTER_LOV_DATA",
							new Object[] { graphInfo.getGraphName(), graphInfo.getGraphMode(), "getColumnMetaData" }),
					e);

			throw e;
		}
		if (cubeColumnInfo != null)
			iType = cubeColumnInfo.getTypeIF();

		IDataObject cubeInfo = null;
		try {
			cubeInfo = cubeDataServiceUtil.getCubeForCubeColumnInfoByCubeId(strCubeId);
			if(cubeInfo == null) {
				cubeInfo = graphInfo.getCubeInfo();
			}
			if (isBackEnd && cubeInfo.getDataObjectType() == ICubeConstants.REALTIME_R_CUBE) {
				cubeInfo = new CubeDAO().getCubeByCubeId(cubeInfo.getrInputCubeId());
			}
			Vector measure = cubeMetadataServiceUtil.getMeasureColumns(cubeInfo);
			if (measure.contains(strColumnName)) {
				if (showGV) {
					List<ActiveGlobalVariableInfo> activeGlobalVariableInfoList = graphInfo
							.getActiveGlobalVariableInfo(userInfo.getUserId());
					List<ActiveGlobalVariableInfo> activeGlobalVariableInfoListIsMultiselect = new ArrayList<>();
					for(int i=0; i<activeGlobalVariableInfoList.size(); i++) {
						if(!activeGlobalVariableInfoList.get(i).getGlobalVariableInfo().isMultiSelect()) {
							activeGlobalVariableInfoListIsMultiselect.add(activeGlobalVariableInfoList.get(i));
						}
					}
					List<SelectItem> globalVariableLOVs = getGlobalVariableForLOV(strColumnName, strStartWith,
							valueList, activeGlobalVariableInfoListIsMultiselect, true);
					lovDataList.addAll(globalVariableLOVs);
				}
				//return lovDataList;
			}
			if (isRealData) {
				CubeViewInfo cubeViewInfo = getViewStruct();
				
				HashMap<String, CubeVector> conditionMap1 = new HashMap<>();
				prepareFilterForLOV(conditionMap1, cubeViewInfo.getConditionInfoList());
				
				combinedCon = prepareFilterConditionsForLOV("", strColumnName, cubeInfo, userInfo,
						conditionMap1, showAllData, isCustomSort, graphInfo.isSkipcubedatasetcolumndataaccesspermission(userInfo), filterCondition);
			}else {
				combinedCon = new CubeVector();
			}
		} catch (CubeException e) {
			ApplicationLog
					.error(ResourceManager.getString("LOG_ERROR_MSG_ERROR_FETCHING_PAGE_FILTER_LOV_DATA", new Object[] {
							graphInfo.getGraphName(), graphInfo.getGraphMode(), "prepareFilterConditionsForLOV" }), e);

			throw e;
		} catch (ALSException e) {
			ApplicationLog
					.error(ResourceManager.getString("LOG_ERROR_MSG_ERROR_FETCHING_PAGE_FILTER_LOV_DATA", new Object[] {
							graphInfo.getGraphName(), graphInfo.getGraphMode(), "prepareFilterConditionsForLOV" }), e);

			throw e;
		} catch (DatabaseOperationException e) {
			ApplicationLog.error(e);
		}

		int mdxOlapServer = -1;
		if (cubeInfo.isMdxCube()) {
			try {
				mdxOlapServer = (new MDXProfileDAO().getById(cubeInfo.getMdxProfileId(), MDXInfo.class))
						.getOlapServer();
			} catch (DatabaseOperationException e) {
				ApplicationLog.error(e);
			}
		}

		try

		{
			combinedCon = CubeUtil.replaceGlobalVarVal(combinedCon, getActiveVariableMap(),
					getOriginalResultSetMetaData(), cubeInfo);

			if (cubeInfo.getDataObjectType() == ICubeConstants.REALTIME_R_CUBE) {
				int index = 0;
				List dataValue = new ArrayList();
				for (String string : graphCube.getrOutputData().keySet()) {
					RData rData = graphCube.getrOutputData().get(string);
					for (int j = 0; j < rData.getHeaders().size(); j++) {
						Header header = rData.getHeaders().get(j);
						if (header.getLable().equals(strColumnName)) {
							index = j;
							break;
						}
					}
					for (List<String> row : rData.getBody()) {
						dataValue.add(row.get(index));
					}
				}
				valueList = dataValue;
			} else {
				
				String objectId = graphInfo.getGraphId();
				if (objectId == null) {
					objectId = graphInfo.getNewGraphId();
				}
				String frequency = null;
				if(!isBackEnd && graphInfo.getDateFrequencyMap() != null && !graphInfo.getDateFrequencyMap().isEmpty() && graphInfo.getDateFrequencyMap().get(strColumnName) != null) {
					frequency = graphInfo.getDateFrequencyMap().get(strColumnName);
				} 
				if(isFromdashboard() && graphInfo.getDashboardInfo() !=null && graphInfo.getStrGroupID() != null && !graphInfo.getStrGroupID().isEmpty()) {
					objectId = graphInfo.getDashboardInfo().getDashboardId()+"_"+graphInfo.getStrGroupID();
				}
				valueList = getCubeDataValuesForLOV(strColumnName, cubeInfo, combinedCon, isCustomSort,
						graphCube.getActiveVariablesMap(), lastIndexValue, strStartWith, objectId, frequency);
			}

			List<ActiveGlobalVariableInfo> activeGlobalVariableInfoList = null;
			List<SelectItem> globalVariableLOVs = null;
			List<String> glbVariables = null;
			if (showGV) {
				activeGlobalVariableInfoList = graphInfo.getActiveTemplateProperties()
						.getActiveGlobalVariableInfo(userInfo.getUserId());
				List<ActiveGlobalVariableInfo> activeGlobalVariableInfoListIsMultiselect = new ArrayList<>();
				for(int i=0; i<activeGlobalVariableInfoList.size(); i++) {
					if(!activeGlobalVariableInfoList.get(i).getGlobalVariableInfo().isMultiSelect()) {
						activeGlobalVariableInfoListIsMultiselect.add(activeGlobalVariableInfoList.get(i));
					}
				}
				globalVariableLOVs = getGlobalVariableForLOV(strColumnName, strStartWith, valueList,
						activeGlobalVariableInfoListIsMultiselect, false);
				glbVariables = new ArrayList<>();
				for (int i = 0; i < globalVariableLOVs.size(); i++) {
					glbVariables.add(globalVariableLOVs.get(i).getValue());
				}
			}

			if (isFromPageFilter) {
				String[][] pageFilterInformation = null;

				List<Object> selectedDataList = new ArrayList<Object>();
				List<Object> selectedData = new ArrayList<Object>();
				if (getPageFilters(graphInfo) != null)
					pageFilterInformation = getPageFilters(graphInfo).clone();
				else
					pageFilterInformation = new String[0][];

				for (int i = 0; i < pageFilterInformation.length; i++) {

					if (pageFilterInformation[i][0].equalsIgnoreCase(strColumnName)
							&& !pageFilterInformation[i][2].equals(ResourceManager.getString("NONE"))
							&& pageFilterInformation[i][8].equals("false")) {
						CubeVector vect = getFilterConditions(strColumnName);
						String filterStrArray = "";
						boolean flag=true;
						if (vect != null && vect.size() > 0) {
							for (Object obj : vect) {
								CubeConditionInfo cinfo = (CubeConditionInfo) obj;
								if(cinfo.getConditionalOperator() == CubeConditionInfo.NULL || cinfo.getConditionalOperator()== CubeConditionInfo.NOTNULL) {
    								if("".equals(filterStrArray))
    									flag=false;
    								continue;
    							}
    							flag=true;
								if (filterStrArray.equals("")) {
									filterStrArray = filterStrArray + cinfo.getConditionalValue();
								} else {
									filterStrArray = filterStrArray + "@@#@@" + cinfo.getConditionalValue();
								}
							}
						}
						if(flag)
							selectedData = StringUtil.toList(filterStrArray.split("@@#@@"));
					}

				}

				for (int i = 0; i < selectedData.size(); i++) {
					Object val = selectedData.get(i);
					if (val.toString().contains(CubeConditionInfo.VARIABLE)) {
						val = val.toString().replace(CubeConditionInfo.VARIABLE, "");
						val = val.toString().trim();
					}
					selectedDataList.add(val);
				}

				if (cubeInfo.isMdxCube()) {
					List<Object> newValueList = new ArrayList<Object>();
					for (int i = 0; i < valueList.size(); i++) {
						if (valueList.get(i) instanceof SelectItem) {
							SelectItem item = (SelectItem) valueList.get(i);
							if (!selectedDataList.contains(item.getValue())) {
								newValueList.add(item);
							}
						}
					}
					selectedDataList.addAll(newValueList);
					valueList = selectedDataList;
				} else {
					if (selectedDataList.size() > 0) {

						List<Object> selectedDataListFordate = new ArrayList<Object>();
						for (int j = 0; j < selectedDataList.size(); j++) {
							Object objValue = selectedDataList.get(j);
							if (iType == Types.DATE || iType == Types.TIME || iType == Types.TIMESTAMP) {
								if (!glbVariables.contains(objValue.toString())) {
									objValue = CubeUtil.stringToJdbcTypeObject(objValue.toString(), iType);
								}
								selectedDataListFordate.add(objValue);
							} else if (iType == Types.BIGINT || iType == Types.INTEGER || iType == Types.SMALLINT) {
								if (selectedDataList.get(j).toString().toUpperCase().contains("NULL")) {
									objValue = "(NULL)";
									selectedDataList.remove(j);
									selectedDataList.add(j, objValue);
								} else if (selectedDataList.get(j).toString().toUpperCase().contains("$")) {
									objValue = selectedDataList.get(j).toString();
								} else {
									if (iType == Types.BIGINT || iType == Types.DOUBLE) {
										objValue = new Long(selectedDataList.get(j).toString());
									} else {
										objValue = new Integer(selectedDataList.get(j).toString());
									}
								}
							} else if (iType == Types.DOUBLE) {
								if (selectedDataList.get(j).toString().toUpperCase().contains("NULL")) {
									objValue = "(NULL)";
									selectedDataList.remove(j);
									selectedDataList.add(j, objValue);
								} else if (selectedDataList.get(j).toString().toUpperCase().contains("$")) {
									objValue = selectedDataList.get(j).toString();
								} else {
									objValue = new Double(selectedDataList.get(j).toString());
								}
							} else if (objValue instanceof String
									&& selectedDataList.get(j).toString().toUpperCase().contains("NULL")) {
								objValue = "(NULL)";
								selectedDataList.remove(j);
								selectedDataList.add(j, objValue);
							}
							valueList.remove(objValue);
						}

						if (selectedDataListFordate.size() > 0) {
							selectedDataListFordate.addAll(valueList);
							valueList = selectedDataListFordate;
						} else {
							selectedDataList.addAll(valueList);
							valueList = selectedDataList;
						}
					}
				}

			}
			combinedCon = CubeUtil.replaceGlobalVarVal(combinedCon, getActiveVariableMap(),
					getOriginalResultSetMetaData(), cubeInfo);

			if (iType != 91 && iType != 92 && iType != 93) {
				valueList = getStartWithFilterDataForLOV(valueList, strStartWith, isCustomSort, lastIndexValue,
						isFromPageFilter);
			}

			if (isCustomSort) {
				List<CubeLabelInfo> cubeLabelInfos = graphInfo.getSortList();
				CubeLabelInfo cubeLabelInfo = new CubeLabelInfo();
				for (CubeLabelInfo sortInfo : cubeLabelInfos) {
					if (sortInfo.getName().equals(strColumnName))
						cubeLabelInfo = sortInfo;
				}
				HashMap<String, CubeVector> customSort = cubeLabelInfo.getCustomSortMap();
				CubeVector colSeq = new CubeVector();
				if (customSort == null) {
					customSort = new HashMap<String, CubeVector>();
					cubeLabelInfo.setCustomSortMap(customSort);
				}
				if (customSort.containsKey(strColumnName)) {
					colSeq = (CubeVector) customSort.get(strColumnName);
				}
				for (int i = 0; i < colSeq.size(); i++) {
					if (cubeInfo.isMdxCube() && mdxOlapServer == AppConstants.MICROSOFT_SSAS) {
						int index = 0;
						for (Iterator iterator = valueList.iterator(); iterator.hasNext(); index++) {
							SelectItem item = (SelectItem) iterator.next();
							if (item.getValue().equals(colSeq.get(i))) {
								valueList.remove(index);
								colSeq.set(i, item.getValue());
								break;
							}
						}
					} else {
						for (int j = 0; j < valueList.size(); j++) {
							if (valueList.get(j).toString().equals(colSeq.get(i))) {
								valueList.remove(j);
								break;
							}
						}
					}
				}
			}

			
			HashtableEx ddvmMap = new HashtableEx();

			if (alsItem == null)
				ddvmMap = (HashtableEx) getActiveDDVMs(graphInfo, userInfo.getUserId());

			if (iType == 4 && !ddvmMap.containsKey(cubeColumnInfo.getName())) {
				try {
					HashtableEx timeDDVMMap = (HashtableEx) getTimeTemplate(graphInfo, cubeColumnInfo.getName());
					if (timeDDVMMap.get(cubeColumnInfo.getName()) != null)
						ddvmMap.put(cubeColumnInfo.getName(), timeDDVMMap.get(cubeColumnInfo.getName()));

				} catch (DatabaseOperationException e) {
					ApplicationLog.error(e);
				}

			}

			
			if (!hideUdhc) {
				CubePackInfoList packConditionList = graphInfo.getPackConditions();
				for(int j=0;j < packConditionList.size();j++) {
					CubeCondition condition = packConditionList.conditionAt(j);
					String label = packConditionList.packLabelAt(j);
					
					if(condition.getColumnName().equals(strColumnName) && condition.getStatus()) {
						if(!valueList.contains(label)) {
							SelectItem item = new SelectItem();
							
							String val = condition.toString();
							if(condition.toString().length() > 40) {
								val = val.substring(0, 40).concat("...");
							}
							item.setLabel(label + " " + val);
							item.setValue(label);
							lovDataList.add(item);
						}
						
						for(int i=0;i<condition.size();i++) {
							valueList.remove(condition.elementAt(i));
						}
					}
				}

				lovDataList.addAll(getDataDisplayValueMappingOnLOV(ddvmMap, valueList, userInfo.getUserId(), iType,strColumnName));
				}else {
					lovDataList = getDataDisplayValueMappingOnLOV(ddvmMap, valueList, userInfo.getUserId(), iType,strColumnName);
				}
			
			
			if (!hideUdhc) {
				Vector vUDLabel = new Vector();
				CubeVector drillUserLabel = new CubeVector();
				List<ActiveUDHCInfo> actUDHCInfoList = graphInfo.getActiveUDHCInfo(userInfo.getUserId());
				for (ActiveUDHCInfo activeUDHC : actUDHCInfoList) {
					CubeVector udhcVec = TemplateUtil.getDataLabelVector(activeUDHC, null);
					CubeDataLabel cdl = (CubeDataLabel) udhcVec.get(0);
					if (cdl.getColumnName().equals(strColumnName)) {
						cdl.setLabelType(CubeDataLabel.ROW_TYPE);
					}
					if (cdl.getColumnName().equals(strColumnName)) {
						cdl.setLabelType(CubeDataLabel.COL_TYPE);
					}
					drillUserLabel.add(cdl);
				}
				Vector vUDHCList = new Vector();
				if (drillUserLabel != null && drillUserLabel.size() > 0) {
					for (int i = 0; i < drillUserLabel.size(); i++) {
						if (!vUDHCList.contains(drillUserLabel.get(i))) {
							vUDHCList.add(drillUserLabel.get(i));
						}
					}
				}
				List<SelectItem> udhcLOVs = getUDHCItemsForLOV(strColumnName, strStartWith, valueList, vUDHCList,
						ddvmMap);

				if (isCustomSort) {
					if (udhcLOVs != null) {
						List<CubeLabelInfo> cubeLabelInfos = graphInfo.getSortList();
						CubeLabelInfo cubeLabelInfo = new CubeLabelInfo();
						for (CubeLabelInfo sortInfo : cubeLabelInfos) {
							if (sortInfo.getName().equals(strColumnName))
								cubeLabelInfo = sortInfo;
						}
						HashMap<String, CubeVector> customSort = cubeLabelInfo.getCustomSortMap();
						CubeVector colSeq = new CubeVector();
						if (customSort == null) {
							customSort = new HashMap<String, CubeVector>();
							cubeLabelInfo.setCustomSortMap(customSort);
						}
						if (customSort.containsKey(strColumnName)) {
							colSeq = (CubeVector) customSort.get(strColumnName);
						}
						for (int i = 0; i < colSeq.size(); i++) {
							if (cubeInfo.isMdxCube() && mdxOlapServer == AppConstants.MICROSOFT_SSAS) {
								int index = 0;
								for (Iterator iterator = valueList.iterator(); iterator.hasNext(); index++) {
									SelectItem item = (SelectItem) iterator.next();
									if (item.getValue().equals(colSeq.get(i))) {
										valueList.remove(index);
										colSeq.set(i, item.getValue());
										break;
									}
								}
							} else {
								int index = 0;
								for (Iterator iterator = udhcLOVs.iterator(); iterator.hasNext(); index++) {
									SelectItem item = (SelectItem) iterator.next();
									if (item.getValue().toString().equals(colSeq.get(i))) {
										udhcLOVs.remove(index);
										break;
									}
								}
							}
						}
					}
				}
				lovDataList.addAll(udhcLOVs);
			}
		} catch (Exception e) {
			ApplicationLog
					.error(ResourceManager.getString("LOG_ERROR_MSG_ERROR_FETCHING_PAGE_FILTER_LOV_DATA", new Object[] {
							graphInfo.getGraphName(), graphInfo.getGraphMode(), "prepareFilterConditionsForLOV" }), e);

			
		}
		if (showGV) {
			List<ActiveGlobalVariableInfo> activeGlobalVariableInfoList = graphInfo
					.getActiveGlobalVariableInfo(userInfo.getUserId());
			List<SelectItem> globalVariableLOVs = getGlobalVariableForLOV(strColumnName, strStartWith, valueList,
					activeGlobalVariableInfoList, false);
			for (int i = 0; i < globalVariableLOVs.size(); i++) {
				if (valueList!=null && !valueList.contains(globalVariableLOVs.get(i).getValue())) {
					lovDataList.add(globalVariableLOVs.get(i));
				}
			}
		}

		if (iType == 91 || iType == 92 || iType == 93) {
			lovDataList = getStartWithFilterDataForLOV(lovDataList, strStartWith, isCustomSort, lastIndexValue,
					isFromPageFilter);
		}

		return lovDataList;
	}

	private CubeVector getPreloadingParameterListFromOrgCube() throws CubeException {
		return graphCube.getPrelodingParameterList();
	}

	/**
	 * This method will sets Filter condition on Graph object.
	 * 
	 * @param requestParams
	 *            Request parameters containing column on which condition is
	 *            applied, condition itself, etc.
	 * @param cubeId
	 *            Cube identifier
	 * @param graphInfo
	 *            Reference of graph with processed information
	 * @param loggedInUser
	 *            Reference to currently logged in user
	 * @throws DatabaseOperationException
	 * @throws ALSException
	 * @throws CubeException
	 */
	public void applyPageFilter(Map<String, String> requestParams, String cubeId, SmartenInfo graphInfo,
			UserInfo loggedInUser)
			throws DatabaseOperationException, ALSException, MDXException, RealTimeCubeException, CubeException {

		HashMap conditionMap = getFilterConditions();
		CubeVector conditionVect = new CubeVector();

		if (conditionMap != null && conditionMap.size() > 0) {
			for (Iterator iterator = conditionMap.keySet().iterator(); iterator.hasNext();) {
				String key = (String) iterator.next();
				conditionVect.addAll((CubeVector) conditionMap.get(key));
			}
			conditionVect = (CubeVector) conditionVect.clone();
		}

		String conditions = requestParams.get("conditions");

		CubeVector conditionVector = null;

		if (conditions != null && conditions.trim().length() > 0) {
			conditionVector = GeneralFiltersUtil.getFilterConditionsVector(conditions, conditionVect,
					getOriginalResultSetMetaData(), graphInfo.getCubeInfo());
		} else {
			conditionVector = new CubeVector();
		}

		setFilterConditions(requestParams.get("column"), conditionVector, graphInfo);

		resetIndex(graphInfo);
		resetDrillVector(graphInfo);
		setDHTMLGraph(graphInfo, loggedInUser);
		refreshPageFilterTooltip(graphInfo);
		for (int i = 0; i < graphInfo.getMultiPageFilterInfo().length; i++) {
			String colName = graphInfo.getMultiPageFilterInfo()[i][0];
			String[] val = requestParams.get("isAdvanceFilter").split(":");
			if (colName.equals(val[0])) {
				if (graphInfo.getMultiPageFilterInfo()[i].length > 3) {
					graphInfo.getMultiPageFilterInfo()[i][3] = val[1];
				}
			}
		}
		String folderId = "";
		if(graphInfo != null && graphInfo.getFolderInfo() !=null) {
			folderId = graphInfo.getFolderInfo().getFolderId();
		}
		String logAction = ResourceManager.getString("VIEW_NAME_DATAFILTER") + " : "
				+ StringUtil.null2String(requestParams.get("column"));

		String strCubeName = graphInfo.getCubeInfo().getDataObjecName();
		String strCubeId = graphInfo.getCubeInfo().getDataObjectId();
		
		UserLog.info(loggedInUser.getSessionID(), loggedInUser.getAuditDisplayName(), logAction,
				ResourceManager.getString("LBL_ANALYSIS_LINK"), graphInfo.getGraphName(),graphInfo.getGraphId(), 
				strCubeName,strCubeId,folderId , AppConstants.DETAIL,loggedInUser.loginfrom());
		

		if (graphInfo.getGraphProperties().getTitleProperties().isTitleVisible()) {
			setObjectPageTitle(graphInfo.getGraphId(),
					graphInfo.getActiveFilterInfo(loggedInUser.getUserId()),
					getPageFilterNew(graphInfo), graphCube.getActiveVariablesMap(),
					graphCube.getResultSetMetaData(), graphInfo.getCubeInfo(),
					graphInfo.getGraphProperties().getTitleProperties(), loggedInUser,
					getActiveDDVMs(graphInfo, loggedInUser.getUserId()));
		}
	}

	/**
	 * To set filter condition information.
	 * 
	 * @param columnName
	 *            the column name
	 * @param conditions
	 *            the filter condition
	 * @throws CubeException
	 */
	private void setFilterConditions(String columnName, CubeVector conditions, SmartenInfo graphInfo)
			throws CubeException {
		CubeVector allConditions = graphInfo.getRayOuterConditions();

		if (conditions == null) {
			conditions = new CubeVector();
		}

		if (allConditions != null && allConditions.size() > 0) {
			for (int i = 0; i < allConditions.size(); i++) {
				CubeConditionInfo cubeConditionInfo = (CubeConditionInfo) allConditions.get(i);

				if (!cubeConditionInfo.getColumnName().equals(columnName)) {
					conditions.add(cubeConditionInfo);
				}
			}
		}
		graphInfo.setRayOuterConditions(conditions);
	}

	/**
	 * This method is used to refresh filter information.
	 * 
	 * @throws CubeException
	 */
	public void refreshPageFilterTooltip(SmartenInfo graphInfo) throws CubeException {
		String[][] s2DArrfilterInfoList = graphInfo.getMultiPageFilterInfo();

		Map<String, CubeVector> pageFilterConditionMap = null;

		try {
			if (s2DArrfilterInfoList != null && s2DArrfilterInfoList.length > 0) {
				if (pageFilterConditionMap == null) {
					pageFilterConditionMap = new HashMap<String, CubeVector>();
				}

				for (String[] filterInfo : s2DArrfilterInfoList) {
					pageFilterConditionMap.put(filterInfo[0], graphOrgCube.getFilterConditions(filterInfo[0]));
				}
			}

			
			HashMap toolTipDataMap = GeneralFiltersUtil.generateToolTipDataForPageValue(pageFilterConditionMap,
					s2DArrfilterInfoList, getOriginalResultSetMetaData(), graphInfo.getCubeInfo());

			if (s2DArrfilterInfoList != null && s2DArrfilterInfoList.length > 0) {
				for (int i = 0; i < s2DArrfilterInfoList.length; i++) {
					s2DArrfilterInfoList[i][2] = StringUtil.null2String(toolTipDataMap.get(s2DArrfilterInfoList[i][0]));
				}
			}

			graphInfo.setMultiPageFilterInfo(s2DArrfilterInfoList);

			List<String> strColumnList = new ArrayList<String>();
			if (s2DArrfilterInfoList != null && s2DArrfilterInfoList.length > 0) {
				for (int i = 0; i < s2DArrfilterInfoList.length; i++) {
					strColumnList.add(s2DArrfilterInfoList[i][0]);
				}
			}
			graphOrgCube.setObjectpagefiltercolumnList(strColumnList);

		} catch (CubeException ex) {
			String graphMode = (graphInfo.getGraphMode() == AppConstants.NEW_MODE) ? "New" : "Open";
			ApplicationLog.error(ResourceManager.getString("LOG_ERROR_MSG_FAILED_TO_REFRESH_PAGE_TOOLTIP",
					new Object[] { graphInfo.getGraphName(), graphMode }), ex);

			throw ex;
		}
	}

	/**
	 * Prepare All Items Map with it's Column Type
	 * 
	 * @param processedAnalysisInfo
	 *            Analysis Info
	 * @return HashMap with column name as key and type as value
	 * @throws ALSException
	 * @throws CubeException
	 */
	public Map<SelectItem, Integer> prepareDimensionItemsMap(String strCubeId, UserInfo userInfo, SmartenInfo smartenInfo) throws CubeException {

		Map<SelectItem, Integer> cubeItemsMap = new LinkedHashMap<SelectItem, Integer>();
		Vector<Vector<String>> dimensionColumn = new Vector<Vector<String>>();

		try {
			IDataObject cubeInfo = cubeDataServiceUtil.getCubeForCubeColumnInfoByCubeId(strCubeId);
			if(cubeInfo == null) {
				cubeInfo = smartenInfo.getCubeInfo();
			}
			if (cubeInfo.getDataObjectType() == ICubeConstants.REALTIME_R_CUBE) {
				cubeInfo = cubeDataServiceUtil.getCubeForCubeColumnInfoByCubeId(graphOrgCube.getrInputCubeId());
			}
			dimensionColumn = cubeMetadataServiceUtil.getDimensionColumnVector(cubeInfo, userInfo, smartenInfo.isSkipcubedatasetcolumndataaccesspermission(userInfo));
		} catch (DatabaseOperationException e) {
			ApplicationLog.error(e);
		}

		List<String> columnsList = new ArrayList<String>();
		columnsList.addAll((Vector<String>) dimensionColumn.get(1));
		columnsList.addAll((Vector<String>) dimensionColumn.get(4));

		for (String columnName : columnsList) {
			int iType = -1;
			iType = CubeUtil.getColumnType(columnName, getOriginalResultSetMetaData(), strCubeId);
			SelectItem selectItem = new SelectItem();
			selectItem.setLabel(columnName);
			selectItem.setValue(columnName);
			cubeItemsMap.put(selectItem, iType);
		}
		return cubeItemsMap;
	}

	/**
	 * Prepare All Items Map with it's Column Type
	 * 
	 * @param processedAnalysisInfo
	 *            Analysis Info
	 * @return HashMap with column name as key and type as value
	 * @throws CubeException
	 */
	public Map<SelectItem, Integer> prepareAllItemsMap(SmartenInfo graphInfo, boolean includeMeasure, UserInfo userInfo)
			throws CubeException {

		List<String> columnsList = new ArrayList<String>();
		Map<SelectItem, Integer> columnsMap = new HashMap<SelectItem, Integer>();
		Vector<Vector<String>> outLinerData = getOutLinerDataWithoutSysGeneratedFields(false, graphInfo);
		columnsList.addAll(outLinerData.get(0));
		columnsList.addAll(outLinerData.get(1));
		if (includeMeasure) {
			columnsList.addAll(graphInfo.getDataColumns());
			if(graphInfo.getGraphType()==16) {
				columnsList.addAll(graphInfo.getTheDataColLabels4());
			}
		}
		List<ActiveUDDCInfo> activeUDDCList = graphInfo.getActiveUDDCInfo(userInfo.getUserId());
		if (activeUDDCList != null && activeUDDCList.size() > 0) {
			for (int cnt = 0; cnt < activeUDDCList.size(); cnt++) {
				ActiveUDDCInfo activeuddcInfo = activeUDDCList.get(cnt);
				String name = getMMDisplayName(activeuddcInfo.getUddcTemplateInfo().getColumnName(), graphInfo);
				columnsList.add(activeuddcInfo.getUddcTemplateInfo().getColumnName());
			}
		}

		for (String columnName : columnsList) {
			int iType = -1;
			iType = getColumnTypeByColumnName(columnName, graphInfo, false);
			SelectItem selectItem = new SelectItem();
			selectItem.setLabel(getAxisDisplayName(columnName, graphInfo));
			selectItem.setValue(columnName);
			columnsMap.put(selectItem, iType);
		}
		return columnsMap;
	}

	public int getColumnTypeByColumnName(String columnName, SmartenInfo graphInfo, boolean isBackEnd)
			throws CubeException {
		int cubeType = -1;
		if (isBackEnd && graphInfo.getCubeInfo().getDatabaseCubeType() == ICubeConstants.REALTIME_R_CUBE) {
			try {
				CubeInfo cubeInfo = new CubeDAO().getCubeByCubeId(graphInfo.getCubeInfo().getrInputCubeId());
				if (cubeInfo.getCubeColumnInfoList() != null && cubeInfo.getCubeColumnInfoList().size() > 0) {
					for (com.elegantjbi.entity.admin.CubeColumnInfo cubeColumnInfo : cubeInfo.getCubeColumnInfoList()) {
						if (cubeColumnInfo.getColumnName().equals(columnName)) {
							if (cubeColumnInfo != null) {
								cubeType = cubeColumnInfo.getColumnType();
							}
							break;
						}
					}
				}
			} catch (DatabaseOperationException e) {
				ApplicationLog.error(e);
			}

		} else {
			if(graphInfo.getDateFrequencyMap() != null && !graphInfo.getDateFrequencyMap().isEmpty() && graphInfo.getDateFrequencyMap().get(columnName) != null) {
				
				if(isBackEnd) {
					cubeType = CubeUtil.getColumnType(columnName,graphInfo.getCubeInfo());
				}else {
					String frequency = graphInfo.getDateFrequencyMap().get(columnName);
					if(frequency != null && !frequency.isEmpty()) {
						cubeType = CubeUtil.isIntegerDateFrequency(frequency);
					} else {
						cubeType = CubeUtil.getColumnType(columnName, getOriginalResultSetMetaData(),
								graphInfo.getCubeInfo().getDataObjectId());
					}
				}
				
			} else {
				cubeType = CubeUtil.getColumnType(columnName, getOriginalResultSetMetaData(),
						graphInfo.getCubeInfo().getDataObjectId());
			}
		}
		return cubeType;
	}

	public Map<Integer, String[]> generateStringFromConditionMap(String columnName, String cubeId)
			throws CubeException, DatabaseOperationException {
		try {
			IDataObject cubeInfo = cubeDataServiceUtil.getCubeForCubeColumnInfoByCubeId(cubeId);
			return GeneralFiltersUtil.generateStringFromConditionMap(graphOrgCube.getFilterConditions(columnName),
					cubeInfo, getOriginalResultSetMetaData());
		} catch (CubeException e) {
			ApplicationLog.error(e);

			throw e;
		}
	}

	/**
	 * Get cube order by info for sort in row
	 * 
	 * @param graphInfo
	 *            graph entity
	 * @return vector of cube order by info
	 */
	private Vector<CubeOrderByInfo> getSortRow(SmartenInfo graphInfo) {

		Vector<CubeOrderByInfo> sortRowVector = new Vector<CubeOrderByInfo>();
		List<CubeLabelInfo> sortInfo = graphInfo.getSortList();
		Vector<String> rowVec = new CubeVector();
		if (null != graphInfo.getRowColumns()) {
			rowVec.addAll((Vector<String>) graphInfo.getRowColumns().clone());
			if (graphInfo.getLineGraphRowLabelsForCombinedGraph() != null
					&& graphInfo.getLineGraphRowLabelsForCombinedGraph().size() > 0) {
				rowVec.addAll((Vector<String>) graphInfo.getLineGraphRowLabelsForCombinedGraph().clone());
			}
			for (int i = 0; i < sortInfo.size(); i++) {
				CubeLabelInfo cubeLabelInfo = sortInfo.get(i);
				for (String rowName : rowVec) {
					if (rowName.equals(cubeLabelInfo.getName()) && cubeLabelInfo.isStatus()) {
						sortRowVector.add((CubeOrderByInfo) cubeLabelInfo);
					} else {
						if (rowName.equals(cubeLabelInfo.getName())) {
							CubeLabelInfo lableInfo = (CubeLabelInfo) cubeLabelInfo.clone();
							lableInfo.setTargetName(ResourceManager.getString("LBL_NONE"));
							lableInfo.setTargetTotalType(0);
							lableInfo.setSortType(ICubeResultSetSupport.sortTypeByName);
							lableInfo.setSortDirection(0);
							lableInfo.setDescOrder(false);
							lableInfo.setCustomSortMap(null);
							lableInfo.setFilterString("");
							lableInfo.setCustomSortMap(null);
							lableInfo.setTargetName("");
							lableInfo.setTargetTotalType(0);
							sortRowVector.add((CubeOrderByInfo) lableInfo);
						}
					}
				}
			}
		}
		return sortRowVector;
	}

	/**
	 * Get cube order by info for sort in col
	 * 
	 * @param graphInfo
	 *            graph entity
	 * @return vector of cube order by info
	 */
	private Vector<CubeOrderByInfo> getSortCol(SmartenInfo graphInfo) {

		Vector<CubeOrderByInfo> sortColVector = new Vector<CubeOrderByInfo>();
		List<CubeLabelInfo> sortInfo = graphInfo.getSortList();
		Vector<String> colVec = new Vector();
		
		colVec.addAll(graphInfo.getDimensionTitleList());
		

		for (int i = 0; i < sortInfo.size(); i++) {
			CubeLabelInfo cubeLabelInfo = sortInfo.get(i);
			for (String colName : colVec) {
				if (colName.equals(cubeLabelInfo.getName()) && cubeLabelInfo.isStatus()) {
					sortColVector.add((CubeOrderByInfo) cubeLabelInfo);
				} else {
					if (colName.equals(cubeLabelInfo.getName())) {
						CubeLabelInfo lableInfo = (CubeLabelInfo) cubeLabelInfo.clone();
						lableInfo.setTargetName(ResourceManager.getString("LBL_NONE"));
						lableInfo.setTargetTotalType(0);
						lableInfo.setSortType(ICubeResultSetSupport.sortTypeByName);
						lableInfo.setSortDirection(0);
						lableInfo.setDescOrder(false);
						lableInfo.setCustomSortMap(null);
						lableInfo.setFilterString("");
						lableInfo.setCustomSortMap(null);
						lableInfo.setTargetName("");
						lableInfo.setTargetTotalType(0);
						sortColVector.add((CubeOrderByInfo) lableInfo);
					}
				}
			}
		}
		return sortColVector;
	}

	/**
	 * Get Custom Sorted Map
	 * 
	 * @param graphInfo
	 *            graph entity
	 * @return Map of custom sorting values
	 */
	private Map<String, CubeVector> getCustSortMap(SmartenInfo graphInfo) {

		Map<String, CubeVector> customSort = new HashMap<String, CubeVector>();
		List<CubeLabelInfo> sortInfo = graphInfo.getSortList();
		for (CubeLabelInfo cubeLabelInfo : sortInfo) {
			if (cubeLabelInfo.getSortType() == ICubeResultSetSupport.sortTypeCustome) {
				customSort.put(cubeLabelInfo.getName(), cubeLabelInfo.getCustomSortMap().get(cubeLabelInfo.getName()));
			}
		}
		return customSort;
	}

	/**
	 * Get Row Column Display Name Map
	 * 
	 * @param graphInfo
	 *            graph entity
	 * @return Map of row column display name
	 * @throws CubeException
	 *             exception
	 */
	public Map<String, String> getRowColumnDisplayNameMap(SmartenInfo graphInfo) throws CubeException {
		return getRowColumnDisplayNameMap(graphInfo, false);
	}

	/**
	 * Get Row Column Display Name Map
	 * 
	 * @param graphInfo
	 *            graph entity
	 * @param isCombinedGraph
	 *            graph is combined-graph or not
	 * @return Map of row column display name
	 * @throws CubeException
	 */
	public Map<String, String> getRowColumnDisplayNameMap(SmartenInfo graphInfo, boolean isCombinedGraph)
			throws CubeException {
		Vector<String> rowLabelNames = graphInfo.getRowColumns();
		Vector<String> columnLabelNames = graphInfo.getColColumns();
		Vector<String> rowsNames = graphInfo.getRowsColumns();//Added for Jira Bug SDEVAPR20-439
		Vector<String> columnsNames = graphInfo.getColsColumns();//Added for Jira Bug SDEVAPR20-439

		Map<String, String> displayMap = new HashMap<String, String>();
		if (rowLabelNames != null && rowLabelNames.size() > 0) {
			for (int i = 0; i < rowLabelNames.size(); i++) {
				String name = getAxisDisplayName(rowLabelNames.get(i).toString(), graphInfo);
				displayMap.put(rowLabelNames.get(i).toString(), name);
			}
		}
		if (columnLabelNames != null && columnLabelNames.size() > 0) {
			for (int i = 0; i < columnLabelNames.size(); i++) {
				String name = getAxisDisplayName(columnLabelNames.get(i).toString(), graphInfo);
				displayMap.put(columnLabelNames.get(i).toString(), name);
			}
		}
		if (rowsNames != null && rowsNames.size() > 0) {
			for (int i = 0; i < rowsNames.size(); i++) {
				String name = getAxisDisplayName(rowsNames.get(i).toString(), graphInfo);
				displayMap.put(rowsNames.get(i).toString(), name);
			}
		}
		if (columnsNames != null && columnsNames.size() > 0) {
			for (int i = 0; i < columnsNames.size(); i++) {
				String name = getAxisDisplayName(columnsNames.get(i).toString(), graphInfo);
				displayMap.put(columnsNames.get(i).toString(), name);
			}
		}

		if (isCombinedGraph) {
			Vector<String> rowLabelNamesLine = graphInfo.getLineGraphRowLabelsForCombinedGraph();
			if (rowLabelNamesLine != null && rowLabelNamesLine.size() > 0) {
				for (int i = 0; i < rowLabelNamesLine.size(); i++) {
					String name = getAxisDisplayName(rowLabelNamesLine.get(i).toString(), graphInfo);
					displayMap.put(rowLabelNamesLine.get(i).toString(), name);
				}
			}
		}

		return displayMap;
	}

	/**
	 * Get Measure Column Display Name Map
	 * 
	 * @param graphInfo
	 *            graph entity
	 * @return Map of Measure column display name
	 * @throws CubeException
	 *             exception
	 */
	public Map<String, String> getMeasureDisplayNameMap(SmartenInfo graphInfo, String userId) throws CubeException {
		return getMeasureDisplayNameMap(graphInfo, false, userId);
	}

	/**
	 * Get Measure Column Display Name Map
	 * 
	 * @param graphInfo
	 *            graph entity
	 * @param isCombinedGraph
	 *            graph is combined-graph or not
	 * @param userId
	 * @return Map of Measure column display name
	 * @throws CubeException
	 */
	public Map<String, String> getMeasureDisplayNameMap(SmartenInfo graphInfo, boolean isCombinedGraph, String userId)
			throws CubeException {
		
		if(graphInfo.getGraphType()==16) {
			isCombinedGraph = true;
		}

		Vector<String> datalabel = graphInfo.getDataColumns();
		Map<String, String> displayMap = new HashMap<>();
		if (datalabel != null && !datalabel.isEmpty()) {
			for (int i = 0; i < datalabel.size(); i++) {
				String name = getMMDisplayName(datalabel.get(i), graphInfo);
				displayMap.put(datalabel.get(i), name);
			}
		}

		if (isCombinedGraph) {
			Vector<String> datalabelLine = graphInfo.getLineGraphDataLabelsForCombinedGraph();
			if (datalabelLine != null && datalabelLine.size() > 0) {
				for (int i = 0; i < datalabelLine.size(); i++) {
					String name = getMMDisplayName(datalabelLine.get(i).toString(), graphInfo);
					displayMap.put(datalabelLine.get(i).toString(), name);
				}
			}
		}

		List<ActiveUDDCInfo> activeUDDCList = graphInfo
				.getActiveUDDCInfo(userId);
		if (activeUDDCList != null && activeUDDCList.size() > 0) {
			for (int cnt = 0; cnt < activeUDDCList.size(); cnt++) {
				ActiveUDDCInfo activeuddcInfo = activeUDDCList.get(cnt);
				String name = getMMDisplayName(activeuddcInfo.getUddcTemplateInfo().getColumnName(), graphInfo);
				displayMap.put(activeuddcInfo.getUddcTemplateInfo().getColumnName(), name);
			}
		}
		return displayMap;
	}

	/**
	 * Get Forecasting Column Map
	 * 
	 * @return map
	 * @throws CubeException
	 */
	public Map<SelectItem, String> getColumnMapForForecasting(SmartenInfo graphInfo) throws CubeException {

		Map<SelectItem, String> coulmnMap = new LinkedHashMap<SelectItem, String>();
		Vector outLinerData = getOutLinerDataWithoutSysGeneratedFields(false, graphInfo);
		Vector<String> rowLabels = (Vector<String>) outLinerData.get(0);
		Vector<String> colLabels = (Vector<String>) outLinerData.get(1);
		String dimension = "";
		if (rowLabels != null) {
			for (String rowString : rowLabels) {
				dimension = rowString;
				SelectItem selectItem = new SelectItem();
				selectItem.setLabel(getAxisDisplayName(dimension, graphInfo));
				selectItem.setValue(dimension);
				if (isNumberForDimension(rowString)) {
					coulmnMap.put(selectItem, "true");
				} else {
					coulmnMap.put(selectItem, "false");
				}
			}
		}
		if (colLabels != null) {
			for (String colString : colLabels) {
				dimension = colString;
				SelectItem selectItem = new SelectItem();
				selectItem.setLabel(getAxisDisplayName(dimension, graphInfo));
				selectItem.setValue(dimension);
				if (isNumberForDimension(colString))
					coulmnMap.put(selectItem, "true");
				else
					coulmnMap.put(selectItem, "false");
			}
		}
		return coulmnMap;
	}

	/**
	 * Action to be taken on DrillDown Event.
	 * 
	 * @param graphInfo
	 *            Reference of graph with processed information
	 * @param params
	 *            Parameters required to perform drill down operation
	 * @param loggedInUserId
	 *            Logged in user's identifier
	 * @throws CubeException
	 *             Thrown CubeException
	 * @throws RemoteException
	 *             Thrown RemoteException
	 * @throws RScriptException
	 */

	public void setGraphDrillDown(SmartenInfo graphInfo, Map<String, String> params, UserInfo loggedInUserInfo)
			throws MDXException, RealTimeCubeException, CubeException, RemoteException, RScriptException {
		String colPath = "";
		String rowPath = "";

		if (params.get("isColumn").trim().equalsIgnoreCase("true")) {
			String colValue = StringUtil.fromHexString(params.get("colValue"));
			colPath = graphInfo.getDrilldownColumnPath();
			if (colPath.length() == 0) {
				if (colValue.trim() != "")
					colPath = params.get("colName") + "$~$" + colValue.trim();
				else
					colPath = params.get("colName") + "$~$" + "@^@";
			} else {
				if (colValue.trim() != "")
					colPath = colPath + "$~$" + colValue.trim();
				else
					colPath = colPath + "$~$" + "@^@";
			}
		}

		if (params.get("isRow").trim().equalsIgnoreCase("true")) {
			String colValue = StringUtil.fromHexString(params.get("colValue"));
			rowPath = graphInfo.getDrilldownRowPath();
			if (rowPath.length() == 0) {
				if (colValue.trim() != "")
					rowPath = params.get("colName") + "$~$" + colValue.trim();
				else
					rowPath = params.get("colName") + "$~$" + "@^@";
			} else {
				if (colValue.trim() != "")
					rowPath = rowPath + "$~$" + colValue.trim();
				else
					rowPath = rowPath + "$~$" + "@^@";
			}
		}

		int drillType = Integer.parseInt(StringUtil.null2String(params.get("drillType")));
		boolean isDrillDown = false;
		boolean isTreeDrillDown = false;

		if (StringUtil.null2String(params.get("isApply")).equals("t"))
			isDrillDown = true;
		else
			isDrillDown = false;

		if (StringUtil.null2String(params.get("isTreeDrillDown")).equals("t"))
			isTreeDrillDown = true;
		else
			isTreeDrillDown = false;

		if (isTreeDrillDown) {
			resetIndex(graphInfo);
			resetDrillVector(graphInfo);
			graphInfo.setDrilldownRowPath("");
			graphInfo.setDrilldownColumnPath("");
		}

		if (isDrillDown && (!rowPath.equals("") || !colPath.equals(""))) {
			List<Object> drilldownColumn = getDrilldownColumnAndValues(graphInfo, rowPath, colPath, drillType);
			String[][] m_DrillDownColumns = (String[][]) drilldownColumn.get(0);
			Object[][] m_DrillDownValues = (Object[][]) drilldownColumn.get(1);
			rowPath = (String) drilldownColumn.get(2);
			colPath = (String) drilldownColumn.get(3);
			String colName = params.get("colName");
			String colValue = StringUtil.fromHexString(params.get("colValue"));
			String stype = params.get("type");

			if (colName != null && !colName.equals("")) {
				int zIndex = -1;
				int xIndex = -1;
				String zName = null;
				String xName = null;

				if ("1".equals(stype) && !isOnlyRowDrillDown(graphInfo)) 
				{
					zIndex = 0;
					zName = colValue;
				} else {
					xIndex = 0;
					xName = colValue;
				}

				DrillDownDetail drillDetail = new DrillDownDetail(zIndex, zName, xIndex, xName, 0, null);
				drillDown(drillDetail, graphInfo, loggedInUserInfo);
			} else {
				drillDown(m_DrillDownColumns, m_DrillDownValues, graphInfo, loggedInUserInfo);

				if (isTreeDrillDown) {
					CubeConditionList labelCondition = new CubeConditionList();
					for (int i = 0; i < m_DrillDownValues.length; i++) {
						for (int j = 0; j < m_DrillDownValues[i].length; j++)
							labelCondition.addElement(
									new CubeCondition(m_DrillDownColumns[i][j], true, m_DrillDownValues[i][j]));
					}
					setLabelConditionList(labelCondition);
				}
			}
			graphInfo.setDrilldownRowPath(rowPath);
			graphInfo.setDrilldownColumnPath(colPath);
		}
	}

	/**
	 * Gets column and column values which is drill down.
	 * 
	 * @param rowPath
	 *            the row path
	 * @param colPath
	 *            the column path
	 * @param drillType
	 *            the type of drill down
	 * @return ArrayList contains drill down columns and its values
	 */
	private List<Object> getDrilldownColumnAndValues(SmartenInfo graphInfo, String rowPath, String colPath,
			int drillType) {
		List<Object> drilldownColumn = new ArrayList<Object>();
		graphInfo.setCombinedPointOnGraph(drillType);
		String m_DrillDownColumns[][] = new String[][] { null, null };
		Object m_DrillDownValues[][] = new Object[][] { null, null };

		Vector vecColumnName1 = new Vector();
		Vector vecColumnValue1 = new Vector();
		Vector vecColumnName2 = new Vector();
		Vector vecColumnValue2 = new Vector();

		Vector rowPathVector = new Vector();
		Vector colPathVector = new Vector();

		StringTokenizer pathTokens = null;

		if (rowPath.equals("") && !graphInfo.getDrilldownRowPath().equals("")) {
			rowPath = graphInfo.getDrilldownRowPath();
		}

		String sColumn = "";
		pathTokens = new StringTokenizer(rowPath, "$~$");
		while (pathTokens.hasMoreTokens()) {
			sColumn = pathTokens.nextToken();
			if (sColumn.equals("@^@"))
				sColumn = " ";
			rowPathVector.addElement(sColumn);
		}

		if (colPath.equals("") && !graphInfo.getDrilldownColumnPath().equals("")) {
			colPath = graphInfo.getDrilldownColumnPath();
		}

		pathTokens = new StringTokenizer(colPath, "$~$");
		sColumn = "";
		while (pathTokens.hasMoreTokens()) {
			sColumn = pathTokens.nextToken();
			if (sColumn.equals("@^@"))
				sColumn = " ";
			colPathVector.addElement(sColumn);
		}

		String[] rowPathObject = (String[]) rowPathVector.toArray(new String[] {});
		String[] colPathObject = (String[]) colPathVector.toArray(new String[] {});

		Vector theRowColLabels = null;
		Vector theColColLabels = null;
		Vector theRowColLabels2 = null;
		theRowColLabels = graphInfo.getRowColumns();
		theColColLabels = graphInfo.getColColumns();

		if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH)
			theRowColLabels2 = graphInfo.getLineGraphRowLabelsForCombinedGraph();

		for (int i = 1; i < colPathObject.length; i++)
			vecColumnValue1.add(colPathObject[i]);

		if (theColColLabels != null && theColColLabels.size() > 0) {
			for (int i = 1; i < colPathObject.length + 1; i++)
				vecColumnName1.add(theColColLabels.elementAt(i - 1).toString());
		}

		int index = 0;

		for (int i = 1 + index; i < rowPathObject.length; i++)
			vecColumnValue2.add(rowPathObject[i]);

		if (rowPathObject.length >= 2 && (rowPathObject[0].contains("(Line)") || rowPathObject[0].contains("(Bar)"))) {

			int iBarOrLine = rowPathObject[0].contains("(Bar)") ? 0 : 1;
			for (int i = 1 + index; i < rowPathObject.length + 1; i++) {
				if (iBarOrLine == 0 && i <= theRowColLabels.size())
					vecColumnName2.add(theRowColLabels.elementAt(i - 1).toString());
				else if (i <= theRowColLabels2.size())
					vecColumnName2.add(theRowColLabels2.elementAt(i - 1).toString());
			}
		} else {
			for (int i = 1 + index; i < rowPathObject.length + 1; i++) {
				if (i <= theRowColLabels.size())
					vecColumnName2.add(theRowColLabels.elementAt(i - 1).toString());
				else if (theRowColLabels2 != null)
					vecColumnName2.add(theRowColLabels2.elementAt(i - 1 - theRowColLabels.size()).toString());
			}
		}
		m_DrillDownValues[0] = new Object[vecColumnValue2.size()];
		m_DrillDownColumns[0] = new String[vecColumnName2.size()];
		for (int i = 0; i < vecColumnName2.size(); i++)
			m_DrillDownColumns[0][i] = (vecColumnName2.elementAt(i)).toString();
		for (int i = 0; i < vecColumnValue2.size(); i++)
			m_DrillDownValues[0][i] = (Object) vecColumnValue2.elementAt(i);

		m_DrillDownValues[1] = new Object[vecColumnValue1.size()];
		m_DrillDownColumns[1] = new String[vecColumnName1.size()];
		for (int i = 0; i < vecColumnName1.size(); i++)
			m_DrillDownColumns[1][i] = (vecColumnName1.elementAt(i)).toString();
		for (int i = 0; i < vecColumnValue1.size(); i++)
			m_DrillDownValues[1][i] = (Object) vecColumnValue1.elementAt(i);

		drilldownColumn.add(m_DrillDownColumns);
		drilldownColumn.add(m_DrillDownValues);
		drilldownColumn.add(rowPath);
		drilldownColumn.add(colPath);

		return drilldownColumn;
	}

	/**
	 * Action to be taken on DrillDown Event when it is done using Tree.
	 * 
	 * @param columnNames
	 *            array of tree path column Names
	 * @param columnValues
	 *            array of tree path column Values
	 * @param graphInfo
	 *            Reference of graph with processed information
	 * @param userId
	 *            currently logged in user's identifier
	 * @throws RScriptException
	 */
	public void drillDown(String[][] columnNames, Object[][] columnValues, SmartenInfo graphInfo, UserInfo userInfo)
			throws MDXException, RealTimeCubeException, CubeException, RScriptException {

		String[][] drillColumns = new String[][] { null, null };
		Object[][] drillValues = new Object[][] { null, null };

		graphInfo.setDrillColumnsAll(columnNames);
		graphInfo.setDrillValuesAll(columnValues);

		Vector drillRootValues = new Vector();
		if (columnNames[0].length > 0) {
			drillColumns[0] = new String[columnNames[0].length - 1];
			for (int i = 0; i < drillColumns[0].length; i++) {
				drillColumns[0][i] = columnNames[0][i + 1];
			}
		}
		if (columnValues[0].length > 0) {
			drillRootValues.add(columnValues[0][0]);
			drillValues[0] = new Object[columnValues[0].length - 1];
			for (int i = 0; i < drillValues[0].length; i++) {
				drillValues[0][i] = columnValues[0][i + 1];
			}
		}
		if (columnNames[1].length > 0) {
			drillColumns[1] = new String[columnNames[1].length - 1];
			for (int i = 0; i < drillColumns[1].length; i++) {
				drillColumns[1][i] = columnNames[1][i + 1];
			}
		}
		if (columnValues[1].length > 0) {
			drillRootValues.add(columnValues[1][0]);
			drillValues[1] = new Object[columnValues[1].length - 1];
			for (int i = 0; i < drillValues[1].length; i++) {
				drillValues[1][i] = columnValues[1][i + 1];
			}
		}

		graphInfo.setDrillColumns(drillColumns);
		graphInfo.setDrillValues(drillValues);
		graphInfo.setDrillRootValues(drillRootValues);
		graphInfo.setBarDrilldownText("");
		graphInfo.setLegendDrilldownText("");
		graphInfo.setxAxisDrilldownText("");

		restoreAllLabelItems(graphInfo);

		DrillDownDetail drillDetail = null;

		if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
			drillDetail = setTreeDrillDownCombined(columnNames, columnValues, graphInfo);
		} else {
			drillDetail = setTreeDrillDown(columnNames, columnValues, graphInfo);
		}
		drillDown(drillDetail, true, true, graphInfo, userInfo, true);
	}

	/**
	 * Sets drill Down vector for drill up.
	 * 
	 * @param columnNames
	 *            array of tree path column Names
	 * @param columnValues
	 *            array of tree path column Values
	 * @return DrillDownDetail Object
	 * @throws CubeException
	 */
	private DrillDownDetail setTreeDrillDown(String[][] columnNames, Object[][] columnValues, SmartenInfo graphInfo)
			throws CubeException {

		DrillDownDetail firstdetail = null;
		boolean bFirst = true;
		int intLength = (int) Math.max(columnValues[0].length, columnValues[1].length);
		Vector<DrillDownDetail> drillDownDetailList = new Vector<DrillDownDetail>();
		Vector drillVector = new Vector();

		if (graphInfo.getDrillDownDetailList() != null) {
			graphInfo.getDrillDownDetailList().removeAllElements();
		} else {
			graphInfo.setDrillDownDetailList(new Vector());
		}
		if (graphInfo.getDrillVector() != null) {
			graphInfo.getDrillVector().removeAllElements();
		} else {
			graphInfo.setDrillVector(new Vector());
		}
		int rowIndex = 1;
		int colIndex = 1;

		for (int i = 0; i < intLength; i++) {

			int zIndex = -1;
			Object zName = null;
			int xIndex = -1;
			Object xName = null;
			int itemPos = -1;
			int seriesPos = -1;
			boolean bRowandColumn = false;

			if (graphInfo.getRowColumns().size() > 0 && graphInfo.getColColumns().size() == 0) {
				xIndex = getLabelPosition(Cube.ROW_LABEL, columnNames[0][i], columnValues[0][i].toString(), graphInfo)
						- 1;
				zName = columnValues[0][i].toString();
				itemPos = 1;
				rowIndex = i + 2;
			}

			if (graphInfo.getRowColumns().size() == 0 && graphInfo.getColColumns().size() > 0) {
				xIndex = getLabelPosition(Cube.COL_LABEL, columnNames[1][i], columnValues[1][i].toString(), graphInfo)
						- 1;
				xName = columnValues[1][i].toString();
				seriesPos = 1;
				colIndex = i + 2;
			}

			if (graphInfo.getRowColumns().size() > 0 && graphInfo.getColColumns().size() > 0) {
				if (i < columnValues[0].length) {
					zIndex = getLabelPosition(Cube.ROW_LABEL, columnNames[0][i], columnValues[0][i].toString(),
							graphInfo) - 1;
					zName = columnValues[0][i].toString();
					itemPos = 1;
					rowIndex = i + 2;
				}
				if (i < columnValues[1].length) {
					xIndex = getLabelPosition(Cube.COL_LABEL, columnNames[1][i], columnValues[1][i].toString(),
							graphInfo) - 1;
					xName = columnValues[1][i].toString();
					seriesPos = 1;
					colIndex = i + 2;
				}
				if (columnValues[0].length == 0) {
					rowIndex = 1;
				}
				if (columnValues[1].length == 0) {
					colIndex = 1;
				}
				if (i < columnValues[0].length && i < columnValues[1].length)
					bRowandColumn = true;
			}

			if (bRowandColumn) {

				DrillDownDetail drillDetail = new DrillDownDetail(itemPos, zName, -1, null, 0, null);
				drillDownDetailList.add(drillDetail);
				Vector record = new Vector();
				record.add(new Integer(rowIndex));
				record.add(new Integer(colIndex - 1));
				record.add(new Integer(-1));
				record.add(new Integer(1));
				drillVector.add(record);

				drillDetail = new DrillDownDetail(-1, null, seriesPos, xName, 0, null);
				drillDownDetailList.add(drillDetail);
				record = new Vector();
				record.add(new Integer(rowIndex));
				record.add(new Integer(colIndex));
				record.add(new Integer(1));
				record.add(new Integer(-1));
				drillVector.add(record);
			} else {
				DrillDownDetail drillDetail = new DrillDownDetail(itemPos, zName, seriesPos, xName, 0, null);
				drillDownDetailList.add(drillDetail);
				Vector record = new Vector();
				record.add(new Integer(rowIndex));
				record.add(new Integer(colIndex));
				record.add(new Integer(seriesPos));
				record.add(new Integer(itemPos));
				drillVector.add(record);
			}
			if (bFirst) {
				firstdetail = new DrillDownDetail(itemPos, zName, seriesPos, xName, 0, null);
				bFirst = false;
			}
		}
		if (rowIndex == 0) {
			rowIndex = 1;
		}
		if (colIndex == 0) {
			colIndex = 1;
		}
		if (rowIndex > 1) {
			rowIndex--;
		}
		if (colIndex > 1) {
			colIndex--;
		}
		graphInfo.setRowIndex(rowIndex);
		graphInfo.setColIndex(colIndex);
		graphInfo.setDrillDownDetailList(drillDownDetailList);
		graphInfo.setDrillVector(drillVector);
		return firstdetail;
	}

	/**
	 * Sets drill Down vector for drill up.
	 * 
	 * @param columnNames
	 *            array of tree path column Names
	 * @param columnValues
	 *            array of tree path column Values
	 * @return DrillDownDetail Object
	 * @throws CubeException
	 */

	private DrillDownDetail setTreeDrillDownCombined(String[][] columnNames, Object[][] columnValues,
			SmartenInfo graphInfo) throws CubeException {

		DrillDownDetail firstdetail = null;
		boolean bFirst = true;
		int intLength = (int) Math.max(columnValues[0].length, columnValues[1].length);
		Vector<DrillDownDetail> drillDownDetailList = new Vector<DrillDownDetail>();
		Vector drillVectorForCombined = new Vector();
		Vector rowVectorDrillDownInfoForCombinedGraph = new Vector();

		if (graphInfo.getDrillDownDetailList() != null) {
			graphInfo.getDrillDownDetailList().removeAllElements();
		} else {
			graphInfo.setDrillDownDetailList(new Vector());
		}
		if (graphInfo.getRowVectorDrillDownInfoForCombinedGraph() != null) {
			graphInfo.getRowVectorDrillDownInfoForCombinedGraph().removeAllElements();
		} else {
			graphInfo.setRowVectorDrillDownInfoForCombinedGraph(new Vector());
		}
		if (graphInfo.getDrillVectorForCombined() != null) {
			graphInfo.getDrillVectorForCombined().removeAllElements();
		} else {
			graphInfo.setDrillVectorForCombined(new Vector());
		}

		int rowIndex = 1;
		int colIndex = 1;
		int rowIndexForLineGraphInCombinedGraph = 1;

		for (int i = 0; i < intLength; i++) {
			int zIndex = -1;
			Object zName = null;
			int xIndex = -1;
			Object xName = null;
			int itemPos = -1;
			int seriesPos = -1;

			boolean bRowandColumn = false;
			if (graphInfo.getCombinedPointOnGraph() == 0) { 
				if (graphInfo.getRowColumns().size() > 0 && graphInfo.getColColumns().size() == 0) {
					xIndex = getLabelPosition(Cube.ROW_LABEL, columnNames[0][i], columnValues[0][i].toString(),
							graphInfo) - 1;
					xName = columnValues[0][i].toString();
					itemPos = 1;
					rowIndex = i + 2;
				}
			} else {
				if (graphInfo.getLineGraphRowLabelsForCombinedGraph().size() > 0
						&& graphInfo.getColColumns().size() == 0) {
					xIndex = getLabelPosition(Cube.ROW_LABEL, columnNames[0][i], columnValues[0][i].toString(),
							graphInfo) - 1;
					xName = columnValues[0][i].toString();
					itemPos = 1;
					rowIndexForLineGraphInCombinedGraph = i + 2;
				}
			}

			if (graphInfo.getRowColumns().size() == 0 && graphInfo.getLineGraphRowLabelsForCombinedGraph().size() == 0
					&& graphInfo.getColColumns().size() > 0) {
				xIndex = getLabelPosition(Cube.COL_LABEL, columnNames[1][i], columnValues[1][i].toString(), graphInfo)
						- 1;
				xName = columnValues[1][i].toString();
				seriesPos = 1;
				colIndex = i + 2;
			}

			if (graphInfo.getRowColumns().size() > 0 || graphInfo.getLineGraphRowLabelsForCombinedGraph().size() > 0) {

				if (i < columnValues[0].length) {
					if (graphInfo.getCombinedPointOnGraph() == 0)
						rowVectorDrillDownInfoForCombinedGraph.add(0);
					else
						rowVectorDrillDownInfoForCombinedGraph.add(1);
				}
			}

			if ((graphInfo.getRowColumns().size() > 0 || graphInfo.getLineGraphRowLabelsForCombinedGraph().size() > 0)
					&& graphInfo.getColColumns().size() > 0) {
				if (graphInfo.getCombinedPointOnGraph() == 0) {
					if (i < columnValues[0].length) {
						zIndex = getLabelPosition(Cube.ROW_LABEL, columnNames[0][i], columnValues[0][i].toString(),
								graphInfo) - 1;
						zName = columnValues[0][i].toString();
						itemPos = 1;
						rowIndex = i + 2;
					}
				} else {
					if (i < columnValues[0].length) {
						zIndex = getLabelPosition(Cube.ROW_LABEL, columnNames[0][i], columnValues[0][i].toString(),
								graphInfo) - 1;
						zName = columnValues[0][i].toString();
						itemPos = 1;
						rowIndexForLineGraphInCombinedGraph = i + 2;
					}
				}
				if (i < columnValues[1].length) {
					xIndex = getLabelPosition(Cube.COL_LABEL, columnNames[1][i], columnValues[1][i].toString(),
							graphInfo) - 1;
					xName = columnValues[1][i].toString();
					seriesPos = 1;
					colIndex = i + 2;
				}
				if (columnValues[0].length == 0) {
					rowIndex = 1;
					rowIndexForLineGraphInCombinedGraph = 1;
				}
				if (columnValues[1].length == 0) {
					colIndex = 1;
				}
			}
			if (i < columnValues[0].length && i < columnValues[1].length)
				bRowandColumn = true;

			if (bRowandColumn) {

				DrillDownDetail drillDetail = new DrillDownDetail(itemPos, zName, -1, null, 0, null);
				drillDownDetailList.add(drillDetail);
				Vector record = new Vector();
				record.add(new Integer(rowIndex));
				record.add(new Integer(rowIndexForLineGraphInCombinedGraph));
				record.add(new Integer(colIndex - 1));
				record.add(new Integer(-1));
				record.add(new Integer(1));
				drillVectorForCombined.add(record);


				drillDetail = new DrillDownDetail(-1, null, seriesPos, xName, 0, null);
				drillDownDetailList.add(drillDetail);
				record = new Vector();
				record.add(new Integer(rowIndex));
				record.add(new Integer(rowIndexForLineGraphInCombinedGraph));
				record.add(new Integer(colIndex));
				record.add(new Integer(1));
				record.add(new Integer(-1));
				drillVectorForCombined.add(record);
			} else {
				DrillDownDetail drillDetail = new DrillDownDetail(itemPos, zName, seriesPos, xName, 0, null);
				drillDownDetailList.add(drillDetail);
				Vector record = new Vector();
				record.add(new Integer(rowIndex));
				record.add(new Integer(rowIndexForLineGraphInCombinedGraph));
				record.add(new Integer(colIndex));
				record.add(new Integer(seriesPos));
				record.add(new Integer(itemPos));
				drillVectorForCombined.add(record);
			}
			if (bFirst) {
				firstdetail = new DrillDownDetail(itemPos, zName, seriesPos, xName, 0, null);
				bFirst = false;
			}
		}
		if (rowIndex == 0) {
			rowIndex = 1;
		}
		if (rowIndexForLineGraphInCombinedGraph == 0) {
			rowIndexForLineGraphInCombinedGraph = 1;
		}
		if (colIndex == 0) {
			colIndex = 1;
		}
		if (rowIndex > 1) {
			rowIndex--;
		}
		if (rowIndexForLineGraphInCombinedGraph > 1) {
			rowIndexForLineGraphInCombinedGraph--;
		}
		if (colIndex > 1) {
			colIndex--;
		}

		graphInfo.setDrillDownDetailList(drillDownDetailList);
		graphInfo.setDrillVectorForCombined(drillVectorForCombined);
		graphInfo.setRowIndex(rowIndex);
		graphInfo.setColIndex(colIndex);
		graphInfo.setRowIndexForLineGraphInCombinedGraph(rowIndexForLineGraphInCombinedGraph);
		graphInfo.setRowVectorDrillDownInfoForCombinedGraph(rowVectorDrillDownInfoForCombinedGraph);

		return firstdetail;
	}

	/**
	 * Action to be taken on DrillDown Event.
	 * 
	 * @param cdetail
	 *            DrillDownEvent
	 * @param graphInfo
	 *            Reference of graph with processed information
	 * @param userId
	 *            currently logged in user's identifier
	 */
	public void drillDown(DrillDownDetail cdetail, SmartenInfo graphInfo, UserInfo userInfo) {
		drillDown(cdetail, false, graphInfo, userInfo);
	}

	/**
	 * Action to be taken on DrillDown Event.
	 * 
	 * @param cdetail
	 *            DrillDownEvent
	 * @param bDrilledFromRoot
	 *            DrillDownEvent is done by tree or by click on graph or legend
	 * @param graphInfo
	 *            Reference of graph with processed information
	 * @param userId
	 *            currently logged in user's identifier
	 */
	private void drillDown(DrillDownDetail cdetail, boolean bDrilledFromRoot, SmartenInfo graphInfo, UserInfo userInfo) {
		drillDown(cdetail, bDrilledFromRoot, false, graphInfo, userInfo, false);
	}

	/**
	 * Action to be taken on DrillDown Event.
	 * 
	 * @param cdetail
	 *            DrillDownEvent
	 * @param bDrilledFromRoot
	 *            DrillDownEvent is done by tree or by click on graph or legend
	 * @param isRefReq
	 *            true if Refresh required
	 * @param graphInfo
	 *            Reference of graph with processed information
	 * @param userId
	 *            currently logged in user's identifier
	 */
	private void drillDown(DrillDownDetail cdetail, boolean bDrilledFromRoot, boolean isRefReq, SmartenInfo graphInfo,
			UserInfo userInfo, boolean isTreeDrillDown) {
		if (!bDrilledFromRoot) {
			graphInfo.setDrillColumns(new String[][] { null, null });
			graphInfo.setDrillValues(new Object[][] { null, null });

			if (!(graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH)) {
				graphInfo.getDrillDownDetailList().addElement(cdetail);
			}
		}

		if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
			drillDownCombined(cdetail, bDrilledFromRoot, graphInfo, userInfo, isTreeDrillDown);
			return;
		}

		int itemIndex = cdetail.getDrilledItemIndex();
		int seriesIndex = cdetail.getDrilledSeriesIndex();

		String seriesName = "", itemName = "";
		Object obj;

		obj = cdetail.getDrilledSeriesName();
		if (obj != null) {
			seriesName = obj.toString();
		}
		obj = cdetail.getDrilledItemName();
		if (obj != null) {
			itemName = obj.toString();

		}

		if (graphInfo.getColColumns().size() < 1 && !isTreeDrillDown) {
			itemIndex = seriesIndex;
			itemName = seriesName;
			seriesIndex = -1;
			seriesName = null;
		}

		int m_rowIndex = graphInfo.getRowIndex();
		int m_colIndex = graphInfo.getColIndex();
		int m_seriesPos = graphInfo.getSeriesPos();
		int m_itemPos = graphInfo.getItemPos();

		String barText = graphInfo.getBarDrilldownText();
		String zText = graphInfo.getLegendDrilldownText();
		String xText = graphInfo.getxAxisDrilldownText();

		Object[][] m_DrillValues = graphInfo.getDrillValues();

		Vector vDrillDownX = graphInfo.getDrillDownListOfX();
		Vector vDrillDownZ = graphInfo.getDrillDownListOfZ();

		if (itemIndex != -1 && seriesIndex != -1) 
		{
			graphInfo.setDrillDownItemString(itemName);
			graphInfo.setDrillDownSeriesLabel(seriesName);

			vDrillDownX.addElement(seriesName);
			vDrillDownZ.addElement(itemName);
			if (bDrilledFromRoot) {
				int intLength = m_DrillValues[0].length > m_DrillValues[1].length ? m_DrillValues[0].length
						: m_DrillValues[1].length;

				barText = graphInfo.getDrillRootValues().elementAt(1).toString() + ", "
						+ graphInfo.getDrillRootValues().elementAt(0).toString();

				for (int i = 0; i < intLength; i++) {
					barText += " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " ";
					String xTemp = "";
					String zTemp = "";
					if (i < m_DrillValues[0].length) {
						xTemp = m_DrillValues[0][i].toString();
						vDrillDownZ.addElement(xTemp);
					}
					if (i < m_DrillValues[1].length) {
						zTemp = m_DrillValues[1][i].toString();
						vDrillDownX.addElement(zTemp);
					}
					if (xTemp.equals("") || zTemp.equals("")) {
						barText += "" + zTemp + xTemp + "";
					} else {
						barText += "" + zTemp + ", " + xTemp + "";
					}

				}
			} else {
				String sTemp = "";

				if (barText.equals("") || barText == null) {
					if (seriesName!=null && seriesName.equals("") || itemName.equals("")) {
						barText = "" + seriesName + itemName + "";
					} else {
						barText = "" + seriesName + ", " + itemName + "";

					}
				} else {
					if (seriesName!=null && seriesName.equals("") || itemName.equals("")) {
						sTemp = "" + seriesName + itemName + "";
					} else {
						sTemp = "" + seriesName + ", " + itemName + "";
					}

					barText += " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + sTemp;
				}

				if (!(zText.equals("") || zText == null)) {
					barText = zText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + barText;
					zText = "";
				}
				if (!(xText.equals("") || xText == null)) {
					barText = xText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + barText;
					xText = "";
				}

			}

			if (m_rowIndex > 0 && m_colIndex > 0) {
				if (m_rowIndex + 1 <= graphInfo.getRowColumns().size()
						|| m_colIndex + 1 <= graphInfo.getColColumns().size()) {
					m_seriesPos = -1;
					m_itemPos = -1;
					
					if (m_rowIndex + 1 <= graphInfo.getRowColumns().size()) {
						m_rowIndex = m_rowIndex + 1;
						m_itemPos = itemIndex + 1;
					}
					if (m_colIndex + 1 <= graphInfo.getColColumns().size()) {
						m_colIndex = m_colIndex + 1;
						m_seriesPos = seriesIndex + 1;
					}

					graphInfo.setRowIndex(m_rowIndex);
					graphInfo.setColIndex(m_colIndex);
					graphInfo.setSeriesPos(m_seriesPos);
					graphInfo.setItemPos(m_itemPos);

					graphInfo.setDrillUpOperation(false);

					boolean isGraphSet = setGraph(false, graphInfo, userInfo);
					if (isRefReq || isGraphSet) // if successfully set Graph
					{
						resetErrorMessage(graphInfo);

						if (!bDrilledFromRoot) {
							setDrillDown(graphInfo);
						}

					}
				}
			}
		} else if (itemIndex != -1 && seriesIndex == -1) 
		{
			graphInfo.setDrillDownItemString(itemName);
			vDrillDownZ.addElement(itemName);
			if (bDrilledFromRoot) {
				int intLength = m_DrillValues[0].length;

				zText = graphInfo.getDrillRootValues().elementAt(0).toString();
				for (int i = 0; i < intLength; i++) {
					String xTemp = "";
					xTemp = m_DrillValues[0][i].toString();
					zText += " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + xTemp + "";
					vDrillDownZ.addElement(xTemp);
				}
			} else {
				if (zText.equals("") || zText == null) {
					zText = itemName;
				} else {
					zText += " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + itemName;
				}

				if (!(barText.equals("") || barText == null)) {
					zText = barText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + zText;
					barText = "";
				}
				if (!(xText.equals("") || xText == null)) {
					zText = xText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + zText;
					xText = "";
				}
			}

			if (m_rowIndex > 0) {
				if (m_rowIndex + 1 <= graphInfo.getRowColumns().size()) {
					
					m_rowIndex = m_rowIndex + 1;
					m_seriesPos = -1;
					m_itemPos = itemIndex + 1;

					graphInfo.setRowIndex(m_rowIndex);
					graphInfo.setColIndex(m_colIndex);
					graphInfo.setSeriesPos(m_seriesPos);
					graphInfo.setItemPos(m_itemPos);

					graphInfo.setDrillUpOperation(false);

					boolean isGraphSet = setGraph(false, graphInfo, userInfo);
					if (!isGraphSet) 
					{
						if (!bDrilledFromRoot) { 
							setDrillDown(graphInfo);
						}
					} else
					{
						resetErrorMessage(graphInfo);

						if (!bDrilledFromRoot) {
							setDrillDown(graphInfo);
						}

					}
				}
			}

		} else if (itemIndex == -1 && seriesIndex != -1) 
		{
			graphInfo.setDrillDownSeriesLabel(seriesName);

			vDrillDownX.addElement(seriesName);

			if (bDrilledFromRoot) {
				int intLength = m_DrillValues[1].length;

				xText = graphInfo.getDrillRootValues().elementAt(0).toString();
				for (int i = 0; i < intLength; i++) {
					String xTemp = "";
					xTemp = m_DrillValues[1][i].toString();
					xText += " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + xTemp + "";
					vDrillDownX.addElement(xTemp);
				}
			} else {
				if (xText.equals("") || xText == null) {
					xText = seriesName;
				} else {
					xText += " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + seriesName;
				}
				if (!(barText.equals("") || barText == null)) {
					xText = barText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + xText;
					barText = "";
				}
				if (!(zText.equals("") || zText == null)) {
					xText = zText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + xText;
					zText = "";
				}
			}

			if (m_colIndex > 0) {
				if (m_colIndex + 1 <= graphInfo.getColColumns().size()) {

					m_colIndex = m_colIndex + 1;
					m_seriesPos = seriesIndex + 1;
					m_itemPos = -1;

					graphInfo.setRowIndex(m_rowIndex);
					graphInfo.setColIndex(m_colIndex);
					graphInfo.setSeriesPos(m_seriesPos);
					graphInfo.setItemPos(m_itemPos);

					graphInfo.setDrillUpOperation(false);

					boolean isGraphSet = setGraph(false, graphInfo, userInfo);
					if (isRefReq || isGraphSet)
					{
						resetErrorMessage(graphInfo);
						if (!bDrilledFromRoot) {
							setDrillDown(graphInfo);
						}

					} else {
						if (!bDrilledFromRoot) { 
							setDrillDown(graphInfo);
						}
					}
				}
			}

		} else if (itemIndex == -1 && seriesIndex == -1) 
		{
		}

		graphInfo.setBarDrilldownText(barText);
		graphInfo.setLegendDrilldownText(zText);
		graphInfo.setxAxisDrilldownText(xText);

		graphInfo.setDrillDownListOfX(vDrillDownX);
		graphInfo.setDrillDownListOfZ(vDrillDownZ);
	}

	/**
	 * Sets Drill Down data for Graph.
	 */
	private void setDrillDown(SmartenInfo graphInfo) {
		if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
			setDrillDownCombined(graphInfo);
			return;
		}

		Vector m_drillVector = graphInfo.getDrillVector();

		if (m_drillVector == null) {
			m_drillVector = new Vector();
		}

		Vector<Integer> record = new Vector<Integer>();

		record.add(graphInfo.getRowIndex());
		record.add(graphInfo.getColIndex());
		record.add(graphInfo.getSeriesPos());
		record.add(graphInfo.getItemPos());

		m_drillVector.add(record);

		graphInfo.setDrillVector(m_drillVector);
	}

	/**
	 * Gets flag to check only row is available in rayouter.
	 * 
	 * @return True if only row is drill down otherwise false
	 */
	private boolean isOnlyRowDrillDown(SmartenInfo graphInfo) {
		if (graphInfo.getColColumns() == null || graphInfo.getColColumns().size() == 0) {
			if (graphInfo.getRowColumns() != null && graphInfo.getRowColumns().size() > 1) {
				return true;
			}
		}

		return false;
	}

	/**
	 * Remove Error message from Graph Dialog and set Graph.
	 */
	private void resetErrorMessage(SmartenInfo graphInfo) {
		if (graphInfo.isGraphVisible()) {
			return;
		}

		graphInfo.setGraphVisible(true);
	}

	public void restoreAllLabelItems(SmartenInfo graphInfo)
			throws MDXException, RealTimeCubeException, CubeException, RScriptException {
		if (graphCube == null) {
			throw new CubeException(ResourceManager.getString("MSG_TEXT_CUBE_NOT_FORMED",
					new Object[] { this.graphDisplayName, this.cubeDisplayName }));
		}

		try {
			graphCube.restoreAllLabelItems();
		} catch (MDXException e) {
			throw e;
		} catch (RealTimeCubeException e) {
			throw e;
		} catch (CubeException e) {
			String graphMode = (graphInfo.getGraphMode() == AppConstants.NEW_MODE) ? "New" : "Open";
			ApplicationLog.error(ResourceManager.getString("LOG_ERROR_FAILED_TO_RESTORE_ALL_LABEL_ITEMS",
					new Object[] { graphInfo.getGraphName(), graphMode }), e);

			throw e;
		}
	}

	/**
	 * To get data format and dimension map from cube.
	 * 
	 * @param inCube
	 *            object of Cube
	 * @throws CubeException
	 * @throws DatabaseOperationException
	 */
	private void setDataFormatAndMapFromCube(SmartenInfo graphInfo, UserInfo userInfo)
			throws CubeException, DatabaseOperationException {
		Vector theRowColLabels = graphInfo.getRowColumns();
		if(graphInfo.getGraphType() == SmartenConstants.SMARTENVIEW_MAP)
		{
			theRowColLabels = new Vector();
			theRowColLabels.add(graphInfo.getGeoColumnName());
		}
		Vector theColColLabels = graphInfo.getColColumns();
		Vector<CubeColumnInfo> theDataColInfoList = graphInfo.getDataColumnInfoList();
		Vector theRowColLabels2 = graphInfo.getLineGraphRowLabelsForCombinedGraph();

		Hashtable dimMapTable = graphOrgCube.getDimensionMap();

		if (dimMapTable.size() > 0) {
			Vector vecRowColumns = getSysGenDimVector(theRowColLabels, theColColLabels, dimMapTable, graphInfo);

			if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
				Vector temp = (Vector) vecRowColumns.elementAt(1);
				boolean flag = false;
				if (theRowColLabels2.size() > 0) {
					for (int i = 0; i < temp.size(); i++) {
						if (temp.get(i).toString().equals(theRowColLabels2.get(0).toString())) {
							flag = true;
						}
					}

				}
				if (flag) {
					vecRowColumns = getSysGenDimVector(theRowColLabels, theRowColLabels2, dimMapTable, graphInfo);
				}
			}

			theRowColLabels.removeAllElements();
			theRowColLabels = (Vector) vecRowColumns.elementAt(0);
			graphInfo.setSysGeneratedRowLabels((Vector) vecRowColumns.elementAt(1));

			Vector vecColColumns = getSysGenDimVector(theColColLabels, theRowColLabels, dimMapTable, graphInfo);

			theColColLabels.removeAllElements();
			theColColLabels = (Vector) vecColColumns.elementAt(0);
			graphInfo.setSysGeneratedColumnLabels((Vector) vecColColumns.elementAt(1));

			if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
				Vector vecRowColumns2 = getSysGenDimVector(theRowColLabels2, theColColLabels, dimMapTable, graphInfo);

				Vector temp = (Vector) vecRowColumns2.elementAt(1);
				boolean flag = false;
				if (theRowColLabels.size() > 0) {
					for (int i = 0; i < temp.size(); i++) {
						if (temp.get(i).toString().equals(theRowColLabels.get(0).toString())) {
							flag = true;
						}
					}

				}
				if (flag) {
					vecRowColumns2 = getSysGenDimVector(theRowColLabels2, theRowColLabels, dimMapTable, graphInfo);
				}

				theRowColLabels2.removeAllElements();
				theRowColLabels2 = (Vector) vecRowColumns2.elementAt(0);
				graphInfo.setSysGeneratedRowLabelsForLineGraph((Vector) vecRowColumns2.elementAt(1));
			}
		}

		boolean isMapNull = false;
		boolean isFormatNull = false;

		if (getActiveDDVMs(graphInfo, userInfo.getUserId()) == null) {
			isMapNull = true;
		}

		Hashtable<String, Vector<Object>> m_dataFormat = null;

		if (graphInfo.getColumnFormat() == null) {
			isFormatNull = true;
			m_dataFormat = new Hashtable<String, Vector<Object>>();
		}

		Hashtable<String, Integer> m_colType = new Hashtable<String, Integer>();

		if (isMapNull || isFormatNull) {
			ICubeResultSetMetaData icubeMetaData;
			try {
				icubeMetaData = graphOrgCube.getOriginalResultSetMetaData();
			} catch (CubeException e) {
				ApplicationLog.error(ResourceManager.getString("LOG_ERROR_MSG_FAILED_TO_GET_ORG_RESULTSET_METADATA",
						new Object[] { graphOrgCube.getName() }), e);

				throw e;
			}
			CubeColumnInfo cubeColumnInfo = null;
			for (int iIndex = 1; iIndex <= icubeMetaData.getColumnCount(); iIndex++) {
				cubeColumnInfo = icubeMetaData.getColumn(iIndex);

				m_colType.put(cubeColumnInfo.getName(), new Integer(cubeColumnInfo.getType()));

				if (isFormatNull) {
					
					switch (cubeColumnInfo.getType()) {
					case Types.DATE:
					case Types.TIME:
					case Types.TIMESTAMP:
						Vector dateData = new Vector();
						dateData.add(new Integer(DATE_FORMAT)); 

						String dateFormat = userManagementServiceUtil.getUserDateDisplayFormat(userInfo.getUserId(),
								Types.DATE);
						String timeFormat = userManagementServiceUtil.getUserDateDisplayFormat(userInfo.getUserId(),
								Types.TIME);

						if (dateFormat == null) {
							dateFormat = "";
						}

						if (timeFormat == null) {
							timeFormat = "";
						}

						dateData.add(dateFormat); 
						dateData.add(timeFormat); 

						m_dataFormat.put(cubeColumnInfo.getName(), dateData);
						break;
					case Types.DOUBLE:
					case Types.FLOAT:
					case Types.SMALLINT:
					case Types.TINYINT:
					case Types.INTEGER:
					case Types.BIGINT:
					case Types.DECIMAL:
					case Types.NUMERIC:
					case Types.REAL:
						Vector<Object> data = new Vector<Object>();

						data.add(new Integer(NUMBER_FORMAT)); 
						data.add(new Integer(0)); 
						data.add(new Integer(0)); 
						data.add(new Boolean(false)); 
						data.add(new String("")); 
						data.add(new Boolean(false)); 
						data.add(new Boolean(false)); 

						m_dataFormat.put(cubeColumnInfo.getName(), data);
						break;
					}
				}
			}
			cubeColumnInfo = null;
			icubeMetaData = null;

			CubeVector userDataColumnInfo = graphOrgCube.getUserColumnInfoList();

			try {
				userDataColumnInfo = graphOrgCube.prepareUserColumnInfoList(userDataColumnInfo,
						graphOrgCube.getDataColumnInfoList(), new HashMap(), new HashMap(), new CubeVector(), new HashMap(),
						new HashMap(), new CubeVector());
			} catch (DatabaseOperationException e) {
				ApplicationLog.error(e);

				throw e;
			}

			userDataColumnInfo = graphOrgCube.prepareDataColumnInfoList(userDataColumnInfo);

			CubeDataColumnInfo cubeDataColumnInfo = null;
			for (int cnt = 0; cnt < userDataColumnInfo.size(); cnt++) {
				cubeDataColumnInfo = (CubeDataColumnInfo) userDataColumnInfo.get(cnt);

				m_colType.put(cubeDataColumnInfo.getName(), new Integer(cubeDataColumnInfo.getType()));

				if (isFormatNull) {
					
					switch (cubeDataColumnInfo.getType()) {
					case Types.DATE:
					case Types.TIME:
					case Types.TIMESTAMP:
						Vector<Object> dateData = new Vector<Object>();
						dateData.add(new Integer(DATE_FORMAT)); 
						dateData.add(new String("")); 
						dateData.add(new String("")); 

						m_dataFormat.put(cubeDataColumnInfo.getName(), dateData);
						break;
					case Types.DOUBLE:
					case Types.FLOAT:
					case Types.SMALLINT:
					case Types.TINYINT:
					case Types.INTEGER:
					case Types.BIGINT:
					case Types.DECIMAL:
					case Types.NUMERIC:
					case Types.REAL:
						Vector<Object> data = new Vector<Object>();

						data.add(new Integer(NUMBER_FORMAT)); 
						data.add(new Integer(0)); 
						data.add(new Integer(0)); 
						data.add(new Boolean(false)); 
						data.add(new String("")); 
						data.add(new Boolean(false)); 
						data.add(new Boolean(false)); 

						m_dataFormat.put(cubeDataColumnInfo.getName(), data);
						break;
					}
				}
			}

			for (int iCnt = 0; iCnt < theDataColInfoList.size(); iCnt++) {
				cubeColumnInfo = (CubeColumnInfo) theDataColInfoList.elementAt(iCnt);

				if (!cubeColumnInfo.getSourceName().equals(cubeColumnInfo.getName())) {
					Vector<Object> data = new Vector<Object>();

					data.add(new Integer(NUMBER_FORMAT)); 
					data.add(new Integer(0)); 
					data.add(new Integer(0)); 
					data.add(new Boolean(false)); 
					data.add(new String("")); 
					data.add(new Boolean(false)); 
					data.add(new Boolean(false)); 

					m_dataFormat.put(cubeColumnInfo.getName(), data);
				}
			}
			cubeColumnInfo = null;
		}

		graphInfo.setColumnType(m_colType);

		graphInfo.setRowColumns(theRowColLabels);
		graphInfo.setColColumns(theColColLabels);
		graphInfo.setLineGraphRowLabelsForCombinedGraph(theRowColLabels2);

	}

	/**
	 * Gets drill down path.
	 * 
	 * @param graph
	 *            the GraphExPanel object
	 * @param sForShortCut
	 *            sets parameter to decide whether it is open from file
	 * @param isHomePage
	 *            sets parameter to decide whether it is from graph or dashboard
	 * @param saveDashBoard
	 *            true if dashboard is saved otherwise false
	 * @param sCmd
	 *            the command for graph
	 * @param firstTime
	 *            sets parameter to decide whether it is first time or not
	 * @return Drill down path
	 * @throws CubeException
	 */
	private List<Object> getDrillDownPath(SmartenInfo graphInfo, String sForShortCut, String isHomePage,
			String saveDashBoard, String sCmd, String firstTime, String sObjName, String std_id) throws CubeException {
		String dPath = "";

		boolean bOnlyRowDrillDown = isOnlyRowDrillDown(graphInfo);

		Vector theRowLabelList = new Vector();
		Vector theColLabelList = new Vector();
		Vector theRowLabelList2 = new Vector();

		List<Object> drillDownItemsForBreadcrumb = new ArrayList<Object>();
		Map<String, List<List<String>>> breadcrumbItemMap = new LinkedHashMap<String, List<List<String>>>();

		int rowLabelValueIndex = bOnlyRowDrillDown ? 1 : 0;
		int colLabelValueIndex = bOnlyRowDrillDown ? 0 : 1;

		if (!isDrillUpPossible(graphInfo)) {
			graphInfo.setDrilldownRowPath("");
			graphInfo.setDrilldownColumnPath("");
		}

		boolean isFirstCboVisible = false;
		boolean isSecondCboVisible = false;
		boolean isXpathVisible = false;
		boolean isZpathVisible = false;
		String cValue = "";

		HashtableEx ddvmList = getActiveDDVMs(graphInfo, getLoggedInUserId());
		setPackDDVMInfo(graphInfo, ddvmList);
		Vector theColLabels = graphInfo.getColColumns();
		Vector theRowLabels = graphInfo.getRowColumns();
		Vector theRowLabels2 = graphInfo.getLineGraphRowLabelsForCombinedGraph();

		Vector vXpath = graphInfo.getDrillDownListOfX();
		String sXPath = ResourceManager.getString("MSG_TEXT_COLUMN_COLUMNS");
		Vector vXpathTemp = new Vector();
		for (int i = 0; i < vXpath.size(); i++) {
			if (i == 0)
				vXpathTemp.add(vXpath.get(i));
			else {
				if (!vXpathTemp.contains(vXpath.get(i)))
					vXpathTemp.add(vXpath.get(i));
			}
		}
		vXpath.clear();
		vXpath.addAll(vXpathTemp);

		if (vXpath != null && vXpath.size() > 0) {
			List<List<String>> colDrilldownItems = new ArrayList<List<String>>();

			List<String> drillUpLinkElement = new ArrayList<String>();

			drillUpLinkElement.add(ResourceManager.getString("MSG_TEXT_COLUMN_COLUMNS"));

			for (int i = 0; i < vXpath.size(); i++) {

				String ddvmKey = "";
				String value = vXpath.elementAt(i).toString();
				if (theColLabels != null && theColLabels.size() >= i)
					ddvmKey = (String) theColLabels.get(i);

				value = GeneralFiltersUtil.formatConditionValues(graphInfo.getCubeInfo(), value,
						getOriginalResultSetMetaData(), ddvmKey, false);

				Vector colDDVM = (Vector) ddvmList.get(ddvmKey);

				if (colDDVM != null && colDDVM.size() > 0) {
					for (int index = 0; index < colDDVM.size(); index++) {
						String[] element = (String[]) colDDVM.get(index);
						if (element[0].equals(value)) {
							value = element[1];
							break;
						}
					}
				}

				if (!sXPath.equals(vXpath.elementAt(i).toString())) {
					sXPath += getDrillUpParameters(ddvmKey, -1, i + 1, 0, isHomePage, sObjName, std_id) + " >> </a>"
							+ value;
					if (!isXpathVisible)
						isXpathVisible = true;

					drillUpLinkElement
							.add(drillUpItemLinkForBraedcrumb(ddvmKey, -1, i + 1, 0, isHomePage, sObjName, std_id));

					colDrilldownItems.add(drillUpLinkElement);

					drillUpLinkElement = new ArrayList<String>();
					drillUpLinkElement.add(value);
				}
			}

			colDrilldownItems.add(drillUpLinkElement);

			breadcrumbItemMap.put(ResourceManager.getString("MSG_TEXT_COLUMN_COLUMNS"), colDrilldownItems);
		}

		if (vXpath.size() == 0)
			sXPath = "";

		boolean colDrilldownPossibleFlag = isColDrillDownPosible(graphInfo);

		if (sXPath.endsWith(SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR) && !colDrilldownPossibleFlag
				&& sXPath.length() > 2)
			sXPath = sXPath.substring(0, sXPath.length() - 1);

		dPath = dPath + "  " + sXPath;
		Vector vZpath = graphInfo.getDrillDownListOfZ();
		Vector vecRowDrillDownInfo = graphInfo.getRowVectorDrillDownInfoForCombinedGraph();
		String sRow = ResourceManager.getString("MSG_TEXT_ROW_COLUMNS");
		String sZPath = sRow;
		String sZPath1 = "";
		String sZPath2 = "";
		boolean bCombinedGraph = false;
		int index, index1, index2;
		index = index1 = index2 = 0;

		if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
			bCombinedGraph = true;
		}
		Vector vZpathTemp = new Vector();
		for (int i = 0; i < vZpath.size(); i++) {
			if (i == 0)
				vZpathTemp.add(vZpath.get(i));
			else {
				if (!vZpathTemp.contains(vZpath.get(i)))
					vZpathTemp.add(vZpath.get(i));
			}
		}
		vZpath.clear();
		vZpath.addAll(vZpathTemp);
		if (vZpath != null && vZpath.size() > 0) {
			List<List<String>> rowDrilldownItems = new ArrayList<List<String>>();

			List<String> drillUpLinkElement = new ArrayList<String>();

			drillUpLinkElement.add(ResourceManager.getString("MSG_TEXT_ROW_COLUMNS"));

			boolean labelUpdatedFlagForBar = false;
			boolean labelUpdatedFlagForLine = false;

			for (int i = 0; i < vZpath.size(); i++) {
				String ddvmKey = "";
				String value = vZpath.elementAt(i).toString();

				if (bCombinedGraph) {

					if (vecRowDrillDownInfo != null && vecRowDrillDownInfo.size() > 0) {

						if ((Integer) vecRowDrillDownInfo.get(i) == 0) {
							if (theRowLabels != null && theRowLabels.size() >= index1)
								ddvmKey = (String) theRowLabels.get(index1);
							index = index1++;
						} else {
							if (theRowLabels2 != null && theRowLabels2.size() >= index2)
								ddvmKey = (String) theRowLabels2.get(index2);
							index = index2++;
						}
					}
				} else {
					index = i;
					if (theRowLabels != null && theRowLabels.size() >= i)
						ddvmKey = (String) theRowLabels.get(i);
				}

				value = GeneralFiltersUtil.formatConditionValues(graphInfo.getCubeInfo(), value,
						getOriginalResultSetMetaData(), ddvmKey, false);

				Vector rowDDVM = (Vector) ddvmList.get(ddvmKey);

				if (rowDDVM != null && rowDDVM.size() > 0) {
					for (int index12 = 0; index12 < rowDDVM.size(); index12++) {
						String[] element = (String[]) rowDDVM.get(index12);
						if (element[0].equals(value)) {
							value = element[1];
							break;
						}
					}
				}

				if (bCombinedGraph) {

					if (vecRowDrillDownInfo != null && vecRowDrillDownInfo.size() > 0) {
						if ((Integer) vecRowDrillDownInfo.get(i) == 0) {
							sZPath1 += getDrillUpParameters(ddvmKey, index + 1, -1, 0, isHomePage, sObjName, std_id)
									+ " >> </a>" + value;

							if (!labelUpdatedFlagForBar) {
								drillUpLinkElement.clear();
								drillUpLinkElement.add(0,
										sRow + " ( " + ResourceManager.getString("LBL_TAB_BAR") + " ) ");

								labelUpdatedFlagForBar = true;
							}

							drillUpLinkElement.add(drillUpItemLinkForBraedcrumb(ddvmKey, index + 1, -1, 0, isHomePage,
									sObjName, std_id));

							rowDrilldownItems.add(drillUpLinkElement);

							drillUpLinkElement = new ArrayList<String>();
							drillUpLinkElement.add(value);
						} else {
							sZPath2 += getDrillUpParameters(ddvmKey, index + 1, -1, 1, isHomePage, sObjName, std_id)
									+ " >> </a>" + value;

							if (!labelUpdatedFlagForLine) {
								drillUpLinkElement.clear();
								drillUpLinkElement.add(0, sRow + " ( " + ResourceManager.getString("LBL_LINE") + " ) ");

								labelUpdatedFlagForLine = true;
							}

							drillUpLinkElement.add(drillUpItemLinkForBraedcrumb(ddvmKey, index + 1, -1, 1, isHomePage,
									sObjName, std_id));

							rowDrilldownItems.add(drillUpLinkElement);

							drillUpLinkElement = new ArrayList<String>();
							drillUpLinkElement.add(value);
						}
					}
				} else {
					sZPath += getDrillUpParameters(ddvmKey, index + 1, -1, 0, isHomePage, sObjName, std_id) + " >> </a>"
							+ value;

					drillUpLinkElement
							.add(drillUpItemLinkForBraedcrumb(ddvmKey, index + 1, -1, 0, isHomePage, sObjName, std_id));

					rowDrilldownItems.add(drillUpLinkElement);

					drillUpLinkElement = new ArrayList<String>();
					drillUpLinkElement.add(value);
				}

				if (!isZpathVisible)
					isZpathVisible = true;
			}

			rowDrilldownItems.add(drillUpLinkElement);

			breadcrumbItemMap.put(ResourceManager.getString("MSG_TEXT_ROW_COLUMNS"), rowDrilldownItems);
		}

		if (bCombinedGraph) {
			sZPath = "";
			if (sZPath1.length() > 0) {
				sZPath = sRow + " ( " + ResourceManager.getString("LBL_TAB_BAR") + " ) " + sZPath1;
			}
			if (sZPath2.length() > 0) {
				if (sZPath.length() > 0)
					sZPath += " , ";
				sZPath += sRow + " ( " + ResourceManager.getString("LBL_LINE") + " ) " + sZPath2;
			}
		}

		if (vZpath.size() > 0)
			sZPath += " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " ";
		if (vZpath.size() == 0)
			sZPath = "";

		boolean rowDrilldownPossibleFlag = isRowDrillDownPosible(graphInfo);

		if (sZPath.endsWith(SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR)
				&& (!rowDrilldownPossibleFlag || !isRowDrillDownPosibleForLineGraphInCombined(graphInfo))
				&& sZPath.length() > 2) {

			sZPath = sZPath.substring(0, sZPath.length() - 1);
		}

		if ((isXpathVisible && isZpathVisible) || (isXpathVisible && isSecondCboVisible && rowDrilldownPossibleFlag)
				|| (isFirstCboVisible && isZpathVisible && colDrilldownPossibleFlag)
				|| (isFirstCboVisible && isSecondCboVisible && rowDrilldownPossibleFlag && colDrilldownPossibleFlag))
			sZPath = " | " + sZPath;

		dPath += sZPath;

		dPath = dPath.replaceAll(">> ",
				"<img src='" + AppContextUtil.getApplicationContextPath() + "/images/arrow_right8.gif'>");
		dPath = dPath.replaceAll(" > ",
				"<img src='" + AppContextUtil.getApplicationContextPath() + "/images/arrow_right.gif'>");

		drillDownItemsForBreadcrumb.add(dPath);
		drillDownItemsForBreadcrumb.add(breadcrumbItemMap);

		return drillDownItemsForBreadcrumb;
	}

	/**
	 * Gets Drill Up parameter.
	 * 
	 * @param sDimName
	 *            String Dimension name
	 * @param iRowIndex
	 *            Integer Row Index
	 * @param iColIndex
	 *            Integer Column Index
	 * @param iDrillType
	 *            Integer Drill Type
	 * @param isHomePage
	 *            sets parameter to decide whether it is from graph or dashboard
	 * @param sObjName
	 *            String Object Name
	 * @param std_id
	 *            String Td Id
	 * @return Drill Up Parameters String.
	 */
	private String getDrillUpParameters(String sDimName, int iRowIndex, int iColIndex, int iDrillType,
			String isHomePage, String sObjName, String std_id) {

		String sFunctionName = isHomePage.equals("false") ? "imageDashboardSmartenViewDrillUp" : "smartenViewDrillUp";
		String temp = " <a href=\"javascript:" + sFunctionName + "('true" + StringUtil.FIELD_SEP + 
				isHomePage + StringUtil.FIELD_SEP +
				"" + StringUtil.FIELD_SEP; 

		if (isHomePage.equals("false")) {
			temp += std_id + StringUtil.FIELD_SEP + 
					sObjName + StringUtil.FIELD_SEP + 
					"5" + StringUtil.FIELD_SEP;
		}

		temp += sDimName + StringUtil.FIELD_SEP + 
				iRowIndex + StringUtil.FIELD_SEP + 
				iColIndex + StringUtil.FIELD_SEP + 
				iDrillType + StringUtil.FIELD_SEP + "')\"> "; 

		return temp;
	}

	private String drillUpItemLinkForBraedcrumb(String sDimName, int iRowIndex, int iColIndex, int iDrillType,
			String isHomePage, String sObjName, String std_id) {
		String sFunctionName = isHomePage.equals("false") ? "imageDashboardSmartenViewDrillUp" : "smartenViewDrillUp";

		String temp = "javascript:" + sFunctionName + "('true" + StringUtil.FIELD_SEP + 
				isHomePage + StringUtil.FIELD_SEP + 
				"" + StringUtil.FIELD_SEP; 

		if (isHomePage.equals("false")) {
			temp += std_id + StringUtil.FIELD_SEP + 
					sObjName + StringUtil.FIELD_SEP + 
					"5" + StringUtil.FIELD_SEP;
		}

		temp += sDimName + StringUtil.FIELD_SEP +
				iRowIndex + StringUtil.FIELD_SEP + 
				iColIndex + StringUtil.FIELD_SEP + 
				iDrillType + StringUtil.FIELD_SEP + "')"; 

		return temp;
	}

	/**
	 * To get drill down data.
	 * 
	 * @return drill down data
	 */
	private Vector getDrillVector(SmartenInfo graphInfo) {
		if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
			return graphInfo.getDrillVectorForCombined();
		} else {
			return graphInfo.getDrillVector();
		}
	}

	/**
	 * To return flag for row drilldown is possible or not in combined graph.
	 * 
	 * @return true if drill down is possible on row otherwise false
	 */
	private boolean isRowDrillDownPosibleForLineGraphInCombined(SmartenInfo graphInfo) {

		boolean bRowDrillDown = false;
		Vector theRowColLabels2 = graphInfo.getLineGraphRowLabelsForCombinedGraph();

		if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
			if (!(graphInfo.isMultipleYAxisLabelsEnableForCombineLine())) {
				if (theRowColLabels2 != null && theRowColLabels2.size() > 1) {
					if (graphInfo.getRowIndexForLineGraphInCombinedGraph() >= theRowColLabels2.size()) {
						bRowDrillDown = false;
					} else {
						bRowDrillDown = true;
					}
				}
			}
		}
		return bRowDrillDown;
	}

	/**
	 * Set Action to be taken on Graph Drill Up.
	 * 
	 * @param sDimName
	 *            Dimention Name
	 * @param iRowIndex
	 *            Graph Row Index
	 * @param iColIndex
	 *            Column Index
	 * @param iDrillType
	 *            Drill Down Type
	 * @param userId
	 *            Logged in user's identifier
	 */
	public void setGraphDrillUp(SmartenInfo graphInfo, String sDimName, int iRowIndex, int iColIndex, int iDrillType,
			UserInfo userInfo) {

		graphInfo.setDrillUpDimName(sDimName);
		graphInfo.setDrillRowIndex(iRowIndex);
		graphInfo.setDrillColIndex(iColIndex);
		graphInfo.setDrillUpType(iDrillType);

		ArrayList arrList = getDrillDownRow(graphInfo, userInfo);
	}

	/**
	 * Gets drill down row list.
	 * 
	 * @param graph
	 *            the GraphExPanel object
	 * @return ArrayList contains ALSController object at 0th index and GraphExPanel
	 *         object at 1st index
	 */
	private ArrayList getDrillDownRow(SmartenInfo graphInfo, UserInfo userInfo) {
		Vector drillVector = getDrillVector(graphInfo);

		boolean bCombinedGraph = (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) ? true : false;
		Vector vOldRowDrillInfo = null;
		Vector vNewRowDrillInfo = null;

		String sDrillupColName = graphInfo.getDrillUpDimName();
		int iItemPos = (graphInfo.getDrillRowIndex() != -1) ? 1 : -1;
		int iSeriesPos = (graphInfo.getDrillColIndex() != -1) ? 1 : -1;

		if (bCombinedGraph)
			vOldRowDrillInfo = graphInfo.getRowVectorDrillDownInfoForCombinedGraph();

		int seriesPos = -1;
		int itemPos = -1;
		int iRowIndex = -1;
		int iRowIndex2 = -1;
		int iColIndex = -1;

		if (sDrillupColName != null && sDrillupColName.length() > 0) {
			itemPos = iItemPos;
			seriesPos = iSeriesPos;
		} else {
			if (drillVector.size() != 0) {
				Vector recordVector = (Vector) drillVector.elementAt(drillVector.size() - 1);

				if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
					seriesPos = ((Integer) recordVector.elementAt(3)).intValue(); 
					itemPos = ((Integer) recordVector.elementAt(4)).intValue(); 
				} else {
					seriesPos = ((Integer) recordVector.elementAt(2)).intValue(); 
					itemPos = ((Integer) recordVector.elementAt(3)).intValue(); 
				}
			}
		}

		drillUp(graphInfo, userInfo);
		setDrillDownDetail(graphInfo);

		drillVector = getDrillVector(graphInfo);

		if (drillVector.size() != 0) {
			Vector recordVector = (Vector) drillVector.elementAt(drillVector.size() - 1);

			if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
				iRowIndex = ((Integer) recordVector.elementAt(0)).intValue(); 
				iRowIndex2 = ((Integer) recordVector.elementAt(1)).intValue(); 
				iColIndex = ((Integer) recordVector.elementAt(2)).intValue(); 
			} else {
				iRowIndex = ((Integer) recordVector.elementAt(0)).intValue(); 
				iColIndex = ((Integer) recordVector.elementAt(1)).intValue(); 
			}
		}

		if (seriesPos != -1 && !graphInfo.getDrilldownColumnPath().equalsIgnoreCase("")) {
			String drillDownColPath = graphInfo.getDrilldownColumnPath();
			if (!drillDownColPath.trim().equals("")) {
				String[] colValues = drillDownColPath.split("\\$\\~\\$");
				String colPath = colValues[0];
				for (int i = 1; i < colValues.length; i++) {
					if ((i + 1) <= iColIndex)
						colPath += "$~$" + colValues[i];
					else
						break;
				}
				drillDownColPath = colPath;
			}
			graphInfo.setDrilldownColumnPath(drillDownColPath);
		}

		if (itemPos != -1 && !graphInfo.getDrilldownRowPath().equalsIgnoreCase("")) {
			String drillDownRowPath = graphInfo.getDrilldownRowPath();

			if (bCombinedGraph) {

				Vector vectRowLabels = graphInfo.getRowColumns();
				Vector vectRowLabels2 = graphInfo.getLineGraphRowLabelsForCombinedGraph();
				vNewRowDrillInfo = graphInfo.getRowVectorDrillDownInfoForCombinedGraph();
				int length = Math.min(vNewRowDrillInfo.size(), vOldRowDrillInfo.size());
				int index1, index2;
				int rindex, rindex2;
				index1 = index2 = 0;
				rindex = rindex2 = 1;
				String rowPath = "";
				if (length >= 1) {
					if (!drillDownRowPath.trim().equals("")) {

						String[] rowValues = drillDownRowPath.split("\\$\\~\\$");
						if (rowValues.length >= 2) {

							rowPath = rowValues[0];
							for (int i = 1; i < rowValues.length; i++) {

								if (length == index1)
									break;

								if (vNewRowDrillInfo.get(index1) == vOldRowDrillInfo.get(index2)) {

									if ((Integer) vNewRowDrillInfo.get(index1) == 0) {
										if (index1 == 0)
											rowPath = vectRowLabels.get(0).toString();
										if ((++rindex) <= iRowIndex) {
											rowPath += "$~$" + rowValues[i];
										}
									} else if ((Integer) vNewRowDrillInfo.get(index1) == 1) {
										if (index1 == 0)
											rowPath = vectRowLabels2.get(0).toString();
										if ((++rindex2) <= iRowIndex2) {
											rowPath += "$~$" + rowValues[i];
										}
									}
									index1++;
									index2++;
								} else {
									index2++;
								}
							}
						}
					}
				}
				drillDownRowPath = rowPath;
			} else {
				if (!drillDownRowPath.trim().equals("")) {
					String[] rowValues = drillDownRowPath.split("\\$\\~\\$");
					String rowPath = rowValues[0];
					for (int i = 1; i < rowValues.length; i++) {
						if ((i + 1) <= iRowIndex)
							rowPath += "$~$" + rowValues[i];
						else
							break;
					}
					drillDownRowPath = rowPath;
				}
			}
			graphInfo.setDrilldownRowPath(drillDownRowPath);
		}
		ArrayList arrList = new ArrayList();
		return arrList;
	}

	/**
	 * Action to be taken on DrillUp.
	 */
	private void drillUp(SmartenInfo graphInfo, UserInfo userInfo) {

		getDrillDown(graphInfo);

		boolean isGraphSet = setGraph(false, graphInfo, userInfo);

		if (!isGraphSet) {
		} else {
			resetErrorMessage(graphInfo);
		}

		graphInfo.setDrillUpOperation(false);
	}

	/**
	 * Restores Drill Down data.
	 */
	private void getDrillDown(SmartenInfo graphInfo) {
		Vector m_drillVector = graphInfo.getDrillVector();

		if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
			getDrillDownCombined(graphInfo);
			return;
		}

		if (m_drillVector == null || m_drillVector.size() < 1) {
			clearDrillUpConditions(false, graphInfo);
			return;
		}

		int m_itemPos = graphInfo.getItemPos();
		int m_seriesPos = graphInfo.getSeriesPos();
		int m_colIndex = graphInfo.getColIndex();
		int m_rowIndex = graphInfo.getRowIndex();

		Vector record = (Vector) m_drillVector.elementAt(m_drillVector.size() - 1);

		if (graphInfo.getDrillUpDimName() != null && graphInfo.getDrillUpDimName().length() > 0) {

			Vector tmpDrillVector = new Vector();
			Vector tmpDrillDetailVector = new Vector();
			int index = 2;

			if (graphInfo.getDrillColIndex() != -1) {
				m_itemPos = -1;
				m_seriesPos = 1;
				m_colIndex = ((Integer) record.elementAt(1)).intValue();

				for (int i = 0; i < m_drillVector.size(); i++) {
					record = (Vector) m_drillVector.get(i);

					if (graphInfo.getDrillColIndex() >= (Integer) record.get(1)) {
						tmpDrillVector.add(record);
						index = (Integer) record.get(0) + 1;
						tmpDrillDetailVector.add(graphInfo.getDrillDownDetailList().get(i));
					} else if (index == (Integer) record.get(0)) {
						record.set(1, graphInfo.getDrillColIndex());
						index++;
						tmpDrillVector.add(record);
						tmpDrillDetailVector.add(graphInfo.getDrillDownDetailList().get(i));
					}
				}
			} else if (graphInfo.getDrillRowIndex() != -1) {
				m_itemPos = 1;
				m_seriesPos = -1;
				m_rowIndex = ((Integer) record.elementAt(0)).intValue();
				for (int i = 0; i < m_drillVector.size(); i++) {

					record = (Vector) m_drillVector.get(i);

					if (graphInfo.getDrillRowIndex() >= (Integer) record.get(0)) {
						tmpDrillVector.add(record);
						index = (Integer) record.get(1) + 1;
						tmpDrillDetailVector.add(graphInfo.getDrillDownDetailList().get(i));
					} else if (index == (Integer) record.get(1)) {
						record.set(0, graphInfo.getDrillRowIndex());
						index++;
						tmpDrillVector.add(record);
						tmpDrillDetailVector.add(graphInfo.getDrillDownDetailList().get(i));
					}
				}
			}
			m_drillVector = tmpDrillVector;
			tmpDrillDetailVector.add(new DrillDownDetail(-1, null, -1, null, -1, null));

			graphInfo.setDrillDownDetailList(tmpDrillDetailVector);
		} else {
			m_rowIndex = ((Integer) record.elementAt(0)).intValue();
			m_colIndex = ((Integer) record.elementAt(1)).intValue();
			m_seriesPos = ((Integer) record.elementAt(2)).intValue();
			m_itemPos = ((Integer) record.elementAt(3)).intValue();
			m_drillVector.remove(record);
		}

		graphInfo.setDrillVector(m_drillVector);

		graphInfo.setItemPos(m_itemPos);
		graphInfo.setSeriesPos(m_seriesPos);
		graphInfo.setColIndex(m_colIndex);
		graphInfo.setRowIndex(m_rowIndex);

		graphInfo.getDrillDownListOfX().clear();
		graphInfo.getDrillDownListOfZ().clear();

		if (m_drillVector.size() < 1) {
			clearDrillUpConditions(false, graphInfo);
		}

		graphInfo.setDrillUpOperation(true);
	}

	/**
	 * Show DrillUp button.
	 * 
	 * @param show
	 *            boolean for show DrillUp buttton
	 */
	private void clearDrillUpConditions(boolean show, SmartenInfo graphInfo) {
		if (show) {
		} else {
			graphInfo.getDrillDownDetailList().removeAllElements();
			graphInfo.setBarDrilldownText("");
			graphInfo.setLegendDrilldownText("");
			graphInfo.setxAxisDrilldownText("");
		}
	}

	/**
	 * Gets row, column, data section's value which is exists in outliner window.
	 * 
	 * @return Row, column and data
	 */
	private Vector getOutLinerDataWithoutSysGeneratedFields(SmartenInfo graphInfo) {
		return getOutLinerDataWithoutSysGeneratedFields(true, graphInfo);
	}

	/**
	 * Gets row, column, data section's value which is exists in outliner window.
	 * 
	 * @param addSysGenDimColumns
	 *            true to add system generated dimension columns otherwise false
	 * @return Row, column and data
	 */
	public Vector getOutLinerDataWithoutSysGeneratedFields(boolean addSysGenDimColumns, SmartenInfo graphInfo) {
		Vector vOutLinerData = new Vector();

		Vector theRowLabels = graphInfo.getRowColumns();
		Vector theColLabels = graphInfo.getColColumns();
		Vector theRowLabels2 = graphInfo.getLineGraphRowLabelsForCombinedGraph();

		String rowLable = graphInfo.getGraphData().getCmbLinerowLabel();

		if (!addSysGenDimColumns && graphInfo.getSysGeneratedRowLabels().size() > 0) {
			Vector modifiedRowLabels = removeSysGenDimCols(theRowLabels, graphInfo.getSysGeneratedRowLabels());
			theRowLabels = modifiedRowLabels;
		}

		if (!addSysGenDimColumns && graphInfo.getSysGeneratedColumnLabels().size() > 0) {
			Vector modifiedColLabels = removeSysGenDimCols(theColLabels, graphInfo.getSysGeneratedColumnLabels());
			theColLabels = modifiedColLabels;
		}

		if (!addSysGenDimColumns && graphInfo.getSysGeneratedRowLabelsForLineGraph().size() > 0) {
			Vector modifiedRowLabels2 = removeSysGenDimCols(graphInfo.getLineGraphRowLabelsForCombinedGraph(),
					graphInfo.getSysGeneratedRowLabelsForLineGraph());
			theRowLabels2 = modifiedRowLabels2;
		}

		vOutLinerData.addElement(theRowLabels);
		vOutLinerData.addElement(theColLabels);
		vOutLinerData.addElement(graphInfo.getDataColumns());
		vOutLinerData.addElement(theRowLabels2);
		vOutLinerData.addElement(graphInfo.getLineGraphDataLabelsForCombinedGraph());

		return vOutLinerData;
	}

	/**
	 * To remove system generated column dimension.
	 * 
	 * @param theCols
	 *            the column names
	 * @param sysGenDimCols
	 *            system generated column dimension
	 * @return column dimension
	 */
	private Vector removeSysGenDimCols(Vector theCols, Vector sysGenDimCols) {
		Vector theModifiedColVector = (Vector) theCols.clone();
		int intSize = sysGenDimCols.size();

		for (int i = 0; i < intSize; i++) {
			theModifiedColVector.removeElement(sysGenDimCols.elementAt(i));
		}
		return theModifiedColVector;
	}

	/**
	 * To set drill down detail.
	 */
	private void setDrillDownDetail(SmartenInfo graphInfo) {
		Vector<DrillDownDetail> m_vecDrillDownDetail = graphInfo.getDrillDownDetailList();

		if (m_vecDrillDownDetail.size() >= 1) {
			graphInfo.setBarDrilldownText("");
			graphInfo.setLegendDrilldownText("");
			graphInfo.setxAxisDrilldownText("");

			int setIndex = m_vecDrillDownDetail.size() - 2;
			if (m_vecDrillDownDetail.size() > 1) {

				DrillDownDetail m_drillDownDetail;

				for (int i = setIndex; i >= 0; i--) {
					m_drillDownDetail = (DrillDownDetail) m_vecDrillDownDetail.elementAt(i);
					int itemIndex = m_drillDownDetail.getDrilledItemIndex();
					int seriesIndex = m_drillDownDetail.getDrilledSeriesIndex();
					if (itemIndex != -1 && seriesIndex != -1)
					{
						clickBar(m_drillDownDetail, graphInfo);
					} else if ((itemIndex != -1 && seriesIndex == -1) || isOnlyRowDrillDown(graphInfo))
					{
						clickZ(m_drillDownDetail, graphInfo);

					} else if (itemIndex == -1 && seriesIndex != -1) 
					{
						clickX(m_drillDownDetail, graphInfo);
					}
				}
				m_vecDrillDownDetail.removeElementAt(m_vecDrillDownDetail.size() - 1);
			}
		}
	}

	/**
	 * To set data of drill down when click on X-axis.
	 * 
	 * @param m_drillDownDetail
	 *            object of DrillDownDetail
	 */
	private void clickX(DrillDownDetail m_drillDownDetail, SmartenInfo graphInfo) {
		String seriesName = "";
		Object obj;

		obj = m_drillDownDetail.getDrilledSeriesName();
		if (obj != null) {
			seriesName = obj.toString();
		}

		String strText = seriesName;

		graphInfo.getDrillDownListOfX().add(0, strText);

		String xText = graphInfo.getxAxisDrilldownText();
		String zText = graphInfo.getLegendDrilldownText();
		String barText = graphInfo.getBarDrilldownText();

		if (graphInfo.getDrillDownDetailList().size() == 1) {
			xText = "";
		} else {
			if (xText.equals("")) {
				xText = strText;
			} else {
				xText = strText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + xText;
			}

		}
		if (!barText.equals("")) {
			xText = xText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + barText;
		}
		if (!zText.equals("")) {
			xText = xText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + zText;
		}
		barText = "";
		zText = "";

		graphInfo.setxAxisDrilldownText(xText);
		graphInfo.setLegendDrilldownText(zText);
		graphInfo.setBarDrilldownText(barText);
	}

