	/**
	 * Apply TimeSiriesFilter.
	 * 
	 * @param requestParamMap
	 *            contains request parameters
	 * @param object
	 *            ALSController/ReportViewerBean
	 * @throws CubeException
	 */
	public void applyTimeFilter(Map<String, String> requestParamMap, SmartenInfo graphInfo) throws CubeException {

		String columnName = StringUtil.null2String(requestParamMap.get("filterColumnName"));
		String isHomePage = StringUtil.null2String(requestParamMap.get("isHomePage"));
		boolean bTimeSeries = Boolean.valueOf((String) requestParamMap.get("bTimeSeries"));
		CubeVector newConditions = TimeSeriesFilter.applyTimeFilter(requestParamMap, graphInfo);

		checkAndResetDrillUp(graphInfo, true);
		if (!bTimeSeries) {
			setFilterConditions(columnName, newConditions, graphInfo);
		} else if (isHomePage.equals("false")) {
		} else {
			if (columnName.indexOf(",") > -1) {
				String[] colName = null;
				HashMap conditions = (HashMap) graphInfo.getTimeConditions().clone();
				colName = StringUtil.toArray(columnName);
				for (int i = 0; i < colName.length; i++) {
					conditions.put(colName[i], newConditions);
				}
				graphInfo.setTimeConditions(conditions);
			} else {
				if (graphInfo.getTimeConditions() != null) {
					if (graphInfo.getGraphType() == SmartenConstants.CANDLE_STICK_GRAPH
							|| graphInfo.getGraphType() == SmartenConstants.HIGH_LOW_OPEN_CLOSE_GRAPH) {
						graphInfo.getTimeConditions().put(columnName, newConditions);
						graphInfo.getTimeConditions().put(columnName + "_1", newConditions);
						graphInfo.getTimeConditions().put(columnName + "_2", newConditions);
					} else
						graphInfo.getTimeConditions().put(columnName, newConditions);
				} else {
					HashMap condMap = new HashMap();
					if (graphInfo.getGraphType() == SmartenConstants.CANDLE_STICK_GRAPH
							|| graphInfo.getGraphType() == SmartenConstants.HIGH_LOW_OPEN_CLOSE_GRAPH) {
						condMap.put(columnName, newConditions);
						condMap.put(columnName + "_1", newConditions);
						condMap.put(columnName + "_2", newConditions);
					} else
						condMap.put(columnName, newConditions);
					graphInfo.setTimeConditions(condMap);
				}
			}
		}
	}

