	public List getDummyDataForAmchartsPreview(String rowLabel, String colLabel, String[] dataLabels, int colLength) {
		List dataList = new ArrayList();
		double d = 0.0;
		int dataLength = dataLabels.length;
		int colSize = colLength;

		if (dataLength >= 2) {
			if (!rowLabel.equals("") && !colLabel.equals("")) {
				for (int k = 0; k < dataLength; k++) {
					for (int i = 0; i < colSize; i++) {
						for (int j = 0; j < 2; j++) {
							d = Math.round(Math.random() * 100);
							dataList.add(d);
						}
					}
				}
			} else {
				String label = rowLabel;
				if (rowLabel.equals(""))
					label = colLabel;

				for (int i = 0; i < colSize; i++) {
					for (int j = 0; j < dataLength; j++) {
						d = Math.round(Math.random() * 100);
						dataList.add(d);
					}
				}
			}
		} else {
			String dataLabel = dataLabels[0];

			if (!rowLabel.equals("") && !colLabel.equals("")) {
				for (int i = 0; i < colSize; i++) {
					for (int j = 0; j < 2; j++) {
						d = Math.round(Math.random() * 100);
						dataList.add(d);
					}
				}
			} else {
				String label = rowLabel;
				if (rowLabel.equals(""))
					label = colLabel;

				for (int i = 0; i < colSize; i++) {
					for (int j = 0; j < 2; j++) {
						d = Math.round(Math.random() * 100);
						dataList.add(d);
					}
				}
			}
		}

		return dataList;
	}

