	/**
	 * Resets DrillDown vector.
	 */
	public void resetDrillVector(SmartenInfo graphInfo) {

		graphInfo.setDrilldownRowPath("");
		graphInfo.setDrilldownColumnPath("");

		if (graphInfo.getDrillRootValues() != null && graphInfo.getDrillRootValues().size() > 0) {
			graphInfo.getDrillRootValues().clear();
		}
		graphInfo.getDrillDownListOfX().clear();
		graphInfo.getDrillDownListOfZ().clear();
		try {
			clearDrillConditions();
		} catch (CubeException e) {
			ApplicationLog.error(e);
		}
		if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
			resetDrillVectorCombined(graphInfo);
			return;
		}
		if (graphInfo.getDrillVector() != null && graphInfo.getDrillVector().size() >= 1) {
			graphInfo.getDrillVector().removeAllElements();

			clearDrillUpConditions(false, graphInfo);
		}
	}

	/**
	 * Save Graph object.
	 * 
	 * @param graphInfo
	 *            graph info entity object
	 * @param loggedInUser
	 *            Logged in user object
	 * @param objectLockManager
	 *            Object lock manager for current object
	 * @param bSaveAs
	 *            True if saveAs graph otherwise false
	 * @return
	 * @throws DatabaseOperationException
	 * @throws RScriptException
	 * @throws CubeException
	 */
	public SmartenInfo saveGraph(SmartenInfo graphInfo, UserInfo loggedInUser, boolean bSaveAs)
			throws DatabaseOperationException, MDXException, RealTimeCubeException, CubeException, RScriptException {
		if (bSaveAs) {
			String strDestGraphId = UniqueIdGeneratorUtil.getUniqueDisplayName(AppConstants.SMARTEN,
					loggedInUser.getUserId()) + AppConstants.SMARTEN_FILE_EXT;
			graphInfo.setGraphId(strDestGraphId);
		}
		setLabelConditionList(new CubeConditionList());
		return updateExistingGraph(graphInfo, loggedInUser, bSaveAs);
	}

	private SmartenInfo updateExistingGraph(SmartenInfo graphInfo, UserInfo loggedInUser, boolean bSaveAs)
			throws CubeException  {

		SmartenInfo savedSmartenInfo = null;
		HashMap<String, String> params = new HashMap<String, String>();
		FileEx fileObj = null;
		try {
			try {
				boolean isNew = (graphInfo.getGraphMode() == AppConstants.NEW_MODE);
				String message = "";

				if (isNew)
					message = ResourceManager.getString("SAVE_NEW_GRAPH");
				else if (bSaveAs)
					message = ResourceManager.getString("CMD_SAVEAS_GRAPH");
				else
					message = ResourceManager.getString("CMD_SAVE_GRAPH");

			} catch (Exception e) {
				ApplicationLog.error(e);
			}

			if (graphInfo.getGraphMode() == AppConstants.OPEN_MODE) {
				String graphId = graphInfo.getGraphId();
				String graphPhysicalName = graphId.substring(0, graphId.indexOf(AppConstants.SMARTEN_FILE_EXT));

				params.put("graphPhysicalName", graphPhysicalName);

			} else if (graphInfo.getGraphMode() == AppConstants.NEW_MODE) {
				graphInfo.setCreatedBy(loggedInUser);
				graphInfo.setCreatedDate(new Date());
			}

			graphInfo.setModifiedBy(loggedInUser);
			graphInfo.setModifiedDate(new Date());

			ObjectCubeDefinitionInfo objectCubeDefinition;

			if (graphInfo.getObjectCubeDefinition() != null) {
				objectCubeDefinition = graphInfo.getObjectCubeDefinition();
			} else {
				objectCubeDefinition = new ObjectCubeDefinitionInfo();
			}

			setObjectCubeDefinition(objectCubeDefinition, graphInfo, loggedInUser.getUsername());

			graphInfo.setObjectCubeDefinition(objectCubeDefinition);

			Vector theRowLabels = new Vector();
			Vector theColLabels = new Vector();

			Vector modifiedRowLabels = new Vector();
			Vector modifiedColLabels = new Vector();

			if (graphInfo.getSysGeneratedRowLabels().size() > 0) {
				modifiedRowLabels = removeSysGenDimCols(graphInfo.getRowColumns(),
						graphInfo.getSysGeneratedRowLabels());
				graphInfo.setRowColumns(modifiedRowLabels);
			} else {
				modifiedRowLabels = graphInfo.getRowColumns();
			}
			if (graphInfo.getSysGeneratedColumnLabels().size() > 0) {
				modifiedColLabels = removeSysGenDimCols(graphInfo.getColColumns(),
						graphInfo.getSysGeneratedColumnLabels());
				graphInfo.setColColumns(modifiedColLabels);
			} else {
				modifiedColLabels = graphInfo.getColColumns();
			}
			if (graphInfo.getSysGeneratedRowLabelsForLineGraph().size() > 0) {
				modifiedRowLabels = removeSysGenDimCols(graphInfo.getLineGraphRowLabelsForCombinedGraph(),
						graphInfo.getSysGeneratedRowLabelsForLineGraph());
				graphInfo.setLineGraphRowLabelsForCombinedGraph(modifiedRowLabels);
			}

			CubeVector colLabelInfoList = new CubeVector();
			CubeVector rowLabelInfoList = new CubeVector();
			int iType = 0;
			for (int i = 0; i < modifiedColLabels.size(); i++) {
				CubeLabelInfo theCubeLabelInfo = new CubeLabelInfo(modifiedColLabels.get(i).toString());
				iType = CubeUtil.getColumnType(modifiedColLabels.get(i).toString(), getOriginalResultSetMetaData(),
						graphInfo.getCubeInfo().getDataObjectId());
				theCubeLabelInfo.setType(iType);
				colLabelInfoList.add(theCubeLabelInfo);
			}

			for (int i = 0; i < modifiedRowLabels.size(); i++) {
				CubeLabelInfo theCubeLabelInfo = new CubeLabelInfo(modifiedRowLabels.get(i).toString());
				iType = CubeUtil.getColumnType(modifiedRowLabels.get(i).toString(), getOriginalResultSetMetaData(),
						graphInfo.getCubeInfo().getDataObjectId());
				theCubeLabelInfo.setType(iType);
				rowLabelInfoList.add(theCubeLabelInfo);
			}

			graphInfo.setColDimensionInfoList(colLabelInfoList);
			graphInfo.setRowDimensionInfoList(rowLabelInfoList);
			SubCubeMetaDataInfo subCubeMetaDataInfo = subcubedao
					.getSubCubeMetaDataInfoByObjectId(graphInfo.getGraphId());
			if(!graphInfo.getCubeInfo().isRealTimeCube()) {
				
				if (subCubeMetaDataInfo == null) {
					subCubeMetaDataInfo = new SubCubeMetaDataInfo();
				}
				subCubeMetaDataInfo.setObjectID(graphInfo.getGraphId());
				graphInfo.setSubCubeMetaDataInfo(subCubeMetaDataInfo);
			}
			
			ArrayList<PageFilterNew> currentFilters = graphInfo.getPageFilterColumnInfo();
			
			if(graphInfo.getDashboardInfo()!=null) {
				String dbId = graphInfo.getDashboardInfo().getDashboardId();
				if(dbId != null && !dbId.isEmpty()) {
					ArrayList<PageFilterNew> finalFiltersToSave = saveFiltersForDashboardObject(graphInfo.getPageFilterColumnInfo(), graphInfo.getOriginalPageFilters());
					graphInfo.setPageFilterColumnInfo(finalFiltersToSave);
					smartenDAO.updateModifiedDateTime(graphInfo);
				}
			}		
			if(graphInfo.getGraphProperties().getColLabelsDisplayMap()!=null && !graphInfo.getGraphProperties().getColLabelsDisplayMap().isEmpty()) {
				graphInfo.getGraphProperties().setColLabelsMap(graphInfo.getGraphProperties().getColLabelsDisplayMap());
			}
			savedSmartenInfo = smartenDAO.update(graphInfo);
			
			if(graphInfo.getDashboardInfo()!=null) {
				String dbId = graphInfo.getDashboardInfo().getDashboardId();
				if(dbId != null && !dbId.isEmpty()) {
					graphInfo.setPageFilterColumnInfo(currentFilters);
				}
			}

			graphInfo.setGraphId(savedSmartenInfo.getGraphId());
			savedSmartenInfo = graphInfo;
			if (!bSaveAs) {
				setUpdateByObjectId(graphInfo.getGraphId(), loggedInUser.getUserId(), true);
			}
			try {
				setDataFormatAndMapFromCube(graphInfo, loggedInUser);
			} catch (DatabaseOperationException e) {
				ApplicationLog.error(e);
			}
			graphCube.setObjectId(graphInfo.getGraphId());
			BIDataset<Row> bidataset = SparkUtil.getRealTimeDatasetMap()
					.get(graphInfo.getNewGraphId() + loggedInUser.getUserId());
			if (bidataset != null) {
				SparkUtil.getRealTimeDatasetMap().remove(savedSmartenInfo.getNewGraphId() + loggedInUser.getUserId());
				SparkUtil.getRealTimeDatasetMap().put(savedSmartenInfo.getGraphId() + loggedInUser.getUserId(),
						bidataset);
			}
			graphCube.setPartitionBy(graphInfo.getPartitionBy());
			graphCube.writeSubeCube(null, false);
			if (graphInfo.getGraphMode() == AppConstants.NEW_MODE) {
				graphInfo.setGraphMode(AppConstants.OPEN_MODE);
			}
		} catch (Exception e) {
			String message = null;
			if (e instanceof DatabaseOperationException) {
				String graphMode = (graphInfo.getGraphMode() == AppConstants.NEW_MODE) ? "New" : "Open";
				message = ResourceManager.getString("LOG_ERROR_FAILED_TO_SAVE_GRAPH",
						new Object[] { graphInfo.getGraphName(), graphMode, loggedInUser.getUsername() }) + " "
						+ e.getMessage();
			} else {
				message = ResourceManager.getString("MSG_TEXT_CUBE_EXCEPTION") + " " + e.toString();
			}

			ApplicationLog.error(message, e);
			throw new CubeException(message);
		} finally {
		}

		return savedSmartenInfo;
	}

