	/**
	 * Sets object cube definition properties from the cube for specified object.
	 * 
	 * @param objectCubeDefinition
	 *            Reference of ObjectCubeDefinitionInfo
	 * @throws CubeException
	 */
	private void setObjectCubeDefinition(ObjectCubeDefinitionInfo objectCubeDefinition, SmartenInfo graphInfo,
			String userName) throws CubeException {

		try {
			objectCubeDefinition.setViewInfo(graphOrgCube.getCubeViewInfo());
			objectCubeDefinition.setLabelConditions(getLabelConditionList());

			CubePackInfoList packInfoList = graphOrgCube.getPackInfoList();
			for (int j = 0; j < packInfoList.size(); j++) {
				ApplicationLog.debug(" = PackInfoList=== " + packInfoList.elementAt(j));
			}

			objectCubeDefinition.setPackConditions(packInfoList);
			objectCubeDefinition.setDataColumns(graphOrgCube.getDataColumnInfoList());
			objectCubeDefinition.setSuppress(new Integer(graphOrgCube.getSupressZeros()));
			objectCubeDefinition.setDrillConditions(graphOrgCube.getDrillConditions());
			objectCubeDefinition.setDrillColumnsMap(graphOrgCube.getDrillColumnMap());
			objectCubeDefinition.setDrillColumnsSummaryInfoMap(graphOrgCube.getDrillColumnsSummaryInfo());
			objectCubeDefinition.setFilterConditions(graphOrgCube.getFilterConditions());
			objectCubeDefinition.setTimeConditions(graphOrgCube.getTimeSeriesFilters());
			objectCubeDefinition.setLastAppliedObjects(graphOrgCube.getLastAppliedObjs());
			objectCubeDefinition.setOrderedDataColumns(graphCube.getOrderedDataColumnInfoList());
			objectCubeDefinition.setLmRecentSettingsInfo(graphOrgCube.getLMRecentInfo());
			objectCubeDefinition.setRowSummaryOnlyColName(graphOrgCube.getRowSummaryOnlyColName());
			objectCubeDefinition.setColumnSummaryOnlyColName(graphOrgCube.getColSummaryOnlyColName());
			objectCubeDefinition.setDistinctCountMap(graphOrgCube.getDistinctCountMap());
			objectCubeDefinition.setrScriptInputVOs(graphOrgCube.getrScriptInputVOs());
			objectCubeDefinition.setrScriptOutputVOs(graphOrgCube.getrScriptOutputVOs());
			objectCubeDefinition.setrProfileId(graphOrgCube.getrProfileId());
			objectCubeDefinition.setrInputCubeId(graphOrgCube.getrInputCubeId());

		} catch (CubeException e) {
			String graphMode = (graphInfo.getGraphMode() == AppConstants.NEW_MODE) ? "New" : "Open";
			ApplicationLog.error(ResourceManager.getString("LOG_ERROR_FAILED_TO_SET_GRAPH_OBJECT_CUBE_DEFINITION",
					new Object[] { graphInfo.getGraphName(), graphMode, userName }), e);

			throw e;
		}
	}

