					if (sample != null)
					{
						sampleBy = sample.getSampleBy();
						samplingMethod = sample.getSampalingMethod();
					}
					Map dimMap = graphInfo.getDimensionValueCountMap();
					int mapCounter = 0;
					allDimCount = dimMap.size();
					Iterator iterator = (Iterator) dimMap.entrySet().iterator();
