	/**
	 * To add active user defined columns in vector for line graph.
	 */
	private void addUserColumnsInDataVector2(SmartenInfo graphInfo, String userId) {
		CubeVector userColumns = new CubeVector();

		if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
			CubeVector uddcList = graphInfo.getUddcInfoListForLineCombinedGraph();

			List<ActiveUDDCInfo> actUDDCInfoList = null;
			if (uddcList != null && uddcList.size() > 0) {
				for (int i = 0; i < uddcList.size(); i++) {

					if (i == 0)
						actUDDCInfoList = graphInfo.getActiveUDDCInfo(userId);

					for (ActiveUDDCInfo aInfo : actUDDCInfoList) {
						UddcTemplateInfo uddcInfo = aInfo.getUddcTemplateInfo();
						if (uddcInfo != null && uddcInfo.getColumnName().equals(uddcList.get(i))) {
							if (!uddcList.contains(uddcInfo))
								userColumns.add(uddcInfo);
						}
					}
				}
			}

		} else {
			userColumns = getActiveUserColumnInfoList(graphInfo, userId);
		}
		if (graphInfo.getTheDataColLabels4() != null) {
			graphInfo.getTheDataColLabels4().removeAllElements();
			graphInfo.getTheDataColLabels4().addAll(graphInfo.getLineGraphDataLabelsForCombinedGraph());
		}

		int index = -1;

		if (userColumns != null && userColumns.size() > 0) {
			for (int colNo = 0; colNo < userColumns.size(); colNo++) {
				UddcTemplateInfo cbColumn = (UddcTemplateInfo) userColumns.elementAt(colNo);
				if (!graphInfo.getTheDataColLabels4().contains(cbColumn.toString())) {
					index = GeneralUtil.getOrderedColumnIndex(graphInfo.getTheDataColLabels4(), cbColumn.toString(),
							graphCube.getOrderedDataColumnInfoList(), userColumns);
					graphInfo.getTheDataColLabels4().insertElementAt(cbColumn.toString(), index);
				}
			}
		}

		if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH && graphInfo.getTheDataColLabels4() != null
				&& graphInfo.getTheDataColLabels4().size() >= 2) {
			setMultipleYAxisLabelsEnableForCombineLine(true, graphInfo);
		} else {
			setMultipleYAxisLabelsEnableForCombineLine(false, graphInfo);
		}

	}

	/**
	 * To set Active User Defined Columns for line graph specified by user name.
	 * 
	 * @param userName
	 *            User Name
	 * @return Active user defined columns
	 */
	private CubeVector getActiveUserColumnInfoList2(SmartenInfo graphInfo, String userName) {
		CubeVector userSpecificColumns = new CubeVector();
		List<ActiveUDDCInfo> actUDDCInfoList = graphInfo.getUddcInfoListForLineCombinedGraph();
		for (ActiveUDDCInfo aInfo : actUDDCInfoList) {
			UddcTemplateInfo uddcInfo = aInfo.getUddcTemplateInfo();
			if (uddcInfo != null) {
				userSpecificColumns.add(uddcInfo);
			}
		}
		return userSpecificColumns;
	}

	/**
	 * Sets Drill Down data for CombinedGraph.
	 */
	private void setDrillDownCombined(SmartenInfo graphInfo) {
		Vector m_drillVectorCombined = graphInfo.getDrillVectorForCombined();

		if (m_drillVectorCombined == null) {
			m_drillVectorCombined = new Vector();
		}

		Vector record = new Vector();

		record.add(graphInfo.getRowIndex());
		record.add(graphInfo.getRowIndexForLineGraphInCombinedGraph());
		record.add(graphInfo.getColIndex());
		record.add(graphInfo.getSeriesPos());
		record.add(graphInfo.getItemPos());

		m_drillVectorCombined.add(record);

		graphInfo.setDrillVectorForCombined(m_drillVectorCombined);
	}

	/**
	 * Get Vector Containing Data Columns Sequence (Set In outliner).
	 * 
	 * @return Data columns
	 */
	private Vector getDataLabelsInSequence(SmartenInfo graphInfo) {
		Vector dataColsInSequence = graphInfo.getDataColLabels3();
		if (dataColsInSequence.size() == 0) {
			if (graphInfo.getDataColumns() != null)
				dataColsInSequence = (Vector) graphInfo.getDataColumns().clone();
			else
				dataColsInSequence = new Vector();
		}

		graphInfo.setDataColLabels3(dataColsInSequence);

		return dataColsInSequence;
	}

	/**
	 * To get axis display name. This method is useful only for CombinedGraph.
	 * 
	 * @param columnVect
	 *            the column names
	 * @param combinedGraphType
	 *            If method is calling for BarGraph then pass "bar" otherwise "line"
	 * @return Axis display name
	 */
	private Vector getAxisDisplayNameCombined(Vector columnVect, String combinedGraphType, SmartenInfo graphInfo) {
		Vector newDisplayVect = new Vector();

		if (columnVect != null && columnVect.size() > 0) {
			for (int i = 0; i < columnVect.size(); i++) {
				newDisplayVect.add(
						getAxisDisplayNameCombined(String.valueOf(columnVect.get(i)), combinedGraphType, graphInfo));
			}
		}
		return newDisplayVect;
	}

	/**
	 * To get display name of axis. This method is useful only for CombinedGraph.
	 * 
	 * @param columnName
	 *            the column names
	 * @param combinedGraphType
	 *            If method is calling for BarGraph then pass "bar" otherwise "line"
	 * @return new display name
	 */
	public String getAxisDisplayNameCombined(String columnName, String combinedGraphType, SmartenInfo graphInfo) {
		String newDisplayName = columnName;
		HashMap axisValueMap = graphInfo.getAxisValueMap();

		if (axisValueMap != null) {
			if (combinedGraphType.equalsIgnoreCase("bar"))
				columnName = columnName.concat("_BAR");
			if (combinedGraphType.equalsIgnoreCase("line"))
				columnName = columnName.concat("_LINE");

			if (axisValueMap.containsKey(columnName)
					&& !(newDisplayName.equals(String.valueOf(axisValueMap.get(columnName))))) {
				newDisplayName = String.valueOf(axisValueMap.get(columnName)).concat(" [ " + newDisplayName + " ]");
			} else {

				if (graphInfo.isMultipleYAxisLabelsEnable() || graphInfo.isMultipleYAxisLabelsEnableForCombineLine()) {
					newDisplayName = getMMDisplayNameCombined(newDisplayName, combinedGraphType, graphInfo);
				}
			}
		}
		return newDisplayName;
	}

	/**
	 * Get Vector Containing Data Columns Sequence ( For Combined Graph Line).
	 * 
	 * @return Data columns
	 */
	private Vector getCombinedLineDataLabelsInSequence(SmartenInfo graphInfo) {
		Vector theDataColLabels4 = graphInfo.getTheDataColLabels4();

		if (theDataColLabels4.size() == 0) {
			if (graphInfo.getLineGraphDataLabelsForCombinedGraph() != null)
				theDataColLabels4 = (Vector) graphInfo.getLineGraphDataLabelsForCombinedGraph().clone();
			else
				theDataColLabels4 = new Vector();
		}

		graphInfo.setTheDataColLabels4(theDataColLabels4);

		return theDataColLabels4;
	}

	/**
	 * This function returns the Display name of the specified Measure Column Name.
	 * This method is useful only for CombinedGraph.
	 * 
	 * @param columnName
	 *            the column name
	 * @param combinedGraphType
	 *            If method is calling for BarGraph then pass "bar" otherwise "line"
	 * @return Multiple measure display name
	 */
	private String getMMDisplayNameCombined(String columnName, String combinedGraphType, SmartenInfo graphInfo) {
		Vector multiMeasureVect = new Vector();
		if (combinedGraphType.equalsIgnoreCase("bar"))
			multiMeasureVect = graphInfo.getMultiMeasureDisplayValues();
		if (combinedGraphType.equalsIgnoreCase("line"))
			multiMeasureVect = graphInfo.getMultiMeasureDisplayValues1();

		if (multiMeasureVect != null && multiMeasureVect.size() > 0) {
			int displayVectLength = multiMeasureVect.size();
			for (int i = 0; i < displayVectLength; i++) {
				String[] values = (String[]) multiMeasureVect.get(i);

				if (columnName.equals(values[0]) && !values[0].equals(values[1])) {
					String newDisplayName = null;
					newDisplayName = values[1].concat(" [ " + columnName + " ]");
					return newDisplayName;
				}
			}
		}

		return columnName;
	}

	/**
	 * To get the formated data objects.
	 * 
	 * @param graphInfo
	 *            SmartenInfo
	 * @param userInfo
	 *            UserInfo
	 * @return formated data objects
	 */
	public ArrayList getFormatedDataList(SmartenInfo graphInfo, UserInfo userInfo) {
		ArrayList formatDataList = new ArrayList();
		ArrayList dataList = null;
		Vector m_dataVector = graphInfo.getGraphDataVector();
		Hashtable<String, Vector<Object>> m_dataFormat = graphInfo.getColumnFormat();

		int digitsAfterDecimal = 0;
		List dateCollabelList = graphInfo.getDataColLabels3();
		boolean isDecInUDDCORInMeasure = false;
		if (null != graphInfo.getColColumns() && !graphInfo.getColColumns().isEmpty()
				&& graphInfo.getColColumns().size() > 0) {
			isDecInUDDCORInMeasure = isMeasureOrUDDC(graphInfo.getColColumns().get(0).toString(), graphInfo,
					userInfo);
		}
		if (m_dataVector != null && m_dataVector.size() > 0) {
			Vector vectColLabel = (Vector) m_dataVector.elementAt(0);
			formatDataList.add((Vector) m_dataVector.elementAt(0));
			String[] colName = (String[]) vectColLabel.toArray(new String[0]);
			HashMap hmFormatObj = new HashMap();
			long columnStart = System.currentTimeMillis();
			ApplicationLog.debug(" column names START");
			for (int i = 0; i < colName.length; i++) {
				digitsAfterDecimal = 0;
				
				if (dateCollabelList.contains(colName[i])
						&& graphInfo.getGraphType() != GraphConstants.COMBINED_GRAPH) {
					if (graphInfo.getGraphType() == GraphConstants.HBAR_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.VBAR_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.STACKED_HBAR_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.STACKED_VBAR_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.PERCENTAGE_HBAR_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.PERCENTAGE_VBAR_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.LINE_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.STACKED_LINE_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.PERCENTAGE_LINE_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.AREA_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.AREA_PERCENTAGE_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.AREA_STACK_GRAPH) {
						if (graphInfo.getGraphProperties().getyAxisPropertiesMap().get("M" + i) != null)
							digitsAfterDecimal = graphInfo.getGraphProperties().getyAxisPropertiesMap().get("M" + i)
									.getLabelProperties().getNumberOfDigits();
					}
					if (graphInfo.getGraphType() == GraphConstants.DRILLED_RADAR_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.DRILLED_STACKED_RADAR_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.HEAT_MAP_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.CANDLE_STICK_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.HIGH_LOW_OPEN_CLOSE_GRAPH) {
						digitsAfterDecimal = graphInfo.getGraphProperties().getDataValueProperties().getNumberFormat()
								.getNumberOfDigits();
					}
					if (graphInfo.getGraphType() == GraphConstants.PIE_GRAPH) {
						if (graphInfo.getGraphProperties().getDataValuePropertiesMap().get(
								"M" + i % graphInfo.getGraphProperties().getDataValuePropertiesMap().size()) != null) {
							digitsAfterDecimal = graphInfo.getGraphProperties().getDataValuePropertiesMap()
									.get("M" + i % graphInfo.getGraphProperties().getDataValuePropertiesMap().size())
									.getNumberFormat().getNumberOfDigits();
							;
						}
					}
					if (graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH) {
						if (isDecInUDDCORInMeasure || (graphInfo.getGraphData().getColLabel() != null
								&& graphInfo.getGraphData().getColLabel().equals("")
								&& graphInfo.getDataColLabels3().size() >= 2))
						{
							if (dateCollabelList.indexOf(colName[i]) == 0)
								digitsAfterDecimal = graphInfo.getGraphProperties().getxAxisProperties()
										.getLabelProperties().getNumberOfDigits();
							if (dateCollabelList.indexOf(colName[i]) == 1)
								digitsAfterDecimal = graphInfo.getGraphProperties().getyAxisPropertiesMap().get("M0")
										.getLabelProperties().getNumberOfDigits();
							if (dateCollabelList.indexOf(colName[i]) == 2)
								digitsAfterDecimal = graphInfo.getGraphProperties().getDataValueProperties()
										.getNumberFormat().getNumberOfDigits();
						} else {
							if (dateCollabelList.indexOf(colName[i]) == 0)
								digitsAfterDecimal = graphInfo.getGraphProperties().getyAxisPropertiesMap().get("M0")
										.getLabelProperties().getNumberOfDigits();
							if (dateCollabelList.indexOf(colName[i]) == 1)
								digitsAfterDecimal = graphInfo.getGraphProperties().getDataValueProperties()
										.getNumberFormat().getNumberOfDigits();
						}
					}
					if (graphInfo.getGraphType() == GraphConstants.NUMERIC_DIAL_GAUGE) {
						digitsAfterDecimal = graphInfo.getGraphProperties().getGaugeDataValueActual().getNumberFormat()
								.getNumberOfDigits();
					}
				} else {
					if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
						if (graphInfo.getDataColLabels3().contains(colName[i]))
							digitsAfterDecimal = graphInfo.getGraphProperties().getCombinedDataValueProperties()
									.getBarnumberFormat().getNumberOfDigits();
						if (graphInfo.getTheDataColLabels4().contains(colName[i]))
							digitsAfterDecimal = graphInfo.getGraphProperties().getCombinedDataValueProperties()
									.getLinenumberFormat().getNumberOfDigits();
					}
				}

				if (getValueFormat(colName[i], m_dataFormat) != null) {
					hmFormatObj.put(colName[i], getValueFormat(colName[i], m_dataFormat));
					ValueFormat valueFormat = getValueFormat(colName[i], m_dataFormat);
					valueFormat.setMaximumFractionDigit(digitsAfterDecimal);
					hmFormatObj.put(colName[i], valueFormat);

				} else if (null != graphInfo.getDataColLabels3() && graphInfo.getDataColLabels3().contains(colName[i])
						|| (null != graphInfo.getTheDataColLabels4()
								&& graphInfo.getTheDataColLabels4().contains(colName[i]))) {
					ValueFormat m_Formatter = new ValueFormat(null);
					m_Formatter.setMaximumFractionDigit(digitsAfterDecimal);
					m_Formatter.setCommaFormat(false);
					m_Formatter.setSuffixUnit(false);
					m_Formatter.setNegativeValRep(0);
					m_Formatter.setCommaPositionStyle(false);
					hmFormatObj.put(colName[i], m_Formatter);
				}

				if (graphInfo.getGraphType() == GraphConstants.D3_CHORD
						|| graphInfo.getGraphType() == GraphConstants.D3_TREEMAP
						|| graphInfo.getGraphType() == GraphConstants.D3_SUNBURST
						|| graphInfo.getGraphType() == GraphConstants.D3_BUBBLE
						|| graphInfo.getGraphType() == GraphConstants.D3_TREELAYOUT) {

					ValueFormat m_Formatter = new ValueFormat(null);
					m_Formatter.setMaximumFractionDigit(2);
					m_Formatter.setCommaFormat(false);
					m_Formatter.setSuffixUnit(false);
					m_Formatter.setNegativeValRep(0);
					m_Formatter.setCommaPositionStyle(false);
					hmFormatObj.put(colName[i], m_Formatter);

				}
			}
			long columnEnd = System.currentTimeMillis();
			ApplicationLog.debug(" column names END " + (columnEnd - columnStart));

			int dataVectSize;
			boolean isClusteredGraph = false;
			if (graphInfo.getGraphData().getColLabel() != null && graphInfo.getGraphData().getRowLabel() != null) {
				isClusteredGraph = true;
			}

			ApplicationLog.debug(" formattedGraphData START");
			long formattedGraphData = System.currentTimeMillis();
			Vector vectColLabelOld = vectColLabel;
			Vector vectColLabelActualSize = new Vector();
			vectColLabel = new Vector();
			formatDataList = new ArrayList();
			List smartenColList = graphInfo.getGraphData().getSmartenColList();
			List smartenRowList = graphInfo.getGraphData().getSmartenRowList();
			if (graphInfo.getGraphType() == SmartenConstants.SMARTENVIEW_TABULAR
					|| graphInfo.getGraphType() == SmartenConstants.SMARTENVIEW_MAP
					|| graphInfo.getGraphType() == GraphConstants.D3_CHORD
					|| graphInfo.getGraphType() == GraphConstants.D3_TREEMAP
					|| graphInfo.getGraphType() == GraphConstants.D3_SUNBURST
					|| graphInfo.getGraphType() == GraphConstants.D3_BUBBLE
					|| graphInfo.getGraphType() == GraphConstants.D3_TREELAYOUT) {
				List ignoreDimAndMeasureList = graphInfo.getIgnoreDimAndMeasureList();
				List measures = new ArrayList();
				measures.addAll(graphInfo.getMeasureTitleList());
				if (measures != null && measures.size() > 0 && ignoreDimAndMeasureList != null
						&& ignoreDimAndMeasureList.size() > 0)
					measures.removeAll(ignoreDimAndMeasureList);
				Collections.reverse(measures);
				vectColLabel.addAll(measures);
				List dimensions = new ArrayList();
				dimensions.addAll(graphInfo.getDimensionTitleList());
				if (dimensions != null && dimensions.size() > 0 && ignoreDimAndMeasureList != null
						&& ignoreDimAndMeasureList.size() > 0)
					dimensions.removeAll(ignoreDimAndMeasureList);
				Collections.reverse(dimensions);
				vectColLabel.addAll(dimensions);
				
			} else {
				if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
					if (null != graphInfo.getDataColLabels3() && !graphInfo.getDataColLabels3().isEmpty()) {
						vectColLabel.add(graphInfo.getDataColLabels3().get(0).toString());
					}
					if (null != graphInfo.getTheDataColLabels4() && !graphInfo.getTheDataColLabels4().isEmpty()) {
						vectColLabel.add(graphInfo.getTheDataColLabels4().get(0).toString());
					}
					if (null != graphInfo.getTheDataColLabels4() && graphInfo.getTheDataColLabels4().isEmpty()
							&& graphInfo.getGraphData().isRowMeasure()
							&& null != graphInfo.getGraphData().getColorMeasureLabel())
						vectColLabel.add(graphInfo.getGraphData().getColorMeasureLabel());
					if (null != graphInfo.getGraphData().getShapeLabel()
							&& !graphInfo.getGraphData().getShapeLabel().isEmpty())
						vectColLabel.add(graphInfo.getGraphData().getShapeLabel());
					if (null != graphInfo.getGraphData().getSizeLabel()
							&& !graphInfo.getGraphData().getSizeLabel().isEmpty())
						vectColLabel.add(graphInfo.getGraphData().getSizeLabel());
					if (null != graphInfo.getGraphData().getCmbBarrowLabel()
							&& !graphInfo.getGraphData().getCmbBarrowLabel().isEmpty()
							&& !"Legend".equals(graphInfo.getGraphData().getCmbBarrowLabel()))
						vectColLabel.add(graphInfo.getGraphData().getCmbBarrowLabel());
					if (null != graphInfo.getGraphData().getCmbBarcolLabel()
							&& !graphInfo.getGraphData().getCmbBarcolLabel().isEmpty())
						vectColLabel.add(graphInfo.getGraphData().getCmbBarcolLabel());
				} else {
					Vector dataLabels = graphInfo.getDataColLabels3();
					if (null != graphInfo.getGraphData().getDataLabel()
							&& !graphInfo.getGraphData().getDataLabel().isEmpty()
							&& !"Data".equals(graphInfo.getGraphData().getDataLabel())
							&& graphInfo.getGraphType() != GraphConstants.BUBBLE_GRAPH
							&& graphInfo.getGraphType() != GraphConstants.STACKED_HBAR_GRAPH
							&& graphInfo.getGraphType() != GraphConstants.STACKED_VBAR_GRAPH) {
						vectColLabel.add(graphInfo.getGraphData().getDataLabel());
					} else {
						if (null != dataLabels && !dataLabels.isEmpty()) {
							for (int i = dataLabels.size() - 1; i >= 0; i--) {
								vectColLabel.add(dataLabels.get(i));
							}
						}
					}
					
					if (null != graphInfo.getGraphData().getSizeLabel()
							&& !graphInfo.getGraphData().getSizeLabel().isEmpty()
							&& !vectColLabel.contains(graphInfo.getGraphData().getSizeLabel()))
						vectColLabel.add(graphInfo.getGraphData().getSizeLabel());
					if (null != graphInfo.getGraphData().getRowLabel()
							&& !graphInfo.getGraphData().getRowLabel().isEmpty()
							&& !"Legend".equals(graphInfo.getGraphData().getRowLabel())
							&& !vectColLabel.contains(graphInfo.getGraphData().getRowLabel()))
						vectColLabel.add(graphInfo.getGraphData().getRowLabel());
					if (null != graphInfo.getGraphData().getColLabel()
							&& !graphInfo.getGraphData().getColLabel().isEmpty()
							&& !vectColLabel.contains(graphInfo.getGraphData().getColLabel()))
						vectColLabel.add(graphInfo.getGraphData().getColLabel());
				}
				if (null != smartenColList && !smartenColList.isEmpty())
				{
					for (int i = smartenColList.size() - 1; i >= 0; i--)
						vectColLabel.add(smartenColList.get(i));
				}
				if (null != smartenRowList && !smartenRowList.isEmpty())
				{
					for (int i = smartenRowList.size() - 1; i >= 0; i--)
						vectColLabel.add(smartenRowList.get(i));
				}
				if (graphInfo.getGraphType() == GraphConstants.CANDLE_STICK_GRAPH
						|| graphInfo.getGraphType() == GraphConstants.HIGH_LOW_OPEN_CLOSE_GRAPH) {
					vectColLabelActualSize = new Vector();
					String[] splitString = graphInfo.getGraphData().getDataLabel().split(",");
					for (int i = 0; i < splitString.length; i++)
						vectColLabelActualSize.add(splitString[i]);

					vectColLabelActualSize.add(splitString[0] + "_4");

					for (int j = 1; j < vectColLabelOld.size(); j++)
						vectColLabelActualSize.add(vectColLabelOld.get(j).toString());
				} 
			}
			long formattedGraphDataEnd = System.currentTimeMillis();
			
			ApplicationLog.debug(" formattedGraphData ENDS time " + (formattedGraphDataEnd - formattedGraphData));
			
			if (!graphInfo.isPerformAggregation()) {
				vectColLabel.clear();
				vectColLabel.addAll(graphInfo.getDataColLabels3());
				Collections.reverse(vectColLabel);
			}
			
			Map<String, String> colLabelMap = graphInfo.getGraphProperties().getColLabelsMap();
			Vector newColLabel = new Vector();
			for(int i=0;i<vectColLabel.size();i++)
			{
				if(colLabelMap.get(vectColLabel.get(i)) != null)
					newColLabel.add(colLabelMap.get(vectColLabel.get(i)));
				else
					newColLabel.add(vectColLabel.get(i));
			}
			vectColLabel = new Vector(newColLabel);
			formatDataList.add((Vector) m_dataVector.elementAt(0)); 

			ApplicationLog.debug(" graphData actual loop START");
			long graphData = System.currentTimeMillis();
			for (int i = 1; i < m_dataVector.size(); i++) {
				Vector dataVect = (Vector) m_dataVector.get(i);
				dataList = new ArrayList();
				dataVectSize = dataVect.size();
				if (graphInfo.getGraphType() == GraphConstants.CANDLE_STICK_GRAPH
						|| graphInfo.getGraphType() == GraphConstants.HIGH_LOW_OPEN_CLOSE_GRAPH) {
					dataVectSize = 2;
					if (isClusteredGraph)
						dataVectSize = 3;
					if (null != smartenRowList && !smartenRowList.isEmpty())
						dataVectSize += smartenRowList.size();
					if (null != smartenColList && !smartenColList.isEmpty())
						dataVectSize += smartenColList.size();
				}
				for (int j = 0; j < dataVectSize; j++) {
					String strVal = "";
					String strDataLabel = vectColLabel.get(j).toString();
					if (j != 0 && graphInfo.getGraphType() == GraphConstants.CANDLE_STICK_GRAPH
							|| graphInfo.getGraphType() == GraphConstants.HIGH_LOW_OPEN_CLOSE_GRAPH)
						strVal = getFormatedNumber(
								dataVect.get(vectColLabelActualSize.indexOf(vectColLabel.get(j).toString())),
								vectColLabel.get(j).toString(), hmFormatObj);
					else
						strVal = getFormatedNumber(
								dataVect.get(vectColLabel.indexOf(vectColLabel.get(j).toString())),
								vectColLabel.get(j).toString(), hmFormatObj);
					for (String cName : colName) {
						if (null != graphInfo.getPackDDVMValues() && graphInfo.getPackDDVMValues().containsKey(cName)) {
							Vector<String[]> packDDVMValues = (Vector<String[]>) graphInfo.getPackDDVMValues()
									.get(cName);
							for (int x = 0; x < packDDVMValues.size(); x++) {
								String[] value = packDDVMValues.get(x);
								if (strVal.equals(value[0])) {
									strVal = value[1];
								}
							}
						}
					}
					dataList.add(strVal);
				}
				formatDataList.add(dataList);
			}
			long graphDataEnd = System.currentTimeMillis();
			ApplicationLog.debug(" graphData actual loop ENDS " + (formattedGraphDataEnd - formattedGraphData));
			hmFormatObj.clear();
		}
		graphInfo.setFormatedDataList(formatDataList);

		return formatDataList;
	}

	/**
	 * To get ValueFormat object from given column name and data format.
	 * 
	 * @param colName
	 *            the column name
	 * @param m_dataFormat
	 *            the data format
	 * @return ValueFormat
	 */
	public ValueFormat getValueFormat(String colName, Hashtable m_dataFormat) {
		if (colName == null)
			return null;
		Vector data = (Vector) m_dataFormat.get(colName);
		ValueFormat m_Formatter = null;
		if (data != null) {
			int colType = ((Integer) data.elementAt(0)).intValue();
			if (colType == DATE_FORMAT) {
				String dateStr = data.elementAt(1).toString();
				String timeStr = data.elementAt(2).toString();
				if (!timeStr.equals("")) {
					dateStr += " " + timeStr;
				}

				m_Formatter = new ValueFormat(dateStr);
			} else if (colType == NUMBER_FORMAT) {
				m_Formatter = new ValueFormat(null);
				if (data.elementAt(2) != null && !data.elementAt(2).equals("")) { 
					m_Formatter.setMaximumFractionDigit(((Integer) data.elementAt(2)).intValue());
				}
				m_Formatter.setCommaFormat(((Boolean) data.elementAt(3)).booleanValue());
				m_Formatter.setSuffixUnit(((Boolean) data.elementAt(5)).booleanValue());
				if (data.elementAt(4) != null && !data.elementAt(4).equals("")) {
					String unitText = data.elementAt(4).toString();
				}
				m_Formatter.setNegativeValRep(((Integer) data.elementAt(1)).intValue());
				m_Formatter.setCommaPositionStyle(((Boolean) data.elementAt(6)).booleanValue());
			}
		}
		return m_Formatter;
	}

	/**
	 * To get format data in string from given valueFormat object.
	 * 
	 * @param valueFormat
	 *            the value formating according its object type
	 * @param obj
	 *            Object
	 * @return format data in string
	 */
	public String getFormatedData(ValueFormat valueFormat, Object obj) {
		return valueFormat.getString(obj);
	}

	/**
	 * Saves all data to CSV.
	 * 
	 * @param in_osOutput
	 *            OutputStream
	 * @param graphInfo
	 *            SmartenInfo
	 * @param userInfo
	 *            UserInfo
	 * @exception RemoteException
	 */
	public void exportGraphDataCSV(OutputStream in_osOutput, SmartenInfo graphInfo, UserInfo userInfo)
			throws RemoteException {
		PrintWriter pwOutput = new PrintWriter(in_osOutput);
		ArrayList dataList = new ArrayList();

		Vector colColLabel = (Vector) graphInfo.getFormatedDataList().get(0);
		for (int i = 1; i < graphInfo.getFormatedDataList().size(); i++) {
			dataList.add(graphInfo.getFormatedDataList().get(i));
		}

		int theRecordCount = dataList.size();
		int theColumnCount = colColLabel.size();

		for (int J = theColumnCount - 1; J >= 0; J--) {
			String columnName = colColLabel.elementAt(J).toString();
			if (J != theColumnCount - 1) {
				pwOutput.print(",");
			}
			pwOutput.print(getAxisDisplayName(columnName, graphInfo));
		}

		for (int i = 0; i < theRecordCount; i++) {
			ArrayList theRow = (ArrayList) dataList.get(i);
			pwOutput.println("");
			for (int J = theColumnCount - 1; J >= 0; J--) 			{
				String value = theRow.get(J).toString();
				if (J != theColumnCount - 1) {
					pwOutput.print(",");
				}
				pwOutput.print(value);
			}
		}
		pwOutput.flush();
	}

	/**
	 * Saves all data to XML.
	 * 
	 * @param in_osOutput
	 *            OutputStream
	 * @param graphInfo
	 *            SmartenInfo
	 * @param userInfo
	 *            UserInfo
	 * @exception RemoteException
	 */
	public void exportGraphDataXML(OutputStream in_osOutput, SmartenInfo graphInfo, UserInfo userInfo,int pageNumber)
			throws RemoteException {
		String rootTag = AppConstants.ROOT_TAG;
		String columnNamesTag = AppConstants.XML_COLUMN_NAMES_TAG;
		String recordTag = AppConstants.XML_RECORD_TAG;
		String columnTag = AppConstants.MSG_TEXT_COLUMN_COLUMNS;

		try {
			BufferedOutputStream bosFile;
			OutputStreamWriter oswFile = null;

			bosFile = new BufferedOutputStream(in_osOutput, 16 * 1024);
			oswFile = new OutputStreamWriter(bosFile, "UTF-8");
			
			int rowCount = graphInfo.getFormatedDataList().size();
			int startIndex = 1;
			int endIndex = rowCount;
			if(pageNumber > 0) {
				setPagination(pageNumber, rowCount-1);
				startIndex = this.getStartRowIndex();
				endIndex = this.getEndRowIndex();				
			}

			ArrayList dataList = new ArrayList();
			Vector colColLabel = (Vector) graphInfo.getFormatedDataList().get(0);
			for (int i = startIndex; i < endIndex; i++) {
				dataList.add(graphInfo.getFormatedDataList().get(i));
			}
			

			int theRecordCount = dataList.size();
			int theColumnCount = colColLabel.size();
			oswFile.write("<?xml version=\"1.0\" encoding=\"utf-8\" ?>");

			oswFile.write("\n");
			oswFile.write("<" + rootTag + ">\n");

			oswFile.write("\t<" + columnNamesTag + ">\n");
			for (int j = theColumnCount - 1; j >= 0; j--) {
				String columnName = colColLabel.elementAt(j).toString();
				oswFile.write("\t\t<" + columnTag + ">");
				oswFile.write(getAxisDisplayName(columnName, graphInfo));// Edited By Nirav
				oswFile.write("</" + columnTag + ">\n");
			}
			oswFile.write("\t</" + columnNamesTag + ">\n");

			for (int i = 0; i < theRecordCount; i++) {
				ArrayList theRow = (ArrayList) dataList.get(i);

				oswFile.write("\t<" + recordTag + ">\n");
				for (int j = theColumnCount - 1; j >= 0; j--) {
					String value = StringEscapeUtils.escapeXml(theRow.get(j).toString());

					oswFile.write("\t\t<" + columnTag + ">");
					oswFile.write(value);
					oswFile.write("</" + columnTag + ">\n");
				}
				oswFile.write("\t</" + recordTag + ">\n");
			}
			oswFile.write("</" + rootTag + ">\n");
			if(pageNumber > 0) {
				oswFile.write("<"+AppConstants.XML_TOTAL_RECORD_TAG+">"+this.getTotalRecord()+"</"+AppConstants.XML_TOTAL_RECORD_TAG+">");
				oswFile.write("<"+AppConstants.XML_TOTAL_PAGE_TAG+">"+this.getPages()+"</"+AppConstants.XML_TOTAL_PAGE_TAG+">");
			}
			oswFile.flush();
		} catch (IOException e) {
			ApplicationLog.error(ResourceManager.getString("LOG_ERROR_MSG_FAILED_TO_DISPLAY_GRAPH_DATA",
					new Object[] { graphInfo.getGraphName(), userInfo.getUsername() }), e);
		}
	}

	/**
	 * DrillDown for combined Graph.
	 * 
	 * @param cdetail
	 *            DrillDownEvent
	 * @param bDrilledFromRoot
	 *            DrillDownEvent is done by tree or by click on graph or legend
	 */
	private void drillDownCombined(DrillDownDetail cdetail, boolean bDrilledFromRoot, SmartenInfo graphInfo,
			UserInfo userInfo, boolean isTreeDrillDown) {
		if (!bDrilledFromRoot) {
			graphInfo.getDrillDownDetailList().addElement(cdetail);
		}

		int itemIndex = cdetail.getDrilledItemIndex();
		int seriesIndex = cdetail.getDrilledSeriesIndex();

		String seriesName = "", itemName = "";
		Object obj;

		obj = cdetail.getDrilledSeriesName();
		if (obj != null) {
			seriesName = obj.toString();
		}
		obj = cdetail.getDrilledItemName();
		if (obj != null) {
			itemName = obj.toString();
		}

		if (graphInfo.getColColumns().size() < 1 && !isTreeDrillDown) {
			itemIndex = seriesIndex;
			itemName = seriesName;
			seriesIndex = -1;
			seriesName = null;
		}

		Vector theColColLabels = graphInfo.getColColumns();
		Vector theRowColLabels2 = graphInfo.getLineGraphRowLabelsForCombinedGraph();
		Vector theRowColLabels = graphInfo.getRowColumns();

		Vector vDrillDownX = graphInfo.getDrillDownListOfX();
		Vector vDrillDownZ = graphInfo.getDrillDownListOfZ();

		Object[][] m_DrillValues = graphInfo.getDrillValues();

		if (itemIndex != -1 && seriesIndex != -1) 
		{
			graphInfo.setDrillDownSeriesLabel(seriesName);
			graphInfo.setDrillDownItemString(itemName);
			vDrillDownX.addElement(seriesName);
			vDrillDownZ.addElement(itemName);

			String barText = graphInfo.getBarDrilldownText();
			String zText = graphInfo.getLegendDrilldownText();
			String xText = graphInfo.getxAxisDrilldownText();

			if (bDrilledFromRoot) {
				int intLength = m_DrillValues[0].length > m_DrillValues[1].length ? m_DrillValues[0].length
						: m_DrillValues[1].length;

				barText = graphInfo.getDrillRootValues().elementAt(1).toString() + ", "
						+ graphInfo.getDrillRootValues().elementAt(0).toString();

				for (int i = 0; i < intLength; i++) {
					barText += " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " ";
					String xTemp = "";
					String zTemp = "";
					if (i < m_DrillValues[0].length) {
						xTemp = m_DrillValues[0][i].toString();
						vDrillDownZ.addElement(xTemp);
					}
					if (i < m_DrillValues[1].length) {
						zTemp = m_DrillValues[1][i].toString();
						vDrillDownX.addElement(zTemp);
					}
					if (xTemp.equals("") || zTemp.equals("")) {
						barText += "" + zTemp + xTemp + "";
					} else {
						barText += "" + zTemp + ", " + xTemp + "";
					}
				}

			} else {
				String sTemp = "";
				if (barText.equals("") || barText == null) {
					barText = "" + seriesName + ", " + itemName + "";
				} else {
					sTemp = "" + seriesName + ", " + itemName + "";
					barText += " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + sTemp;
				}

				if (!(zText.equals("") || zText == null)) {
					barText = zText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + barText;
					zText = "";
				}
				if (!(xText.equals("") || xText == null)) {
					barText = xText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + barText;
					xText = "";
				}
			}

			graphInfo.setBarDrilldownText(barText);
			graphInfo.setLegendDrilldownText(zText);
			graphInfo.setxAxisDrilldownText(xText);

			if (graphInfo.getCombinedPointOnGraph() == 1) 
			{
				if (graphInfo.getRowIndexForLineGraphInCombinedGraph() > 0 && graphInfo.getColIndex() > 0) {

					int m_rowIndex2 = graphInfo.getRowIndexForLineGraphInCombinedGraph();
					int m_seriesPos = graphInfo.getSeriesPos();
					int m_itemPos = graphInfo.getItemPos();
					int m_colIndex = graphInfo.getColIndex();

					if (m_rowIndex2 + 1 <= theRowColLabels2.size() || m_colIndex + 1 <= theColColLabels.size()) {

						m_seriesPos = -1;
						m_itemPos = -1;
						if (m_rowIndex2 + 1 <= theRowColLabels2.size()) {
							m_rowIndex2 = m_rowIndex2 + 1;
							m_itemPos = itemIndex + 1;
						}
						if (m_colIndex + 1 <= theColColLabels.size()) {
							m_colIndex = m_colIndex + 1;
							m_seriesPos = seriesIndex + 1;
						}
						graphInfo.setDrillUpOperation(false);

						graphInfo.setRowIndexForLineGraphInCombinedGraph(m_rowIndex2);
						graphInfo.setSeriesPos(m_seriesPos);
						graphInfo.setItemPos(m_itemPos);
						graphInfo.setColIndex(m_colIndex);

						boolean setGraphFlag = setGraph(false, graphInfo, userInfo);
						if (!bDrilledFromRoot) {
								if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
									graphInfo.getRowVectorDrillDownInfoForCombinedGraph()
											.add(graphInfo.getCombinedPointOnGraph());
								}
								setDrillDown(graphInfo);
							}
						}

				}
			} else if (graphInfo.getCombinedPointOnGraph() == 0) 
			{
				if (graphInfo.getRowIndex() > 0 && graphInfo.getColIndex() > 0) {

					int m_rowIndex = graphInfo.getRowIndex();
					int m_colIndex = graphInfo.getColIndex();
					int m_seriesPos = graphInfo.getSeriesPos();
					int m_itemPos = graphInfo.getItemPos();

					if (m_rowIndex + 1 <= theRowColLabels.size() || m_colIndex + 1 <= theColColLabels.size()) {
						m_seriesPos = -1;
						m_itemPos = -1;
						
						if (m_rowIndex + 1 <= theRowColLabels.size()) {
							m_rowIndex = m_rowIndex + 1;
							m_itemPos = itemIndex + 1;
						}
						if (m_colIndex + 1 <= theColColLabels.size()) {
							m_colIndex = m_colIndex + 1;
							m_seriesPos = seriesIndex + 1;
						}
						graphInfo.setDrillUpOperation(false);

						graphInfo.setRowIndex(m_rowIndex);
						graphInfo.setColIndex(m_colIndex);
						graphInfo.setSeriesPos(m_seriesPos);
						graphInfo.setItemPos(m_itemPos);

						boolean setGraphFlag = setGraph(false, graphInfo, userInfo);
						if (!setGraphFlag) 
						{
							
						} else 
						{
							
							if (!bDrilledFromRoot) {
								if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
									graphInfo.getRowVectorDrillDownInfoForCombinedGraph()
											.add(graphInfo.getCombinedPointOnGraph());
								}
								setDrillDown(graphInfo);
							}

						}
					}
				}
			}

		} else if (itemIndex != -1 && seriesIndex == -1) 
		{
			graphInfo.setDrillDownItemString(itemName);
			vDrillDownZ.addElement(itemName);

			String zText = graphInfo.getLegendDrilldownText();
			String barText = graphInfo.getBarDrilldownText();
			String xText = graphInfo.getxAxisDrilldownText();

			if (bDrilledFromRoot) {
				int intLength = m_DrillValues[0].length;

				zText = graphInfo.getDrillRootValues().elementAt(0).toString();
				for (int i = 0; i < intLength; i++) {
					String xTemp = "";
					xTemp = m_DrillValues[0][i].toString();
					zText += " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + xTemp + "";
					vDrillDownZ.addElement(xTemp);
				}
			} else {
				if (zText.equals("") || zText == null) {
					zText = itemName;
				} else {
					zText += " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + itemName;
				}

				if (!(barText.equals("") || barText == null)) {
					zText = barText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + zText;
					barText = "";
				}
				if (!(xText.equals("") || xText == null)) {
					zText = xText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + zText;
					xText = "";
				}
			}

			graphInfo.setLegendDrilldownText(zText);
			graphInfo.setBarDrilldownText(barText);
			graphInfo.setxAxisDrilldownText(xText);

			if (graphInfo.getCombinedPointOnGraph() == 1) 
			{
				if (graphInfo.getRowIndexForLineGraphInCombinedGraph() > 0) {

					int m_rowIndex2 = graphInfo.getRowIndexForLineGraphInCombinedGraph();
					int m_itemPos = graphInfo.getItemPos();

					if (m_rowIndex2 + 1 <= theRowColLabels2.size()) {
						m_rowIndex2 = m_rowIndex2 + 1;

						m_itemPos = itemIndex + 1;

						graphInfo.setSeriesPos(-1);
						graphInfo.setDrillUpOperation(false);

						graphInfo.setRowIndexForLineGraphInCombinedGraph(m_rowIndex2);
						graphInfo.setItemPos(m_itemPos);

						boolean setGraphFlag = setGraph(false, graphInfo, userInfo);
						if (!bDrilledFromRoot) {
								if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
									graphInfo.getRowVectorDrillDownInfoForCombinedGraph()
											.add(graphInfo.getCombinedPointOnGraph());
								}
								setDrillDown(graphInfo);
							}

						
					}
				}
			} else if (graphInfo.getCombinedPointOnGraph() == 0) 
			{
				if (graphInfo.getRowIndex() > 0) {

					int m_rowIndex = graphInfo.getRowIndex();
					int m_itemPos = graphInfo.getItemPos();

					if (m_rowIndex + 1 <= theRowColLabels.size()) {
						m_rowIndex = m_rowIndex + 1;
						m_itemPos = itemIndex + 1;

						graphInfo.setSeriesPos(-1);
						graphInfo.setDrillUpOperation(false);

						graphInfo.setRowIndex(m_rowIndex);
						graphInfo.setItemPos(m_itemPos);

						boolean setGraphFlag = setGraph(false, graphInfo, userInfo);
							if (!bDrilledFromRoot) {
								if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {
									graphInfo.getRowVectorDrillDownInfoForCombinedGraph()
											.add(graphInfo.getCombinedPointOnGraph());
								}
								setDrillDown(graphInfo);
							}

					}
				}
			}


		} else if (itemIndex == -1 && seriesIndex != -1) 
		{
			graphInfo.setDrillDownSeriesLabel(seriesName);
			vDrillDownX.addElement(seriesName);

			String barText = graphInfo.getBarDrilldownText();
			String zText = graphInfo.getLegendDrilldownText();
			String xText = graphInfo.getxAxisDrilldownText();

			if (bDrilledFromRoot) {
				int intLength = m_DrillValues[1].length;

				xText = graphInfo.getDrillRootValues().elementAt(0).toString();
				for (int i = 0; i < intLength; i++) {
					String xTemp = "";
					xTemp = m_DrillValues[1][i].toString();
					xText += " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + xTemp + "";
					vDrillDownX.addElement(xTemp);
				}
			} else {
				if (xText.equals("") || xText == null) {
					xText = seriesName;
				} else {
					xText += " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + seriesName;
				}
				if (!(barText.equals("") || barText == null)) {
					xText = barText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + xText;
					barText = "";
				}
				if (!(zText.equals("") || zText == null)) {
					xText = zText + " " + SmartenConstants.LABEL_DRILLDOWN_PATH_SEPARATOR + " " + xText;
					zText = "";
				}
			}

			graphInfo.setLegendDrilldownText(zText);
			graphInfo.setBarDrilldownText(barText);
			graphInfo.setxAxisDrilldownText(xText);

			if (graphInfo.getColIndex() > 0) {

				int m_colIndex = graphInfo.getColIndex();
				int m_seriesPos = graphInfo.getSeriesPos();

				if (m_colIndex + 1 <= theColColLabels.size()) {

					m_colIndex = m_colIndex + 1;
					m_seriesPos = seriesIndex + 1;

					graphInfo.setItemPos(-1);
					graphInfo.setDrillUpOperation(false);

					graphInfo.setColIndex(m_colIndex);
					graphInfo.setSeriesPos(m_seriesPos);

					boolean setGraphFlag = setGraph(false, graphInfo, userInfo);

					if (!bDrilledFromRoot) {
							setDrillDown(graphInfo);
						}


				}
			}
		}
		else if (itemIndex == -1 && seriesIndex == -1) {
		}
	}

	/**
	 * Restores Drill Down data for CombinedGraph.
	 */
	private void getDrillDownCombined(SmartenInfo graphInfo) {

		Vector m_drillVectorCombined = graphInfo.getDrillVectorForCombined();
		Vector m_vectRowDrillDownInfo = graphInfo.getRowVectorDrillDownInfoForCombinedGraph();

		if (m_drillVectorCombined == null || m_drillVectorCombined.size() < 1) {
			clearDrillUpConditions(false, graphInfo);
			return;
		}

		Vector record = (Vector) m_drillVectorCombined.elementAt(m_drillVectorCombined.size() - 1);

		int iTmpDrillIndex = -1;

		int m_rowIndex = graphInfo.getRowIndex();
		int m_colIndex = graphInfo.getColIndex();
		int m_rowIndex2 = graphInfo.getRowIndexForLineGraphInCombinedGraph();
		int m_itemPos = graphInfo.getItemPos();
		int m_seriesPos = graphInfo.getSeriesPos();

		if (graphInfo.getDrillUpDimName() != null && graphInfo.getDrillUpDimName().length() > 0) {

			Vector tmpDrillVector = new Vector();
			Vector tmpDrillDetailVector = new Vector();
			Vector tmpRowDrillDownInfo = new Vector();
			int index1 = 2;
			int index2 = 2;
			int iRowDrillDownIndex = 0;

			Vector m_vecDrillDownDetail = graphInfo.getDrillDownDetailList();

			int drillColIndex = graphInfo.getDrillColIndex();
			int drillRowIndex = graphInfo.getDrillRowIndex();

			if (drillColIndex != -1) {

				m_itemPos = -1;
				m_seriesPos = 1;
				iTmpDrillIndex = drillColIndex;
				drillColIndex = m_colIndex;
				m_colIndex = iTmpDrillIndex;

				graphInfo.setDrillColIndex(drillColIndex);

				for (int i = 0; i < m_drillVectorCombined.size(); i++) {
					record = (Vector) m_drillVectorCombined.get(i);

					if (m_colIndex >= (Integer) record.get(2)) {
						tmpDrillVector.add(record);
						index1 = (Integer) record.get(0) + 1;
						index2 = (Integer) record.get(1) + 1;
						tmpDrillDetailVector.add(m_vecDrillDownDetail.get(i));
					} else if (index1 == (Integer) record.get(0)) {
						record.set(2, m_colIndex);
						index1++;
						index2 = (Integer) record.get(1) + 1;
						tmpDrillVector.add(record);
						tmpDrillDetailVector.add(m_vecDrillDownDetail.get(i));
					} else if (index2 == (Integer) record.get(1)) {
						record.set(2, m_colIndex);
						index2++;
						index1 = (Integer) record.get(0) + 1;
						tmpDrillVector.add(record);
						tmpDrillDetailVector.add(m_vecDrillDownDetail.get(i));
					}
				}
			} else if (drillRowIndex != -1) {
				m_itemPos = 1;
				m_seriesPos = -1;

				if (graphInfo.getDrillUpType() == 0) {

					iTmpDrillIndex = drillRowIndex;
					drillRowIndex = m_rowIndex;
					m_rowIndex = iTmpDrillIndex;

					graphInfo.setDrillRowIndex(drillRowIndex);

					for (int i = 0; i < m_drillVectorCombined.size(); i++) {

						record = (Vector) m_drillVectorCombined.get(i);

						if (m_rowIndex >= (Integer) record.get(0)) {
							tmpDrillVector.add(record);
							index1 = (Integer) record.get(1) + 1;
							index2 = (Integer) record.get(2) + 1;
							tmpDrillDetailVector.add(m_vecDrillDownDetail.get(i));
							if ((Integer) record.get(3) == -1 && (Integer) record.get(4) != -1)
								tmpRowDrillDownInfo.add(m_vectRowDrillDownInfo.get(iRowDrillDownIndex++));
						} else if (index1 == (Integer) record.get(1)) {
							record.set(0, m_rowIndex);
							index1++;
							index2 = (Integer) record.get(2) + 1;
							tmpDrillVector.add(record);
							tmpDrillDetailVector.add(m_vecDrillDownDetail.get(i));
							tmpRowDrillDownInfo.add(m_vectRowDrillDownInfo.get(iRowDrillDownIndex++));
						} else if (index2 == (Integer) record.get(2)) {
							record.set(0, m_rowIndex);
							index2++;
							index1 = (Integer) record.get(1) + 1;
							tmpDrillVector.add(record);
							tmpDrillDetailVector.add(m_vecDrillDownDetail.get(i));
						} else {
							iRowDrillDownIndex++;
						}
					}
				} else {
					iTmpDrillIndex = drillRowIndex;
					drillRowIndex = m_rowIndex2;
					m_rowIndex2 = iTmpDrillIndex;

					for (int i = 0; i < m_drillVectorCombined.size(); i++) {

						record = (Vector) m_drillVectorCombined.get(i);

						if (m_rowIndex2 >= (Integer) record.get(1)) {
							tmpDrillVector.add(record);
							index1 = (Integer) record.get(0) + 1;
							index2 = (Integer) record.get(2) + 1;
							tmpDrillDetailVector.add(m_vecDrillDownDetail.get(i));
							if ((Integer) record.get(3) == -1 && (Integer) record.get(4) != -1)
								tmpRowDrillDownInfo.add(m_vectRowDrillDownInfo.get(iRowDrillDownIndex++));
						} else if (index1 == (Integer) record.get(0)) {
							record.set(1, m_rowIndex2);
							index1++;
							index2 = (Integer) record.get(2) + 1;
							tmpDrillVector.add(record);
							tmpDrillDetailVector.add(m_vecDrillDownDetail.get(i));
							tmpRowDrillDownInfo.add(m_vectRowDrillDownInfo.get(iRowDrillDownIndex++));
						} else if (index2 == (Integer) record.get(2)) {
							record.set(1, m_rowIndex2);
							index2++;
							index1 = (Integer) record.get(0) + 1;
							tmpDrillVector.add(record);
							tmpDrillDetailVector.add(m_vecDrillDownDetail.get(i));
						} else {
							iRowDrillDownIndex++;
						}
					}
				}
				m_vectRowDrillDownInfo = tmpRowDrillDownInfo;

				graphInfo.setRowVectorDrillDownInfoForCombinedGraph(m_vectRowDrillDownInfo);
			}
			m_drillVectorCombined = tmpDrillVector;
			tmpDrillDetailVector.add(new DrillDownDetail(-1, null, -1, null, -1, null));
			m_vecDrillDownDetail = tmpDrillDetailVector;

			graphInfo.setDrillVectorForCombined(m_drillVectorCombined);
		} else {
			m_rowIndex = ((Integer) record.elementAt(0)).intValue();
			m_rowIndex2 = ((Integer) record.elementAt(1)).intValue();
			m_colIndex = ((Integer) record.elementAt(2)).intValue();
			m_seriesPos = ((Integer) record.elementAt(3)).intValue();
			m_itemPos = ((Integer) record.elementAt(4)).intValue();
			m_drillVectorCombined.remove(record);
			if (m_itemPos != -1 && m_seriesPos == -1) {
				graphInfo.setDrillUpType((Integer) m_vectRowDrillDownInfo.get(m_vectRowDrillDownInfo.size() - 1));
				m_vectRowDrillDownInfo.remove(m_vectRowDrillDownInfo.size() - 1);
			}
		}

		graphInfo.setRowIndex(m_rowIndex);
		graphInfo.setColIndex(m_colIndex);
		graphInfo.setRowIndexForLineGraphInCombinedGraph(m_rowIndex2);
		graphInfo.setItemPos(m_itemPos);
		graphInfo.setSeriesPos(m_seriesPos);

		if (m_drillVectorCombined.size() < 1) {
			clearDrillUpConditions(false, graphInfo);
		}
		graphInfo.setDrillUpOperation(true);

		graphInfo.getDrillDownListOfX().clear();
		graphInfo.getDrillDownListOfZ().clear();
	}

	/**
	 * Resets DrillDown vector for combined Graph.
	 */
	private void resetDrillVectorCombined(SmartenInfo graphInfo) {
		if (graphInfo.getDrillVectorForCombined() != null && graphInfo.getDrillVectorForCombined().size() >= 1) {
			graphInfo.getDrillVectorForCombined().removeAllElements();
		}
		if (graphInfo.getRowVectorDrillDownInfoForCombinedGraph() != null
				&& graphInfo.getRowVectorDrillDownInfoForCombinedGraph().size() >= 1) {
			graphInfo.getRowVectorDrillDownInfoForCombinedGraph().removeAllElements();
		}
	}

