			if (rankList != null) {
				for (int i = 0; i < rankList.size(); i++) {
					ArrayList tempCol = new ArrayList();
					tempCol.addAll(rowLabels);
					ArrayList tempRow = new ArrayList();
					tempRow.addAll(colLabeList);
					colRankVal = getRankInString(rankList.get(i), tempCol, tempRow, graphInfo);
					allRankList.add(colRankVal);
				}
			}
