	/**
	 * This method is use to generat required data for graph.
	 * 
	 * @param graphInfo
	 * @param params
	 * @return
	 */
	public Map generateRequiredItemsForGraph(SmartenInfo graphInfo, Map<String, String> params) {
		params.put("tdProperty", getDashbordTdId());
		String imageMapData = pushGraphImageMapData(graphInfo, params);
		String strGraphCss = "";

		boolean isD3Graph = false;
		if (graphInfo.getGraphType() == SmartenConstants.SMARTENVIEW_MAP
				&& graphInfo.getGraphProperties().getMapAreaProperties() != null) {
			
			if (getDashbordTdId().equalsIgnoreCase(""))					
				strGraphCss = graphInfo.getGraphProperties().generateSmartenMapCss(graphInfo, getDashbordTdId()+"");
			else 
				strGraphCss = graphInfo.getGraphProperties().generateSmartenMapCss(graphInfo, "mapDivDimension"+getDashbordTdId()+" .");
		}
		else if (!isD3Graph) {
			if (getDashbordTdId().equalsIgnoreCase(""))
				strGraphCss = graphInfo.getGraphProperties().generateSmartenCss(graphInfo, isXAxisVisible(graphInfo),
						isYAxisVisible(graphInfo), "");
			else {
					strGraphCss = graphInfo.getGraphProperties().generateSmartenCss(graphInfo,
							isXAxisVisible(graphInfo), isYAxisVisible(graphInfo),
							getDashbordTdId() + "dashboard-chart-dim .");
			}
		}

		Vector<Object[]> legends = new Vector<Object[]>();
		Map map = new HashMap();
		
		List<String> activeRankDimNameList = new ArrayList<String>();
		CubeRankDataLabel rankDataLabel = null;
		if(graphInfo.getRankList() !=null && !graphInfo.getRankList().isEmpty()) {
			for (int cnt = 0; cnt < graphInfo.getRankList().size(); cnt++) {
				rankDataLabel = graphInfo.getRankList().get(cnt);
				if(null != rankDataLabel && rankDataLabel.isShowOthers() && rankDataLabel.isStatus())
				{
					activeRankDimNameList.add(rankDataLabel.getColumnName());
				}
			}
		}
		
		if (graphInfo.getGraphType() == SmartenConstants.COMBINED_GRAPH) {

			map.put("legendDrilldownLinkMapForLineGrf", graphInfo.getLegendDrilldownLinkMapForLineGraph());

			String[] str = imageMapData.split("~");
			
			List barRowList = graphInfo.getGraphData().getCmbBarrowList();
			List lineRowList = graphInfo.getGraphData().getCmbLinerowList();
			List colList = graphInfo.getGraphData().getCmbBarcolList();
			String barRowLabel = graphInfo.getGraphData().getCmbBarrowLabel();
			String barColLabel = graphInfo.getGraphData().getCmbBarcolLabel();
			String lineRowLabel = graphInfo.getGraphData().getCmbLinerowLabel();
			int colCnt = 0, barCnt = 0, lineCnt = 0, colListSize = 0, barRowListSize = 0, lineRowListSize = 0;
			if(null != colList && !colList.isEmpty())
				colListSize = colList.size();
			if(null != barRowList && !barRowList.isEmpty())
				barRowListSize = barRowList.size();
			if(null != lineRowList && !lineRowList.isEmpty())
				lineRowListSize = lineRowList.size();
			
			if (str.length > 0) {
				for (String barstr : str[0].split(";")) {
					if(null != colList && !colList.isEmpty() && colCnt < colListSize && colList.get(colCnt) != null && null != barColLabel && activeRankDimNameList.contains(barColLabel)
							&& colList.get(colCnt) instanceof String && ICubeConstants.OTHER_STRING.equals(colList.get(colCnt)))
					{
						graphInfo.getGraphData().getDrillColLinkList().add("null");
					}
					else
					{
						graphInfo.getGraphData().getDrillColLinkList().add(barstr);
					}
					colCnt++;
				}
				for (String linestr : str[1].split(";")) {
					if(null != barRowList && !barRowList.isEmpty() && barCnt < barRowListSize && barRowList.get(barCnt) != null && null != barRowLabel && activeRankDimNameList.contains(barRowLabel)
							&& barRowList.get(barCnt) instanceof String && ICubeConstants.OTHER_STRING.equals(barRowList.get(barCnt)))
					{
						graphInfo.getGraphData().getDrillBarLinkList().add("null");
					}
					else
					{
						graphInfo.getGraphData().getDrillBarLinkList().add(linestr);
					}
					barCnt++;
				}
				for (String linestr : str[2].split(";")) {
					if(null != lineRowList && !lineRowList.isEmpty() && lineCnt < lineRowListSize && lineRowList.get(lineCnt) != null && null != lineRowLabel && activeRankDimNameList.contains(lineRowLabel)
							&& lineRowList.get(lineCnt) instanceof String && ICubeConstants.OTHER_STRING.equals(lineRowList.get(lineCnt)))
					{
						graphInfo.getGraphData().getDrillLineLinkList().add("null");
					}
					else
					{
						graphInfo.getGraphData().getDrillLineLinkList().add(linestr);
					}
					lineCnt++;
				}
			}

		}
		if (graphInfo.getGraphType() == SmartenConstants.SMARTENVIEW_MAP
				&& null != graphInfo.getGraphData().getMapdataValueList()
				&& graphInfo.getGraphData().getMapdataValueList().isEmpty()) {
			graphInfo.setGraphVisible(false);
		}

		if (!graphInfo.isGraphVisible()) {
			String strErrorMsg = ResourceManager.getString("ERROR_NO_DATA_FOUND_VERIFY_CONDITION");
			if (getNodatafoundErrorCode() != null && !getNodatafoundErrorCode().equals("")) {
				if (getNodatafoundErrorCode().equals("NoDataFound101")) {
					strErrorMsg = ResourceManager.getString("ERROR_NO_DATA_FOUND_ZERO_RECORD_CUBE");
				} else if (getNodatafoundErrorCode().equals("NoDataFound102")) {
					strErrorMsg = ResourceManager.getString("ERROR_NO_DATA_FOUND_VERIFY_CONDITION");
				} else if (getNodatafoundErrorCode().equals("NoDataFound103")) {
					strErrorMsg = ResourceManager.getString("ERROR_NO_DATA_FOUND_COLUMN_ACCESS");
				} else if (getNodatafoundErrorCode().equals("NoDataFound104")) {
					strErrorMsg = ResourceManager.getString("ERROR_NO_DATA_FOUND_MEASURE_ACCESS");
				} else if (getNodatafoundErrorCode().equals("NoDataFound105")) {
					strErrorMsg = ResourceManager.getString("ERROR_NO_DATA_FOUND_CUBE_MEASURE_ACCESS");
				} else if (getNodatafoundErrorCode().equals("NoDataFound106")) {
					strErrorMsg = ResourceManager.getString("ERROR_NO_DATA_FOUND_CUBE_COLUMN_ACCESS");
				} else if (getNodatafoundErrorCode().equals("NoDataFound107")) {
					strErrorMsg = ResourceManager.getString("ERROR_NO_DATA_FOUND_OBJECT_FILTER");
				} else if (getNodatafoundErrorCode().equals("NoDataFound108")) {
					strErrorMsg = ResourceManager.getString("ERROR_NO_DATA_FOUND_OBJECT_DATA_ACCESS_FILTER");
				} else if (getNodatafoundErrorCode().equals("NoDataFound109")) {
					strErrorMsg = ResourceManager.getString("ERROR_NO_DATA_FOUND_OBJECT_RETRIEVAL_FILTER");
				} else if (getNodatafoundErrorCode().equals("NoDataFound110")) {
					strErrorMsg = ResourceManager.getString("ERROR_NO_DATA_FOUND_OBJECT_DRILL_FILTER");
				} else if (getNodatafoundErrorCode().equals("NoDataFound111")) {
					strErrorMsg = ResourceManager.getString("ERROR_NO_DATA_FOUND_OBJECT_PAGE_FILTER");
				} else if (getNodatafoundErrorCode().equals("NoDataFound112")) {
					strErrorMsg = ResourceManager.getString("ERROR_NO_DATA_FOUND_OBJECT_CUBE_FILTER");
				} else {
					strErrorMsg = ResourceManager.getString("ERROR_NO_DATA_FOUND_VERIFY_CONDITION");
				}
			}
			if (graphInfo.getGraphType() == SmartenConstants.SMARTENVIEW_MAP
					&& null != graphInfo.getGraphData().getMapdataValueList()
					&& graphInfo.getGraphData().getMapdataValueList().isEmpty())
				strErrorMsg = ResourceManager.getString("ERROR_MSG_BLANKINFO_MSG_NO_DATA_FOUND");
			map.put("errorMessage", strErrorMsg);
		} else {
			map.put("errorMessage", "");
		}
		map.put("imageMapData", imageMapData);
		if (imageMapData != null) {
			
			List rowList = graphInfo.getGraphData().getRowList();
			List colList = graphInfo.getGraphData().getColList();
			String rowLabel = graphInfo.getGraphData().getRowLabel();
			String colLabel = graphInfo.getGraphData().getColLabel();
			int rowListSize = 0, colListSize = 0;
			if(null != rowList && !rowList.isEmpty() && null != rowLabel && !"Legend".equalsIgnoreCase(rowLabel)) {
				rowListSize = rowList.size();
			}
			if(null != colList && !colList.isEmpty()) {
				colListSize = colList.size();
			}
			int cnt = 0;
			boolean colStart = false;
			
			List<String> drillList = new ArrayList<String>();
			for (String str : imageMapData.split(";")) {
				if(null != rowLabel && !"Legend".equalsIgnoreCase(rowLabel) && !activeRankDimNameList.isEmpty())//When both Row & Col present
				{
					if(null != rowList && !rowList.isEmpty() && !colStart && activeRankDimNameList.contains(rowLabel)
						&& cnt < rowListSize && rowList.get(cnt) != null && rowList.get(cnt) instanceof String && ICubeConstants.OTHER_STRING.equals(rowList.get(cnt)))
					{
						drillList.add("null");
					}
					else if(null != colList && !colList.isEmpty() && null != colLabel && colStart && activeRankDimNameList.contains(colLabel)
						&& cnt < colListSize && colList.get(cnt) != null && colList.get(cnt) instanceof String && ICubeConstants.OTHER_STRING.equals(colList.get(cnt)))
					{
						drillList.add("null");
					}
					else
					{
						drillList.add(str);
					}
					cnt++;
					if(cnt == rowListSize && colStart == false)
					{
						cnt = 0;
						colStart = true;
					}
				}
				else
				{
					if(null != colList && !colList.isEmpty() && null != colLabel && !activeRankDimNameList.isEmpty() && activeRankDimNameList.contains(colLabel)
						&& cnt < colListSize && colList.get(cnt) != null && colList.get(cnt) instanceof String && ICubeConstants.OTHER_STRING.equals(colList.get(cnt)))
					{
						drillList.add("null");
					}
					else
					{
						drillList.add(str);
					}
					cnt++;
				}
			}
			graphInfo.getGraphData().setDrillLinkList(drillList);
		}
		map.put("graphcss", strGraphCss);
		map.put("smartencss", strGraphCss);
		map.put("legendDrilldownLinkMap", graphInfo.getLegendDrilldownLinkMap());
		map.put("currentTimeStamp", params.get("currentTimeStamp"));
		map.put("totalObjects", graphInfo.getGraphDataVector() != null ? graphInfo.getGraphDataVector().size() - 1 : 0);
		map.put("gaugeLegendInfo", legends);
		map.put("isGraphVisible", graphInfo.isGraphVisible());

		return map;
	}

