	public SmartenInfo processGraphChangeType(SmartenInfo graphInfo, UserInfo userInfo) {
		long startTime = System.currentTimeMillis();
		if (graphInfo.getGraphType() != GraphConstants.COMBINED_GRAPH) {
			List<ActiveUDDCInfo> delInfoList = new ArrayList<ActiveUDDCInfo>();
			List<ActiveUDDCInfo> activeUDDCList = graphInfo.getActiveUDDCInfo(userInfo.getUserId());
			if (activeUDDCList != null && activeUDDCList.size() > 0) {
				for (int cnt = 0; cnt < activeUDDCList.size(); cnt++) {

					for (int cnt1 = 0; cnt1 < graphInfo.getUddcInfoListForLineCombinedGraph().size(); cnt1++) {
						if (activeUDDCList.get(cnt).getUddcTemplateInfo().getColumnName()
								.contains(graphInfo.getUddcInfoListForLineCombinedGraph().get(cnt1).toString())) {
							ActiveUDDCInfo uddcInfo = activeUDDCList.get(cnt);
							delInfoList.add(uddcInfo);
						}
					}
				}
			}
			for (ActiveUDDCInfo activeInfo : delInfoList) {
				activeUDDCList.remove(activeInfo);
			}

			CubeVector v1 = graphCube.getOrderedDataColumnInfoList();
			CubeVector condList = new CubeVector();
			boolean flag = false;
			for (int cnt = 0; cnt < v1.size(); cnt++) {
				for (int cnt1 = 0; cnt1 < graphInfo.getUddcInfoListForLineCombinedGraph().size(); cnt1++) {
					if (v1.get(cnt).toString()
							.contains(graphInfo.getUddcInfoListForLineCombinedGraph().get(cnt1).toString())) {
						flag = true;
					}
				}
				if (!flag) {
					condList.add(v1.get(cnt));
				}
			}

			try {
				setOrderedDataColumnInfoList(condList);
			} catch (CubeException e) {
				ApplicationLog.error(e);
			}

			graphInfo.getActiveTemplateProperties().setActiveUDDCInfo(activeUDDCList);

			graphInfo.setUddcInfoListForLineCombinedGraph(new CubeVector());
			graphInfo.setTheDataColLabels4(new CubeVector());
		}
		if (graphInfo.getGraphType() == GraphConstants.COMBINED_GRAPH) {
			graphInfo.setUddcInfoListForLineCombinedGraph(new CubeVector());
			graphInfo.setLineGraphDataLabelsForCombinedGraph(new CubeVector());
			graphInfo.setTheDataColLabels4(new CubeVector());
			graphInfo.setLineGraphRowLabelsForCombinedGraph(new CubeVector());// for cmb Line
			graphInfo.getGraphData().setCmbLinerowLabel(null);
			graphInfo.getGraphData().setCmbLinerowList(new ArrayList());
			graphInfo.getGraphData().setCmbLinedataLabel(null);
			graphInfo.getGraphData().setCmbLinedataList(new ArrayList());
		}

		doGraphChanged(graphInfo.getGraphType(), true, graphInfo, userInfo);
		graphInfo.setGraphMode(AppConstants.NEW_MODE);
		setDefaultProperties(graphInfo);
		if (!(graphInfo.getGraphMode() == AppConstants.NEW_MODE)) {
			graphInfo.setGraphMode(AppConstants.OPEN_MODE);
		}
		long endTime = System.currentTimeMillis();

		return graphInfo;

	}

	/**
	 * Gets system generated dimension vector.
	 * 
	 * @param sourceColLabels
	 *            Source column labels
	 * @param otherColLabels
	 *            Other column labels
	 * @param dimMapTable
	 *            Dimension map
	 * @return Vector contains system generated dimension list
	 */
	public Vector getSysGenDimVector(Vector sourceColLabels, Vector otherColLabels, Hashtable dimMapTable, SmartenInfo graphInfo) {
		Vector returnVec = new Vector();
		Vector vDimMap = new Vector();
		String skey = "";
		Vector vModifiedCols = new Vector();
		Vector vSysGenDim = new Vector();

		if (!dimMapTable.isEmpty()) {
			int colSize = sourceColLabels.size();
			for (int i = 0; i < colSize; i++) {
				boolean bOccuranceFound = false;
				String strCol = sourceColLabels.elementAt(i).toString();
				int iColumnType = 0;
				try {
					iColumnType = GeneralFiltersUtil.getCubeColumnType(graphInfo.getCubeInfo(),strCol);
				} catch (CubeException e) {
					ApplicationLog.error(e);
				}
				Map<String, String> dateFrequencyMap = graphInfo.getDateFrequencyMap();
				String frequency = "";
				boolean isFrequencyDrill = false;
					if(dateFrequencyMap != null && !dateFrequencyMap.isEmpty() && dateFrequencyMap.get(strCol) != null && !dateFrequencyMap.get(strCol).isEmpty()) {
						frequency = dateFrequencyMap.get(strCol);
					}
					if(frequency != null && !frequency.isEmpty() && (iColumnType == Types.DATE || iColumnType == Types.TIMESTAMP)) {
						List<String> frequencyDrillList = KPIConstants.getFrequencyDimensionMap(strCol, frequency);
						if(frequencyDrillList != null && frequencyDrillList.size() > 1) {
							isFrequencyDrill = true;
							for(String str:frequencyDrillList) {
								vModifiedCols.addElement(strCol);
								vSysGenDim.addElement(strCol);
							}
							vSysGenDim.remove(strCol);
						}
					}
					if(!isFrequencyDrill) {
				for (Enumeration enumDimMap = dimMapTable.keys(); enumDimMap.hasMoreElements();) {
					skey = enumDimMap.nextElement().toString();
					vDimMap = (Vector) dimMapTable.get(skey);

					if (!bOccuranceFound) {
						boolean bFound = false;
						int j;
						for (j = 0; j < vDimMap.size(); j++) {
							if (sourceColLabels.elementAt(i).toString().equals(vDimMap.elementAt(j).toString())) {
								bFound = true;
								break;
							}
						}

						if (bFound) {
							for (int k = j; k < vDimMap.size(); k++) {
								if (!otherColLabels.contains(vDimMap.elementAt(k))) {
									if (!sourceColLabels.contains(vDimMap.elementAt(k))) {
										vSysGenDim.addElement(vDimMap.elementAt(k));
									}

									if (!vModifiedCols.contains(vDimMap.elementAt(k))) {
										if (k == j || !sourceColLabels.contains(vDimMap.elementAt(k))) {
											vModifiedCols.addElement(vDimMap.elementAt(k));
										} else {
											break;
										}
									}
								}
							}
						} else {
							if (!vModifiedCols.contains(sourceColLabels.elementAt(i))) {
								vModifiedCols.addElement(sourceColLabels.elementAt(i));
							}
						}
					}
				}
					}
			}
		}
		returnVec.addElement(vModifiedCols);
		returnVec.addElement(vSysGenDim);
		return returnVec;
	}

	private double setAdjustedDigitValueForGauge(int adjustedDigit, double value) {
		value = value / Math.pow(10, adjustedDigit);
		return value;
	}

	private void activeddvmForNewAddedColumn(SmartenInfo graphInfo, List<DDVMTemplateInfo> ddvmTemplateInfoList)
			throws DatabaseOperationException, ALSException {

		if (ddvmTemplateInfoList != null && ddvmTemplateInfoList.size() > 0) {
			List<Long> ddvmId = new ArrayList<Long>();
			List<AnalysisActiveDDVMInfo> activeDDVMList = graphInfo.getActiveTemplateProperties().getActiveDDVMInfo();
			if (activeDDVMList != null && activeDDVMList.size() > 0) {
				for (int j = 0; j < activeDDVMList.size(); j++) {
					AnalysisActiveDDVMInfo ddvmInfo = activeDDVMList.get(j);
					if (ddvmInfo.getDdvmTemplateInfo() != null) {
						ddvmId.add(ddvmInfo.getDdvmTemplateInfo().getId());
					}
				}
			}
			for (DDVMTemplateInfo analysisDDVMInfo : ddvmTemplateInfoList) {
				long lsavedTmpId = analysisDDVMInfo.getId();
				if (!ddvmId.contains(lsavedTmpId)) {
					analysisDDVMInfo.setStatus(true);
					AnalysisActiveDDVMInfo aDDVMInfo = new AnalysisActiveDDVMInfo();
					aDDVMInfo.setCubeId(analysisDDVMInfo.getCubeId());
					aDDVMInfo.setObjectId(graphInfo.getGraphId());
					aDDVMInfo.setDdvmTemplateInfoId(analysisDDVMInfo.getId());
					aDDVMInfo.setDdvmTemplateInfo(analysisDDVMInfo);
					if (activeDDVMList != null)
					activeDDVMList.add(aDDVMInfo);
				}
				ddvmId.add(lsavedTmpId);
			}
			graphInfo.getActiveTemplateProperties().setActiveDDVMInfo(activeDDVMList);
		}
	}

