	/**
	 * Gets data display value map which status is activated.
	 * 
	 * @return HashtableEx contains active data display value map
	 * @throws DatabaseOperationException
	 */
	private HashtableEx getTimeTemplate(SmartenInfo graphInfo, String strColumnName) throws DatabaseOperationException {
		HashtableEx hValues = new HashtableEx();
		HashtableEx tempValues = null;
		HashtableEx ddvmValues = new HashtableEx();

		List<DDVMTemplateInfo> ddvmInfoList = ddvmTemplateDAO
				.getDDVMTempInfoByCubeAndColumnName(graphInfo.getCubeInfo().getDataObjectId(), strColumnName);
		Vector rowLabelList = graphInfo.getRowColumns();
		Vector colLabelList = graphInfo.getColColumns();

		Enumeration enumTemp = null;
		String name = null;
		Vector ddvmVec = null;
		String[] objList = null;
		List<DDVMConditionInfo> ddvmConditionList = null;

		try {
			for (DDVMTemplateInfo ddvmTemplateInfo : ddvmInfoList) {
				name = ddvmTemplateInfo.getColumnName();
				ddvmConditionList = ddvmTemplateInfo.getDdvmConditionInfoList();
				ddvmVec = new Vector();
				for (DDVMConditionInfo condInfo : ddvmConditionList) {
					objList = new String[2];
					objList[0] = condInfo.getActualValue();
					objList[1] = condInfo.getNewValue();
					ddvmVec.add(objList);

					hValues.put(name, ddvmVec);
				}
				tempValues = CubeUtil.addAll((HashtableEx) tempValues, (HashtableEx) hValues.clone(), true);

				if (tempValues != null) {
					enumTemp = tempValues.keys();
					while (enumTemp.hasMoreElements()) {
						String colName = (String) enumTemp.nextElement();

						if (rowLabelList.contains(colName)) {
							ddvmValues.put(colName, tempValues.get(colName));
						} else if (colLabelList.contains(name)) {
							ddvmValues.put(colName, tempValues.get(colName));
						}
					}
				}
				hValues.clear();
			}
		} catch (Exception e) {
			ApplicationLog.error(e);
		}

		return ddvmValues;
	}

	/**
	 * Gets map with changed column name
	 * 
	 * @param colLabelsMap
	 * @param rowColMap
	 * @return map with changed column name
	 */
	private HashMap<String, String> getColumnLabelMapFromOtherMap(Map<String, String> colLabelsMap,
			Map<String, String> rowColMap) {

		HashMap<String, String> requiredMap = new HashMap<String, String>();

		for (String key : rowColMap.keySet()) {
			if (!colLabelsMap.containsKey(key)) {
				requiredMap.put(key, rowColMap.get(key));
			} else {
				String value = colLabelsMap.get(key);
				if (value.trim().isEmpty()) {
					value = key;
				}
				requiredMap.put(key, value);
			}
		}

		return requiredMap;
	}

