	public Map<String, Map<String, Object>> getSelectedDataOperation(SmartenInfo graphInfo,
			Map<String, String> messureMap, boolean isDateDimension, boolean isPostData) {
		List<com.elegantjbi.entity.admin.CubeColumnInfo> cubeColumnInfoList = graphInfo.getCubeInfo()
				.getDataObjectColumnInfoList();
		Map<String, Map<String, Object>> measureDataMap = new HashMap<String, Map<String, Object>>();
		Map<String, Object> tempData = new LinkedHashMap();
		boolean isUddc = true;
		for (Object key : messureMap.keySet()) {
			isUddc = true;
			if ((graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH
					|| graphInfo.getGraphType() == GraphConstants.SMARTENVIEW_TABULAR)
					&& !graphInfo.isPerformAggregation())
				tempData.put(ResourceManager.getString("LBL_NONE"), -1);// As discussed
			if (isPostData)
				tempData.putAll(StringUtil.getAggDataOperationMap());
			else
				tempData.putAll(StringUtil.getDataOperationMap(isDateDimension, graphInfo.getCubeInfo().isMdxCube()));
			int idx = cubeColumnInfoList.indexOf(key.toString());
			for (com.elegantjbi.entity.admin.CubeColumnInfo cci : cubeColumnInfoList) {
				boolean isDummyColumn = false;
				if (cci.getColumnName().equals(key.toString())) {
					isDummyColumn = true;
				} else if (key.toString().indexOf('_') != -1) {
					String SourceColNameifDummy = key.toString().substring(0, key.toString().lastIndexOf('_'));
					if (SourceColNameifDummy.equals(cci.getColumnName())) {
						isDummyColumn = true;
					}
				}
				if (isDummyColumn) {
					isUddc = false;
					int iOperations = cci.getCubeMeasureDataOperationValue();
					if ((iOperations & ICubeConstants.SUM) != ICubeConstants.SUM) {
						tempData.remove(ALSCommandNameList.VIEW_NAME_QT_TOTAL);
						tempData.remove(ALSCommandNameList.VIEW_NAME_QT_AVERAGE);
						tempData.remove(ALSCommandNameList.VIEW_NAME_QT_VALID_AVERAGE);
					}
					if ((iOperations & ICubeConstants.COUNT) != ICubeConstants.COUNT) {
						tempData.remove(ALSCommandNameList.VIEW_NAME_QT_COUNT);
						tempData.remove(ALSCommandNameList.VIEW_NAME_QT_AVERAGE);
					}
					if ((iOperations & ICubeConstants.EFFECTIVE_COUNT) != ICubeConstants.EFFECTIVE_COUNT) {
						tempData.remove(ALSCommandNameList.VIEW_NAME_QT_VALID_COUNT);
						tempData.remove(ALSCommandNameList.VIEW_NAME_QT_VALID_AVERAGE);
					}
					if ((iOperations & ICubeConstants.MINIMUM) != ICubeConstants.MINIMUM) {
						tempData.remove(ALSCommandNameList.VIEW_NAME_QT_MIN);
					}
					if ((iOperations & ICubeConstants.MAXIMUM) != ICubeConstants.MAXIMUM) {
						tempData.remove(ALSCommandNameList.VIEW_NAME_QT_MAX);
					}
					if ((iOperations & ICubeConstants.FIRST) != ICubeConstants.FIRST) {
						tempData.remove(ALSCommandNameList.VIEW_NAME_QT_FIRST);
					}
					if ((iOperations & ICubeConstants.LAST) != ICubeConstants.LAST) {
						tempData.remove(ALSCommandNameList.VIEW_NAME_QT_LAST);
					}
					measureDataMap.put("" + key, tempData);
					break;
				}
			}

			if (isUddc) {
				tempData = StringUtil.getDataOperationMap(false, true);
				measureDataMap.put("" + key, tempData);
			}
		}
		return measureDataMap;
	}

	/**
	 * @param graphInfo
	 * @param userinfo
	 * @param modelMap
	 * @param cubeInfo 
	 */
	public void getAppliedFilterInfo(SmartenInfo graphInfo, UserInfo userinfo, ModelMap modelMap, IDataObject cubeInfo) {

		List<OutLinerFilterTemplateInfo> outLinerInfoList = new ArrayList<OutLinerFilterTemplateInfo>();
		List<OutLinerFilterTemplateInfo> outLinerInfoList2 = new ArrayList<OutLinerFilterTemplateInfo>();
		try {
			List<ActiveFilterInfo> activeFilterList = graphInfo.getActiveFilterInfo(getLoggedInUserId());
			if (activeFilterList == null) {
				activeFilterList = new ArrayList<ActiveFilterInfo>();
			}
			for (int k = 0; k < activeFilterList.size(); k++) {
				outLinerInfoList
						.add((OutLinerFilterTemplateInfo) activeFilterList.get(k).getOutLinerFilterTemplateInfo());
			}
			List<ConditionInfo> tempConList = null;
			List<ConditionInfo> cubeConList = null;
			if (outLinerInfoList != null && outLinerInfoList.size() > 0) {
				for (int i = 0; i < outLinerInfoList.size(); i++) {
					OutLinerFilterTemplateInfo outlinerInfo = outLinerInfoList.get(i);

					if (outlinerInfo == null) {
						outlinerInfo = new OutLinerFilterTemplateInfo();
					}

					List<ConditionInfo> condiList = outlinerInfo.getConditionInfo();
					if (condiList != null) {
						if (outlinerInfo.getFilterType() == AppConstants.FRONT_END) {
							tempConList = new ArrayList<ConditionInfo>();
							List<String> grId = new ArrayList<String>();
							GeneralFiltersUtil.setConditionFilterList(condiList, tempConList, grId,
									graphInfo.getCubeInfo(), getOriginalResultSetMetaData());
						} else {
							cubeConList = new ArrayList<ConditionInfo>();
							List<String> grId = new ArrayList<String>();
							GeneralFiltersUtil.setConditionFilterList(condiList, cubeConList, grId,
									graphInfo.getCubeInfo(), getOriginalResultSetMetaData());
						}
					}
					outlinerInfo.setTempCondition(tempConList);
					outlinerInfo.setCubeCondition(cubeConList);
					
					String str = GeneralFiltersUtil.makeConditionReadableAsMore1(outlinerInfo.getCubeCondition(), graphInfo.getGraphId(), outlinerInfo.getCubeId(),
		    				cubeInfo, null, userinfo, null);
		    		outlinerInfo.setConditionExpression(str);
		    		
					outLinerInfoList2.add(outlinerInfo);
				}
			}

			String[][] pageFilterFields = getPageFilters(graphInfo);
			if (pageFilterFields == null) {
				pageFilterFields = new String[0][];
			}
			boolean showFilterTab = false;
			if (pageFilterFields != null) {
				for (String[] pageObj : pageFilterFields) {
					if (pageObj != null && pageObj.length > 1 && pageObj[2] != null)
						;
					{
						if (!pageObj[2].equalsIgnoreCase(ResourceManager.getString("LBL_NONE"))) {
							showFilterTab = true;
							break;
						}
					}
				}
			}
			String strNone = ResourceManager.getString("LBL_NONE");
			modelMap.put("strNone", strNone);
			modelMap.put("showFilterTab", showFilterTab);
			modelMap.put("pageFilterFields", pageFilterFields);
			modelMap.put("isFromSmarten", true);// Added
		} catch (CubeException e) {
			ApplicationLog.error(ResourceManager.getString("LOG_ERROR_MSG_FAILED_TO_OPEN_OBJECTINFORMATION_GRAPH",
					new Object[] { graphInfo.getGraphName(), userinfo.getUsername() }), e);
		} catch (CloneNotSupportedException e) {
			ApplicationLog.error(ResourceManager.getString("LOG_ERROR_MSG_FAILED_TO_OPEN_OBJECTINFORMATION_GRAPH",
					new Object[] { graphInfo.getGraphName(), userinfo.getUsername() }), e);
		}

		/** time series start **/
		HashMap timeseriesList = new HashMap();
		try {
			HashMap temptimeseriesList = graphOrgCube.getTimeSeriesFilters();
			Iterator iterator = temptimeseriesList.entrySet().iterator();
			while (iterator.hasNext()) {
				Map.Entry mapEntry = (Map.Entry) iterator.next();
				CubeVector conditionvector = (CubeVector) mapEntry.getValue();
				String conditionValue = "";
				if (conditionvector != null && conditionvector.size() > 0) {
					for (int i = 0; i < conditionvector.size(); i++) {
						conditionValue += conditionvector.get(i) + ",";
					}
					conditionValue = conditionValue.substring(0, conditionValue.length() - 1);
					if (conditionValue != null && conditionValue.length() > 0) {
						String timeSeries = GeneralFiltersUtil.getConditionDiscription(conditionvector, ",");
						timeseriesList.put(mapEntry.getKey(), timeSeries);
					}
				}
			}
		} catch (Exception e) {
			ApplicationLog.error(ResourceManager.getString("LOG_ERROR_MSG_FAILED_TO_OPEN_OBJECTINFORMATION_GRAPH",
					new Object[] { graphInfo.getGraphName(), userinfo.getUsername() }), e);
		}

		/** time series end **/

		Map<String, String> dashboardFilterInfoMap = graphInfo.getDashboardFilterInfoMap();
		modelMap.put("dashboardFilterInfoMap", dashboardFilterInfoMap);
		modelMap.put("timeseriesList", timeseriesList);
		modelMap.put("allConditionalOperators", GeneralFiltersUtil.getAllAvailableOperatorsMap());
		modelMap.put("dateConditionalOperators", GeneralFiltersUtil.getDateDimensionOperratorMap());
		modelMap.put("filtersList", outLinerInfoList2);
		modelMap.put("graphInfo", graphInfo);
	}

