	private String getFormatedNumber(Object obj, String colLabel, HashMap hmFormatObj) {
		String strVal = "";
		if (null != hmFormatObj.get(colLabel)) {
			if (obj instanceof CubeDataObject && obj != null) {
				if (((CubeDataObject) obj).getObjValue() == null || obj.toString().length() == 0 || obj.toString() == null) {
					strVal = getFormatedData((ValueFormat) hmFormatObj.get(colLabel), new Double(0));
				} else {
					strVal = getFormatedData((ValueFormat) hmFormatObj.get(colLabel), new Double(obj.toString()));
				}
			} else if (obj instanceof Timestamp)
				strVal = getFormatedData((ValueFormat) hmFormatObj.get(colLabel), obj);
			else if (obj instanceof Number)
				strVal = getFormatedData((ValueFormat) hmFormatObj.get(colLabel), new Double(obj.toString()));
			else
				strVal = StringUtil.null2String(obj);
		} else {
			strVal = StringUtil.null2String(obj);
		}
		return strVal;
	}

	public GraphData generatePieGraphdata(Vector dataVector, GraphData graphData, boolean isTotalVisible,
			int divisionValue, SmartenInfo graphInfo, String userId, List adjustedDigitList) {

		int dataIndex;
		List dataList = new ArrayList();

		int colIndex;
		List colList = graphData.getColList();

		int rowIndex;
		List rowList = graphData.getRowList();

		Vector header = (Vector) dataVector.elementAt(0);
		dataVector.removeElementAt(0);

		dataIndex = header.indexOf(graphData.getDataLabel());
		colIndex = header.indexOf(graphData.getColLabel());
		rowIndex = header.indexOf(graphData.getRowLabel());

		int colListSize = colList.size();
		int rowListSize = rowList.size();

		if (colListSize == 0) {
			colList.addAll(rowList);
			colListSize = rowListSize;
			colIndex = rowIndex;
			graphData.setColLabel(graphData.getRowLabel());

			rowListSize = 0;
			rowList.clear();
			rowIndex = -1;
			graphData.setRowLabel(null);
		}

		if (rowListSize == 0) {
			rowListSize = 1;
		}

		List dataListForTotal = null;
		if (isTotalVisible) {
			dataListForTotal = new ArrayList();
		}

		HashtableEx ddvmMap = new HashtableEx();
		ddvmMap = (HashtableEx) getActiveDDVMs(graphInfo, userId);
		Vector packDisplayList = null;
		if (ddvmMap != null && ddvmMap.size() > 0) {
			if (ddvmMap.containsKey(graphData.getRowLabel())) {
				packDisplayList = (Vector) ddvmMap.get(graphData.getRowLabel());
			} else if (ddvmMap.containsKey(graphData.getColLabel())) {
				packDisplayList = (Vector) ddvmMap.get(graphData.getColLabel());
			}
		}

		
		List tempAdjustedDigitList = new ArrayList();

		for (int i = 0; i < adjustedDigitList.size(); i++) {
			tempAdjustedDigitList.add(adjustedDigitList.get(i));
		}

		
		List trendValue = new ArrayList();
		List trendAlgoList = new ArrayList();
		List originalColValues = new ArrayList();
		if (graphInfo.getGraphProperties().getTrendlinePropertiesMap().size() != 0) {

			Map<Integer, TrendLineProperties> testMap = graphInfo.getGraphProperties().getTrendlinePropertiesMap();
			for (Entry<Integer, TrendLineProperties> entry : testMap.entrySet()) {
				String[] splitString = ((String) entry.getValue().getTrendLineColumn()).split(",");
				originalColValues.add(splitString[0].toString());
				trendValue.add(splitString[0]);
				trendAlgoList.add(entry.getValue().getTrendLineType().toString());
			}

		}

		if (packDisplayList != null && packDisplayList.size() > 0) {
			for (int i = 0; i < trendValue.size(); i++) {

				for (Iterator iterator = packDisplayList.iterator(); iterator.hasNext();) {
					String[] values = (String[]) iterator.next();
					if (values[1].equalsIgnoreCase(trendValue.get(i).toString())) {
						trendValue.set(i, values[0]);
						break;
					}
					if (values[0].equalsIgnoreCase(trendValue.get(i).toString())) {
						trendValue.set(i, values[1]);
						break;
					}
				}
			}
		}

		Map tempMap = graphInfo.getGraphData().getKeyValueMap();
		int dataVecSize = dataVector.size();
		int recordCount = 0;
		boolean isSwitch = false;
		int zerValueConut = 0;
		Map<String, List> trendMap = new HashMap<String, List>();
		graphData.setColList(colList);
		graphData.setRowList(rowList);
		graphData.setTrendMap(trendMap);
		graphData.setDataList(new ArrayList());
		graphData.setAdjustedDigitList(tempAdjustedDigitList);

		return graphData;

	}

	public GraphData generateGraphData(Vector dataVector, GraphData graphData, boolean isTotalVisible,
			int divisionValue, SmartenInfo graphInfo, String userId, List adjustedDigitList) {
		int dataIndex;
		List dataList = new ArrayList();

		int colIndex;
		List colList = graphData.getColList();

		int rowIndex;
		List rowList = graphData.getRowList();

		int sizeIndex = -1;
		List sizeList = graphData.getSizeList();

		int shapeIndex = -1;
		List shapeList = graphData.getShapeList();

		int rowsIndex;
		List rowsList = graphData.getRowsList();

		int colsIndex;
		List colsList = graphData.getColsList();

		List rowsIndexList = new ArrayList();
		List colsIndexList = new ArrayList();

		int noOfRows = 0;
		int noOfColumns = 0;

		if (graphInfo.getGraphData().isSmartenRowsEnable())
			noOfRows = graphInfo.getGraphData().getSmartenRowList().size();
		if (graphInfo.getGraphData().isSmartenColoumnsEnable())
			noOfColumns = graphInfo.getGraphData().getSmartenColList().size();

		Vector header = (Vector) dataVector.elementAt(0);
		dataVector.removeElementAt(0);

		dataIndex = header.indexOf(graphData.getDataLabel());
		colIndex = header.indexOf(graphData.getColLabel());
		rowIndex = header.indexOf(graphData.getRowLabel());

		if (graphData.getSizeLabel() != null && graphData.getRowLabel() != null
				&& !graphData.getRowLabel().equals(graphData.getSizeLabel()))
			sizeIndex = header.indexOf(graphData.getSizeLabel());
		if (graphData.getShapeLabel() != null && graphData.getRowLabel() != null
				&& !graphData.getRowLabel().equals(graphData.getShapeLabel()))
			shapeIndex = header.indexOf(graphData.getShapeLabel());

		int sizeListSize = 1;
		int shapeListSize = 1;
		int colListSize = colList.size();
		int rowListSize = rowList.size();
		if (graphData.getSizeList() != null)
			sizeListSize = sizeList.size();
		if (graphData.getShapeList() != null)
			shapeListSize = shapeList.size();

		colsIndex = header.indexOf(graphData.getColsLabel());
		rowsIndex = header.indexOf(graphData.getRowsLabel());

		if (graphInfo.getGraphData().isSmartenRowsEnable() && graphInfo.isPerformAggregation()) {
			for (int i = 0; i < noOfRows; i++) {
				int index = header.indexOf(graphInfo.getGraphData().getSmartenRowList().get(i).toString());
				rowsIndexList.add(index);
			}
		}
		if (graphInfo.getGraphData().isSmartenColoumnsEnable()) {
			for (int i = 0; i < noOfColumns; i++) {
				int index = header.indexOf(graphInfo.getGraphData().getSmartenColList().get(i).toString());
				colsIndexList.add(index);
			}
		}
		int rowsListSize = 0;
		int colsListSize = 0;
		if (rowsList != null)
			rowsListSize = rowsList.size();
		if (colsList != null)
			colsListSize = colsList.size();
		if (colListSize == 0 && !graphInfo.isCategoryMeasure()) {
			colList.addAll(rowList);
			colListSize = rowListSize;
			colIndex = rowIndex;
			graphData.setColLabel(graphData.getRowLabel());

			rowListSize = 0;
			rowList.clear();
			rowIndex = -1;
			graphData.setRowLabel(null);
		}
		if (graphInfo.getGraphData().isSmartenRowsEnable() && graphInfo.isPerformAggregation()) {
			
			graphInfo.getGraphData().setRowListClone(rowList);
			
		}
		if (rowListSize == 0) {
			rowListSize = 1;
		}
		if (rowsListSize == 0) {
			rowsListSize = 1;
		}
		if (colsListSize == 0) {
			colsListSize = 1;
		}

		List dataListForTotal = null;
		if (isTotalVisible) {
			dataListForTotal = new ArrayList();
		}

		HashtableEx ddvmMap = new HashtableEx();
		ddvmMap = (HashtableEx) getActiveDDVMs(graphInfo, userId);
		Vector packDisplayList = null;
		if (ddvmMap != null && ddvmMap.size() > 0) {
			if (ddvmMap.containsKey(graphData.getRowLabel())) {
				packDisplayList = (Vector) ddvmMap.get(graphData.getRowLabel());
			} else if (ddvmMap.containsKey(graphData.getColLabel())) {
				packDisplayList = (Vector) ddvmMap.get(graphData.getColLabel());
			}
		}

		List tempAdjustedDigitList = new ArrayList();

		if ((graphInfo.getDataColLabels3().size() > 1
				&& (graphInfo.getGraphType() == SmartenConstants.STACKED_VBAR_GRAPH
						|| graphInfo.getGraphType() == SmartenConstants.STACKED_HBAR_GRAPH)
				&& (graphInfo.getGraphData().getRowLabel() == null && graphInfo.getGraphData().getColLabel() == null))
				|| (graphInfo.getGraphType() == SmartenConstants.VBAR_GRAPH
						|| graphInfo.getGraphType() == SmartenConstants.HBAR_GRAPH
						|| graphInfo.getGraphType() == SmartenConstants.LINE_GRAPH
						|| graphInfo.getGraphType() == SmartenConstants.AREA_DEPTH_GRAPH)
						&& (graphInfo.getGraphData().getRowLabel() != null
								&& graphInfo.getGraphData().getRowLabel().equalsIgnoreCase("Legend"))) {
			for (int i = 0; i < adjustedDigitList.size(); i++) {
				for (int j = 0; j < rowList.size(); j++) {
					if (adjustedDigitList.size() > j)
						tempAdjustedDigitList.add(adjustedDigitList.get(j));
					else
						tempAdjustedDigitList.add(adjustedDigitList.get(0));
				}
			}
		} else if (graphInfo.getGraphType() != SmartenConstants.COMBINED_GRAPH
				&& graphInfo.getGraphType() != SmartenConstants.DRILLED_RADAR_GRAPH
				&& graphInfo.getGraphType() != SmartenConstants.DRILLED_STACKED_RADAR_GRAPH
				&& graphInfo.getGraphType() != SmartenConstants.PIE_GRAPH
				&& graphInfo.getGraphType() != SmartenConstants.HISTOGRAM_GRAPH
				&& graphInfo.getGraphType() != SmartenConstants.CANDLE_STICK_GRAPH
				&& graphInfo.getGraphType() != SmartenConstants.HIGH_LOW_OPEN_CLOSE_GRAPH
				&& graphInfo.getGraphType() != SmartenConstants.NUMERIC_DIAL_GAUGE) {
			int divValue;
			for (int i = 0; i < rowListSize; i++) {
				divValue = graphInfo.getGraphProperties().getyAxisPropertiesMap().get("M0").getLabelProperties()
						.getAdjustedDigit();
				divValue = (int) (Math.pow(10, divValue));
				tempAdjustedDigitList.add(divValue);
			}
		}

		if (graphInfo.getGraphProperties().getSmartenProperties().isSameScale()) {
			int adjustedOfFirst = Integer.parseInt(adjustedDigitList.get(0).toString());
			adjustedDigitList.clear();
			for (int i = 0; i < graphInfo.getDataColLabels3().size(); i++) {
				adjustedDigitList.add(adjustedOfFirst);
			}
		}
		List trendValue = new ArrayList();
		List trendAlgoList = new ArrayList();
		List originalColValues = new ArrayList();
		if (graphInfo.getGraphProperties().getTrendlinePropertiesMap().size() != 0) {

			Map<Integer, TrendLineProperties> testMap = graphInfo.getGraphProperties().getTrendlinePropertiesMap();
			for (Entry<Integer, TrendLineProperties> entry : testMap.entrySet()) {
				String[] splitString = ((String) entry.getValue().getTrendLineColumn()).split(",");
				originalColValues.add(splitString[0].toString());
				trendValue.add(splitString[0]);
				trendAlgoList.add(entry.getValue().getTrendLineType().toString());
			}

		}


		if (packDisplayList != null && packDisplayList.size() > 0) {
			for (int i = 0; i < trendValue.size(); i++) {

				for (Iterator iterator = packDisplayList.iterator(); iterator.hasNext();) {
					String[] values = (String[]) iterator.next();
					if (values[1].equalsIgnoreCase(trendValue.get(i).toString())) {
						trendValue.set(i, values[0]);
						break;
					}
					if (values[0].equalsIgnoreCase(trendValue.get(i).toString())) {
						trendValue.set(i, values[1]);
						break;
					}
				}
			}
		}

		Map<String, Double> tempMap = graphInfo.getGraphData().getKeyValueMap();
		int tempRowsCount = 0;
		List rowsKeyList = new ArrayList();
		List colsKeyList = new ArrayList();
		int rowsKeyListSize = rowsKeyList.size();
		int colsKeyListSize = colsKeyList.size();

		if (rowsKeyListSize == 0)
			rowsKeyListSize = 1;
		if (colsKeyListSize == 0)
			colsKeyListSize = 1;

		int dataVecSize = dataVector.size();
		int recordCount = 0;
		boolean isSwitch = false;
		int zerValueConut = 0;
		Map<String, List> trendMap = new HashMap<String, List>();
		if (trendValue.size() > 0) {
			Double dataValue = 0.0;
			String dataKey = "";
			dataKey += graphInfo.getDataColLabels3().get(0).toString();
			if (graphInfo.getDataColLabels3().size() > 0 && graphData.getRowLabel() != null
					&& graphData.getRowLabel().equalsIgnoreCase("Legend"))
				dataKey = "";
			for (int ii = 0; ii < trendValue.size(); ii++) {
				isSwitch = false;
				recordCount = 0;
				List tempTrendList = new ArrayList();// temp
				for (int i = 0; i < colListSize; i++) {
					String colValueFromList = colList.get(i).toString();
					for (int j = 0; j < rowListSize; j++) {
						String keyValue = colList.get(i).toString();
						if (recordCount >= dataVecSize) {
							dataList.add(null);
							continue;
						}

						if (rowIndex != -1) {
							keyValue += rowList.get(j).toString();
						}
						keyValue += dataKey;
						dataValue = null;
						if (tempMap.get(keyValue) != null)
							dataValue = Double.valueOf(String.valueOf(tempMap.get(keyValue)));

						if (dataValue == null) {
							dataList.add(null);
							tempTrendList.add(null);
							continue;
						}

						if (isTotalVisible) {
							dataListForTotal.add(dataValue);
						}

						if (tempAdjustedDigitList.size() > 0)
							dataValue = dataValue / Double.valueOf(tempAdjustedDigitList.get(j).toString());
						else
							dataValue = dataValue / divisionValue;
						if (trendValue.get(ii).toString().equalsIgnoreCase(graphData.getRowLabel())
								|| trendValue.get(ii).toString().equalsIgnoreCase(graphData.getColLabel())) {
							tempTrendList.add(dataValue);
							isSwitch = true;
							if (graphData.getRowLabel() != null && graphData.getRowLabel().equals("Legend")
									&& graphInfo.getDataColLabels3().size() > 1
									&& graphInfo.getGraphData().getColLabel() != null) {
								tempTrendList.remove(dataValue);
								isSwitch = false;
								zerValueConut++;
							}
						}

						else if (rowList.size() > 0
								&& trendValue.get(ii).toString().equalsIgnoreCase(rowList.get(j).toString())) {
							tempTrendList.add(dataValue);
							isSwitch = true;
						} else if (rowList.size() == 0
								&& trendValue.get(ii).toString().equalsIgnoreCase(colList.get(j).toString())) {
							tempTrendList.add(dataValue);
							isSwitch = true;
						} else {
							zerValueConut++;
						}

						dataList.add(dataValue);
						recordCount++;
					}
				}
				if (!isSwitch) {
					for (int i = 0; i < zerValueConut; i++) {
						tempTrendList.add(null);
					}
				}
				int s = Integer.parseInt((String) trendAlgoList.get(ii));
				List valuesAfterTrend = new ArrayList();
				if (isSwitch) {
					switch (s) {
					case 1:
						valuesAfterTrend = Linear(tempTrendList);
						isSwitch = true;
						break;
					case 2:
						valuesAfterTrend = Logarithmic(tempTrendList);
						isSwitch = true;
						break;
					case 5:
						valuesAfterTrend = Exponential(tempTrendList);
						isSwitch = true;
						break;
					case 6:
						valuesAfterTrend = MovingAverage(tempTrendList);
						isSwitch = true;
						break;

					}
					trendMap.put(originalColValues.get(ii) + (String) trendAlgoList.get(ii), valuesAfterTrend);
				} else {
					trendMap.put(originalColValues.get(ii) + (String) trendAlgoList.get(ii), tempTrendList);
				}
			}
		}
		String rowLabel = graphInfo.getGraphData().getRowLabel();

		String sizeLabel = graphInfo.getGraphData().getSizeLabel();

		String shapeLabel = graphInfo.getGraphData().getShapeLabel();

		if ((graphInfo.getGraphType() == GraphConstants.LINE_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.STACKED_LINE_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.PERCENTAGE_LINE_GRAPH)
				&& !graphInfo.getGraphData().isSizeMeasure())

		{

			if (sizeLabel != null && rowLabel != null && !sizeLabel.equals(rowLabel)) {
				List sizeListTemp = new ArrayList();
				for (int j = 0; j < sizeListSize; j++) {
					sizeListTemp.add(j);
				}
				graphData.setSizeValueList(sizeListTemp);
			}

		}

		if (!graphInfo.isCategoryMeasure())
			graphData.setColList(colList);
		graphData.setRowList(rowList);
		graphData.setTrendMap(trendMap);
		graphData.setDataList(dataList);

		if (graphInfo.getGraphType() == GraphConstants.PERCENTAGE_VBAR_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.PERCENTAGE_HBAR_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.PERCENTAGE_LINE_GRAPH
				|| graphInfo.getGraphType() == GraphConstants.AREA_PERCENTAGE_GRAPH) {
			int precision = graphInfo.getGraphProperties().getyAxisPropertiesMap().get("M" + 0).getLabelProperties()
					.getNumberOfDigits();
		}

		if (graphInfo.getGraphType() != GraphConstants.PIE_GRAPH
				&& graphInfo.getGraphType() != GraphConstants.NUMERIC_DIAL_GAUGE) {
			int precision = graphInfo.getGraphProperties().getyAxisPropertiesMap().get("M" + 0).getLabelProperties()
					.getNumberOfDigits();
			boolean clustered = false;
			if ((graphInfo.getGraphData().getRowLabel() != null
					&& !graphInfo.getGraphData().getRowLabel().equalsIgnoreCase("legend"))
					&& graphInfo.getGraphData().getColLabel() != null
					&& graphInfo.getGraphType() != GraphConstants.STACKED_HBAR_GRAPH
					&& graphInfo.getGraphType() != GraphConstants.STACKED_VBAR_GRAPH
					&& graphInfo.getGraphType() != GraphConstants.PERCENTAGE_HBAR_GRAPH
					&& graphInfo.getGraphType() != GraphConstants.PERCENTAGE_VBAR_GRAPH
					&& graphInfo.getGraphType() != GraphConstants.DRILLED_STACKED_RADAR_GRAPH
					&& graphInfo.getGraphType() != GraphConstants.STACKED_LINE_GRAPH
					&& graphInfo.getGraphType() != GraphConstants.PERCENTAGE_LINE_GRAPH
					&& graphInfo.getGraphType() != GraphConstants.AREA_STACK_GRAPH
					&& graphInfo.getGraphType() != GraphConstants.AREA_PERCENTAGE_GRAPH)
				clustered = true;

			if (graphInfo.getGraphType() == GraphConstants.STACKED_HBAR_GRAPH
					|| graphInfo.getGraphType() == GraphConstants.STACKED_VBAR_GRAPH
					|| graphInfo.getGraphType() == GraphConstants.STACKED_LINE_GRAPH
					|| graphInfo.getGraphType() == GraphConstants.AREA_STACK_GRAPH) {
				long createStackedStartTime = System.currentTimeMillis();
				
				long createStackedEndTime = System.currentTimeMillis();
				ApplicationLog.debug("createStacked Loop start  " + (createStackedEndTime - createStackedStartTime));
			}
			graphData.setAdjustedDigitList(tempAdjustedDigitList);
		}

		return graphData;
	}

