	public List Logarithmic(List tempTrendList) {
		double[][] doubleArray = new double[tempTrendList.size()][2];
		List trendAns = new ArrayList();
		for (int i = 0; i < tempTrendList.size(); i++) {
			doubleArray[i][0] = (double) i + 1;
			if (tempTrendList.get(i) != null)
				doubleArray[i][1] = (double) tempTrendList.get(i);
			else
				doubleArray[i][1] = 1;
		}
		int n = 0;
		double[] sum = new double[4];
		for (int len = doubleArray.length; n < len; n++) {
			sum[0] += Math.log(doubleArray[n][0]);
			sum[1] += doubleArray[n][1] * Math.log(doubleArray[n][0]);
			sum[2] += doubleArray[n][1];
			sum[3] += Math.pow(Math.log(doubleArray[n][0]), 2);
		}
		double B = (n * sum[1] - sum[2] * sum[0]) / (n * sum[3] - sum[0] * sum[0]);
		if (n == 0)
			n = 1;

		double A = (sum[2] - B * sum[0]) / n;

		for (int i = 0, len = doubleArray.length; i < len; i++) {
			double coordinate = A + B * Math.log(doubleArray[i][0]);
			trendAns.add(coordinate);
		}

		return trendAns;
	}

	public List Linear(List tempTrendList) {
		int N = tempTrendList.size(); 
		int n = 0; 

		double sumx = 0.0; 
		double sumy = 0.0; 
		double sumx2 = 0.0; 
		double sumy2 = 0.0; 
		double sumxy = 0.0; 

		double[] x = new double[tempTrendList.size()];
		double[] y = new double[tempTrendList.size()];
		List trendAns = new ArrayList();

		for (int i = 0; i < tempTrendList.size(); i++) {
			if (tempTrendList.get(i) != null)
			{
				y[i] = (double) tempTrendList.get(i);
				x[i] = (double)i + 1;
			}

		}

		while (n != N) {
			sumx += x[n];
			sumy += y[n];
			sumx2 += x[n] * x[n];
			sumy2 += y[n] * y[n];
			sumxy += x[n] * y[n];
			n++;
		}
		double exp = (n * sumx2 - sumx * sumx);
		if (exp == 0)
			exp = 1;
		if(n==0)
			n=1;
		double a = (n * sumxy - sumx * sumy) / exp;
		double b = (sumy - a * sumx) / n;
		double r = (n * sumxy - sumx * sumy) / Math.sqrt((n * sumx2 - sumx * sumx) * (n * sumy2 - sumy * sumy));

		for (int i = 0; i < tempTrendList.size(); i++) {
			trendAns.add(a * x[i] + b);
		}

		return trendAns;

	}

	public List Exponential(List tempTrendList) {
		List trendAns = new ArrayList();
		List<Double> X = new ArrayList<Double>();
		for (int i = 0; i < tempTrendList.size(); i++) {
			X.add(i + 1.00);
		}

		Double sumX = 0.00;
		Double sumX2 = 0.00;
		Double sumY = 0.00;
		Double sumYlin = 0.00;
		Double sumY2 = 0.00;
		Double sumY2lin = 0.00;
		Double sumXY = 0.00;
		Double sumXYlin = 0.00;

		int N = tempTrendList.size();

		Double e = Math.E;

		for (int i = 0; i < N; i++) {
			sumX = sumX + X.get(i);
			sumX2 = sumX2 + Math.pow(X.get(i), 2);

			if (tempTrendList.get(i) != null)
			{
				sumY = sumY + Math.log((double) tempTrendList.get(i));
				sumY2 = sumY2 + Math.pow(Math.log((double) tempTrendList.get(i)), 2);
				sumXY = sumXY + (X.get(i) * (Math.log((double) tempTrendList.get(i))));

				sumYlin = sumYlin + (double) tempTrendList.get(i);
				sumY2lin = sumY2lin + Math.pow((double) tempTrendList.get(i), 2);
				sumXYlin = sumXYlin + X.get(i) * (double) tempTrendList.get(i);
			}
		}

		
		Double b = 0.00;
		Double exp = (N * sumX2 - (sumX * sumX));
		if (exp == 0)
			exp = 1.00;

		b = ((N * sumXY) - (sumX * sumY)) / exp;

		Double bLin = 0.00;
		
		double temp =(N * sumX2 - (sumX * sumX));
		if(temp==0.0)
		{
			temp=1.0;
		}
		
		bLin = ((N * sumXYlin) - (sumX * sumYlin)) / temp;


		Double a = 0.00;
		a = Math.pow(e, (sumY - (b * sumX)) / N);

		Double aLin = 0.00;
		double temps=(N * sumX2 - sumX * sumX);
		
		if(temps==0)
			temps=1;
		
		aLin = (sumYlin * sumX2 - sumX * sumXYlin) / temps;

		
		Double c = 0.00; 
		Double d = 0.00; 
		Double r = 0.00; 
		if(N==0)
			N=1;
		
		c = (b) * (sumXY - sumX * sumY / N);
		d = sumY2 - (sumY * sumY) / N;
		if(d==0)
			d=1.00;
		
		r = c / d;

		Double cLin = 0.00; 
		Double dLin = 0.00; 
		Double rLin = 0.00; 
		cLin = (bLin) * (sumXYlin - sumX * sumYlin / N);
		dLin = sumY2lin - (sumYlin * sumYlin) / N;
		rLin = cLin / dLin;

		
		Double p = 0.00;
		if (r > 0) {
			p = Math.sqrt(r);
		} else {
			p = 0.00;
		}

		Double pLin = 0.00;
		if (rLin > 0) {
			pLin = Math.sqrt(rLin);
		} else {
			pLin = 0.00;
		}

		Double std_err = 0.00;
		std_err = Math.sqrt((d - c) / (N - 2));

		Double std_errLin = 0.00;
		std_errLin = Math.sqrt((dLin - cLin) / (N - 2));


		for (int i = 0; i < tempTrendList.size(); i++) {
			double value = a * (Math.exp((b * X.get(i))));
			trendAns.add(value);
		}

		return trendAns;
	}

	public List MovingAverage(List tempTrendList) {
		double sum = 0.0;
		List trendAns = new ArrayList();
		double[] testData = new double[tempTrendList.size()];
		int[] period;
		for (int i = 0; i < tempTrendList.size(); i++) {
			if (tempTrendList.get(i) != null)
				testData[i] = (double) tempTrendList.get(i);
		}
		Queue<Double> window = new LinkedList<Double>();
		int[] windowSizes = { 2 };
		for (int windSize : windowSizes) {
			period = windowSizes;
			for (double x : testData) {
				sum += x;
				window.add(x);
				if (window.size() > windSize) {
					sum -= window.remove();
				}
				trendAns.add(sum / window.size());
			}
		}
		return trendAns;
	}

