	public List createRangeColorSmarten(String startColor, String endColor, int autoRangeDivValue) {
		List colorList = new ArrayList();
		try {
			Color start = Color.decode(startColor);
			Color end = Color.decode(endColor);

			int startRed = start.getRed();
			int startGreen = start.getGreen();
			int startBlue = start.getBlue();

			int endRed = end.getRed();
			int endGreen = end.getGreen();
			int endBlue = end.getBlue();

			int tempRed, tempBlue, tempGreen;
			if (autoRangeDivValue > 255)
				autoRangeDivValue = 255;
			for (int i = 0; i < autoRangeDivValue; i++) {
				tempRed = startRed + ((i * (endRed - startRed)) / autoRangeDivValue);
				tempGreen = startGreen + ((i * (endGreen - startGreen)) / autoRangeDivValue);
				tempBlue = startBlue + ((i * (endBlue - startBlue)) / autoRangeDivValue);

				String hex = String.format("#%02x%02x%02x", tempRed, tempGreen, tempBlue);
				colorList.add(hex);
			}

		} catch (NumberFormatException e) {
			ApplicationLog.error(e);
			String[] barColor = new String[] { "#8daacb", "#fc7362", "#bbd854", "#ffd92f", "#66c296", "#e5b694",
					"#e78ad2", "#b3b3b3", "#a6d8e3", "#abe9bc", "#1b7d9c", "#ffbfc9", "#4da741", "#c4b2d6", "#b22424",
					"#00acac", "#be6c2c", "#695496", "#349152", "#c9a16c", "#2d6396", "#fb2600", "#1596ff", "#fc9400",
					"#36fa92", "#ec8b8b", "#93c2ff", "#f7d584", "#b1fb83", "#50407f", "#64c7cd", "#02adf2", "#828813",
					"#3ab54a", "#ed008c", "#a5a4a4" };
			colorList = Arrays.asList(barColor);
			return colorList;
		}
		return colorList;
	}

