	/**
	 * Generates GraphData for Pie graph
	 * 
	 * @param dataVector
	 * @param graphData
	 * @param isTotalVisible
	 * @param divisionValue
	 * @param graphInfo
	 * @return
	 */
	public GraphData generatePieDoughnutGraphdata(Vector dataVector, GraphData graphData, boolean isTotalVisible,
			int divisionValue, SmartenInfo graphInfo, List adjustedDigitList) {
		int dataIndex;
		List dataList = new ArrayList();

		int colIndex;
		List rowList = graphData.getColList();

		int rowIndex;
		List colList = graphData.getRowList();

		Vector header = (Vector) dataVector.elementAt(0);
		dataVector.removeElementAt(0);

		dataIndex = header.indexOf(graphData.getDataLabel());
		colIndex = header.indexOf(graphData.getColLabel());
		rowIndex = header.indexOf(graphData.getRowLabel());

		int colListSize = colList.size();
		int rowListSize = rowList.size();

		if (colListSize == 0) {
			colList.addAll(rowList);
			colListSize = rowListSize;
			colIndex = rowIndex;
			graphData.setColLabel(graphData.getRowLabel());

			rowListSize = 0;
			rowList.clear();
			rowIndex = -1;
			graphData.setRowLabel(null);
		}

		if (rowListSize == 0) {
			rowListSize = 1;
		}
		int noOfRows = 0;
		int noOfColumns = 0;

		if (graphInfo.getGraphData().isSmartenRowsEnable())
			noOfRows = graphInfo.getGraphData().getSmartenRowList().size();
		if (graphInfo.getGraphData().isSmartenColoumnsEnable())
			noOfColumns = graphInfo.getGraphData().getSmartenColList().size();

		if (noOfRows == 0)
			noOfRows = 1;

		List rowsKeyList = new ArrayList();
		List colsKeyList = new ArrayList();
		if (graphInfo.getGraphData().isSmartenRowsEnable() && !graphInfo.isRowsMeasure()) {
			rowsKeyList = getTempRowsKeyList(noOfRows, graphInfo, colListSize, rowIndex);
		}
		if (graphInfo.getGraphData().isSmartenColoumnsEnable() && !graphInfo.isColsMeasure()) {
			colsKeyList = getTempColsKeyList(noOfColumns, graphInfo);
		}
		int rowsKeyListSize = rowsKeyList.size();
		int colsKeyListSize = colsKeyList.size();

		if (rowsKeyListSize == 0)
			rowsKeyListSize = 1;
		if (colsKeyListSize == 0)
			colsKeyListSize = 1;

		int sizeIndex = -1;
		List sizeList = graphData.getSizeList();

		int shapeIndex = -1;
		List shapeList = graphData.getShapeList();

		if (graphData.getSizeLabel() != null && !graphData.getRowLabel().equals(graphData.getSizeLabel()))
			sizeIndex = header.indexOf(graphData.getSizeLabel());
		if (graphData.getShapeLabel() != null && !graphData.getRowLabel().equals(graphData.getShapeLabel()))
			shapeIndex = header.indexOf(graphData.getShapeLabel());

		int sizeListSize = 1;
		int shapeListSize = 1;
		if (graphData.getSizeList() != null)
			sizeListSize = sizeList.size();
		if (graphData.getShapeList() != null)
			shapeListSize = shapeList.size();

		List dataListForTotal = null;
		if (isTotalVisible) {
			dataListForTotal = new ArrayList();
		}

		List tempAdjustedDigitList = new ArrayList();

		for (int i = 0; i < adjustedDigitList.size(); i++) {
			tempAdjustedDigitList.add(adjustedDigitList.get(i));
		}

		List trendValue = new ArrayList();
		List trendAlgoList = new ArrayList();
		if (graphInfo.getGraphProperties().getTrendlinePropertiesMap().size() != 0) {

			Map<Integer, TrendLineProperties> testMap = graphInfo.getGraphProperties().getTrendlinePropertiesMap();
			for (Entry<Integer, TrendLineProperties> entry : testMap.entrySet()) {
				String[] splitString = ((String) entry.getValue().getTrendLineColumn()).split(",");
				trendValue.add(splitString[0]);
				trendAlgoList.add(entry.getValue().getTrendLineType().toString());
			}

		}
		List rowsIndexList = new ArrayList();
		List colsIndexList = new ArrayList();
		if (graphInfo.getGraphData().isSmartenRowsEnable()) {
			for (int i = 0; i < noOfRows; i++) {
				int index = header.indexOf(graphInfo.getGraphData().getSmartenRowList().get(i).toString());
				rowsIndexList.add(index);
			}
		}
		if (graphInfo.getGraphData().isSmartenColoumnsEnable()) {
			for (int i = 0; i < noOfColumns; i++) {
				int index = header.indexOf(graphInfo.getGraphData().getSmartenColList().get(i).toString());
				colsIndexList.add(index);
			}
		}
		Map<String, Double> tempMap = new HashMap<String, Double>();
		int dataVecSize = dataVector.size();
		int recordCount = 0;
		boolean isSwitch = false;
		int zerValueConut = 0;
		Map<String, List> trendMap = new HashMap<String, List>();

		int rowsCount = 0;

		graphData.setColList(colList);
		graphData.setRowList(rowList);
		graphData.setDataList(dataList);
		graphData.setTrendMap(trendMap);

		return graphData;
	}

	public void reArrengeDataItems(List<ActiveUDDCInfo> activeUDDCList, SmartenInfo graphInfo, UserInfo userInfo) {
		List<String> measureList = null;
		boolean removeUddc = false;
		boolean deactiveUddc = false;
		try {
			measureList = metadataServiceUtil.getMeasureList(graphInfo.getCubeInfo(), userInfo, false,graphInfo.isSkipcubedatasetcolumndataaccesspermission(userInfo));
			CubeVector m_OrderedDataColumnInfoList = graphCube.getOrderedDataColumnInfoList();

			deactiveUddc = true;
			if ((graphInfo.getGraphType() == GraphConstants.SCATTER_LINE_GRAPH
					|| graphInfo.getGraphType() == GraphConstants.BUBBLE_GRAPH) && graphInfo.getColColumns().size() > 0
					&& graphInfo.getColColumns().get(0) != null) {
				CubeVector tempDataList = new CubeVector();
				CubeVector tempUDDClist = new CubeVector();

				for (int j = 0; j < activeUDDCList.size(); j++) {
					UddcTemplateInfo uInfo = activeUDDCList.get(0).getUddcTemplateInfo();
					tempUDDClist.add(uInfo.getTemplateName());
				}
				List<String> uddcList = new ArrayList<String>();
				try {
					uddcList = uddcTemplateDAO.getUDDCNameList(graphCube.getName(), userInfo.getUserId());
				} catch (Exception e) {
					ApplicationLog.error(e);
				}
				for (int i = 0; i < m_OrderedDataColumnInfoList.size(); i++) {
					if (!uddcList.contains(m_OrderedDataColumnInfoList.get(i))) {
						tempDataList.add(m_OrderedDataColumnInfoList.get(i));
					} else {
						if (tempUDDClist.contains(m_OrderedDataColumnInfoList.get(i)))
							tempDataList.add(m_OrderedDataColumnInfoList.get(i));
					}
				}
				for (int i = 0; i < activeUDDCList.size(); i++) {
					UddcTemplateInfo uInfo = activeUDDCList.get(i).getUddcTemplateInfo();
					if (!(m_OrderedDataColumnInfoList.contains(uInfo.getTemplateName()))) {
						m_OrderedDataColumnInfoList.add(uInfo.getTemplateName());
					}
				}
				if (activeUDDCList != null && activeUDDCList.size() == 0) {
					m_OrderedDataColumnInfoList.removeAllElements();
					m_OrderedDataColumnInfoList.addAll(tempDataList);
				}
			} else {
				m_OrderedDataColumnInfoList.removeAllElements();
				for (int k = 0; k < graphInfo.getMeasureTitleList().size(); k++) {
					m_OrderedDataColumnInfoList.add(graphInfo.getMeasureTitleList().get(k).toString());

				}

				for (int i = 0; i < activeUDDCList.size(); i++) {
					UddcTemplateInfo uInfo = activeUDDCList.get(i).getUddcTemplateInfo();
					if (!(m_OrderedDataColumnInfoList.contains(uInfo.getTemplateName()))) {
						m_OrderedDataColumnInfoList.add(uInfo.getTemplateName());
					}
				}
			}

		} catch (DatabaseOperationException e) {
			ApplicationLog.error(e);
		}

	}

	public void addRemoveYAxisPropertiesFromMap(SmartenInfo graphInfo, UserInfo userInfo,
			CubeVector orderedDataColumnInfoList) {
		Map<String, YaxisTrendProperties> yaxisMap = graphInfo.getGraphProperties().getyAxisPropertiesMap();
		Map<String, YaxisTrendProperties> finYAxisPropertyMap = new LinkedHashMap<String, YaxisTrendProperties>();
		List<Integer> colList = new ArrayList<Integer>();
		if (null != orderedDataColumnInfoList) {

			for (int i = 0; i < orderedDataColumnInfoList.size(); i++) {
				String colName = (String) orderedDataColumnInfoList.get(i);
				generateYAxisPropertyMap(i, colName, graphInfo, yaxisMap, finYAxisPropertyMap,userInfo);
			}
			
		}
		if (orderedDataColumnInfoList!=null && orderedDataColumnInfoList.size() == 0) {
			graphInfo.getGraphProperties().setyAxisPropertiesMap(yaxisMap);
		} else {
			graphInfo.getGraphProperties().setyAxisPropertiesMap(finYAxisPropertyMap);
		}
	}

	public boolean isMeasureOrUDDC(String dimensionName, SmartenInfo graphInfo, UserInfo userInfo) {
		if (null != dimensionName && !dimensionName.isEmpty() && null != graphInfo.getCubeInfo()) {
		
			try {
				List<String> vDimension = cubeMetadataServiceUtil.getDimensionColumns(graphInfo.getCubeInfo(), userInfo,graphInfo.isSkipcubedatasetcolumndataaccesspermission(userInfo));
				return !vDimension.contains(dimensionName);
			} catch (CubeException e) {
				ApplicationLog.error(e);
				return false;
			}
		} else {
			return false;
		}
	}

