	/**
	 * generates HighlightArea properties for Map in SmartenView
	 * 
	 * @param smartenInfo
	 * @param dataValuList
	 * @return
	 */
	public String getHighlightArea(SmartenInfo smartenInfo, ArrayList<ArrayList<Object>> dataValuList) {
		ObjectMapper mapper = new ObjectMapper();

		String jsonObject = null;
		List<String> dataList = new ArrayList<String>();
		List<HighlightAreaProperties> areaList = new ArrayList<HighlightAreaProperties>();
		HighlightAreaProperties areaProperties;
		if (dataValuList == null)
			dataValuList = new ArrayList();
		try {
			List rowMeasureListtemp = smartenInfo.getGraphData().getRowMeasureListForMap();
			List rangeColorList = smartenInfo.getGraphProperties().getRangeColorList();
			List customColorList = smartenInfo.getGraphProperties().getCustomColors();

			//
			int fixInt = dataValuList.get(0).size() - 1;
			int geoColDimensionSize = 0;
			Map<String, Integer> dimensionValueCountMap = smartenInfo.getDimensionValueCountMap();
			if (null != smartenInfo.getGeoColumnName() && null != dimensionValueCountMap
					&& !dimensionValueCountMap.isEmpty()
					&& dimensionValueCountMap.get(smartenInfo.getGeoColumnName()) != null && fixInt > 4)
			{
				geoColDimensionSize = dimensionValueCountMap.get(smartenInfo.getGeoColumnName()).intValue();
			}
			List fadeColorList = new ArrayList();
			List tempColorList = new ArrayList();
			List<Double> rowMeasureListColor = new ArrayList();
			Map measureColorMaptemp = new HashMap();
			Map measureColorMap = new HashMap();
			List<String> measureListForSmartenviewTab = smartenInfo.getMeasureTitleList();
			if (null == measureListForSmartenviewTab)
				measureListForSmartenviewTab = new ArrayList<String>();
			int fixIntTemp = fixInt;
			if (fixInt > 4 && null != measureListForSmartenviewTab && fixInt > measureListForSmartenviewTab.size())
				fixIntTemp = fixInt - (measureListForSmartenviewTab.size() - 1);
			for (int x = 0; x < dataValuList.size(); x++) {
				if (measureListForSmartenviewTab.size() > 0) {
					if (measureColorMaptemp != null
							&& measureColorMaptemp.get(dataValuList.get(x).get(0).toString()) != null) {
						measureColorMaptemp.put(dataValuList.get(x).get(0).toString(),
								(Double.parseDouble(
										measureColorMaptemp.get(dataValuList.get(x).get(0).toString()).toString())
										+ Double.parseDouble(dataValuList.get(x).get(fixIntTemp).toString())));
					} else {
						measureColorMaptemp.put(dataValuList.get(x).get(0).toString(),
								Double.parseDouble(dataValuList.get(x).get(fixIntTemp).toString()));
					}
					rowMeasureListtemp.add(Double.parseDouble(dataValuList.get(x).get(fixIntTemp).toString()));
				}
			}
			rowMeasureListColor = new ArrayList<Double>(measureColorMaptemp.values());
			if (rowMeasureListtemp != null && rowMeasureListtemp.size() > 0) {
				tempColorList = new ArrayList(rowMeasureListColor);
				fadeColorList = createRangeColorSmarten("#000099", "#ffffff", rowMeasureListColor.size() + 2);
				fadeColorList.remove(fadeColorList.size() - 1);
				fadeColorList.remove(fadeColorList.size() - 2);
				Collections.reverse(fadeColorList);
				Collections.reverse(tempColorList);
				for (int i = 0; i < fadeColorList.size(); i++) {
					measureColorMap.put(tempColorList.get(i).toString(), fadeColorList.get(i));
				}
				smartenInfo.getGraphData().setColorListForMap(fadeColorList);
				smartenInfo.getGraphData().setMeasureColorMap(measureColorMap);
				smartenInfo.getGraphData().setRowMeasureListForMap(rowMeasureListtemp);
			}
			

			for (int x = 0; x < dataValuList.size(); x++) {

				if (!dataList.contains(dataValuList.get(x).get(3))) {
					areaProperties = new HighlightAreaProperties();
					areaProperties.setId((String) dataValuList.get(x).get(3));

					if (smartenInfo.getGraphProperties().getMapColorType() == 6) {
						if (rowMeasureListtemp != null && rowMeasureListtemp.size() > 0
								&& smartenInfo.getGraphProperties().getColorType() != 3
								&& smartenInfo.getGraphProperties().getColorType() != 1) {
							areaProperties.setColor(measureColorMap
									.get(measureColorMaptemp.get(dataValuList.get(x).get(0).toString()).toString())
									.toString());
							areaProperties.setRollOverColor(measureColorMap
									.get(measureColorMaptemp.get(dataValuList.get(x).get(0).toString()).toString())
									.toString());
						}

						if (smartenInfo.getGraphProperties().getColorType() == 2) {
							areaProperties.setColor(smartenInfo.getGraphProperties().getColor());
							areaProperties.setRollOverColor(smartenInfo.getGraphProperties().getColor());
						}

						
						if (smartenInfo.getGraphProperties().getColorType() == 3
								&& smartenInfo.getGraphProperties().getColorRange() == 0)
						{
							if (null != rangeColorList && rangeColorList.size() > x % geoColDimensionSize) {
								areaProperties.setColor(rangeColorList.get(x % geoColDimensionSize).toString());
								areaProperties.setRollOverColor(rangeColorList.get(x % geoColDimensionSize).toString());
							}
						}
						if (smartenInfo.getGraphProperties().getColorType() == 3
								&& smartenInfo.getGraphProperties().getColorRange() == 1)
						{
							if (null != rangeColorList && rangeColorList.size() > x % geoColDimensionSize) {
								areaProperties.setColor(rangeColorList.get(x % geoColDimensionSize).toString());
								areaProperties.setRollOverColor(rangeColorList.get(x % geoColDimensionSize).toString());
							}
						}

						if (smartenInfo.getGraphProperties().getColorType() == 1
								&& smartenInfo.getGraphProperties().getCustomColorType() == 0)
						{
							if (rowMeasureListtemp != null && rowMeasureListtemp.size() > 0) {
								areaProperties.setColor(measureColorMap
										.get(measureColorMaptemp.get(dataValuList.get(x).get(0).toString()).toString())
										.toString());
								areaProperties.setRollOverColor(measureColorMap
										.get(measureColorMaptemp.get(dataValuList.get(x).get(0).toString()).toString())
										.toString());
							}
						}
						if (smartenInfo.getGraphProperties().getColorType() == 1
								&& smartenInfo.getGraphProperties().getCustomColorType() == 4)
						{
							if (null != customColorList && customColorList.size() > x) {
								areaProperties.setColor(customColorList.get(x).toString());
								areaProperties.setRollOverColor(customColorList.get(x).toString());
							}
						}
						
					} else {
						areaProperties.setColor("#FFFFFF");
						areaProperties.setRollOverColor("#FFFFFF");
					}

					dataList.add((String) dataValuList.get(x).get(3));
					areaList.add(areaProperties);
				}

			}
			jsonObject = mapper.writeValueAsString(areaList);
		} catch (IOException e) {
			ApplicationLog.error(e);
		}

		return jsonObject;
	}

