	public void reArrangeMapForNonAggregatedData(SmartenInfo smartenInfo, HashMap requestParamMap, int noOfMeasures) {
		String[] orderedData = StringUtil.toArray((String) requestParamMap.get("orderedDataLabels"));
		String rows = "";
		String cols = "";
		boolean isPieChart = smartenInfo.getGraphType() == GraphConstants.PIE_GRAPH;
		boolean isCombinedChart = smartenInfo.getGraphType() == GraphConstants.COMBINED_GRAPH;

		smartenInfo.setCategoryMeasure(true);
		String collabels = "";
				if (!isCombinedChart) {
			int measures = orderedData.length - 1;
			if (measures == 1) {
				requestParamMap.put("collabels", orderedData[0]);
				smartenInfo.setCategoryMeasureLabel(orderedData[0]);
				return;
			}

			for (int i = 0; i < measures; i++) {
				if (i == measures - 1) {
					if (isPieChart)
						collabels = orderedData[i];
					else
						requestParamMap.put("rowlabels", orderedData[i]);
				} else {
					if (i == measures - 2 && !isPieChart)
						collabels = orderedData[i];
					else {
						if (i % 2 == 0)
							rows = rows + orderedData[i] + ",";
						else
							cols = cols + orderedData[i] + ",";
					}
				}
			}
		} else {
			collabels = orderedData[0];
			String[] dataItems = StringUtil.toArray((String) requestParamMap.get("datalabels"));
			String[] dataItemsForLine = StringUtil.toArray((String) requestParamMap.get("datalabels2"));
			requestParamMap.put("rowlabels", "");
			requestParamMap.put("collabels", orderedData[0]);
			smartenInfo.setCategoryMeasureLabel(orderedData[0]);
			if (dataItems.length == 2) {
				requestParamMap.put("datalabels", dataItems[0] + "," + dataItems[1]);
				requestParamMap.put("datalabels2", "");
			} else if (dataItems.length >= 3) {
				int measures = orderedData.length - 2;
				for (int i = 0; i < measures; i++) {
					if (i == measures - 1)
						collabels = orderedData[i];// requestParamMap.put("collabels",orderedData[i]);
					else {
						if (i % 2 == 0)
							rows = rows + orderedData[i] + ",";
						else
							cols = cols + orderedData[i] + ",";
					}
				}
				requestParamMap.put("collabels", collabels);
				requestParamMap.put("datalabels", dataItems[dataItems.length - 2]);
				requestParamMap.put("datalabels2", dataItems[dataItems.length - 1]);
			}
		}
		requestParamMap.put("collabels", collabels);
		smartenInfo.setCategoryMeasureLabel(collabels);
		if (rows.endsWith(","))
			rows = rows.substring(0, rows.length() - 1);
		if (cols.endsWith(","))
			cols = cols.substring(0, cols.length() - 1);

		requestParamMap.put("coloumns", cols);
		requestParamMap.put("rows", rows);
	}


	public void reArrangeMeasure(SmartenInfo smartenInfo, HashMap requestParamMap) {
		String[] rows = StringUtil.toArray((String) requestParamMap.get("rows"));
		String[] cols = StringUtil.toArray((String) requestParamMap.get("coloumns"));
		String[] colItems = StringUtil.toArray((String) requestParamMap.get("collabels"));
		String[] rowItems = StringUtil.toArray((String) requestParamMap.get("rowlabels"));
		String[] sizes = StringUtil.toArray((String) requestParamMap.get("sizes"));
		String[] shape = StringUtil.toArray((String) requestParamMap.get("shapes"));
		String[] orderedDataLabels = StringUtil.toArray((String) requestParamMap.get("orderedDataLabels"));

		String newMeasure = "";

		for (int i = 0; i < rows.length; i++)
			newMeasure += rows[i] + ",";

		for (int i = 0; i < cols.length; i++)
			newMeasure += cols[i] + ",";

		for (int i = 0; i < colItems.length; i++)
			newMeasure += colItems[i] + ",";

		for (int i = 0; i < rowItems.length; i++)
			newMeasure += rowItems[i] + ",";

		for (int i = 0; i < sizes.length; i++)
			newMeasure += sizes[i] + ",";

		for (int i = 0; i < orderedDataLabels.length; i++)
			newMeasure += orderedDataLabels[i] + ",";

		if (newMeasure.endsWith(","))
			newMeasure = newMeasure.substring(0, newMeasure.length() - 1);

		requestParamMap.put("orderedDataLabels", newMeasure);
		requestParamMap.put("datalabels", newMeasure);

		smartenInfo.setRowsMeasure(false);
		smartenInfo.setColsMeasure(false);

	}

	/**
	 * generate required data of GeoColumns for SmartenView Map
	 * 
	 * @param smarteninfo
	 * @param colLabel
	 * @param noOfMeasures
	 * @param noOfDimension
	 */
	public void getSmartenViewMapDetails(SmartenInfo smarteninfo, String colLabel, int noOfDimension, int noOfMeasures,
			boolean fromGraphTypeChange) {
		List geoColumnInfoList = smarteninfo.getGraphData().getGeoColumnInfoListForSmartenview();
		List dimList = new ArrayList();
		if (smarteninfo.getGraphMode() == AppConstants.NEW_MODE)
			dimList = smarteninfo.getGraphData().getDimensionListForSmartenview();
		else
			dimList = smarteninfo.getDimensionTitleList();

		String strCubeId = smarteninfo.getCubeInfo() != null ? smarteninfo.getCubeInfo().getDataObjectId():"";
		String dimensionName = "";
		boolean allDimGeoColoumn = false;
		int count = 0;
		for (int j = 0; j < dimList.size(); j++) {
			dimensionName = dimList.get(j).toString();
			for (int i = 0; i < geoColumnInfoList.size(); i++) {
				GeographicalColumnInfo geographicalColumnInfo = (GeographicalColumnInfo) geoColumnInfoList.get(i);
				if (strCubeId.endsWith(MashUpConstants.DATASETS_FILE_EXT)) {
					if (dimensionName.equalsIgnoreCase(geographicalColumnInfo.getGeoGraphicalColumnName()))
						count++;
				} else {
					if (geographicalColumnInfo.getGeographicRole().equalsIgnoreCase(dimensionName))
						count++;
				}
			}
		}
		if (count > 0)
			allDimGeoColoumn = true;
		if (fromGraphTypeChange && noOfMeasures > 0)
			smarteninfo.setSmartenMap(true);
		else {
			if (allDimGeoColoumn && noOfMeasures > 0 || (fromGraphTypeChange && smarteninfo.getGraphType() == 71))
				smarteninfo.setSmartenMap(true);
			else
				smarteninfo.setSmartenMap(false);
		}

	}

	public void converD3Vectortographdata(Vector actualDatavector, CubeResultSet theResultSet, Vector d3Vector,
			SmartenInfo smartenInfo, HashtableEx ddvmMap) {

		Vector temp = new Vector();
		Vector temp3 = new Vector();
		List<String> dimensionListForSmartenviewTab = smartenInfo.getDimensionTitleList();
		
		List dimOneList = new ArrayList();
		List dimTwoList = new ArrayList();
		List dimThreeList = new ArrayList();
		List dimFourList = new ArrayList();
		List dimFiveList = new ArrayList();
		int dimOneIndex = 0;
		int dimTwoIndex = 1;
		int dimThreeIndex = 2;
		int dimFourIndex = 3;
		int dimFiveIndex = 4;
		if (smartenInfo.getGraphType() == GraphConstants.D3_TREEMAP) {
			if (smartenInfo.getDimensionTitleList().size() == 2)
				dimOneIndex = 1;
			if (smartenInfo.getDimensionTitleList().size() == 3)
				dimOneIndex = 2;
		}
		if (smartenInfo.getGraphType() == GraphConstants.D3_TREELAYOUT)
			dimOneIndex = dimensionListForSmartenviewTab.size() - 1;
		for (int i = 0; i < d3Vector.size(); i++) {
			Vector temp1 = (Vector) d3Vector.get(i);
			for (int l = 0; l < temp1.size(); l++) {
				Vector temp2 = (Vector) temp1.get(l);
				for (int m = temp2.size() - 1; m >= 0; m--) {
					if (!"".equals(temp2.get(m).toString()))
						temp3.addElement(temp2.get(m));
				}
			}

			d3Vector.clear();
			d3Vector.add(temp3);
		}
		double tempSumDouble = 0;
		Map<String,Object> measureColAvgMap =  new LinkedHashMap<>();
		for (int j = 0; j < actualDatavector.size(); j++) {

			CubeRecord cashRecord = (CubeRecord) theResultSet.get(j);
			int cashRecordSize = cashRecord.size();

			if (smartenInfo.isSmartenTabular() && smartenInfo.getDimensionTitleList().isEmpty())
																								
			{
				cashRecordSize = cashRecordSize / 2;
			}
			boolean isMapOrTabular = (smartenInfo.isSmartenTabular() || smartenInfo.isSmartenMap());
			DecimalFormat df = new DecimalFormat("0.00");
			Vector records = new Vector(cashRecordSize);
			
			if (cashRecordSize > 0) {
				cashRecordSize = cashRecordSize - 1;
			}
			if (isMapOrTabular) {
				for (int k = cashRecordSize; k >= 0; k--) {
					if (cashRecord.get(k) != null) {
						if (cashRecord.get(k) instanceof Double)
							records.add(df.format(cashRecord.get(k)));
						else if (cashRecord.get(k) instanceof Integer)
							records.add(Math.abs(Integer.valueOf(cashRecord.get(k).toString()).intValue()));
						else if (cashRecord.get(k) instanceof Long)
							records.add(Math.abs(Long.valueOf(cashRecord.get(k).toString()).longValue()));
						else {
							String cashRacordStr = cashRecord.get(k).toString();
							if (ddvmMap != null && ddvmMap.size() > 0)
							{
								for (int i = 0; i < dimensionListForSmartenviewTab.size(); i++) {
									if (ddvmMap.containsKey(dimensionListForSmartenviewTab.get(i))) {
										Vector packDisplayList = (Vector) ddvmMap
												.get(dimensionListForSmartenviewTab.get(i));
										if (packDisplayList != null && packDisplayList.size() > 0) {
											for (Iterator iterator = packDisplayList.iterator(); iterator.hasNext();) {
												String[] values = (String[]) iterator.next();
												if (values[0].equalsIgnoreCase(cashRacordStr))
													cashRacordStr = values[1];
											}
										}
									}
								}
							}
							records.add(cashRacordStr);
						}
						if (cashRecord.get(k) instanceof BigDecimal) {
						    tempSumDouble = BigDecimal.valueOf(tempSumDouble).add((BigDecimal) cashRecord.get(k)).doubleValue();
						} else if (cashRecord.get(k) instanceof Double) {
						    tempSumDouble += (Double) cashRecord.get(k);
						} else if (cashRecord.get(k) instanceof Float) {
						    tempSumDouble += ((Float) cashRecord.get(k)).doubleValue();
						} else if (cashRecord.get(k) instanceof Long) {
						    tempSumDouble += ((Long) cashRecord.get(k)).doubleValue();
						} else if (cashRecord.get(k) instanceof Integer) {
						    tempSumDouble += ((Integer) cashRecord.get(k)).doubleValue();
						} else if (cashRecord.get(k) instanceof Short) {
						    tempSumDouble += ((Short) cashRecord.get(k)).doubleValue();
						} else if (cashRecord.get(k) instanceof Byte) {
						    tempSumDouble += ((Byte) cashRecord.get(k)).doubleValue();
						}
					}
					else
					{
						records.add(AppConstants.NULL_DISPLAY_VALUE);
					}
				}
			} else {
				for (int k = cashRecordSize; k >= 0; k--) {
					if (cashRecord.get(k) != null) {
						if (cashRecord.get(k) instanceof Double || cashRecord.get(k) instanceof Long) {
							records.add(cashRecord.get(k));
						if (cashRecord.get(k) instanceof BigDecimal) {
						    tempSumDouble = BigDecimal.valueOf(tempSumDouble).add((BigDecimal) cashRecord.get(k)).doubleValue();
						} else if (cashRecord.get(k) instanceof Double) {
						    tempSumDouble += (Double) cashRecord.get(k);
						} else if (cashRecord.get(k) instanceof Float) {
						    tempSumDouble += ((Float) cashRecord.get(k)).doubleValue();
						} else if (cashRecord.get(k) instanceof Long) {
						    tempSumDouble += ((Long) cashRecord.get(k)).doubleValue();
						} else if (cashRecord.get(k) instanceof Integer) {
						    tempSumDouble += ((Integer) cashRecord.get(k)).doubleValue();
						} else if (cashRecord.get(k) instanceof Short) {
						    tempSumDouble += ((Short) cashRecord.get(k)).doubleValue();
						} else if (cashRecord.get(k) instanceof Byte) {
						    tempSumDouble += ((Byte) cashRecord.get(k)).doubleValue();
						}
						}
						else {
							if(cashRecord.get(dimOneIndex) != null)
								dimOneList.add(cashRecord.get(dimOneIndex).toString());
							else
								dimOneList.add(AppConstants.NULL_DISPLAY_VALUE);
							if (k == dimTwoIndex)
								dimTwoList.add(cashRecord.get(k).toString());
							if (k == dimThreeIndex)
								dimThreeList.add(cashRecord.get(k).toString());
							if (k == dimFourIndex)
								dimFourList.add(cashRecord.get(k).toString());
							if (k == dimFiveIndex)
								dimFiveList.add(cashRecord.get(k).toString());
							String cashRacordStr = cashRecord.get(k).toString();
							if (ddvmMap != null && ddvmMap.size() > 0)
							{
								for (int i = 0; i < dimensionListForSmartenviewTab.size(); i++) {
									if (ddvmMap.containsKey(dimensionListForSmartenviewTab.get(i))) {
										Vector packDisplayList = (Vector) ddvmMap
												.get(dimensionListForSmartenviewTab.get(i));
										if (packDisplayList != null && packDisplayList.size() > 0) {
											for (Iterator iterator = packDisplayList.iterator(); iterator.hasNext();) {
												String[] values = (String[]) iterator.next();
												if (values[0].equalsIgnoreCase(cashRacordStr))
													cashRacordStr = values[1];
											}
										}
									}
								}
							}
							records.add(cashRacordStr);
						}
					} else {
						records.add("(NULL)");
					}
				}
			}
			d3Vector.add(records);
			if(j==actualDatavector.size()-1) {
				double finalsum =tempSumDouble/actualDatavector.size();
				if(null !=smartenInfo.getDataColLabels3() && !smartenInfo.getDataColLabels3().isEmpty())
				measureColAvgMap.put(smartenInfo.getDataColLabels3().get(0).toString(), finalsum);
			}
		}
		smartenInfo.setMeasureColAvgMap(measureColAvgMap);
		smartenInfo.getGraphData().setColList(new ArrayList(new LinkedHashSet(dimOneList)));
		smartenInfo.getGraphData().setRowList(new ArrayList(new LinkedHashSet(dimTwoList)));
		smartenInfo.getGraphData().setRowsList(new ArrayList(new LinkedHashSet(dimThreeList)));
		smartenInfo.getGraphData().setColsList(new ArrayList(new LinkedHashSet(dimFourList)));
		smartenInfo.getGraphData().setDataList(new ArrayList(new LinkedHashSet(dimFiveList)));
		smartenInfo.setGraphDataVector(d3Vector);

	}

	public Vector convertCommonD3DDVM(HashtableEx ddvmMap, List dimensionTitleList, Vector dimensionsVector,
			CubeResultSet theResultSet) {
		Vector dimensionsVectors = new Vector();

		for (int i = 0; i < dimensionsVector.size(); i++) {
			Vector records = new Vector();
			CubeRecord cashRecord = (CubeRecord) dimensionsVector.get(i);
			for (int k = 0; k < cashRecord.size(); k++) {
				if (cashRecord.get(k) != null) {
					if (cashRecord.get(k) instanceof Double || cashRecord.get(k) instanceof Long)
						records.add(cashRecord.get(k));
					else {
						String cashRacordStr = cashRecord.get(k).toString();
						if (ddvmMap != null && ddvmMap.size() > 0)
						{
							for (int j = 0; j < dimensionTitleList.size(); j++) {
								if (k < dimensionTitleList.size() && ddvmMap.containsKey(dimensionTitleList.get(k))) {
									Vector packDisplayList = (Vector) ddvmMap.get(dimensionTitleList.get(j));
									if (packDisplayList != null && packDisplayList.size() > 0) {
										for (Iterator iterator = packDisplayList.iterator(); iterator.hasNext();) {
											String[] values = (String[]) iterator.next();
											if (values[0].equalsIgnoreCase(cashRacordStr))
												cashRacordStr = values[1];
										}
									}
								}
							}
						}
						records.add(cashRacordStr);
					}
				} else {
					records.add("(NULL)");
				}
			}
			dimensionsVectors.add(records);

		}

		return dimensionsVectors;

	}

	public void setContextFilterForD3(SmartenInfo graphInfo) {
		
		Map contextFilterMapD3 = new HashMap<String, String>();
		List dimList = graphInfo.getDimensionTitleList();
		int dimSize = dimList.size();
		ImageGenerationMst imageGenerationMst = null;
		Vector theColLabelList = new Vector();
		for (int i = 0; i < dimSize; i++) {
			imageGenerationMst = new ImageGenerationMst();
			imageGenerationMst.setF_graphType("D3TreeMap");
			imageGenerationMst.setM_XAxisName(dimList.get(i).toString());
			if (i == 0)
				theColLabelList = new Vector(graphInfo.getGraphData().getColList());
			else if (i == 1)
				theColLabelList = new Vector(graphInfo.getGraphData().getRowList());
			else if (i == 2)
				theColLabelList = new Vector(graphInfo.getGraphData().getRowsList());
			else if (i == 3)
				theColLabelList = new Vector(graphInfo.getGraphData().getColsList());
			else if (i == 4)
				theColLabelList = new Vector(graphInfo.getGraphData().getDataList());
			imageGenerationMst.setTheColLabelList(theColLabelList);
			imageGenerationMst.setZAxisLabelList(new Vector());
			imageGenerationMst.setEnableContectFilter(true);
			imageGenerationMst.setResizeRequired(graphInfo.isResizeRequired());
			imageGenerationMst.setDashBoardTdId(getDashbordTdId());
			imageGenerationMst.setObjName(graphInfo.getGraphId());

			imageGenerationMst.setIsHomePage("false");
			imageGenerationMst.setEnableDrillDown(false);
			imageGenerationMst.setDashBoard(true);
			imageGenerationMst.setColDrill(true);
			imageGenerationMst.setObjectFilterApplied(true);

			String imageMapData = null;
			imageMapData = imageGenerationMst.initImageMap(getDashbordTdId());
			String[] split = imageMapData.split(";");

			
			for (int j = 0; j < theColLabelList.size(); j++)
				contextFilterMapD3.put(theColLabelList.get(j).toString(), split[j]);

		}
		graphInfo.setContextFilterMapD3(contextFilterMapD3);
		
	}

