	/**
	 * Sets filter conditions for specified column. (For Page filter)
	 * 
	 * @param colName
	 * @param colConditions
	 * @throws ALSException
	 */
	public void setPageFilterConditions(String colName, CubeVector colConditions, SmartenInfo smartenInfo)
			throws MDXException, RealTimeCubeException, CubeException, ALSException {
		if (graphOrgCube == null) {
			throw new ALSException(ResourceManager.getString("MSG_TEXT_CUBE_NOT_FORMED",
					new Object[] { this.graphDisplayName, this.cubeDisplayName }));
		}
		try {
			graphOrgCube.setFilterConditions(colName, colConditions);
		} catch (MDXException e) {
			throw e;
		} catch (RealTimeCubeException e) {
			throw e;
		} catch (Exception e) {
			throw new CubeException(e.getMessage(), e);
		}
	}

