	private List arrangeDimensionsForMap(List dimensionList, SmartenInfo smartenInfo) {
		List mapDimensionList = new ArrayList();
		List<GeographicalColumnInfo> geoColumnInfoList = smartenInfo.getGraphData()
				.getGeoColumnInfoListForSmartenview();
		if (null == geoColumnInfoList || (null != geoColumnInfoList && geoColumnInfoList.isEmpty())) {
			try {
				geoColumnInfoList = getGeographicalColumnByCubeID(smartenInfo.getCubeInfo().getDataObjectId());
			} catch (DatabaseOperationException e1) {
				ApplicationLog.error(e1);
			}
		}
		boolean isGeoColumn = false;
		String strCubeId = smartenInfo.getCubeInfo().getDataObjectId();
		for (int j = 0; j < dimensionList.size(); j++) {

			for (int i = 0; i < geoColumnInfoList.size(); i++) {
				GeographicalColumnInfo geographicalColumnInfo = (GeographicalColumnInfo) geoColumnInfoList.get(i);
				if ((!strCubeId.endsWith(MashUpConstants.DATASETS_FILE_EXT)
						&& geographicalColumnInfo.getGeographicRole().equalsIgnoreCase(dimensionList.get(j).toString()))
						|| (strCubeId.endsWith(MashUpConstants.DATASETS_FILE_EXT) && dimensionList.get(j).toString()
								.equalsIgnoreCase(geographicalColumnInfo.getGeoGraphicalColumnName()))) {
					isGeoColumn = true;
					mapDimensionList.add(dimensionList.get(j).toString());
					if (null == smartenInfo.getGeoColumnName()
							&& mapDimensionList.contains(dimensionList.get(j).toString()))
																							
																							
						smartenInfo.setGeoColumnName(dimensionList.get(j).toString());
				}
			}
		}
		for (int k = 0; k < dimensionList.size(); k++) {
			if (!mapDimensionList.contains(dimensionList.get(k).toString()))
				mapDimensionList.add(dimensionList.get(k).toString());
		}
		return mapDimensionList;
	}

