	boolean isBounded(double top, double left, double bottom, double right, double latitude, double longitude) {
		if (top >= latitude && latitude >= bottom) {
			
			if (left <= right && left <= longitude && longitude <= right) {
				return true;
			} else if (left > right && (left <= longitude || longitude <= right)) {
				return true;
			}
		}
		return false;
	}

	protected String FormatObject(Object in_objValue, SmartenInfo smartenInfo, 
			com.elegantjbi.vo.properties.NumberFormat numberFormat, boolean isCommaSeparate) {
		String strData = "";

		if (in_objValue == null)
			return null;

		if (in_objValue instanceof Number) {
			double dValue = ((Number) in_objValue).doubleValue();

			int place = numberFormat.getAdjustedDigit();
			if (place > 0) {
				dValue /= Math.pow(10, place);
			}

			Object commaSepObj = numberFormat.isCommaSeprator();
			boolean commaSep = false;
			if (isCommaSeparate && commaSepObj != null) {
				commaSep = ((Boolean) commaSepObj).booleanValue();
			}

			int commaPosStyleObj = numberFormat.getCommaFormat();
			boolean commaPosStyle = false;
			if (commaPosStyleObj == 2)
				commaPosStyle = true;

			if (commaSep && commaPosStyle && (dValue <= -100000 || dValue >= 100000)) {
				numberFormat.setCommaSeprator(false);
				String strFmt = GetDecimalFormatString(numberFormat);
				numberFormat.setCommaSeprator(true);
				java.text.DecimalFormat DecFormat = new java.text.DecimalFormat(strFmt);
				strData = DecFormat.format(dValue);
				strData = StringUtil.modifyDataForIndianStyleCommaPos(strData, null, false);
			} else {
				String strFmt = "#####0";
				if (isCommaSeparate)
					strFmt = GetDecimalFormatString(numberFormat);
				java.text.DecimalFormat DecFormat = new java.text.DecimalFormat(strFmt);
				if (Double.isInfinite(dValue) || Double.isNaN(dValue))
					strData = "";
				else
					strData = DecFormat.format(dValue);
			}
			if (numberFormat.isShowadAdjustedSuffixed())
				strData += GeneralUtil.getAdjustedDigitSuffix(place);
		}

		return strData;
	}

	public String GetDecimalFormatString(com.elegantjbi.vo.properties.NumberFormat numberFormat) {
		String strFormat = "";
		Object key_coma = null;

		key_coma = numberFormat.isCommaSeprator();

		if (key_coma != null) {
			boolean bValue = ((Boolean) key_coma).booleanValue();
			if (bValue) {
				strFormat += "###,##0";
			} else {
				strFormat += "#####0";
			}
		}
		Object obj = null;

		obj = numberFormat.getNumberOfDigits();

		int scale = 0;
		if (obj != null) {
			scale = ((Integer) obj).intValue();
		}
		for (int i = 0; i < scale; i++) {
			if (i == 0) {
				strFormat += '.';
			}
			strFormat += '0';
		}
		strFormat += ';';
		int iChoice = 0;

		iChoice = numberFormat.getNegativeNumberFormat();

		switch (iChoice) {
		case 0:
			strFormat += '-';
			break;
		case 1:
			strFormat += " ";
			break;
		case 2:
			strFormat += '(';
			break;
		case 3:
			strFormat += ResourceManager.getString("DOLLAR");
			break;
		case 4:
			strFormat += ResourceManager.getString("EURO");
			break;
		}

		obj = key_coma;
		if (obj != null) {
			boolean bValue = ((Boolean) obj).booleanValue();
			if (bValue) {
				strFormat += "###,##0";
			} else {
				strFormat += "#####0";
			}
		}
		for (int i = 0; i < scale; i++) {
			if (i == 0) {
				strFormat += '.';
			}
			strFormat += '0';
		}

		switch (iChoice) {
		case 2:
			strFormat += ')';
			break;
		}

		return strFormat;
	}
	public List sortSmartenList(int sortType,boolean isDescSort,boolean isAdvanceSort,List dimList,String dimName,SmartenInfo graphInfo)
	{
		
			if(sortType == 0)
			{
				if(!isDescSort) 
					Collections.sort(dimList);
				else
					Collections.sort(dimList, Collections.reverseOrder());
			}
			if(sortType == 3)
			{
				Map<String, CubeVector> custSortMap = getCustSortMap(graphInfo);
				if (custSortMap != null && custSortMap.get(dimName) != null) {
					List colSortedValueList = new ArrayList(custSortMap.get(dimName));
					if(colSortedValueList != null && colSortedValueList.size() == dimList.size()
						&& null != dimList && colSortedValueList.contains(dimList.get(0).toString()))
					{
						colSortedValueList = changeDataType(colSortedValueList,dimList.get(0));
						dimList = new ArrayList(colSortedValueList);
					}
					else
					{
						
						return dimList;
					}
				}
			}
			
		return dimList;
	}
	public List changeDataType(List originalList,Object firstValue)
	{
		List changedList = new ArrayList();
		if(firstValue instanceof String)
		{	
			changedList.addAll(originalList);
		}
		if(firstValue instanceof Integer)
		{	
			for(int i=0;i<originalList.size();i++)
				changedList.add(Integer.parseInt(originalList.get(i).toString()));
		}
		if(firstValue instanceof Double)
		{	
			for(int i=0;i<originalList.size();i++)
				changedList.add(Double.parseDouble(originalList.get(i).toString()));
		}
		
		return changedList;
	}
	public void removeDataLabels(Map requestParamMap,List ignoreList)
	{
		String newDataLabels = "";
		
		List removeDataList = new ArrayList();
		String[] datalabels = StringUtil.toArray((String) requestParamMap.get("datalabels"));
		
		String[] activeUddcs = StringUtil.toArray((String) requestParamMap.get("userDataLabels"));
		String[] userAddedUddcs = StringUtil.toArray((String) requestParamMap.get("useraddeduddcs"));
		String[] userAddedDataItems = StringUtil.toArray((String) requestParamMap.get("useraddeddatalabels"));
		String[] userAddedDataItemsPosition = StringUtil
				.toArray((String) requestParamMap.get("useraddeddatalabelsposition"));
		
		String newColumn ="";
		for(int i=0;i<activeUddcs.length;i++)
		{	
			removeDataList.add(activeUddcs[i]);
			if(!ignoreList.contains(activeUddcs[i]))
				newColumn = newColumn + activeUddcs[i] + ",";
		}
		if(newColumn.endsWith(","))
			requestParamMap.put("userDataLabels",newColumn.substring(0, newColumn.length() - 1));
		else
			requestParamMap.put("userDataLabels","");
		
		newColumn ="";
		for(int i=1;i<userAddedUddcs.length;i+=2)
		{
			
			removeDataList.add(userAddedUddcs[i]);
			if(!ignoreList.contains(userAddedUddcs[i]))
				newColumn = newColumn + userAddedUddcs[i-1] + ","+ userAddedUddcs[i] + ",";
		}
		if(newColumn.endsWith(","))
			requestParamMap.put("useraddeduddcs",newColumn.substring(0, newColumn.length() - 1));
		else
			requestParamMap.put("useraddeduddcs","");
		
		newColumn ="";
		for(int i=1;i<userAddedDataItems.length;i+=2)
		{
			removeDataList.add(userAddedDataItems[i]);
			if(!ignoreList.contains(userAddedDataItems[i]))
				newColumn = newColumn + userAddedDataItems[i-1] + "," + userAddedDataItems[i]+ ",";
		}
		if(newColumn.endsWith(","))
			requestParamMap.put("useraddeddatalabels",newColumn.substring(0, newColumn.length() - 1));
		else
			requestParamMap.put("useraddeddatalabels","");
		
		for(int i=0;i<datalabels.length;i++)
		{
			if(!removeDataList.contains(datalabels[i]) && !ignoreList.contains(datalabels[i]))
				newDataLabels = newDataLabels + datalabels[i] +",";
		}
		
		if (newDataLabels.endsWith(",")) {
			newDataLabels = newDataLabels.substring(0, newDataLabels.length() - 1);
		}
		requestParamMap.put("datalabels", newDataLabels);
		
	}
	
