	public void setActiveGlobalVariableMapForLinkedObject(
			List<ActiveGlobalVariableInfo> linkedObjectActiveGlobalVariableList) {
		if(graphOrgCube != null && graphOrgCube.getActiveVariablesMap() != null && !graphOrgCube.getActiveVariablesMap().isEmpty()) {
			for(ActiveGlobalVariableInfo activeInfo : linkedObjectActiveGlobalVariableList) {
				Vector gName = (Vector) graphOrgCube.getActiveVariablesMap().get(activeInfo.getGlobalVariableInfo().getGlobalVariableName());
				if(gName.get(1) != null && !gName.get(1).equals("")) {
					gName.set(1, activeInfo.getVariableValue());
				}
			}
		}
		
	}
	
	public String getValueFromColumnLabel(String label, SmartenInfo graphInfo) {
		if (graphInfo.getGraphProperties().getColLabelsMap() != null && graphInfo.getGraphProperties().getColLabelsMap().size() != 0) {
			for(String s : graphInfo.getGraphProperties().getColLabelsMap().keySet()) {
				if(graphInfo.getGraphProperties().getColLabelsMap().get(s).equalsIgnoreCase(label)) {
					return s;
				}
			}
		}
		return label;
	}
	
	public void setStop(boolean stop) {
		if(graphOrgCube != null)
			graphOrgCube.setStop(stop);
		if(graphCube != null)
			graphCube.setStop(stop);
	}
