public boolean retrievalonloadcheck(SmartenInfo graphInfo, UserInfo userInfo) {
	boolean isRetrievalonload = true;
	try {
		ArrayList<String> lstStr = new ArrayList();
		if(graphInfo.getActiveTemplateProperties().getPreloadingParameters() != null) {
			if(graphInfo.getCubeInfo() != null) {
				String[] columnNames = GeneralFiltersUtil.getColumnNamesWithMeasure(cubeMetadataServiceUtil, graphInfo.getCubeInfo(), userInfo);
				if(columnNames != null && columnNames.length > 0) {
					List slt = Arrays.asList(columnNames);
					for(ParamItem item:graphInfo.getActiveTemplateProperties().getPreloadingParameters()) {
						if(slt.contains(item.getColumnName())) {
							lstStr.add(item.getColumnName());
						}
						}
					}
				}
			}
			if(lstStr.isEmpty()) {
				 isRetrievalonload = false;
			}
		} catch (Exception e) {
			ApplicationLog.error(e);
		}
		return isRetrievalonload;	
}


