public void prepareGraphCubeIfEmpty(SmartenInfo graphInfo,
        int rowIndex, int labelIndex, 
        String theYLabelName,
        Vector<?> theRowColLabels, 
        Vector<?> theColColLabels, 
        Vector<?> theDataColLabels) {
	
		try {

			CubeVector rowLabel = new CubeVector();
			CubeVector colLabel = new CubeVector();
			CubeVector dataLabel = new CubeVector();
			CubeLabelInfo theCubeLabelInfo;
			CubeColumnInfo theYCubeColumnInfo = null;
			boolean bflagForDuplicateMeasure = false;

			if (theRowColLabels != null && !theRowColLabels.isEmpty() && rowIndex < theRowColLabels.size()) {
				for (int i = 0; i < rowIndex; i++) {
					theCubeLabelInfo = new CubeLabelInfo((String) theRowColLabels.elementAt(i));
					rowLabel.addElement(theCubeLabelInfo);
				}
			}

			if (theColColLabels != null && !theColColLabels.isEmpty() && labelIndex < theColColLabels.size()) {
				for (int i = 0; i < labelIndex; i++) {
					theCubeLabelInfo = new CubeLabelInfo((String) theColColLabels.elementAt(i));
					rowLabel.addElement(theCubeLabelInfo);
				}
			}

			if (getMultipleYAxisLabelsEnable(graphInfo) || graphInfo.isFlagForAllData()) {
				for (int i = 0; i < theDataColLabels.size(); i++) {
					Object dataCol = theDataColLabels.elementAt(i);
					if (!(dataCol instanceof CubeColumnInfo)) {
						theYCubeColumnInfo = getColumnMetaData(graphInfo, dataCol.toString());
						if (theYCubeColumnInfo != null && getUserDataColumn(theYLabelName) == null) {
							dataLabel.addElement(theYCubeColumnInfo);
						}
					} else {
						bflagForDuplicateMeasure = true;
					}
				}

				if (bflagForDuplicateMeasure) {
					dataLabel.addAll(graphInfo.getTempUserColumns());
				}

			} else {
				theYCubeColumnInfo = getColumnMetaData(graphInfo, theYLabelName);
				if (theYCubeColumnInfo != null && getUserDataColumn(theYLabelName) == null) {
					dataLabel.addElement(theYCubeColumnInfo);
				}
			}

			setFilterConditionsOnCube(new CubeVector());

			Object[] templates = graphOrgCube.getActiveTemplates(TemplateUtil.ANALYSIS_MAINFILTER);
			graphOrgCube.setActiveTemplates(TemplateUtil.ANALYSIS_MAINFILTER, new Object[] {}, false);

			graphCube = graphOrgCube.getSubCube(rowLabel, colLabel, dataLabel, new CubeVector(), false, false, false,
					false, null, false, true, false, "true");

			setFilterConditionsOnCube(graphInfo.getRayOuterConditions());
			refreshPageFilterTooltip(graphInfo);
			graphOrgCube.setActiveTemplates(TemplateUtil.ANALYSIS_MAINFILTER, templates, false);

		}catch(Exception e) {
			ApplicationLog.error(e);
		}
		
}

	public void saveFiltersOnObject(SmartenInfo graphInfoOrg, UserInfo userInfo, String heirarchy) throws DatabaseOperationException{
		SmartenInfo graphInfo = new SmartenInfo();
		String alsDefinition = smartenDAO.getSmartenDefinitionById(graphInfoOrg.getGraphId());
		graphInfo.setGraphDefinition(alsDefinition);
		//analysisInfo.setAnalysisId(analysis.getProcessedAnalysisInfo().getAnalysisId());
		graphInfo.setCubeInfo(graphInfoOrg.getCubeInfo());
		graphInfo.setCubeDefinition(graphInfoOrg.getCubeDefinition());
		graphInfo.setModifiedDate(new Date());
		graphInfo.setModifiedBy(userInfo);
		graphInfo.readFromXml();
		
		if(graphInfo.getMultiPageFilterInfo() != null && graphInfo.getMultiPageFilterInfo().length > 0) {
			graphInfo.setPageFilterColumnInfo(graphInfoOrg.getOriginalPageFilters());
			graphInfo.setMultiPageFilterInfo(null);
		}
		
		List<PageFilterNew> oldList = graphInfo.getPageFilterColumnInfo();
		
		ArrayList<PageFilterNew> newList = graphInfoOrg.getPageFilterColumnInfo();
		
		ArrayList<PageFilterNew> toBeSavedList = getUpdatedFilterList(newList, oldList, userInfo);
		
		graphInfo.writeToXmlForFilters(toBeSavedList);
	
		long privateFilter = toBeSavedList.stream().filter(p->p.isPublicAccess()==false).count();

		if(privateFilter > 0) {
			smartenDAO.updateFilter(graphInfo, graphInfoOrg.getGraphId());
			GeneralUtil.auditUserActionLog(graphInfo, userInfo, heirarchy, ResourceManager.getString("LBL_PRIVATE_FILTER_CHANGED"), AppConstants.DETAIL);

		}
		
	}
	public DecimalFormat DesimalformaterNLP(UserInfo userInfo) {
		String digitsAfterDecimal = userInfo.getNumberOfDigits();
		
		int digits = Integer.parseInt(digitsAfterDecimal);
		
		StringBuilder pattern = new StringBuilder("#");
	    if (digits > 0) {
	        pattern.append(".");
	        for (int i = 0; i < digits; i++) {
	            pattern.append("0");
	        }
	    }
	    DecimalFormat df = new DecimalFormat(pattern.toString());
	   // df.setRoundingMode(RoundingMode.DOWN);
		 return df;
	}
