	@Override
	public String getColumnDisplayNameFromObject(String columnName, Object info) throws ALSException, CubeException {
		String newDisplayName = columnName;		
		Map<String, String> axisValueMap = ((SmartenInfo) info).getGraphProperties().getColLabelsMap();//graphInfo.getAxisDisplayValues();
		 if (axisValueMap == null || axisValueMap.isEmpty()) {
			 axisValueMap = ((SmartenInfo) info).getAxisDisplayValues();
		 }
		if (axisValueMap != null) {
			if (axisValueMap.containsKey(columnName) && !(columnName.equals(axisValueMap.get(columnName)))) {
				newDisplayName = axisValueMap.get(columnName);
			} else {
				newDisplayName = columnName;
			}
		}

		return newDisplayName;
	}
	
	private Map<String, String> buildColLabelsDisplayMap(
	        Map<String, String> colLabelsMap,
	        Map<String, ColumnNameDisplayVo> colDisplayMap) {

	    Map<String, String> result = new HashMap<>();

	    if (colLabelsMap == null || colLabelsMap.isEmpty()) {
	        return result;
	    }

	    for (Map.Entry<String, String> entry : colLabelsMap.entrySet()) {

	        String key = entry.getKey();
	        String value = entry.getValue();

	        String finalValue;

	        // ?? CASE 1: key == value ? use display name
	        if (value != null && value.equals(key)) {

	            if (colDisplayMap != null && colDisplayMap.containsKey(key)) {
	            	ColumnNameDisplayVo dimInfo = colDisplayMap.get(key);
	                String displayName = dimInfo != null ? dimInfo.getDisplayName() : key;
	                finalValue = Parser.unescapeEntities(displayName, false);
	            } else {
	                finalValue = Parser.unescapeEntities(value, false);
	            }
	        }
	        // ?? CASE 2: key != value ? use original
	        else {
	            finalValue = Parser.unescapeEntities(value, false);
	        }
	        result.put(key, finalValue);
	    }

	    return result;
	}
	
	public String setDisplayNameForSmartenTabular(SmartenInfo smartenInfo, List<String> headerCols, String colLabel) {
	    try {
	        Map<String, ColumnNameDisplayVo> colDisplayMap = getColumnDescAndDisplayName(
	                                        smartenInfo.getCubeInfo(), smartenInfo, false);
	        
	        if (colDisplayMap != null && !colDisplayMap.isEmpty()) {
	            
	            if (headerCols != null && !headerCols.isEmpty()) {
	                // Original logic - replace list values with display names
	                headerCols.replaceAll(value ->
	                    Optional.ofNullable(colDisplayMap.get(value))
	                            .map(ColumnNameDisplayVo::getDisplayName)
	                            .filter(displayName -> !displayName.isEmpty())
	                            .orElse(value)
	                );
	            } else {
	                // headerCols is null ? get colLabel value from map and return
	                return Optional.ofNullable(colDisplayMap.get(colLabel))
	                               .map(ColumnNameDisplayVo::getDisplayName)
	                               .filter(displayName -> !displayName.isEmpty())
	                               .orElse(colLabel);  // fallback to original colLabel
	            }
	        }
	        
	    } catch (ALSException | CubeException e) {
	        ApplicationLog.error(e);
	    }
	    return colLabel;
	}
	
	public void updateColLabelsMap(SmartenInfo graphInfo, Map<String, String> colLabelsMap) {
	    if (colLabelsMap == null || colLabelsMap.isEmpty()) {
	        return;
	    }

	    Map<String, ColumnNameDisplayVo> colDisplayMap = null;
	    try {
	        colDisplayMap = getColumnDescAndDisplayName(graphInfo.getCubeInfo(), graphInfo, false);
	    } catch (ALSException | CubeException e) {
	    }

	    Map<String, String> colLabelsDisplayMap = buildColLabelsDisplayMap(colLabelsMap, colDisplayMap);

	    Map<String, String> existingOriginal = graphInfo.getGraphProperties().getColLabelsDisplayMap();

	    if (existingOriginal == null || existingOriginal.isEmpty()) {
	        // First time - store original as is
	        graphInfo.getGraphProperties().setColLabelsDisplayMap(colLabelsMap);
	    } else {
	        // Merge only new keys into existing original
	        for (Map.Entry<String, String> entry : colLabelsMap.entrySet()) {
	            if (!existingOriginal.containsKey(entry.getKey())) {
	                existingOriginal.put(entry.getKey(), entry.getValue());
	            }
	        }
	        graphInfo.getGraphProperties().setColLabelsDisplayMap(existingOriginal);
	    }

	    // Always update display map
	    graphInfo.getGraphProperties().setColLabelsMap(colLabelsDisplayMap);
	}
